def header_filters(request):
    governates = Governate.objects.all()
    selected_governate_param = request.GET.get('governate')
    selected_governate = None
    selected_governate_name = None
    
    if selected_governate_param:
        try:
            # First try to get by ID (if it's a number)
            if selected_governate_param.isdigit():
                selected_governate = Governate.objects.get(id=int(selected_governate_param))
                selected_governate_name = selected_governate.name
            else:
                # If not a number, try to get by name (for backward compatibility)
                selected_governate = Governate.objects.get(name=selected_governate_param)
                selected_governate_name = selected_governate_param
        except (Governate.DoesNotExist, ValueError):
            selected_governate = None
            selected_governate_name = None  # Set to None if not found
    
    return {
        'governates': governates,
        'selected_governate': selected_governate,
        'selected_governate_param': selected_governate_param,
        'selected_governate_name': selected_governate_name,
    }

    

def track_product_view(request, obj):
    """Track product view: increment view_count only once per user session."""
    if not request.user.is_authenticated:
        return

    # Unique key per user and product
    session_key = f'viewed_{request.user.id}_{obj._meta.model_name}_{obj.id}'

    if not request.session.get(session_key):
        # Mark as viewed in this session
        request.session[session_key] = True

        # Increment the view count on the object (handle possible field names)
        view_field = None
        for field in ['view_count', 'views', 'total_views', 'visit_count']:
            if hasattr(obj, field):
                view_field = field
                break

        if view_field:
            current = getattr(obj, view_field, 0)
            setattr(obj, view_field, current + 1)
            obj.save(update_fields=[view_field])

