def track_recently_viewed(request, product_id, product_category, product_data):
    """Track recently viewed products in session (temporary storage) - Works for ALL categories"""
    
    # Get existing recently viewed from session or create empty list
    recently_viewed = request.session.get('recently_viewed', [])
    
    # Create product entry with all possible fields
    product_entry = {
        'id': str(product_id),
        'category': product_category,
        'display_category': product_data.get('display_category', ''),
        'title': product_data.get('title', ''),
        'price': str(product_data.get('price', '')),
        'main_image': product_data.get('main_image', ''),
        'images_json': product_data.get('images_json', '[]'),  # CRITICAL: Store all images
        'city': product_data.get('city', ''),
        'url': product_data.get('url', ''),
        'viewed_at': timezone.now().isoformat(),
        'listing_type': product_data.get('listing_type', ''),
        # Motors fields
        'make': product_data.get('make', ''),
        'model': product_data.get('model', ''),
        'name': product_data.get('name', ''),  # Added this
        'model_year': product_data.get('model_year', ''),
        'year': product_data.get('year', ''),
        'regional_spec': product_data.get('regional_spec', ''),
        # Properties fields
        'bedrooms': product_data.get('bedrooms', ''),
        'bathrooms': product_data.get('bathrooms', ''),
        'area': product_data.get('area', ''),
        # Electronics fields
        'brand': product_data.get('brand', ''),
        'model_number': product_data.get('model_number', ''),
    }
    
    # Remove if already exists (to move to front)
    recently_viewed = [item for item in recently_viewed 
                      if not (item.get('id') == str(product_id) and item.get('category') == product_category)]
    
    # Add to beginning of list
    recently_viewed.insert(0, product_entry)
    
    # Keep only last 15 items
    recently_viewed = recently_viewed[:15]
    
    # Save back to session
    request.session['recently_viewed'] = recently_viewed
    request.session.modified = True
    
    return recently_viewed
