# Add this to your views.py
def get_user_preferred_categories(request):
    """Get user's most viewed categories from session"""
    recently_viewed = request.session.get('recently_viewed', [])
    
    if not recently_viewed:
        return None
    
    # Count category frequency
    category_counts = {}
    for item in recently_viewed:
        category = item.get('display_category', item.get('category', 'Other'))
        category_counts[category] = category_counts.get(category, 0) + 1
    
    if not category_counts:
        return None
    
    # Get most viewed category
    preferred_category = max(category_counts, key=category_counts.get)
    
    return preferred_category


