def index6(request):
    # ========== ADD 45‑DAY EXPIRY CUTOFF ==========
    cutoff_date = timezone.now() - timedelta(days=45)

    governates = Governate.objects.prefetch_related(
        Prefetch('districts', queryset=District.objects.all())
    ).all()
    advertisement = Advertisement.objects.filter(
        category=AdvertisementCategory.MOBILES, 
        is_active=True
    )

    # Filters
    selected_governate_param = request.GET.get('governate')
    selected_district = request.GET.get('district')
    selected_cities = request.GET.getlist('city')
    selected_listing_type = request.GET.get('listing_type')
    name_query = request.GET.get('name', '')
    banners = Banner.objects.filter(category='mobiles', is_active=True)

    # Initialize selected_governate for display
    selected_governate = None
    if selected_governate_param:
        try:
            if selected_governate_param.isdigit():
                selected_governate = Governate.objects.get(id=int(selected_governate_param))
            else:
                selected_governate = Governate.objects.get(name=selected_governate_param)
        except Governate.DoesNotExist:
            selected_governate = None

    # Mobile categories
    categories = {
        'mobiles': Mobile,
        'tablets': Tablet,
        'smartwatches': SmartWatch,
        'headsets': Headset,
        'covers': Cover,
        'accessories': Accessory,
        'mobilesims': MobileSIM,
    }

    category_ads = {
        'mobile_ads': [],
        'tablet_ads': [],
        'smartwatch_ads': [],
        'headset_ads': [],
        'cover_ads': [],
        'accessory_ads': [],
        'mobilesim_ads': [],
    }

    for category_name, model in categories.items():
        # ========== ADD 45‑DAY CUTOFF TO BASE QUERY ==========
        query = model.objects.filter(
            status='approved',
            created_at__gte=cutoff_date   # <-- ADDED
        )

        # Apply filters
        if selected_cities:
            query = query.filter(city_id__in=selected_cities)
        elif selected_district:
            cities = Cities.objects.filter(district_id=selected_district)
            query = query.filter(city_id__in=cities.values_list('id', flat=True))
        elif selected_governate_param:
            cities = Cities.objects.filter(district__governate_id=selected_governate_param)
            query = query.filter(city_id__in=cities.values_list('id', flat=True))

        if selected_listing_type:
            query = query.filter(listing_type=selected_listing_type)

        if name_query:
            query = query.filter(
                Q(title__icontains=name_query) |
                Q(brand__icontains=name_query) |
                Q(model_number__icontains=name_query) |
                Q(description__icontains=name_query) |
                Q(city__name__icontains=name_query) |
                Q(city__district__governate__name__icontains=name_query)
            )

        # ========== ADD BOOST ANNOTATION (no extra queries) ==========
        # Use model._meta.model_name (e.g., 'mobile', 'tablet', etc.)
        # Adjust if your BoostUsage.listing_type uses different strings
        boost_subquery = BoostUsage.objects.filter(
            listing_type=model._meta.model_name,
            listing_id=OuterRef('id'),
            is_active=True
        )
        query = query.annotate(is_boosted=Exists(boost_subquery))

        # Fetch latest 5 (same as original, but now each item has .is_boosted)
        items = query.order_by('-id')[:5]

        for item in items:
            # Get images
            if hasattr(item, 'images'):
                images = [{"image": img.image.url} for img in item.images.all()]
            else:
                images = []
                
            main_image_url = images[0]["image"] if images else "/static/assets/images/resource/default.jpg"
            images_json = mark_safe(json.dumps(images))

            ad_dict = {
                'category': category_name,
                'data': item,
                'main_image_url': main_image_url,
                'images_json': images_json,
                # ========== ADD BOOST FLAG TO TEMPLATE CONTEXT ==========
                'is_boosted': getattr(item, 'is_boosted', False),
            }

            # Push into respective block
            if category_name == 'mobiles':
                category_ads['mobile_ads'].append(ad_dict)
            elif category_name == 'tablets':
                category_ads['tablet_ads'].append(ad_dict)
            elif category_name == 'smartwatches':
                category_ads['smartwatch_ads'].append(ad_dict)
            elif category_name == 'headsets':
                category_ads['headset_ads'].append(ad_dict)
            elif category_name == 'covers':
                category_ads['cover_ads'].append(ad_dict)
            elif category_name == 'accessories':
                category_ads['accessory_ads'].append(ad_dict)
            elif category_name == 'mobilesims':
                category_ads['mobilesim_ads'].append(ad_dict)

    # Districts for dropdown
    districts = District.objects.filter(governate_id=selected_governate_param) if selected_governate_param else None

    context = {
        **category_ads,
        'advertisement': advertisement,
        'governates': governates,
        'districts': districts,
        'selected_governate': selected_governate,
        'selected_governate_obj': selected_governate,
        'selected_governate_param': selected_governate_param,
        'selected_district_obj': District.objects.filter(id=selected_district).first() if selected_district else None,
        'selected_city_objs': Cities.objects.filter(id__in=selected_cities) if selected_cities else [],
        'selected_listing_type': selected_listing_type,
        'name_query': name_query,
        'banners': banners,
    }
    return render(request, 'index-6.html', context)

from django.db.models import Q, Exists, OuterRef
