def index3(request):
    # ========== ADD 45‑DAY EXPIRY CUTOFF ==========
    cutoff_date = timezone.now() - timedelta(days=45)

    # --- Location hierarchy ---
    governates = Governate.objects.prefetch_related(
        Prefetch('districts', queryset=District.objects.all())
    ).all()

    advertisement = Advertisement.objects.filter(
        category=AdvertisementCategory.REAL_ESTATE, 
        is_active=True
    )

    # --- GET parameters ---
    selected_governates = request.GET.getlist('governate')
    selected_districts = request.GET.getlist('district')
    selected_cities = request.GET.getlist('city')
    selected_category = request.GET.get('category')
    selected_listing_type = request.GET.get('listing_type')
    name_query = request.GET.get('name', '')
    banners = Banner.objects.filter(category='real_estate', is_active=True)
    # Count approved ads in each category (unchanged, but note: does not apply 45-day cutoff)
    category_counts = {
        'villa': Villa.objects.filter(status='approved').count(),
        'land': Land.objects.filter(status='approved').count(),
        'apartment': Apartment.objects.filter(status='approved').count(),
        'office': Office.objects.filter(status='approved').count(),
        'shop': Shop.objects.filter(status='approved').count(),
        'cafe': Cafe.objects.filter(status='approved').count(),
        'wholebuilding': Wholebuilding.objects.filter(status='approved').count(),
    }

    # Define model mapping
    categories = {
        'apartment': {'model': Apartment, 'filters': ['rent', 'sell']},
        'villa': {'model': Villa, 'filters': ['rent', 'sell']},
        'shop': {'model': Shop, 'filters': ['rent', 'sell']},
        'land': {'model': Land, 'filters': ['sell']},
        'cafe': {'model': Cafe, 'filters': ['sell', 'rent']},
        'office': {'model': Office, 'filters': ['rent']},
        'wholebuilding': {'model': Wholebuilding, 'filters': ['rent']}
    }

    # --- Apply location filters ---
    def apply_location_filters(queryset):
        if selected_cities:
            return queryset.filter(city_id__in=selected_cities)

        if selected_districts:
            cities = Cities.objects.filter(district_id__in=selected_districts)
            return queryset.filter(city_id__in=cities.values_list('id', flat=True))

        if selected_governates:
            cities = Cities.objects.filter(district__governate_id__in=selected_governates)
            return queryset.filter(city_id__in=cities.values_list('id', flat=True))

        return queryset

    all_ads = []
    for category_name, details in categories.items():
        model = details['model']
        for listing_type in details['filters']:
            # ========== ADD 45‑DAY CUTOFF TO BASE QUERY ==========
            queryset = model.objects.filter(
                status='approved',
                listing_type=listing_type,
                created_at__gte=cutoff_date   # <-- ADDED
            )

            # 🔎 SEARCH EVERYTHING START
            if name_query:
                queryset = queryset.filter(
                    Q(property_title__icontains=name_query) |
                    Q(description__icontains=name_query) |
                    Q(city__name__icontains=name_query) |
                    Q(city__district__name__icontains=name_query) |
                    Q(city__district__governate__name__icontains=name_query)
                )
            # 🔎 SEARCH EVERYTHING END

            # ========== ADD BOOST ANNOTATION ==========
            # Use model._meta.model_name (e.g., 'villa', 'apartment', etc.)
            boost_subquery = BoostUsage.objects.filter(
                listing_type=model._meta.model_name,
                listing_id=OuterRef('id'),
                is_active=True
            )
            queryset = queryset.annotate(is_boosted=Exists(boost_subquery))

            items = queryset.order_by('-id')[:5]

            for item in items:
                images = [{"image": img.image.url} for img in item.images.all()]
                main_image_url = images[0]["image"] if images else "/static/assets/images/resource/default.jpg"
                images_json = mark_safe(json.dumps(images)) if images else "[]"

                # --- Safe Region Name ---
                try:
                    region_name = (
                        item.city.district.governate.governate_name
                        if item.city and item.city.district and item.city.district.governate
                        else ""
                    )
                except:
                    region_name = ""

                all_ads.append({
                    'category': category_name.capitalize(),
                    'listing_type': listing_type.capitalize(),
                    'data': item,
                    'main_image_url': main_image_url,
                    'images_json': images_json,
                    'product_type': category_name.lower(),
                    'region_name': region_name,
                    # ========== ADD BOOST FLAG ==========
                    'is_boosted': getattr(item, 'is_boosted', False),
                })

    # Filter ads by type after collecting all (unchanged)
    land_ads = [ad for ad in all_ads if ad['category'].lower() == 'land' and ad['listing_type'].lower() == 'sell']
    apartment_ads = [ad for ad in all_ads if ad['category'].lower() == 'apartment']
    villa_ads = [ad for ad in all_ads if ad['category'].lower() == 'villa']
    shop_ads = [ad for ad in all_ads if ad['category'].lower() == 'shop' ]
    cafe_ads = [ad for ad in all_ads if ad['category'].lower() == 'cafe']
    office_ads = [ad for ad in all_ads if ad['category'].lower() == 'office' and ad['listing_type'].lower() == 'rent']
    wholebuilding_ads = [ad for ad in all_ads if ad['category'].lower() == 'wholebuilding' and ad['listing_type'].lower() == 'rent']

    # --- Dropdown linkage (unchanged) ---
    districts = District.objects.filter(governate_id__in=selected_governates) if selected_governates else None
    cities = Cities.objects.filter(district_id__in=selected_districts) if selected_districts else None

    # --- OCR & Coordinate Extraction (unchanged) ---
    extracted_text = ""
    table_data = []
    converted_coords = []

    if request.method == 'POST' and 'image' in request.FILES:
        form = ImageUploadForm(request.POST, request.FILES)
        if form.is_valid():
            uploaded_image = form.save()
            image_path = uploaded_image.image.path

            image = PILImage.open(image_path).convert('L').filter(ImageFilter.MedianFilter(size=3))
            image = image.point(lambda x: 0 if x < 128 else 255, '1')
            extracted_text = pytesseract.image_to_string(image)

            lines = extracted_text.split("\n")
            for line in lines:
                numbers = re.findall(r"\d+\.\d+|\d+", line)
                if len(numbers) >= 2:
                    table_data.append((numbers[0], numbers[1]))

            utm_proj = Proj(proj="utm", zone=40, ellps="WGS84", south=False)
            wgs_proj = Proj(proj="latlong", datum="WGS84")
            transformer = Transformer.from_proj(utm_proj, wgs_proj)

            for easting, northing in table_data:
                try:
                    lon, lat = transformer.transform(float(easting), float(northing))
                    converted_coords.append((lat, lon))
                except Exception as e:
                    print(f"⚠ Coordinate conversion error: {e}")
    else:
        form = ImageUploadForm()

    context = {
        'all_ads': all_ads,
        'land_ads': land_ads,
        'apartment_ads': apartment_ads,
        'villa_ads': villa_ads,
        'shop_ads': shop_ads,
        'cafe_ads': cafe_ads,
        'office_ads': office_ads,
        'wholebuilding_ads': wholebuilding_ads,
        'category_counts': category_counts,
        'advertisement': advertisement,

        # Location dropdown data
        'governates': governates,
        'districts': districts,
        'cities': cities,
        'banners': banners,
        'selected_governates': selected_governates,
        'selected_districts': selected_districts,
        'selected_governate_param': selected_governates[0] if selected_governates else None,
        'selected_governate': Governate.objects.filter(id__in=selected_governates).first() if selected_governates else None,
        'selected_cities': selected_cities,

        'selected_category': selected_category,
        'selected_listing_type': selected_listing_type,
        'name_query': name_query,

        'property_locations': json.dumps([
            {
                'title': ad['data'].property_title,
                'lat': ad['data'].latitude,
                'lng': ad['data'].longitude,
                'category': ad['product_type'].capitalize(),
                'url': reverse('browseads1', kwargs={
                    'category': ad['product_type'].capitalize(),
                    'id': ad['data'].id
                })
            }
            for ad in all_ads if ad['data'].latitude and ad['data'].longitude
        ]),
        'form': form,
        'extracted_text': extracted_text,
        'table_data': table_data,
        'converted_coords': converted_coords,
    }

    return render(request, 'index-3.html', context)

from django.db.models import Q
