from django.shortcuts import render
from django.db.models import Q
from django.core.paginator import Paginator
from django.http import HttpResponse
from django.template.loader import render_to_string
import json


def search_results(request):

    advertisement = Advertisement.objects.filter(
        category=AdvertisementCategory.MOTORS, 
        is_active=True
    )

    # ================= BASIC PARAMS =================
    keyword = request.GET.get('keyword', '').strip()
    sort_by = request.GET.get('sort', '-id')
    page_number = request.GET.get('page', 1)

    # ================= LOCATION FILTER PARAMS =================
    selected_governate_params = request.GET.getlist('governate')
    selected_district_params = request.GET.getlist('district')
    selected_cities = request.GET.getlist('city')

    # ================= PRICE RANGE =================
    price_from = request.GET.get('price_from')
    price_to = request.GET.get('price_to')

    results = []
    total_count = 0

    # 🔥 IMPORTANT: Only run search if keyword exists
    if keyword:

        # -------- PRE-CALCULATE CITY FILTER --------
        filtered_city_ids = None

        if selected_cities:
            filtered_city_ids = selected_cities

        elif selected_district_params:
            filtered_city_ids = list(
                Cities.objects.filter(
                    district_id__in=selected_district_params
                ).values_list('id', flat=True)
            )

        elif selected_governate_params:
            filtered_city_ids = list(
                Cities.objects.filter(
                    district__governate_id__in=selected_governate_params
                ).values_list('id', flat=True)
            )

        # ================= ALL CATEGORY MODELS =================
        category_model_map = {
            'land': Land,
            'villa': Villa,
            'commercial': Commercial,
            'farm': Farm,
            'apartment': Apartment,
            'factory': Factory,
            'complex': Complex,
            'job':JobPost,
            'jobcategory':JobCategory,
            'clinic': Clinic,
            'hostel': Hostel,
            'office': Office,
            'shop': Shop,
            'cafe': Cafe,
            'staff': Staff,
            'warehouse': Warehouse,
            'townhouse': Townhouse,
            'fullfloors': Fullfloors,
            'showrooms': Showrooms,
            'wholebuilding': Wholebuilding,
            'supermarket': Supermarket,
            'foreign': Foreign,
            'shared': Shared,
            'suits': Suits,

            'automobile': Automobile,
            'motorcycle': Motorcycle,
            'scooter': Scooter,
            'quadbikes': Quadbikes,
            'heavyvehicle': HeavyVehicle,
            'helmetclothes': HelmetClothes,
            'boat': Boat,
            'numberplate': NumberPlate,
            'junkcar': JunkCar,
            'autoaccessorypart': AutoAccessoryPart,
            'tiresandcaps': TiresAndCaps,
            'drivingtraining': DrivingTraining,

            'mobile': Mobile,
            'tablet': Tablet,
            'smartwatch': SmartWatch,
            'cover': Cover,
            'accessory': Accessory,
            'mobilesim': MobileSIM,
            'headset': Headset,

            'computerlisting': ComputerListing,
            'businessindustriallisting': BusinessIndustrialListing,
            'petlisting': PetListing,
            'sportslisting': SportsListing,
            'musicallisting': MusicalListing,
            'gaminglisting': GamingListing,
            'ticketvoucherlisting': TicketVoucherListing,
            'collectiblelisting': CollectibleListing,
            'bookslisting': BooksListing,
            'musiclisting': MusicListing,
            'dvdsmovieslisting': DVDsMoviesListing,
            'furniturehomegardenlisting': FurnitureHomeGardenListing,
            'babyitemslisting': BabyItemsListing,
            'toyslisting': ToysListing,
            'lostfoundlisting': LostFoundListing,
            'cameralisting': CameraListing,
            'jewelrylisting': JewelryListing,
            'homeappliancelisting': HomeApplianceListing,
            'clothingaccessorieslisting': ClothingAccessoriesListing,
            'electronicslisting': ElectronicsListing,

            'autoservicelisting': AutoServiceListing,
            'consultancyservicelisting': ConsultancyServiceListing,
            'domesticservicelisting': DomesticServiceListing,
            'evententertainmentservicelisting': EventEntertainmentServiceListing,
            'freelancersservicelisting': FreelancersServiceListing,
            'healthwellbeingservicelisting': HealthWellbeingServiceListing,
            'homemaintenanceservicelisting': HomeMaintenanceServiceListing,
            'moversservicelisting': MoversServiceListing,
            'restorationservicelisting': RestorationServiceListing,
            'tutorsservicelisting': TutorsServiceListing,
            'webcomputerservicelisting': WebComputerServiceListing,
            'otherservicelisting': OtherServiceListing,
        }

        # ================= SEARCH LOOP =================
        for category_name, model in category_model_map.items():

            try:
                queryset = model.objects.filter(status='approved')
                model_fields = [f.name for f in model._meta.get_fields()]

                # -------- KEYWORD SEARCH --------
                search_query = Q()

                if 'property_title' in model_fields:
                    search_query |= Q(property_title__icontains=keyword)

                if 'title' in model_fields:
                    search_query |= Q(title__icontains=keyword)

                if 'name' in model_fields:
                    search_query |= Q(name__icontains=keyword)

                if 'description' in model_fields:
                    search_query |= Q(description__icontains=keyword)

                if 'brand' in model_fields:
                    search_query |= Q(brand__icontains=keyword)
                
                if 'make' in model_fields:
                    search_query |= Q(make__icontains=keyword)

                if 'model' in model_fields:
                    search_query |= Q(model__icontains=keyword)


                if 'city' in model_fields:
                    search_query |= Q(city__name__icontains=keyword)
                    search_query |= Q(city__district__name__icontains=keyword)
                    search_query |= Q(city__district__governate__name__icontains=keyword)

                queryset = queryset.filter(search_query).distinct()

                # -------- LOCATION FILTER (ONLY AFTER KEYWORD MATCH) --------
                if 'city' in model_fields and filtered_city_ids:
                    queryset = queryset.filter(city_id__in=filtered_city_ids)

                # -------- PRICE FILTER (ONLY AFTER KEYWORD MATCH) --------
                if 'price' in model_fields:
                    try:
                        if price_from:
                            queryset = queryset.filter(price__gte=float(price_from))
                        if price_to:
                            queryset = queryset.filter(price__lte=float(price_to))
                    except:
                        pass

                # -------- BUILD RESULT LIST --------
                for item in queryset:
                    images = list(item.images.all()[:5]) if hasattr(item, 'images') else []

                    results.append({
                        'category': category_name,
                        'model_name': model.__name__,
                        'data': item,
                        'images': images,
                        'images_json': json.dumps(
                            [img.image.url for img in images]
                        ) if images else '[]',
                        'price': getattr(item, 'price', 0),
                        'title': getattr(
                            item,
                            'title',
                            getattr(item, 'property_title',
                                    getattr(item, 'name',
                                            getattr(item, 'make', '')))
                        ),
                        'city': getattr(item, 'city', None),
                        'created_at': getattr(item, 'created_at', None),
                        'id': getattr(item, 'id', 0),
                    })

            except Exception as e:
                print(f"Error searching {category_name}: {e}")
                continue

        total_count = len(results)

        # -------- SORTING --------
        if sort_by == 'oldest':
            results.sort(key=lambda x: x['created_at'] or x['id'])
        elif sort_by == 'price_asc':
            results.sort(key=lambda x: float(x['price'] or 0))
        elif sort_by == 'price_desc':
            results.sort(key=lambda x: float(x['price'] or 0), reverse=True)
        else:
            results.sort(key=lambda x: x['id'], reverse=True)

    # ================= PAGINATION =================
    paginator = Paginator(results, 9)
    page_obj = paginator.get_page(page_number)

    current_params = request.GET.copy()
    current_params.pop('page', None)

    # ================= GET LOCATION DATA FOR FILTERS =================
    # Get all governates for the filter sidebar
    governates = Governate.objects.all().order_by('name')
    
    # Get districts based on selected governates (if any)
    if selected_governate_params:
        districts = District.objects.filter(governate_id__in=selected_governate_params).order_by('name')
    else:
        districts = District.objects.all().order_by('name')[:100]  # Limit for performance
    
    # Get cities based on selected districts (if any)
    if selected_district_params:
        cities = Cities.objects.filter(district_id__in=selected_district_params).order_by('name')
    elif selected_governate_params:
        cities = Cities.objects.filter(district__governate_id__in=selected_governate_params).order_by('name')
    else:
        cities = Cities.objects.all().order_by('name')[:100]  # Limit for performance

    context = {
        'keyword': keyword,
        'page_obj': page_obj,
        'total_results': total_count,
        'total_count': total_count,
        'advertisement': advertisement,
        'current_params': current_params.urlencode(),
        'current_sort': sort_by,
        'is_search_results': True,

        'price_from': price_from,
        'price_to': price_to,
        'selected_governate_params': selected_governate_params,
        'selected_district_params': selected_district_params,
        'selected_cities': selected_cities,
        
        # Add location data for filters
        'governates': governates,
        'districts': districts,
        'cities': cities,
    }

    if request.headers.get('X-Requested-With') == 'XMLHttpRequest':
        html = render_to_string('search-result-partial.html', context, request=request)
        return HttpResponse(html)

    return render(request, 'search-results.html', context)

def clear_search_filters(request):
    """Redirect to search results with only the keyword parameter"""
    keyword = request.GET.get('keyword', '').strip()
    if keyword:
        return redirect(f"{reverse('search_results')}?keyword={keyword}")
    return redirect('search_results')

