from django.core.paginator import Paginator
from django.shortcuts import render
from django.db.models import Q
from .models import Chalet, Villa, Land, Commercial, Farm  # Ensure you import your models
import json

def chalet(request):
    # Define a mapping of region codes to full names
    region_mapping = {
       'MS': 'Muscat',
    'DH': 'Dhofar',
    'BT': 'Al Batinah',
    'DA': 'Al Dakhiliyah',
    'SH': 'Al Sharqiyah',
    'BZ': 'Al Buraimi',
    'DZ': 'Musandam',
    'WT': 'Al Wusta',
    'ZU': 'Al Dhahirah'
    }

    # Fetch query parameters
    selected_region_code = request.GET.get('region', None)  # If no region is selected, use None
    selected_listing_type = request.GET.get('listing_type', None)  # If no listing type is selected, use None
    selected_city = [city for city in request.GET.getlist('city') if city and city.lower() != 'null']
    name_query = request.GET.get('name', '')  # Search query
    price_from = request.GET.get('price_from')  # Price range: from
    price_to = request.GET.get('price_to')      # Price range: to
    selected_amenities = request.GET.get('amenities', None)  # Amenities filter
    filters = request.GET.get('filters', '')  # Additional filters
    bedrooms = request.GET.get('bedrooms')  # Bedrooms filter
    bathrooms = request.GET.get('bathrooms')  # Bathrooms filter
    tenancy_information = request.GET.get('tenancy_information')  # Tenancy information filter

    # Start with all approved chalets
    chalet_queryset = Chalet.objects.filter(status='approved')

    # Apply region filter if selected
    if selected_region_code and selected_region_code != "all":
        chalet_queryset = chalet_queryset.filter(regions=selected_region_code)

    # Apply listing type filter if selected
    if selected_listing_type and selected_listing_type != "all":
        chalet_queryset = chalet_queryset.filter(listing_type=selected_listing_type)

    # Filter by city if selected and not "All Cities"
    if selected_city and selected_city != "All Cities":
        chalet_queryset = chalet_queryset.filter(cities__icontains=selected_city)

    # Apply amenities filter if selected
    if selected_amenities and selected_amenities != "all":
        chalet_queryset = chalet_queryset.filter(amenities__icontains=selected_amenities)

    # Apply search query filter
    if name_query:
        chalet_queryset = chalet_queryset.filter(
            Q(property_title__icontains=name_query) |
            Q(regions__icontains=name_query) |
            Q(cities__icontains=name_query) |
            Q(listing_type__icontains=name_query) 
        )

    # Price Range Filtering
    if price_from and price_to:
        chalet_queryset = chalet_queryset.filter(price__gte=price_from, price__lte=price_to)
    elif price_from:
        chalet_queryset = chalet_queryset.filter(price__gte=price_from)
    elif price_to:
        chalet_queryset = chalet_queryset.filter(price__lte=price_to)

    # Bedrooms Filtering
    if bedrooms:
        chalet_queryset = chalet_queryset.filter(bedrooms=bedrooms)

    # Bathrooms Filtering
    if bathrooms:
        chalet_queryset = chalet_queryset.filter(bathrooms=bathrooms)

    # Tenancy Information Filtering
    if tenancy_information and tenancy_information != "all":
        chalet_queryset = chalet_queryset.filter(tenancy_information=tenancy_information)

    # Additional filters
    if filters:
        chalet_queryset = chalet_queryset.filter(property_title__icontains=filters)

    # Process images for each chalet
    for chalet in chalet_queryset:
        chalet.images_json = json.dumps([image.image.url for image in chalet.images.all()])

    # Calculate category counts
    category_counts = {
        'villa': Villa.objects.filter(status='approved').count(),
        'land': Land.objects.filter(status='approved').count(),
        'commercial': Commercial.objects.filter(status='approved').count(),
        'chalet': Chalet.objects.filter(status='approved').count(),
        'farm': Farm.objects.filter(status='approved').count(),
    }

    # Set up pagination
    paginator = Paginator(chalet_queryset, 6)  # Show 6 chalets per page
    page_number = request.GET.get('page')  
    page_obj = paginator.get_page(page_number)  

    # Get the available regions and property types for the filter dropdowns
    regions = [("all", "All")] + list(Chalet.REGION_CHOICES)  # Assuming REGION_CHOICES is a class variable in the Chalet model
    listing_types = [("all", "All")] + list(Chalet.TRANSACTION_CHOICES)  # Assuming TRANSACTION_CHOICES is a class variable in the Chalet model
    tenancy_options = [("all", "All")] + list(Chalet.tenancy_information.field.choices)  # Tenancy information choices

    # Render the template with the context
    return render(request, 'estate/chalet.html', {
        'page_obj': page_obj,
        'regions': regions,
        'listing_types': listing_types,
        'tenancy_options': tenancy_options,
        'selected_region': region_mapping.get(selected_region_code, selected_region_code) if selected_region_code else None,  # Pass the full region name
        'selected_listing_type': selected_listing_type,  # Pass the selected listing type to the template
        'selected_amenities': selected_amenities,  # Pass the selected property type to the template
        'selected_city':selected_city,
        'category_counts': category_counts,
        'name_query': name_query,
        'price_from': price_from,
        'price_to': price_to,
        'filters': filters,
        'bedrooms': bedrooms,
        'bathrooms': bathrooms,
        'tenancy_information': tenancy_information,
    })

def chalet_details(request, id):
    chalet = get_object_or_404(Chalet, id=id)
    return render(request, 'estate/chalet_details.html', {'chalet': chalet})

    
# views.py - UPDATED with first_name and last_name
import random
import time
import re
from django.shortcuts import render, redirect
from django.contrib import messages
from django.conf import settings
from django.contrib.auth import get_user_model
from django.core.validators import validate_email
from django.core.exceptions import ValidationError
import requests

from .services.email_service import EmailOTPService

CustomUser = get_user_model()

def normalize_oman_phone(phone):
    """Keep your original phone normalization (Oman, +968)"""
    phone = re.sub(r'\D', '', phone.strip())
    if phone.startswith('0'):
        phone = phone[1:]
    if phone.startswith('968'):
        phone = phone[3:]
    if len(phone) not in [7, 8]:
        return None
    return '+968' + phone

def is_valid_email_abstract(email):
    """Abstract API email validation"""
    api_key = settings.ABSTRACT_API_KEY
    url = f"https://emailvalidation.abstractapi.com/v1/?api_key={api_key}&email={email}"
    try:
        response = requests.get(url, timeout=10)
        data = response.json()
        if data.get("is_valid_format", {}).get("value") and data.get("deliverability") == "DELIVERABLE":
            return True
        return False
    except Exception:
        return False

def signup_view1(request):
    if request.method == "POST":
        # ---------- STEP 2: VERIFY OTP ----------
        if "verify_otp" in request.POST:
            entered_otp = request.POST.get("otp")
            session_otp = request.session.get("otp")
            email = request.session.get("email")
            phone = request.session.get("phone")
            user_type = request.session.get("user_type", "regular")
            first_name = request.session.get("first_name")
            last_name = request.session.get("last_name")
            otp_created_at = request.session.get("otp_created_at")

            if not session_otp or not email or not otp_created_at:
                messages.error(request, "Session expired. Please restart.")
                request.session.flush()
                return redirect("signup")

            if time.time() - otp_created_at > 300:   # 5 minutes
                messages.error(request, "OTP expired. Request a new one.")
                request.session.pop("otp", None)
                request.session.pop("otp_created_at", None)
                return render(request, "signup.html", {
                    "show_otp": True,
                    "email": email,
                    "phone": phone,
                    "user_type": user_type,
                    "first_name": first_name,
                    "last_name": last_name,
                })

            if entered_otp == str(session_otp):
                request.session["email_verified"] = True
                return render(request, "signup.html", {
                    "show_password_form": True,
                    "email": email,
                    "phone": phone,
                    "user_type": user_type,
                    "first_name": first_name,
                    "last_name": last_name,
                })
            else:
                messages.error(request, "Invalid OTP. Try again.")
                return render(request, "signup.html", {
                    "show_otp": True,
                    "email": email,
                    "phone": phone,
                    "user_type": user_type,
                    "first_name": first_name,
                    "last_name": last_name,
                })

        # ---------- STEP 3: FINAL REGISTRATION (username + password) ----------
        elif "final_register" in request.POST:
            if not request.session.get("email_verified"):
                messages.error(request, "Please verify your email first.")
                return redirect("signup")

            username = request.POST.get("username")
            password1 = request.POST.get("password1")
            password2 = request.POST.get("password2")
            email = request.session.get("email")
            phone = request.session.get("phone")
            user_type = request.session.get("user_type", "regular")
            first_name = request.session.get("first_name")
            last_name = request.session.get("last_name")

            # Validation
            if not username or not password1:
                messages.error(request, "Username and password are required.")
                return render(request, "signup.html", {
                    "show_password_form": True,
                    "email": email,
                    "phone": phone,
                    "user_type": user_type,
                    "first_name": first_name,
                    "last_name": last_name,
                })

            if password1 != password2:
                messages.error(request, "Passwords do not match.")
                return render(request, "signup.html", {
                    "show_password_form": True,
                    "email": email,
                    "phone": phone,
                    "user_type": user_type,
                    "first_name": first_name,
                    "last_name": last_name,
                })

            if len(password1) < 8:
                messages.error(request, "Password must be at least 8 characters.")
                return render(request, "signup.html", {
                    "show_password_form": True,
                    "email": email,
                    "phone": phone,
                    "user_type": user_type,
                    "first_name": first_name,
                    "last_name": last_name,
                })

            # Username unique check
            if CustomUser.objects.filter(username=username).exists():
                messages.error(request, "Username already taken.")
                return render(request, "signup.html", {
                    "show_password_form": True,
                    "email": email,
                    "phone": phone,
                    "user_type": user_type,
                    "first_name": first_name,
                    "last_name": last_name,
                })

            # Create user with first_name and last_name
            try:
                user = CustomUser.objects.create_user(
                    username=username,
                    email=email,
                    first_name=first_name,
                    last_name=last_name,
                    phone=phone,
                    password=password1,
                    user_type=user_type
                )
                if user_type == "agent":
                    user.is_active = False
                    user.is_approved = False
                    user.save()
                    messages.success(request, "Agent account created! Awaiting admin approval.")
                else:
                    user.is_active = True
                    user.is_approved = True
                    user.save()
                    messages.success(request, "Registration successful! Please log in.")
                request.session.flush()
                return redirect("login")
            except Exception as e:
                messages.error(request, f"Error creating account: {str(e)}")
                return render(request, "signup.html", {
                    "show_password_form": True,
                    "email": email,
                    "phone": phone,
                    "user_type": user_type,
                    "first_name": first_name,
                    "last_name": last_name,
                })

        # ---------- STEP 1: FIRST_NAME + LAST_NAME + EMAIL + PHONE + USER_TYPE, VALIDATE & SEND OTP ----------
        else:
            # Collect fields
            first_name = request.POST.get("first_name", "").strip()
            last_name = request.POST.get("last_name", "").strip()
            email = request.POST.get("email", "").strip()
            phone = request.POST.get("phone", "").strip()
            user_type = request.POST.get("user_type", "regular")

            # ---- First name validation ----
            if not first_name:
                messages.error(request, "First name is required.")
                return render(request, "signup.html", {
                    "user_types": CustomUser.USER_TYPE_CHOICES[:-1],
                    "first_name": first_name,
                    "last_name": last_name,
                    "email": email,
                    "phone": phone,
                    "user_type": user_type,
                })
            # Optional: allow only letters and spaces
            if not re.match(r'^[A-Za-z\s]+$', first_name):
                messages.error(request, "First name can only contain letters and spaces.")
                return render(request, "signup.html", {
                    "user_types": CustomUser.USER_TYPE_CHOICES[:-1],
                    "first_name": first_name,
                    "last_name": last_name,
                    "email": email,
                    "phone": phone,
                    "user_type": user_type,
                })

            # ---- Last name validation ----
            if not last_name:
                messages.error(request, "Last name is required.")
                return render(request, "signup.html", {
                    "user_types": CustomUser.USER_TYPE_CHOICES[:-1],
                    "first_name": first_name,
                    "last_name": last_name,
                    "email": email,
                    "phone": phone,
                    "user_type": user_type,
                })
            if not re.match(r'^[A-Za-z\s]+$', last_name):
                messages.error(request, "Last name can only contain letters and spaces.")
                return render(request, "signup.html", {
                    "user_types": CustomUser.USER_TYPE_CHOICES[:-1],
                    "first_name": first_name,
                    "last_name": last_name,
                    "email": email,
                    "phone": phone,
                    "user_type": user_type,
                })

            # ---- Phone validation (original logic) ----
            if not phone:
                messages.error(request, "Phone number is required.")
                return render(request, "signup.html", {
                    "user_types": CustomUser.USER_TYPE_CHOICES[:-1],
                    "first_name": first_name,
                    "last_name": last_name,
                    "email": email,
                    "user_type": user_type,
                })
            normalized_phone = normalize_oman_phone(phone)
            if not normalized_phone:
                messages.error(request, "Invalid phone number (must be 7-8 digits).")
                return render(request, "signup.html", {
                    "user_types": CustomUser.USER_TYPE_CHOICES[:-1],
                    "first_name": first_name,
                    "last_name": last_name,
                    "email": email,
                    "user_type": user_type,
                })
            phone = normalized_phone

            # ---- Email validation (Abstract API) ----
            if not email:
                messages.error(request, "Email is required.")
                return render(request, "signup.html", {
                    "user_types": CustomUser.USER_TYPE_CHOICES[:-1],
                    "first_name": first_name,
                    "last_name": last_name,
                    "phone": phone,
                    "user_type": user_type,
                })
            try:
                validate_email(email)
            except ValidationError:
                messages.error(request, "Invalid email format.")
                return render(request, "signup.html", {
                    "user_types": CustomUser.USER_TYPE_CHOICES[:-1],
                    "first_name": first_name,
                    "last_name": last_name,
                    "phone": phone,
                    "user_type": user_type,
                })
            if not is_valid_email_abstract(email):
                messages.error(request, "Email address is invalid or non-deliverable. Please use a real email.")
                return render(request, "signup.html", {
                    "user_types": CustomUser.USER_TYPE_CHOICES[:-1],
                    "first_name": first_name,
                    "last_name": last_name,
                    "phone": phone,
                    "user_type": user_type,
                })

            # ---- Uniqueness checks ----
            if CustomUser.objects.filter(email=email).exists():
                messages.error(request, "This email is already registered. Please login.")
                return render(request, "signup.html", {
                    "user_types": CustomUser.USER_TYPE_CHOICES[:-1],
                    "first_name": first_name,
                    "last_name": last_name,
                    "phone": phone,
                    "user_type": user_type,
                })
            if CustomUser.objects.filter(phone=phone).exists():
                messages.error(request, "This phone number is already registered. Please login.")
                return render(request, "signup.html", {
                    "user_types": CustomUser.USER_TYPE_CHOICES[:-1],
                    "first_name": first_name,
                    "last_name": last_name,
                    "email": email,
                    "user_type": user_type,
                })

            # ---- Generate OTP and send via email ----
            otp = EmailOTPService.generate_otp()
            request.session["otp"] = otp
            request.session["email"] = email
            request.session["phone"] = phone
            request.session["user_type"] = user_type
            request.session["first_name"] = first_name
            request.session["last_name"] = last_name
            request.session["otp_created_at"] = int(time.time())
            request.session["email_verified"] = False

            success, response = EmailOTPService.send_otp(email, otp)
            if success:
                messages.success(request, f"Verification code sent to {email}")
                # No test OTP display on screen
            else:
                messages.error(request, f"Failed to send OTP: {response.get('error')}")
                return render(request, "signup.html", {
                    "user_types": CustomUser.USER_TYPE_CHOICES[:-1],
                    "first_name": first_name,
                    "last_name": last_name,
                    "email": email,
                    "phone": phone,
                    "user_type": user_type,
                })

            return render(request, "signup.html", {
                "show_otp": True,
                "email": email,
                "phone": phone,
                "user_type": user_type,
                "first_name": first_name,
                "last_name": last_name,
            })

    # GET request – show initial form with fields for first_name, last_name, email, phone, user_type
    return render(request, "signup.html", {
        "user_types": CustomUser.USER_TYPE_CHOICES[:-1],  # exclude admin
        # No pre-filled values, but template can have empty inputs
    })

from django.http import JsonResponse
from .services.email_service import EmailOTPService
import time

def resend_otp(request):
    if request.method == 'POST':
        email = request.POST.get('email')
        phone = request.POST.get('phone')
        user_type = request.POST.get('user_type', 'regular')

        if not email or not phone:
            return JsonResponse({"success": False, "error": "Email and phone are required."})

        # Generate new OTP
        otp = EmailOTPService.generate_otp()

        # Update session
        request.session["otp"] = otp
        request.session["email"] = email
        request.session["phone"] = phone
        request.session["user_type"] = user_type
        request.session["otp_created_at"] = int(time.time())
        request.session["email_verified"] = False

        # Send OTP via email
        success, response = EmailOTPService.send_otp(email, otp)
        if success:
            return JsonResponse({"success": True})
        else:
            return JsonResponse({"success": False, "error": response.get("error", "Failed to send OTP")})

    return JsonResponse({"success": False, "error": "Invalid request method."})


# Update your custom_logout_view function:

def custom_logout_view(request):
    logout(request)
    request.session.flush()
    
    # Check the referer to determine where to redirect
    referer = request.META.get('HTTP_REFERER', '')
    
    if '/subadmin/' in referer:
        return redirect('subadmin_login')
    elif '/admin/' in referer:
        return redirect('admin')
    else:
        return redirect('login1')

    
from django.db.models import Q
from django.core.paginator import Paginator
