def electronics_details(request, id):
    electronics = get_object_or_404(ElectronicsListing, id=id)
    advertisement = Advertisement.objects.filter(
        category=AdvertisementCategory.OTHER_CLASSIFIED, 
        is_active=True
    )
    track_product_view(request, electronics)

    # ========== RECENTLY VIEWED TRACKING ==========
    # Get all images for the electronics listing
    images_recent = []
    if hasattr(electronics, 'images') and electronics.images.exists():
        images_recent = [{"image": img.image.url} for img in electronics.images.all()]
    elif hasattr(electronics, 'main_image') and electronics.main_image:
        images_recent = [{"image": electronics.main_image.url}]
    
    # Get main image URL
    main_image_url = images_recent[0]["image"] if images_recent else "/static/assets/images/resource/default.jpg"
    
    # Convert images to JSON string
    images_json = json.dumps(images_recent)
    
    # Get title
    title = ""
    if hasattr(electronics, 'title') and electronics.title:
        title = electronics.title
    elif hasattr(electronics, 'product_name') and electronics.product_name:
        title = electronics.product_name
    elif hasattr(electronics, 'name') and electronics.name:
        title = electronics.name
    else:
        title = f"Electronics #{electronics.id}"
    
    # Get city name
    city_name = ""
    if hasattr(electronics, 'city') and electronics.city:
        city_name = electronics.city.name
    
    # Get price
    price = electronics.price if hasattr(electronics, 'price') else 0
    
