def lostfound_details(request, id):
    lostfound = get_object_or_404(LostFoundListing, id=id)
    advertisement = Advertisement.objects.filter(
        category=AdvertisementCategory.OTHER_CLASSIFIED, 
        is_active=True
    )
    track_product_view(request, lostfound)

    # ========== RECENTLY VIEWED TRACKING ==========
    # Get all images for the lost & found listing
    images_recent = []
    if hasattr(lostfound, 'images') and lostfound.images.exists():
        images_recent = [{"image": img.image.url} for img in lostfound.images.all()]
    elif hasattr(lostfound, 'main_image') and lostfound.main_image:
        images_recent = [{"image": lostfound.main_image.url}]
    
    # Get main image URL
    main_image_url = images_recent[0]["image"] if images_recent else "/static/assets/images/resource/default.jpg"
    
    # Convert images to JSON string
    images_json = json.dumps(images_recent)
    
    # Get title
    title = ""
    if hasattr(lostfound, 'title') and lostfound.title:
        title = lostfound.title
    elif hasattr(lostfound, 'product_name') and lostfound.product_name:
        title = lostfound.product_name
    elif hasattr(lostfound, 'name') and lostfound.name:
        title = lostfound.name
    else:
        title = f"Lost & Found #{lostfound.id}"
    
    # Get city name
    city_name = ""
    if hasattr(lostfound, 'city') and lostfound.city:
        city_name = lostfound.city.name
    
    # Get price
    price = lostfound.price if hasattr(lostfound, 'price') else 0
    
    product_data = {
        'title': title,
        'price': price,
        'main_image': main_image_url,
        'images_json': images_json,
        'city': city_name,
        'url': request.build_absolute_uri(),
        'listing_type': '',
        'display_category': 'Other Categories',
        'brand': '',
        'category_type': 'lostfoundlisting',
    }
    
    # Track the recently viewed product
    track_recently_viewed(request, str(lostfound.id), 'lostfoundlisting', product_data)
    # ========== END RECENTLY VIEWED TRACKING ==========

    # Report submission
    if request.method == "POST" and "report_submit" in request.POST:
        reason = request.POST.get("reason")
        description = request.POST.get("description", "")

        if reason:
            ProductReport.objects.create(
                reporter=request.user if request.user.is_authenticated else None,
                reason=reason,
                description=description,
                content_type=ContentType.objects.get_for_model(lostfound),
                object_id=lostfound.id,
            )
            messages.success(request, "Thank you for reporting. We'll review it shortly.")
            return redirect(request.path)
        else:
            messages.error(request, "Please select a valid reason for the report.")
    
    # Get governates for filters (if needed)
    governates = Governate.objects.prefetch_related(
        Prefetch('districts', queryset=District.objects.all())
    ).all()
    
    # Check if favorited
    is_favorited = False
    if request.user.is_authenticated:
        content_type = ContentType.objects.get_for_model(lostfound)
        is_favorited = Favorite.objects.filter(
            user=request.user,
            content_type=content_type,
            object_id=lostfound.id
        ).exists()
    
    images = lostfound.images.all() if hasattr(lostfound, "images") else []
    videos = lostfound.videos.all() if hasattr(lostfound, "videos") else []
    
    # Location display string
    location_display = ""
    if lostfound.city and lostfound.city.district and lostfound.city.district.governate:
        location_display = f"{lostfound.city.name}, {lostfound.city.district.name}, {lostfound.city.district.governate.name}"
    
    # ========== GET COORDINATES FOR MAP ==========
    # Try to get coordinates from lostfound first, then fallback to city, then default
    latitude = None
    longitude = None
    
    # Check if lostfound has coordinates
    if hasattr(lostfound, 'latitude') and lostfound.latitude and hasattr(lostfound, 'longitude') and lostfound.longitude:
        latitude = float(lostfound.latitude)
        longitude = float(lostfound.longitude)
        print(f"Using lostfound coordinates: {latitude}, {longitude}")
    
    # Fallback to city coordinates if available
    elif lostfound.city:
        if hasattr(lostfound.city, 'latitude') and lostfound.city.latitude and hasattr(lostfound.city, 'longitude') and lostfound.city.longitude:
            latitude = float(lostfound.city.latitude)
            longitude = float(lostfound.city.longitude)
            print(f"Using city coordinates: {latitude}, {longitude}")
        else:
            # If city doesn't have coordinates, use geocoding or default
            try:
                from geopy.geocoders import GoogleV3
                geolocator = GoogleV3(api_key='YOUR_GOOGLE_API_KEY')  # Replace with your API key
                location = geolocator.geocode(f"{lostfound.city.name}, Egypt")
                if location:
                    latitude = location.latitude
                    longitude = location.longitude
                    print(f"Geocoded coordinates: {latitude}, {longitude}")
                else:
                    # Default to Egypt center
                    latitude = 26.8206
                    longitude = 30.8025
            except Exception as e:
                print(f"Geocoding failed: {e}")
                # Default to Egypt center
                latitude = 26.8206
                longitude = 30.8025
    else:
        # Default to Egypt center
        latitude = 26.8206
        longitude = 30.8025
        print("Using default coordinates for Egypt")
    
    # Convert to string for template
    lat_str = str(latitude) if latitude else "26.8206"
    lng_str = str(longitude) if longitude else "30.8025"
    
    # Create map URL
    map_url = f"https://www.google.com/maps?q={lat_str},{lng_str}&hl=en&z=15&output=embed"
    directions_url = f"https://www.google.com/maps/dir/?api=1&destination={lat_str},{lng_str}"

    return render(request, "othercategory/lostfound_details.html", {
        "lostfound": lostfound,
        "images": images,
        "videos": videos,
        "advertisement": advertisement,
        'governates': governates,
        'main_image_url': main_image_url,
        'images_json': images_json,
        'images_recent': images_recent,
        'location_display': location_display,
        'is_favorited': is_favorited,
        'favorite_product_type': 'lostfoundlisting',
        # Location data for map
        'latitude': lat_str,
        'longitude': lng_str,
        'map_url': map_url,
        'directions_url': directions_url,
        'location_name': location_display or lostfound.city.name if lostfound.city else "Location",
    })

def pet(request):
    # Governates with prefetch
    governates = Governate.objects.prefetch_related(
        Prefetch('districts', queryset=District.objects.all())
    ).all()
    advertisement = Advertisement.objects.filter(
        category=AdvertisementCategory.OTHER_CLASSIFIED, 
        is_active=True
    )

    # Multi-value filter params for location
    selected_governate_params = request.GET.getlist('governate')
    selected_district_params = request.GET.getlist('district')
    selected_cities = request.GET.getlist('city')
    banners = Banner.objects.filter(category='other_classified', is_active=True)

    # Filters
    category = request.GET.get('category')
    age = request.GET.get('age')
    condition = request.GET.get('condition')
    pet_type = request.GET.get('pet_type')
    accessory_type = request.GET.get('accessory_type')
    ads_posted = request.GET.get('ads_posted')
    listing_type = request.GET.get('listing_type')
    breed = request.GET.get('breed')
    accept_exchange = request.GET.get('accept_exchange')
    price_from = request.GET.get('price_from')
    price_to = request.GET.get('price_to')
    sort_by = request.GET.get('sort', 'newest')

    # ========== EXPIRY CUTOFF (45 days) ==========
    cutoff_date = timezone.now() - timedelta(days=45)

    # Base queryset (approved + not expired)
    queryset = PetListing.objects.filter(
        status='approved',
        created_at__gte=cutoff_date
    ).select_related('city')

    # Track if any filter applied
    has_filters = any([
        selected_governate_params, selected_district_params, selected_cities,
        category, age, condition, pet_type, accessory_type, ads_posted,
        listing_type, breed, accept_exchange, price_from, price_to
    ])

    # Location filters - using multi-value approach
    if selected_cities:
        queryset = queryset.filter(city_id__in=selected_cities)
    elif selected_district_params:
        cities = Cities.objects.filter(district_id__in=selected_district_params)
        queryset = queryset.filter(city_id__in=cities.values_list('id', flat=True))
    elif selected_governate_params:
        cities = Cities.objects.filter(district__governate_id__in=selected_governate_params)
        queryset = queryset.filter(city_id__in=cities.values_list('id', flat=True))

    # Dropdown - districts list
    districts = District.objects.filter(governate_id__in=selected_governate_params) if selected_governate_params else None

    # Apply other filters
    if category:
        queryset = queryset.filter(category__in=category.split(','))
    if age:
        queryset = queryset.filter(age__in=age.split(','))
    if listing_type:
        queryset = queryset.filter(listing_type=listing_type)
    if condition:
        queryset = queryset.filter(condition__in=condition.split(','))
    if pet_type:
        queryset = queryset.filter(pet_type__in=pet_type.split(','))
    if accessory_type:
        queryset = queryset.filter(accessory_type__in=accessory_type.split(','))

    # Ads posted filter
    if ads_posted:
        now = timezone.now()
        date_filters = []
        for val in ads_posted.split(','):
            if val == "Today":
                date_filters.append(now - timedelta(days=1))
            elif val == "3days":
                date_filters.append(now - timedelta(days=3))
            elif val == "1wk":
                date_filters.append(now - timedelta(weeks=1))
            elif val == "2wks":
                date_filters.append(now - timedelta(weeks=2))
            elif val == "1m":
                date_filters.append(now - timedelta(days=30))
            elif val == "6m":
                date_filters.append(now - timedelta(days=180))
        if date_filters:
            queryset = queryset.filter(created_at__gte=min(date_filters))

    # Breed
    if breed:
        queryset = queryset.filter(breed__icontains=breed)

    # Accept exchange
    if accept_exchange:
        if accept_exchange.lower() == 'true':
            queryset = queryset.filter(accept_exchange=True)
        elif accept_exchange.lower() == 'false':
            queryset = queryset.filter(accept_exchange=False)

    # Price range
    try:
        if price_from:
            queryset = queryset.filter(price__gte=int(price_from))
        if price_to:
            queryset = queryset.filter(price__lte=int(price_to))
    except (ValueError, TypeError):
        pass

    # Convert queryset to list for Python sorting
    pet_items = list(queryset)

    # ========== ADD BOOST INFORMATION FOR MAIN RESULTS ==========
    if pet_items:
        item_ids = [item.id for item in pet_items]
        boosts = BoostUsage.objects.filter(
            listing_type='petlisting',  # adjust if needed
            listing_id__in=item_ids,
            is_active=True
        )
        boost_dict = {b.listing_id: b for b in boosts}
        for item in pet_items:
            boost = boost_dict.get(item.id)
            if boost and boost.is_boost_active():
                item.is_boosted = True
                item.boost_days_left = boost.days_remaining
            else:
                item.is_boosted = False
                item.boost_days_left = 0

    # --------- SORTING FUNCTION ---------
    def sort_items(data_list, sort_key):
        if sort_key == 'price_asc':
            data_list.sort(key=lambda x: x.price or 0)
        elif sort_key == 'price_desc':
            data_list.sort(key=lambda x: x.price or 0, reverse=True)
        elif sort_key == 'oldest':
            data_list.sort(key=lambda x: x.created_at)
        else:  # newest
            data_list.sort(key=lambda x: x.created_at, reverse=True)
        return data_list
    # -------------------------------------

    # Sort main results
    pet_items = sort_items(pet_items, sort_by)

    # ========== RELATED PRODUCTS (with 45-day cutoff & boost) ==========
    related_pets = []
    show_related = False
    
    if has_filters and len(pet_items) == 0:
        # Get related items (approved + not expired)
        related_queryset = PetListing.objects.filter(
            status='approved',
            created_at__gte=cutoff_date   # <-- added cutoff date
        ).order_by('-created_at')[:6]

        related_pets = list(related_queryset)

        # Add boost info and images for related items
        if related_pets:
            rel_ids = [r.id for r in related_pets]
            rel_boosts = BoostUsage.objects.filter(
                listing_type='petlisting',
                listing_id__in=rel_ids,
                is_active=True
            )
            rel_boost_dict = {b.listing_id: b for b in rel_boosts}
            for r in related_pets:
                boost = rel_boost_dict.get(r.id)
                if boost and boost.is_boost_active():
                    r.is_boosted = True
                    r.boost_days_left = boost.days_remaining
                else:
                    r.is_boosted = False
                    r.boost_days_left = 0
                r.images_json = json.dumps([img.image.url for img in r.images.all()])

        # Sort related items
        related_pets = sort_items(related_pets, sort_by)
        show_related = True

    # Add images JSON for main results
    for item in pet_items:
        item.images_json = json.dumps([img.image.url for img in item.images.all()])

    total_count = len(pet_items)

    # Determine which items to paginate
    items_to_paginate = related_pets if show_related else pet_items

    # Pagination
    current_params = request.GET.copy()
    if 'page' in current_params:
        del current_params['page']

    paginator = Paginator(items_to_paginate, 6)
    page_number = request.GET.get('page', 1)
    try:
        page_obj = paginator.get_page(page_number)
    except EmptyPage:
        page_obj = paginator.get_page(paginator.num_pages)

    # Breadcrumb data
    selected_governate_objs = Governate.objects.filter(id__in=selected_governate_params) if selected_governate_params else []
    selected_district_objs = District.objects.filter(id__in=selected_district_params) if selected_district_params else []
    selected_city_objs = Cities.objects.filter(id__in=selected_cities) if selected_cities else []

    # Final Context
    context = {
        'page_obj': page_obj,
        'current_params': current_params.urlencode(),
        
        'governates': governates,
        'districts': districts,
        
        'selected_governate_objs': selected_governate_objs,
        'selected_district_objs': selected_district_objs,
        'selected_city_objs': selected_city_objs,
        
        'selected_governate': selected_governate_objs.first() if selected_governate_objs else None,
        'selected_governate_param': selected_governate_params[0] if selected_governate_params else None,
        
        'category': category,
        'condition': condition,
        'pet_type': pet_type,
        'age': age,
        'accessory_type': accessory_type,
        'breed': breed,
        'accept_exchange': accept_exchange,
        'price_from': price_from,
        'price_to': price_to,
        'listing_type': listing_type,
        'advertisement': advertisement,
        'banners' : banners,
        
        'current_sort': sort_by,
        'sort_options': [
            {'value': 'newest', 'label': 'Newest First'},
            {'value': 'oldest', 'label': 'Oldest First'},
            {'value': 'price_asc', 'label': 'Price: Low to High'},
            {'value': 'price_desc', 'label': 'Price: High to Low'},
        ],
        
        'total_count': total_count,
        'formatted_url_name': request.resolver_match.url_name.replace('_', ' ').title(),
        
        'related_pets': related_pets,
        'show_related': show_related,
    }

    if request.headers.get('X-Requested-With') == 'XMLHttpRequest':
        return render(request, 'othercategory/pet_list_partial.html', context)

    return render(request, 'othercategory/pet.html', context)
