    # ===============================
    try:
        if price_from:
            queryset = queryset.filter(price__gte=float(price_from))
        if price_to:
            queryset = queryset.filter(price__lte=float(price_to))
    except:
        pass

    # ===============================
    #        DATE POSTED
    # ===============================
    if date_posted_list:
        now = timezone.now()
        q_filter = Q()

        for val in date_posted_list:
            if val == 'today':
                q_filter |= Q(created_at__gte=now - timedelta(days=1))
            elif val == '3days':
                q_filter |= Q(created_at__gte=now - timedelta(days=3))
            elif val == '1wk':
                q_filter |= Q(created_at__gte=now - timedelta(weeks=1))
            elif val == '2wks':
                q_filter |= Q(created_at__gte=now - timedelta(weeks=2))
            elif val == '1m':
                q_filter |= Q(created_at__gte=now - timedelta(days=30))
            elif val == '6m':
                q_filter |= Q(created_at__gte=now - timedelta(days=180))

        queryset = queryset.filter(q_filter)

    # ===============================
    #        SORTING
    # ===============================
    if sort_by == 'price_asc':
        queryset = queryset.order_by('price')
    elif sort_by == 'price_desc':
        queryset = queryset.order_by('-price')
    elif sort_by == 'oldest':
        queryset = queryset.order_by('created_at')
    else:
        queryset = queryset.order_by('-created_at')

    # ===============================
    #        RELATED HOME MAINTENANCE (with expiry & boost)
    # ===============================
    related_homemaintenance = []
    related_homemaintenance_count = 0
    show_related = False

    # Convert main queryset to list now
    homemaintenance_list = list(queryset)

    if has_filters and len(homemaintenance_list) == 0:
        show_related = True
        # Use the same expiry cutoff for related
        related_queryset = HomeMaintenanceServiceListing.objects.filter(
            status='approved',
            created_at__gte=cutoff_date
        ).select_related('city').prefetch_related('images')
        
        # Apply the same sorting logic
        if sort_by == 'price_asc':
            related_queryset = related_queryset.order_by('price')
        elif sort_by == 'price_desc':
            related_queryset = related_queryset.order_by('-price')
        elif sort_by == 'oldest':
            related_queryset = related_queryset.order_by('created_at')
        else:
            related_queryset = related_queryset.order_by('-created_at')
            
        related_homemaintenance = related_queryset[:6]
        related_homemaintenance_count = related_homemaintenance.count()

        # Add boost info and images for related items
        if related_homemaintenance:
            rel_ids = [r.id for r in related_homemaintenance]
            rel_boosts = BoostUsage.objects.filter(
                listing_type='homemaintenanceservicelisting',   # adjust as needed
                listing_id__in=rel_ids,
                is_active=True
            )
            rel_boost_dict = {b.listing_id: b for b in rel_boosts}
            for r in related_homemaintenance:
                boost = rel_boost_dict.get(r.id)
                if boost and boost.is_boost_active():
                    r.is_boosted = True
                    r.boost_days_left = boost.days_remaining
                else:
                    r.is_boosted = False
                    r.boost_days_left = 0
                r.images_json = json.dumps([img.image.url for img in r.images.all()])

    # ========== ADDED: Boost information for main results ==========
    if homemaintenance_list:
        hm_ids = [h.id for h in homemaintenance_list]
        boosts = BoostUsage.objects.filter(
            listing_type='homemaintenanceservicelisting',   # adjust as needed
            listing_id__in=hm_ids,
            is_active=True
        )
        boost_dict = {b.listing_id: b for b in boosts}
        for h in homemaintenance_list:
            boost = boost_dict.get(h.id)
            if boost and boost.is_boost_active():
                h.is_boosted = True
                h.boost_days_left = boost.days_remaining
            else:
                h.is_boosted = False
                h.boost_days_left = 0

    # ===============================
    #        IMAGES JSON
    # ===============================
    for item in homemaintenance_list:
        item.images_json = json.dumps([img.image.url for img in item.images.all()])

    homemaintenance_count = len(homemaintenance_list)

    # ===============================
    #        PAGINATION
    # ===============================
    current_params = request.GET.copy()
    if 'page' in current_params:
        del current_params['page']

    # Only paginate if we have regular results (not showing related)
    if show_related:
        page_obj = []   # empty for related fallback
    else:
        paginator = Paginator(homemaintenance_list, 6)
        page_number = request.GET.get('page')
        try:
            page_obj = paginator.get_page(page_number)
        except EmptyPage:
            page_obj = paginator.get_page(paginator.num_pages)

    # ===============================
    #        BREADCRUMBS
    # ===============================
    selected_governate_objs = Governate.objects.filter(id__in=selected_governate_params) if selected_governate_params else []
    selected_district_objs = District.objects.filter(id__in=selected_district_params) if selected_district_params else []
    selected_city_objs = Cities.objects.filter(id__in=selected_cities) if selected_cities else []

    # === ADD THESE 3 LINES HERE ===
