def movers_details(request, id):
    movers = get_object_or_404(MoversServiceListing, id=id)
    advertisement = Advertisement.objects.filter(
        category=AdvertisementCategory.SERVICES, 
        is_active=True
    )
    track_product_view(request, movers)

    # ========== RECENTLY VIEWED TRACKING ==========
    # Get all images for the movers service
    images_recent = []
    if hasattr(movers, 'images') and movers.images.exists():
        images_recent = [{"image": img.image.url} for img in movers.images.all()]
    elif hasattr(movers, 'main_image') and movers.main_image:
        images_recent = [{"image": movers.main_image.url}]
    
    # Get main image URL
    main_image_url = images_recent[0]["image"] if images_recent else "/static/assets/images/resource/default.jpg"
    
    # Convert images to JSON string
    images_json = json.dumps(images_recent)
    
    # Get title
    title = ""
    if hasattr(movers, 'title') and movers.title:
        title = movers.title
    elif hasattr(movers, 'service_title') and movers.service_title:
        title = movers.service_title
    elif hasattr(movers, 'name') and movers.name:
        title = movers.name
    else:
        title = f"Movers Service #{movers.id}"
    
    # Get city name
    city_name = ""
    if hasattr(movers, 'city') and movers.city:
        city_name = movers.city.name
    
    # Get price
    price = movers.price if hasattr(movers, 'price') else 0
    
    product_data = {
        'title': title,
        'price': price,
        'main_image': main_image_url,
        'images_json': images_json,
        'city': city_name,
        'url': request.build_absolute_uri(),
        'listing_type': '',
        'display_category': 'Services',
        'brand': '',
        'category_type': 'moversservicelisting',
    }
    
    # Track the recently viewed product
    track_recently_viewed(request, str(movers.id), 'moversservicelisting', product_data)
    # ========== END RECENTLY VIEWED TRACKING ==========

    # Handle price drop notification request
    if request.method == 'POST' and 'notify_price_drop' in request.POST:
        if request.user.is_authenticated:
            if request.user != movers.user:
                message_content = (
                    f"Hello! I'm interested in your product '{movers.title}' "
                    f"and would like to know if you can reduce the price. "
                    f"Please let me know if there's any flexibility in the price."
                )
                
                ChatMessage.objects.create(
                    sender=request.user,
                    receiver=movers.user,
                    message=message_content,
                    is_read=False
                )
                messages.success(request, "Message sent to the owner! They will contact you soon.")
            else:
                messages.warning(request, "You cannot message yourself.")
        else:
            messages.error(request, "Please login to contact the owner.")
            return redirect('login')
        
        return redirect('movers_details', id=id)

    # Handle report submission
    if request.method == 'POST' and 'report_submit' in request.POST:
        reason = request.POST.get('reason')
        description = request.POST.get('description', '')

        if reason:
            ProductReport.objects.create(
                reporter=request.user if request.user.is_authenticated else None,
                reason=reason,
                description=description,
                content_type=ContentType.objects.get_for_model(movers),
                object_id=movers.id
            )
            messages.success(request, "Thank you for reporting. We'll review it shortly.")
            return redirect(request.path)
        else:
            messages.error(request, "Please select a valid reason for the report.")
    
    # Get governates for filters (if needed)
    governates = Governate.objects.prefetch_related(
        Prefetch('districts', queryset=District.objects.all())
    ).all()
    
    # Check if favorited
    is_favorited = False
    if request.user.is_authenticated:
        content_type = ContentType.objects.get_for_model(movers)
        is_favorited = Favorite.objects.filter(
            user=request.user,
            content_type=content_type,
            object_id=movers.id
        ).exists()
    
    # Images for gallery / carousel
    images = movers.images.all() if hasattr(movers, 'images') else []
    videos = movers.videos.all() if hasattr(movers, 'videos') else []
    
    # Location display string
    location_display = ""
    if movers.city and movers.city.district and movers.city.district.governate:
        location_display = f"{movers.city.name}, {movers.city.district.name}, {movers.city.district.governate.name}"
    
    # ========== GET COORDINATES FOR MAP ==========
    # Try to get coordinates from movers first, then fallback to city, then default
    latitude = None
    longitude = None
    
    # Check if movers has coordinates
    if hasattr(movers, 'latitude') and movers.latitude and hasattr(movers, 'longitude') and movers.longitude:
        latitude = float(movers.latitude)
        longitude = float(movers.longitude)
        print(f"Using movers coordinates: {latitude}, {longitude}")
    
    # Fallback to city coordinates if available
    elif movers.city:
        if hasattr(movers.city, 'latitude') and movers.city.latitude and hasattr(movers.city, 'longitude') and movers.city.longitude:
            latitude = float(movers.city.latitude)
            longitude = float(movers.city.longitude)
            print(f"Using city coordinates: {latitude}, {longitude}")
        else:
            # If city doesn't have coordinates, use geocoding or default
            try:
                from geopy.geocoders import GoogleV3
                geolocator = GoogleV3(api_key='YOUR_GOOGLE_API_KEY')  # Replace with your API key
                location = geolocator.geocode(f"{movers.city.name}, Egypt")
                if location:
                    latitude = location.latitude
                    longitude = location.longitude
                    print(f"Geocoded coordinates: {latitude}, {longitude}")
                else:
                    # Default to Egypt center
                    latitude = 26.8206
                    longitude = 30.8025
            except Exception as e:
                print(f"Geocoding failed: {e}")
                # Default to Egypt center
                latitude = 26.8206
                longitude = 30.8025
    else:
        # Default to Egypt center
        latitude = 26.8206
        longitude = 30.8025
        print("Using default coordinates for Egypt")
    
    # Convert to string for template
    lat_str = str(latitude) if latitude else "26.8206"
    lng_str = str(longitude) if longitude else "30.8025"
    
    # Create map URL
    map_url = f"https://www.google.com/maps?q={lat_str},{lng_str}&hl=en&z=15&output=embed"
    directions_url = f"https://www.google.com/maps/dir/?api=1&destination={lat_str},{lng_str}"

    return render(request, 'community/movers_details.html', {
        'movers': movers,
        'images': images,
        'videos': videos,
        'advertisement': advertisement,
        'governates': governates,
        'main_image_url': main_image_url,
        'images_json': images_json,
        'images_recent': images_recent,
        'location_display': location_display,
        'is_favorited': is_favorited,
        'favorite_product_type': 'moversservicelisting',
        # Location data for map
        'latitude': lat_str,
        'longitude': lng_str,
        'map_url': map_url,
        'directions_url': directions_url,
        'location_name': location_display or movers.city.name if movers.city else "Location",
    })


def otherservices(request):
    # --- Location hierarchy ---
    governates = Governate.objects.prefetch_related(
        Prefetch('districts', queryset=District.objects.all())
    ).all()
    advertisement = Advertisement.objects.filter(
        category=AdvertisementCategory.REAL_ESTATE, 
        is_active=True
    )

    # --- Multi-select parameters ---
    selected_governate_params = request.GET.getlist('governate')
    selected_district_params = request.GET.getlist('district')
    selected_cities = request.GET.getlist('city')

    # --- Other services-specific filters ---
    service_type = request.GET.get('service_type')
    price_from = request.GET.get('price_from')
    price_to = request.GET.get('price_to')
    date_posted_list = request.GET.getlist('listing_type')
    sort_by = request.GET.get('sort', 'newest')
    banners = Banner.objects.filter(category='services', is_active=True)

    # --- Track if any filter applied ---
    has_filters = any([
        selected_governate_params, selected_district_params, selected_cities,
        service_type, price_from, price_to, date_posted_list
    ])

    # ========== ADDED: 45-day expiry cutoff ==========
    cutoff_date = timezone.now() - timedelta(days=45)

    # --- Base queryset (modified to exclude expired) ---
    queryset = OtherServiceListing.objects.filter(
        status='approved',
        created_at__gte=cutoff_date   # <-- added expiry
    ).select_related('city')

    # ===============================
    #    LOCATION FILTERS (NEW)
    # ===============================
    if selected_cities:
        queryset = queryset.filter(city_id__in=selected_cities)
    elif selected_district_params:
        cities = Cities.objects.filter(district_id__in=selected_district_params)
        queryset = queryset.filter(city_id__in=cities.values_list('id', flat=True))
    elif selected_governate_params:
        cities = Cities.objects.filter(district__governate_id__in=selected_governate_params)
        queryset = queryset.filter(city_id__in=cities.values_list('id', flat=True))

    # Dropdown linkage
    districts = District.objects.filter(governate_id__in=selected_governate_params) if selected_governate_params else None

    # ===============================
    #     SERVICE TYPE FILTER
    # ===============================
    if service_type:
        queryset = queryset.filter(service_type__in=service_type.split(','))

    # ===============================
    #        PRICE FILTER
    # ===============================
    try:
        if price_from:
            queryset = queryset.filter(price__gte=float(price_from))
        if price_to:
            queryset = queryset.filter(price__lte=float(price_to))
    except:
        pass

    # ===============================
    #        DATE POSTED
    # ===============================
    if date_posted_list:
        now = timezone.now()
        q_filter = Q()

        for val in date_posted_list:
            if val == 'today':
                q_filter |= Q(created_at__gte=now - timedelta(days=1))
            elif val == '3days':
                q_filter |= Q(created_at__gte=now - timedelta(days=3))
            elif val == '1wk':
                q_filter |= Q(created_at__gte=now - timedelta(weeks=1))
            elif val == '2wks':
                q_filter |= Q(created_at__gte=now - timedelta(weeks=2))
            elif val == '1m':
                q_filter |= Q(created_at__gte=now - timedelta(days=30))
            elif val == '6m':
                q_filter |= Q(created_at__gte=now - timedelta(days=180))

        queryset = queryset.filter(q_filter)

    # ===============================
    #        GET FILTERED COUNT
    # ===============================
    filtered_count = queryset.count()
    
    # ===============================
    #        SORTING (ON QUERYSET)
    # ===============================
    if sort_by == 'price_asc':
        queryset = queryset.order_by('price')
    elif sort_by == 'price_desc':
        queryset = queryset.order_by('-price')
    elif sort_by == 'oldest':
        queryset = queryset.order_by('created_at')
    else:
        queryset = queryset.order_by('-created_at')

    # ===============================
    #        CONVERT TO LIST (to attach boost info)
    # ===============================
    otherservices_list = list(queryset)

    # ========== ADDED: Boost information for main results ==========
    if otherservices_list:
        os_ids = [o.id for o in otherservices_list]
        boosts = BoostUsage.objects.filter(
            listing_type='otherservicelisting',   # adjust as needed
            listing_id__in=os_ids,
            is_active=True
        )
        boost_dict = {b.listing_id: b for b in boosts}
        for o in otherservices_list:
            boost = boost_dict.get(o.id)
            if boost and boost.is_boost_active():
                o.is_boosted = True
                o.boost_days_left = boost.days_remaining
            else:
                o.is_boosted = False
                o.boost_days_left = 0

    # ===============================
    #        RELATED OTHER SERVICES (with expiry & boost)
    # ===============================
    related_otherservices = []
    related_otherservices_count = 0
    show_related = False

    if has_filters and filtered_count == 0:
        show_related = True
        
        # Get related other services - show ALL services (respecting expiry)
        related_queryset = OtherServiceListing.objects.filter(
            status='approved',
            created_at__gte=cutoff_date   # <-- added expiry
        ).select_related('city')
        
        # Apply the same sorting logic
        if sort_by == 'price_asc':
            related_queryset = related_queryset.order_by('price')
        elif sort_by == 'price_desc':
            related_queryset = related_queryset.order_by('-price')
        elif sort_by == 'oldest':
            related_queryset = related_queryset.order_by('created_at')
        else:
            related_queryset = related_queryset.order_by('-created_at')
            
        # If service_type filter was applied, prioritize same service_type
        # but if none exist, show all services
        if service_type:
            same_type_queryset = related_queryset.filter(
                service_type__in=service_type.split(',')
            )
            if same_type_queryset.exists():
                related_otherservices = list(same_type_queryset[:6])
            else:
                related_otherservices = list(related_queryset[:6])
        else:
            related_otherservices = list(related_queryset[:6])
            
        related_otherservices_count = len(related_otherservices)

        # Add boost info and images for related items
        if related_otherservices:
            rel_ids = [r.id for r in related_otherservices]
            rel_boosts = BoostUsage.objects.filter(
                listing_type='otherservicelisting',
                listing_id__in=rel_ids,
                is_active=True
            )
            rel_boost_dict = {b.listing_id: b for b in rel_boosts}
            for r in related_otherservices:
                boost = rel_boost_dict.get(r.id)
                if boost and boost.is_boost_active():
                    r.is_boosted = True
                    r.boost_days_left = boost.days_remaining
                else:
                    r.is_boosted = False
                    r.boost_days_left = 0
                r.images_json = json.dumps([img.image.url for img in r.images.all()])

    # ===============================
    #        IMAGES JSON FOR REGULAR RESULTS
    # ===============================
    for item in otherservices_list:
        item.images_json = json.dumps([img.image.url for img in item.images.all()])

    otherservices_count = len(otherservices_list)

    # ===============================
    #        PAGINATION
    # ===============================
    current_params = request.GET.copy()
    if 'page' in current_params:
        del current_params['page']

    # Only paginate if we have regular results
    if not show_related:
        paginator = Paginator(otherservices_list, 6)
        page_number = request.GET.get('page')
        try:
            page_obj = paginator.get_page(page_number)
        except EmptyPage:
            page_obj = paginator.get_page(paginator.num_pages)
    else:
        page_obj = []  # Empty page_obj for related results

    # ===============================
    #        BREADCRUMBS
    # ===============================
    selected_governate_objs = Governate.objects.filter(id__in=selected_governate_params) if selected_governate_params else []
    selected_district_objs = District.objects.filter(id__in=selected_district_params) if selected_district_params else []
    selected_city_objs = Cities.objects.filter(id__in=selected_cities) if selected_cities else []

    # === ADD THESE 3 LINES HERE ===
    selected_governate_param = selected_governate_params[0] if selected_governate_params else None
    selected_district_param = selected_district_params[0] if selected_district_params else None
    selected_city_param = selected_cities[0] if selected_cities else None

    context = {
        'page_obj': page_obj,
        'results': otherservices_list,
        'otherservices_count': otherservices_count,
        'advertisement': advertisement,
        'current_params': current_params.urlencode(),

        # Related
        'related_otherservices': related_otherservices,
        'related_otherservices_count': related_otherservices_count,
        'show_related': show_related,
        'banners' : banners,

        # Location
        # Location
        'governates': governates,
        'districts': districts,
        'selected_governate_objs': selected_governate_objs,
        'selected_district_objs': selected_district_objs,
        'selected_city_objs': selected_city_objs,

        # === ADD THESE 4 LINES HERE ===
        'selected_governate': selected_governate_objs.first() if selected_governate_objs else None,
        'selected_governate_param': selected_governate_param,
        'selected_district_param': selected_district_param,
        'selected_city_param': selected_city_param,

        # Filters
        'service_type': service_type,
        'price_from': price_from,
        'price_to': price_to,
        'date_posted': date_posted_list,

        # Sorting
        'current_sort': sort_by,
        'sort_options': [
            {'value': 'newest', 'label': 'Newest First'},
            {'value': 'oldest', 'label': 'Oldest First'},
            {'value': 'price_asc', 'label': 'Price: Low to High'},
            {'value': 'price_desc', 'label': 'Price: High to Low'},
        ],

        'service_type_choices': OtherServiceListing.SERVICE_TYPE_CHOICES if hasattr(OtherServiceListing, 'SERVICE_TYPE_CHOICES') else AutoServiceListing.SERVICE_TYPE_CHOICES,
        'formatted_url_name': request.resolver_match.url_name.replace("_", " ").title(),
    }

    if request.headers.get('X-Requested-With') == 'XMLHttpRequest':
        return render(request, 'community/otherservice_list_partial.html', context)

    return render(request, 'community/otherservice.html', context)

