def job(request):
    governates = Governate.objects.prefetch_related(
        Prefetch('districts', queryset=District.objects.all())
    ).all()
    categories = JobCategory.objects.all()
    companies = Company.objects.all()
    
    # ==============================
    # GET FILTER PARAMS
    # ==============================
    selected_governate_params = request.GET.getlist('governate')
    selected_district_params = request.GET.getlist('district')
    selected_cities = request.GET.getlist('city')
    banners = Banner.objects.filter(category='job', is_active=True)
    selected_company = request.GET.get('company')
    number_of_vacancies = request.GET.get('number_of_vacancies')
    qualifications = request.GET.get('qualifications')
    job_type = request.GET.getlist('job_type')
    experience_required = request.GET.getlist('experience')
    gender = request.GET.get('gender')
    nationality = request.GET.get('nationality')
    working_hours = request.GET.get('working_hours')
    working_days = request.GET.get('working_days')
    city = request.GET.get('city')
    salary_from = request.GET.get('salary_from')
    salary_to = request.GET.get('salary_to')
    keyword = request.GET.get('keyword')
    sort_by = request.GET.get('sort', 'newest')

    # Category (from navbar)
    selected_categories_param = request.GET.get('job_category')
    selected_categories = selected_categories_param.split(',') if selected_categories_param else []

    # Resolve location objects
    selected_governate_objs = Governate.objects.filter(id__in=selected_governate_params) if selected_governate_params else []
    selected_district_objs = District.objects.filter(id__in=selected_district_params) if selected_district_params else []
    selected_city_objs = Cities.objects.filter(id__in=selected_cities) if selected_cities else []

    selected_governate = selected_governate_objs.first() if selected_governate_objs else None

    # ==============================
    # BASE QUERY with optimization (fixed: removed invalid prefetch)
    # ==============================
    queryset = JobPost.objects.filter(
        application_deadline__gte=timezone.now()
    ).select_related(
        'company',
        'company__city',
        'company__city__district',
        'company__city__district__governate',
        'job_category'
    )
    # Note: 'job_requirements' does not exist – removed prefetch_related

    # ==============================
    # LOCATION FILTERS
    # ==============================
    if selected_cities:
        queryset = queryset.filter(company__city_id__in=selected_cities)
    elif selected_district_params:
        cities = Cities.objects.filter(district_id__in=selected_district_params)
        queryset = queryset.filter(company__city_id__in=cities.values_list('id', flat=True))
    elif selected_governate_params:
        cities = Cities.objects.filter(district__governate_id__in=selected_governate_params)
        queryset = queryset.filter(company__city_id__in=cities.values_list('id', flat=True))

    # ==============================
    # CATEGORY FILTERS
    # ==============================
    if selected_categories:
        queryset = queryset.filter(job_category__id__in=selected_categories)

    # ==============================
    # OTHER FILTERS
    # ==============================
    if selected_company:
        queryset = queryset.filter(company_id=selected_company)
    if job_type:
        queryset = queryset.filter(job_type__in=job_type)
    if experience_required:
        queryset = queryset.filter(experience_required__in=experience_required)
    if gender:
        queryset = queryset.filter(gender__in=gender.split(','))
    if number_of_vacancies:
        queryset = queryset.filter(number_of_vacancies__in=number_of_vacancies.split(','))
    if qualifications:
        queryset = queryset.filter(qualifications__icontains=qualifications)
    if nationality:
        queryset = queryset.filter(nationality__in=[nationality])
    if working_hours:
        queryset = queryset.filter(working_hours__in=working_hours.split(','))
    if working_days:
        queryset = queryset.filter(working_days__in=working_days.split(','))

    if city:
        queryset = queryset.filter(company__city__name__icontains=city)

    # Salary range
    try:
        if salary_from:
            queryset = queryset.filter(salary_range__gte=int(salary_from))
        if salary_to:
            queryset = queryset.filter(salary_range__lte=int(salary_to))
    except (ValueError, TypeError):
        pass

    # Keyword search
    if keyword:
        queryset = queryset.filter(
            Q(title__icontains=keyword) |
            Q(description__icontains=keyword) |
            Q(skills_required__icontains=keyword) |
            Q(qualifications__icontains=keyword) |
            Q(company__company_name__icontains=keyword)
        )

    # Sorting
    if sort_by == 'oldest':
        queryset = queryset.order_by('posted_on')
    elif sort_by == 'title':
        queryset = queryset.order_by('title')
    else:
        queryset = queryset.order_by('-posted_on')

    # ==============================
    # PAGINATION
    # ==============================
    paginator = Paginator(queryset, 6)
    page_number = request.GET.get('page')

    try:
        page_obj = paginator.get_page(page_number)
    except EmptyPage:
        page_obj = paginator.get_page(paginator.num_pages)

    districts = District.objects.filter(governate_id__in=selected_governate_params) if selected_governate_params else None

    # ==============================
    # BREADCRUMB HANDLING
    # ==============================
    breadcrumb_label = None

    if selected_categories:
        try:
            cat_ids = [int(i) for i in selected_categories]
            selected_cat_names = JobCategory.objects.filter(id__in=cat_ids).values_list('name', flat=True)
            breadcrumb_label = " / ".join(selected_cat_names)
        except:
            breadcrumb_label = "Jobs"

    elif job_type:
        breadcrumb_label = " / ".join([t.replace("-", " ").replace("_", " ").title() for t in job_type])

    elif qualifications:
        breadcrumb_label = qualifications.replace("-", " ").title()

    elif selected_company:
        company = Company.objects.filter(id=selected_company).first()
        if company:
            breadcrumb_label = company.company_name

    elif keyword:
        breadcrumb_label = f"Search: {keyword}"

    elif selected_city_objs:
        city_names = []
        for city in selected_city_objs:
            if hasattr(city, 'name'):
                city_names.append(city.name)
            elif hasattr(city, 'city_name'):
                city_names.append(city.city_name)
            else:
                city_names.append(str(city))
        breadcrumb_label = " / ".join(city_names)

    elif selected_district_objs:
        district = selected_district_objs.first()
        if hasattr(district, 'name'):
            breadcrumb_label = district.name
        elif hasattr(district, 'district_name'):
            breadcrumb_label = district.district_name
        else:
            breadcrumb_label = str(district)

    elif selected_governate_objs:
        governate = selected_governate_objs.first()
        if hasattr(governate, 'governate_name'):
            breadcrumb_label = governate.governate_name
        elif hasattr(governate, 'name'):
            breadcrumb_label = governate.name
        else:
            breadcrumb_label = str(governate)

    else:
        breadcrumb_label = "All Jobs"

    # ==============================
    # TRACK IF FILTERS ARE APPLIED
    # ==============================
    has_filters = any([
        selected_governate_params, selected_district_params, selected_cities,
        selected_categories, selected_company, job_type, experience_required,
        gender, number_of_vacancies, qualifications, nationality,
        working_hours, working_days, city, salary_from, salary_to, keyword
    ])

    # ==============================
    # RELATED JOBS (when no results found)
    # ==============================
    related_jobs = []
    related_jobs_count = 0

    if has_filters and queryset.count() == 0:
        # Try to find related jobs based on similar criteria
        related_queryset = JobPost.objects.filter(application_deadline__gte=timezone.now())
        
        # If location was selected, prioritize same area
        if selected_cities:
            related_queryset = related_queryset.filter(company__city_id__in=selected_cities)
        elif selected_district_params:
            cities = Cities.objects.filter(district_id__in=selected_district_params)
            related_queryset = related_queryset.filter(company__city_id__in=cities.values_list('id', flat=True))
        elif selected_governate_params:
            cities = Cities.objects.filter(district__governate_id__in=selected_governate_params)
            related_queryset = related_queryset.filter(company__city_id__in=cities.values_list('id', flat=True))
        
        # If categories were selected, prioritize same category
        if selected_categories and not related_queryset.exists():
            related_queryset = JobPost.objects.filter(
                application_deadline__gte=timezone.now(),
                job_category__id__in=selected_categories
            )
        
        # If still no results, get latest jobs
        if not related_queryset.exists():
            related_queryset = JobPost.objects.filter(application_deadline__gte=timezone.now())
        
        # Apply sorting to related jobs
        if sort_by == 'oldest':
            related_queryset = related_queryset.order_by('posted_on')
        elif sort_by == 'title':
            related_queryset = related_queryset.order_by('title')
        else:
            related_queryset = related_queryset.order_by('-posted_on')
        
        related_jobs = list(related_queryset[:6])
        related_jobs_count = len(related_jobs)

    # ==============================
    # CONTEXT
    # ==============================
    context = {
        'results': page_obj.object_list,
        'page_obj': page_obj,
        'categories': categories,
        'companies': companies,
        'governates': governates,
        'districts': districts,

        'selected_governate_objs': selected_governate_objs,
        'selected_district_objs': selected_district_objs,
        'selected_city_objs': selected_city_objs,
        'selected_governate': selected_governate,
        'selected_governate_param': selected_governate_params[0] if selected_governate_params else None,
        'selected_district_obj': selected_district_objs.first() if selected_district_objs else None,

        'selected_company': selected_company,
        'job_type': job_type,
        'experience_required': experience_required,
        'gender': gender,
        'number_of_vacancies': number_of_vacancies,
        'nationality': nationality,
        'working_hours': working_hours,
        'working_days': working_days,
        'city': city,
        'banners': banners,
        
        'salary_from': salary_from,
        'salary_to': salary_to,
        'keyword': keyword,

        'current_sort': sort_by,
        'sort_options': [
            {'value': 'newest', 'label': 'Newest First'},
            {'value': 'oldest', 'label': 'Oldest First'},
            {'value': 'title', 'label': 'Job Title (A-Z)'},
        ],

        'total_count': queryset.count(),
        'formatted_url_name': request.resolver_match.url_name.replace("_", " ").title(),

        # Selected categories for UI
        'selected_categories': selected_categories,

        # BREADCRUMB LABEL
        'breadcrumb_label': breadcrumb_label,
        
        # Related jobs for when no results
        'related_jobs': related_jobs,
        'related_jobs_count': related_jobs_count,
        'show_related': has_filters and queryset.count() == 0,
        
        # Track if filters are applied
        'has_filters': has_filters,
    }

    # AJAX partial return
    if request.headers.get('X-Requested-With') == 'XMLHttpRequest':
        return render(request, 'Job/job_list_partial.html', context)

    return render(request, 'Job/job.html', context)


def full_time_jobs(request):
    # Fetch all job categories
    categories = JobCategory.objects.all()

    # Fetch approved full-time job posts grouped by category
    jobs_by_category = {
        category.name: JobPost.objects.filter(
            job_category=category,
            job_type='full-time' ,application_deadline__gte=timezone.now() # Filter for full-time jobs based on the job_type choice
        ).order_by('-posted_on')  # Limit to 2 per category
        for category in categories
    }

    # Flatten jobs into a single list with additional details
    full_time_jobs = []
    for category_name, jobs in jobs_by_category.items():
        for job in jobs:
            # Ensure jobs are not repeated
            full_time_jobs.append({
                'category': category_name,
                'data': job,
                'job_type': job.job_type,
            })

    context = {
        'full_time_jobs': full_time_jobs,
    }

    return render(request, 'full_time.html', context)


