def browseads2(request, category, id):
    category_key = category.lower()

    # ---------------- CATEGORY → MODEL MAP ----------------
    ad_model_mapping = {

        # ===== REAL ESTATE =====
        'land': Land,
        'villa': Villa,
        'apartment': Apartment,
        'office': Office,
        'shop': Shop,
        'cafe': Cafe,
        'wholebuilding': Wholebuilding,

        # ===== VEHICLES =====
        'automobiles': Automobile,
        'motorcycles': Motorcycle,
        'scooter': Scooter,
        'junkcars': JunkCar,
        'heavy_vehicles': HeavyVehicle,
        'boats': Boat,
        'tiresandcaps': TiresAndCaps,
        'accessoriesparts': AutoAccessoryPart,
        'number_plate': NumberPlate,

        # ===== VEHICLE SERVICES =====
        'driving_training': DrivingTraining,
        'car_repair_maintenance': CarRepairMaintenance,

        # ===== SERVICES =====
        'auto_services': AutoServiceListing,
        'consultancy_services': ConsultancyServiceListing,
        'domestic_services': DomesticServiceListing,
        'event_services': EventEntertainmentServiceListing,
        'health_services': HealthWellbeingServiceListing,
        'home_maintenance_services': HomeMaintenanceServiceListing,
        'movers_services': MoversServiceListing,
        'restoration_services': RestorationServiceListing,
        'tutors_services': TutorsServiceListing,
        'web_computer_services': WebComputerServiceListing,
        'freelancers_services': FreelancersServiceListing,
        'other_services': OtherServiceListing,

        # ===== ELECTRONICS & GOODS =====
        'electronics_listings': ElectronicsListing,
        'computer_listings': ComputerListing,
        'business_industrial_listings': BusinessIndustrialListing,
        'home_appliance_listings': HomeApplianceListing,
        'sports_listings': SportsListing,
        'clothing_listings': ClothingAccessoriesListing,
        'camera_listings': CameraListing,
        'jewelry_listings': JewelryListing,
        'pet_listings': PetListing,
        'musical_listings': MusicalListing,
        'gaming_listings': GamingListing,
        'baby_items_listings': BabyItemsListing,
        'toys_listings': ToysListing,
        'ticketvoucher_listings': TicketVoucherListing,
        'collectible_listings': CollectibleListing,
        'books_listings': BooksListing,
        'music_listings': MusicListing,
        'lost_found_listings': LostFoundListing,
        'dvds_movies_listings': DVDsMoviesListing,
        'furniture_home_garden_listings': FurnitureHomeGardenListing,

        # ===== MOBILES =====
        'mobiles': Mobile,
        'tablets': Tablet,
        'smartwatches': SmartWatch,
        'headsets': Headset,
        'covers': Cover,
        'accessories': Accessory,
        'mobilesims': MobileSIM,
    }

    # ---------------- GET MODEL ----------------
    ad_model = ad_model_mapping.get(category_key)
    if not ad_model:
        raise Http404(f"No model found for category: {category}")

    # ---------------- GET AD ----------------
    ad = ad_model.objects.filter(id=id).first()
    if not ad:
        raise Http404("No matching ad found")

    features = []

    # ---------------- COMMON FIELDS ----------------
    if hasattr(ad, 'price') and ad.price:
        features.append(('Price', f"OMR {ad.price}"))

    if hasattr(ad, 'city') and ad.city:
        features.append((
            'Location',
            f"{ad.city.name}, {ad.city.district.name}, {ad.city.district.governate.name}"
        ))
    elif hasattr(ad, 'location') and ad.location:
        features.append(('Location', ad.location))

    # ---------------- CATEGORY SPECIFIC ----------------

    if isinstance(ad, Land):
        features.append(('Plot Area', f"{ad.plot_area} sqm" if ad.plot_area else "Not specified"))

    elif isinstance(ad, Villa):
        features += [
            ('Bedrooms', ad.bedrooms or "Not specified"),
            ('Bathrooms', ad.bathrooms or "Not specified"),
            ('Plot Area', f"{ad.plot_area} sqm" if ad.plot_area else "Not specified"),
        ]

    elif isinstance(ad, Automobile):
        features += [
            ('Make', ad.make or "Not specified"),
            ('Year', ad.year or "Not specified"),
            ('Transmission', ad.transmission or "Not specified"),
        ]

    elif isinstance(ad, Motorcycle) or isinstance(ad, Scooter):
        features += [
            ('Make', ad.make or "Not specified"),
            ('Model', ad.model or "Not specified"),
            ('Year', ad.year or "Not specified"),
        ]

    elif isinstance(ad, HeavyVehicle):
        features.append(('Year', ad.year or "Not specified"))

    elif isinstance(ad, Boat):
        features += [
            ('Boat Type', ad.boat_type or "Not specified"),
            ('Length', f"{ad.length} m" if ad.length else "Not specified"),
        ]

    elif isinstance(ad, NumberPlate):
        features += [
            ('Number', ad.number or "Not specified"),
            ('Region', ad.regions or "Not specified"),
        ]

    elif isinstance(ad, Mobile):
        features += [
            ('Brand', ad.brand or "Not specified"),
            ('Condition', ad.condition or "Not specified"),
            ('Storage', f"{ad.storage} GB" if ad.storage else "Not specified"),
        ]

    elif isinstance(ad, Computer):
        features += [
            ('Brand', ad.brand or "Not specified"),
            ('Condition', ad.condition or "Not specified"),
        ]

    elif isinstance(ad, Pet):
        features += [
            ('Type', ad.pet_type or "Not specified"),
            ('Breed', ad.breed or "Not specified"),
            ('Age', ad.age or "Not specified"),
        ]

    elif isinstance(ad, Book):
        features += [
            ('Title', ad.book_name or "Not specified"),
            ('Genre', ad.genre or "Not specified"),
            ('Condition', ad.condition or "Not specified"),
        ]

    elif hasattr(ad, 'service_type'):
        features.append(('Service Type', ad.service_type or "Not specified"))

    # ---------------- RENDER ----------------
    return render(request, 'browse-ads-2.html', {
        'ad': ad,
        'features': features,
        'category': category_key.replace('_', ' ').title(),
    })


