def servicedetails(request, category, id):
    # ======================================================
    # ✅ NORMALIZE CATEGORY (MAIN FIX)
    # ======================================================
    category = (category or "").strip().lower()

    # Remove "listing" if present
    if category.endswith("listing"):
        category = category.replace("listing", "")

    # Remove "service" suffix if needed
    if category.endswith("service"):
        category = category.replace("service", "")

    # ======================================================
    # 🔹 CATEGORY → MODEL MAPPING
    # ======================================================
    ad_model_mapping = {
        'auto': AutoServiceListing,
        'autoservices': AutoServiceListing,

        'consultancy': ConsultancyServiceListing,

        'domestic': DomesticServiceListing,

        'event': EventEntertainmentServiceListing,
        'events': EventEntertainmentServiceListing,

        'health': HealthWellbeingServiceListing,

        'homemaintenance': HomeMaintenanceServiceListing,

        'movers': MoversServiceListing,

        'restoration': RestorationServiceListing,

        'tutor': TutorsServiceListing,
        'tutors': TutorsServiceListing,

        'webcomputer': WebComputerServiceListing,
        'webservice': WebComputerServiceListing,

        'freelancer': FreelancersServiceListing,

        'other': OtherServiceListing,
        'otherservices': OtherServiceListing,
    }

    # ======================================================
    # 🔍 FIND MODEL
    # ======================================================
    model = ad_model_mapping.get(category)

    if not model:
        raise Http404(f"Invalid category: {category}")

    # ======================================================
    # ✅ SAFE QUERY (FIXED)
    # ======================================================
    ad = model.objects.filter(id=id, status__iexact='approved').first()

    if not ad:
        raise Http404("No matching service found")

    # ======================================================
    # 📸 GET ALL IMAGES FOR THE AD
    # ======================================================
    images = []
    if hasattr(ad, 'images') and ad.images.exists():
        # Get ALL images for the carousel
        images = [{"image": img.image.url} for img in ad.images.all()]
    elif hasattr(ad, 'main_image') and ad.main_image:
        # Fallback to single main image
        images = [{"image": ad.main_image.url}]
    
    # Get main image URL (first image)
    main_image_url = images[0]["image"] if images else "/static/assets/images/resource/default.jpg"
    
    # Convert images to JSON string for the template
    images_json = json.dumps(images)
    
    # ======================================================
    # 🏷 TITLE
    # ======================================================
    if hasattr(ad, 'service_title'):
        title = ad.service_title
    elif hasattr(ad, 'title'):
        title = ad.title
    elif hasattr(ad, 'name'):
        title = ad.name
    else:
        title = f"Service #{ad.id}"

    # ======================================================
    # 📍 CITY
    # ======================================================
    city_name = ""
    if hasattr(ad, 'city') and ad.city:
        city_name = ad.city.name

    # ======================================================
    # 💰 PRICE
    # ======================================================
    price = 0
    if hasattr(ad, 'price') and ad.price:
        price = ad.price
    elif hasattr(ad, 'hourly_rate') and ad.hourly_rate:
        price = ad.hourly_rate
    elif hasattr(ad, 'fixed_price') and ad.fixed_price:
        price = ad.fixed_price

    # ======================================================
    # 👁 RECENTLY VIEWED
    # ======================================================
    product_data = {
        'title': title,
        'price': price,
        'main_image': main_image_url,
        'images_json': images_json,  # ADD THIS - store all images
        'city': city_name,
        'url': request.build_absolute_uri(),  # Use full URL
        'listing_type': '',
        'display_category': 'Services',
        'service_type': category,
    }

    track_recently_viewed(request, str(ad.id), category, product_data)

    # ======================================================
    # 💬 CONTACT MESSAGE
    # ======================================================
    if request.method == 'POST' and 'notify_price_drop' in request.POST:
        if request.user.is_authenticated:
            if request.user != ad.user:
                ChatMessage.objects.create(
                    sender=request.user,
                    receiver=ad.user,
                    message=f"Hello! Is the price ({price} OMR) negotiable?",
                    is_read=False
                )
                messages.success(request, "Message sent!")
            else:
                messages.warning(request, "You cannot message yourself.")
        else:
            messages.error(request, "Please login first.")
            return redirect('login1')

        return redirect('servicedetails', category=category, id=id)

    # ======================================================
    # 📍 LOCATION
    # ======================================================
    location_display = ""
    if getattr(ad, 'city', None) and getattr(ad.city, 'district', None) and getattr(ad.city.district, 'governate', None):
        location_display = f"{ad.city.name}, {ad.city.district.name}, {ad.city.district.governate.name}"

    # ======================================================
    # 🎥 VIDEOS
    # ======================================================
    videos = ad.videos.all() if hasattr(ad, 'videos') else []

    # ======================================================
    # ⭐ FAVORITES
    # ======================================================
    is_favorited = False
    if request.user.is_authenticated:
        content_type = ContentType.objects.get_for_model(ad)
        is_favorited = Favorite.objects.filter(
            user=request.user,
            content_type=content_type,
            object_id=ad.id
        ).exists()

    # ======================================================
    # 🔹 GOVERNATES
    # ======================================================
    governates = Governate.objects.prefetch_related(
        Prefetch('districts', queryset=District.objects.all())
    )

    # ======================================================
    # 🔹 ADS
    # ======================================================
    advertisement = Advertisement.objects.filter(
        category=AdvertisementCategory.REAL_ESTATE,
        is_active=True
    )

    # ======================================================
    # 🎯 FINAL CONTEXT
    # ======================================================
    context = {
        'ad': ad,
        'governates': governates,
        'advertisement': advertisement,
        'videos': videos,
        'main_image': main_image_url,
        'images_json': images_json,  # FIXED - use images_json variable
        'images': images,  # ADD THIS for debugging if needed
        'location_display': location_display,
        'is_favorited': is_favorited,
        'favorite_product_type': category,
    }

    return render(request, 'servicedetails.html', context)

