from django.contrib.auth.decorators import login_required
from django.contrib.auth import update_session_auth_hash
from django.shortcuts import render, redirect, get_object_or_404
from django.contrib import messages
from .models import CustomUser

@login_required
def account_settings(request, user_id):
    # Security: only allow users to edit their own settings
    if request.user.id != user_id:
        messages.error(request, "You cannot edit another user's settings.")
        return redirect('home')  # change to your actual home URL name

    user = get_object_or_404(CustomUser, id=user_id)

    if request.method == 'POST':
        # --- Handle account deactivation ---
        if "deactivate_account" in request.POST:
            # Confirm password for deactivation (optional but recommended)
            password = request.POST.get('confirm_password_deactivate')
            if user.check_password(password):
                user.is_active = False
                user.save()
                # Log out the user after deactivation
                from django.contrib.auth import logout
                logout(request)
                messages.success(request, "Your account has been deactivated. You can contact support to reactivate.")
                return redirect('login')  # redirect to login or home
            else:
                messages.error(request, "Incorrect password. Account not deactivated.")
                return render(request, 'account_settings.html', {'user': user})

        # --- Handle password change ---
        else:
            current_password = request.POST.get('current_password')
            new_password = request.POST.get('new_password')
            confirm_password = request.POST.get('confirm_password')

            if user.check_password(current_password):
                if new_password == confirm_password:
                    user.set_password(new_password)
                    user.save()
                    update_session_auth_hash(request, user)  # keep user logged in
                    messages.success(request, "Your password has been changed successfully.")
                    return redirect('account_settings', user_id=user.id)
                else:
                    messages.error(request, "New passwords do not match.")
            else:
                messages.error(request, "Current password is incorrect.")

            return render(request, 'account_settings.html', {'user': user})

    return render(request, 'account_settings.html', {'user': user})


