from django.shortcuts import render, redirect
from django.contrib import messages
from django.contrib.auth.decorators import login_required
from django.http import JsonResponse
from .models import JobSeeker, JobCategory, JobSeekerProfile, Skill
from .forms import JobSeekerForm, JobSeekerProfileForm, CustomSkillForm



@login_required
def jobcategories(request):
    jobcat = JobCategory.objects.all()
    skills = Skill.objects.all()
    governates = Governate.objects.all()
    districts = District.objects.all()
    cities = Cities.objects.all()
    
    # Initialize form variables
    form = None
    profile_form = None
    user_has_profile = False
    existing_profiles = []
    existing_category_ids = set()
    
    # Check if user already has a basic profile
    try:
        jobseeker = request.user.jobseeker
        user_has_profile = True
        existing_profiles = jobseeker.profiles.all()
        existing_category_ids = set(profile.job_category.id for profile in existing_profiles)
        
        for category in jobcat:
            category.has_profile = category.id in existing_category_ids
            category.existing_profile = next(
                (profile for profile in existing_profiles if profile.job_category.id == category.id), 
                None
            )
            
    except JobSeeker.DoesNotExist:
        jobseeker = None
        for category in jobcat:
            category.has_profile = False
            category.existing_profile = None

    if request.method == "POST":
        # Handle custom skill addition via AJAX
        if 'add_skill' in request.POST:
            custom_skill_form = CustomSkillForm(request.POST)
            if custom_skill_form.is_valid():
                skill_name = custom_skill_form.cleaned_data['skill_name']
                skill, created = Skill.objects.get_or_create(name=skill_name)
                return JsonResponse({
                    'success': True,
                    'skill_id': skill.id,
                    'skill_name': skill.name,
                    'created': created
                })
            else:
                return JsonResponse({
                    'success': False,
                    'errors': custom_skill_form.errors
                })
        
        # Check which form is being submitted
        if 'job_category' in request.POST:  # This is the profile form
            if user_has_profile:
                profile_form = JobSeekerProfileForm(request.POST, request.FILES)
                if profile_form.is_valid():
                    profile = profile_form.save(commit=False)
                    profile.jobseeker = jobseeker
                    
                    # Check if profile already exists for this category
                    if JobSeekerProfile.objects.filter(jobseeker=jobseeker, job_category=profile.job_category).exists():
                        messages.error(request, f"You already have a profile for {profile.job_category.name} category.")
                    else:
                        profile.save()
                        profile_form.save_m2m()  # Save many-to-many fields
                        messages.success(request, f'Profile for {profile.job_category.name} category added successfully!')
                    return redirect('jobcategories')
            else:
                messages.error(request, "Please create your basic profile first.")
                
        else:  # This is the basic profile form
            if not user_has_profile:
                form = JobSeekerForm(request.POST)
                if form.is_valid():
                    jobseeker = form.save(commit=False)
                    jobseeker.user = request.user
                    jobseeker.is_completed = True
                    jobseeker.save()
                    form.save_m2m()  # This saves the skills
                    messages.success(request, 'Basic profile created successfully! Now you can add job categories and resumes.')
                    return redirect('jobcategories')
            else:
                messages.error(request, "You already have a basic profile.")
                
    else:
        # GET request - initialize forms
        if not user_has_profile:
            form = JobSeekerForm()
        else:
            profile_form = JobSeekerProfileForm()

    custom_skill_form = CustomSkillForm()

    context = {
        'jobcat': jobcat,
        'skills': skills,
        'governates': governates,
        'districts': districts,
        'cities': cities,
        'form': form,
        'profile_form': profile_form,
        'custom_skill_form': custom_skill_form,
        'user_has_profile': user_has_profile,
        'existing_profiles': existing_profiles,
        'existing_category_ids': existing_category_ids,
        'countries': countries,
    }

    return render(request, 'Jobseeker/jobcategory.html', context)

