from django.utils.http import url_has_allowed_host_and_scheme
from django.conf import settings
from django.shortcuts import redirect, render
from django.contrib.auth import authenticate, login
from django.contrib import messages

def custom_login_view1(request):
    # Get the next page URL from GET or POST
    next_url = request.GET.get('next') or request.POST.get('next') or ''
    
    if request.method == 'POST':
        form = CustomAuthenticationForm(request, data=request.POST)
        username = request.POST.get('username')
        password = request.POST.get('password')

        if username and password:
            user = authenticate(request, username=username, password=password)
            if user is not None:
                if not user.is_staff:
                    login(request, user)

                    # Check if next_url is safe
                    if url_has_allowed_host_and_scheme(next_url, allowed_hosts={request.get_host()}, require_https=request.is_secure()):
                        return redirect(next_url)
                    else:
                        return redirect('index')  # fallback if next is unsafe
                else:
                    messages.error(request, "Admins cannot log in from the user login page.")
                    return redirect('login1')
            else:
                messages.error(request, "Invalid username or password.")
    else:
        form = CustomAuthenticationForm()

    return render(request, 'login.html', {
        'form': form, 
        'next_url': next_url
    })



