from django.core.mail import EmailMultiAlternatives
from django.utils.http import urlsafe_base64_encode
from django.utils.encoding import force_bytes
from django.urls import reverse, reverse_lazy
from django.contrib import messages
from django import forms
from .models import CustomUser

# ===================== CUSTOM SET PASSWORD FORM (with optional new username) =====================
class CustomSetPasswordForm(SetPasswordForm):
    """Extends Django's SetPasswordForm with an optional new_username field."""
    new_username = forms.CharField(
        max_length=150,
        required=False,
        label="New username",
        help_text="Leave blank if you know your username."
    )

    def clean_new_username(self):
        username = self.cleaned_data.get('new_username')
        if username:
            # Case‑insensitive uniqueness check, exclude current user
            if CustomUser.objects.filter(username__iexact=username).exclude(pk=self.user.pk).exists():
                raise forms.ValidationError("This username is already taken.")
        return username

    def save(self, commit=True):
        user = super().save(commit=False)
        new_username = self.cleaned_data.get('new_username')
        if new_username:
            user.username = new_username
        if commit:
            user.save()
        return user

