from django.conf import settings  # add this import at the top of the file

def password_reset_view(request):
    if request.method == 'POST':
        email = request.POST.get('email')

        # Look up the user first; "not found" is the only expected error.
        try:
            user = CustomUser.objects.get(email=email)
        except CustomUser.DoesNotExist:
            return render(request, 'password_reset_form.html',
                          {'error_message': 'No account found with this email address.'})

        # Everything below can fail on reverse() or send(); reveal it instead of 500.
        try:
            token = default_token_generator.make_token(user)
            uid = urlsafe_base64_encode(force_bytes(user.pk))

            domain = request.get_host()
            protocol = 'https' if request.is_secure() else 'http'
            site_name = domain.split(':')[0]

            reset_link = f"{protocol}://{domain}{reverse('password_reset_confirm', kwargs={'uidb64': uid, 'token': token})}"

            subject = f"Reset your {site_name} password"
            user_display_name = user.username

            text_content = f"""
Reset Your Password – {site_name}

Hello {user_display_name},

You requested a password reset for your account ({email}).

Click the link below to set a new password (valid for 24 hours):

{reset_link}

If you didn't request this, please ignore this email.

– The {site_name} Team
            """

            html_content = f"""
            <div style="font-family:'Inter',sans-serif;max-width:560px;margin:auto;padding:20px;">
                <h2 style="color:#1a1a2e;">Reset your password</h2>
                <p>Hello {user_display_name},</p>
                <p>We received a request to reset the password for the account associated with <strong>{email}</strong>.</p>
                <p>
                    <a href="{reset_link}"
                       style="display:inline-block;background:#1a1a2e;color:#fff;text-decoration:none;
                              padding:12px 28px;border-radius:40px;font-weight:600;">
                        Reset My Password →
                    </a>
                </p>
                <p style="font-size:13px;word-break:break-all;">
                    Or paste this link into your browser:<br>{reset_link}
                </p>
                <p style="color:#888;font-size:13px;">If you didn't request this, you can safely ignore this email.</p>
            </div>
            """

            # Use the SAME sender style that works for your username email.
            from_email = getattr(settings, 'DEFAULT_FROM_EMAIL', None) or f"noreply@{site_name}"

            msg = EmailMultiAlternatives(subject, text_content, from_email, [email])
            msg.attach_alternative(html_content, "text/html")
            msg.send()

            return render(request, 'password_reset_form.html',
                          {'success_message': 'Account Recovery email has been sent. Please check your inbox.'})

        except Exception as e:
            # TEMPORARY diagnostic — shows the real reason instead of a blank 500.
            return render(request, 'password_reset_form.html',
                          {'error_message': f'Could not send reset email: {e}'})

    return render(request, 'password_reset_form.html')


from django.contrib.auth.tokens import default_token_generator
from django.utils.http import urlsafe_base64_encode, urlsafe_base64_decode
