from .models import CustomUser


# ---------- STEP 1: request a username-change link ----------
def forgot_username_view(request):
    if request.method == 'POST':
        email = request.POST.get('email')
        try:
            user = CustomUser.objects.get(email=email)

            token = default_token_generator.make_token(user)
            uid = urlsafe_base64_encode(force_bytes(user.pk))

            domain = request.get_host()
            protocol = 'https' if request.is_secure() else 'http'
            site_name = domain.split(':')[0]
            change_link = f"{protocol}://{domain}{reverse('change_username_confirm', kwargs={'uidb64': uid, 'token': token})}"

            subject = f"Set a new username for {site_name}"
            text_content = f"""
Hello,

We received a request to change the username for your {site_name} account.

Click the link below to choose a new username (valid for a limited time):

{change_link}

If you didn't request this, you can safely ignore this email.

– The {site_name} Team
            """
            html_content = f"""
            <div style="font-family:'Inter',sans-serif;max-width:560px;margin:auto;padding:20px;">
                <h2 style="color:#1a1a2e;">Set a new username</h2>
                <p>Hello,</p>
                <p>We received a request to change the username for your <strong>{site_name}</strong> account.</p>
                <p>
                    <a href="{change_link}"
                       style="display:inline-block;background:#1a1a2e;color:#fff;text-decoration:none;
                              padding:12px 28px;border-radius:40px;font-weight:600;">
                        Choose a new username →
                    </a>
                </p>
                <p style="color:#888;font-size:13px;">If you didn't request this, you can safely ignore this email.</p>
            </div>
            """

            from_email = f"noreply@{site_name}"
            msg = EmailMultiAlternatives(subject, text_content, from_email, [email])
            msg.attach_alternative(html_content, "text/html")
            msg.send()

        except CustomUser.DoesNotExist:
            pass  # don't reveal whether the email exists

        return render(request, 'forgot_username.html', {
            'success_message': 'A link to set a new username has been sent. Please check your inbox.'
        })

    return render(request, 'forgot_username.html')


# ---------- STEP 2: confirm link + set the new username ----------
def change_username_confirm_view(request, uidb64, token):
    try:
        uid = force_str(urlsafe_base64_decode(uidb64))
        user = CustomUser.objects.get(pk=uid)
    except (TypeError, ValueError, OverflowError, CustomUser.DoesNotExist):
        user = None

    # Invalid or expired link
    if user is None or not default_token_generator.check_token(user, token):
        return render(request, 'change_username_confirm.html', {'validlink': False})

    if request.method == 'POST':
        new_username = request.POST.get('new_username', '').strip()

        if not new_username:
            error = "Username is required."
        elif ' ' in new_username:
            error = "Username cannot contain spaces."
        elif len(new_username) > 25:
            error = "Username must be 25 characters or fewer."
        elif CustomUser.objects.filter(username__iexact=new_username).exclude(pk=user.pk).exists():
            error = "This username is already taken."
        else:
            user.username = new_username
            user.save()
            messages.success(request, "Your username has been updated. Please log in.")
            return redirect('login')

        return render(request, 'change_username_confirm.html', {
            'validlink': True,
            'error_message': error,
        })

    return render(request, 'change_username_confirm.html', {'validlink': True})

# ===================== CUSTOM PASSWORD RESET CONFIRM VIEW =====================
class CustomPasswordResetConfirmView(PasswordResetConfirmView):
    template_name = 'password_reset_confirm.html'
    success_url = reverse_lazy('login')
    form_class = CustomSetPasswordForm   # use our custom form with optional new_username

    def form_valid(self, form):
        response = super().form_valid(form)
        # Build success message
        msg = "Your password has been successfully reset."
        if form.cleaned_data.get('new_username'):
            msg += " Your username has also been updated."
        messages.success(self.request, msg)
        return response

    def form_invalid(self, form):
        messages.error(self.request, "Please correct the errors below.")
        return super().form_invalid(form)
        
