def get_category_type(product_type):
    """Determine if product type is a property or other category"""
    
    property_types = [
        'land', 'villa', 'apartment', 'commercial', 'farm', 'factory', 
        'complex', 'clinic', 'hostel', 'office', 'shop', 'cafe', 
        'staff', 'warehouse', 'townhouse', 'fullfloors', 'showrooms', 
        'wholebuilding', 'supermarket', 'foreign', 'shared', 'suits', 'chalet'
    ]
    
    if product_type in property_types:
        return 'property'
    else:
        return 'other'


