def notify_admin_exclusive_request(property_obj, user, product_type):
    """Send email notification for exclusive requests"""
    from django.core.mail import send_mail
    from django.conf import settings
    from django.contrib.auth import get_user_model

    User = get_user_model()

    admin_emails = list(
        User.objects.filter(is_superuser=True)
        .exclude(email='')
        .values_list('email', flat=True)
    )

    if not admin_emails:
        return

    send_mail(
        f"Exclusive Listing Request: {property_obj.property_title}",
        f"""
User: {user.username} (ID: {user.id})
Email: {user.email}

Property Details:
- Type: {product_type}
- Title: {property_obj.property_title}
- Price: {property_obj.price} OMR
- Property ID: {property_obj.id}

Please review this exclusive listing request.

Best regards,
System
""",
        settings.DEFAULT_FROM_EMAIL,
        admin_emails,
        fail_silently=True,
    )


# ============================================
# 🔥 UNIVERSAL PROPERTY HANDLER
# ============================================
def process_property_registration(request, product_type, form_data, temp_files, posting_method, status='pending'):
    user = request.user

    FORM_MAP = {
        'land': (LandForm, LandImage, LandVideo),
        'villa': (Villaform, VillaImage, VillaVideo),
        'apartment': (ApartmentForm, ApartmentImage, ApartmentVideo),
        'commercial': (CommercialForm, ComImage, ComVideo),
        'farm': (FarmForm, FarmImage, FarmVideo),
        'factory': (FactoryForm, FactoryImage, FactoryVideo),
        'complex': (ComplexForm, ComplexImage, ComplexVideo),
        'clinic': (ClinicForm, ClinicImage, ClinicVideo),
        'hostel': (HostelForm, HostelImage, HostelVideo),
        'office': (OfficeForm, OfficeImage, OfficeVideo),
        'shop': (ShopForm, ShopImage, ShopVideo),
        'cafe': (CafeForm, CafeImage, CafeVideo),
        'staff': (StaffForm, StaffImage, StaffVideo),
        'warehouse': (WarehouseForm, WarehouseImage, WarehouseVideo),
        'townhouse': (Townhouseform, TownhouseImage, TownhouseVideo),
        'fullfloors': (Fullfloorsform, FullfloorsImage, FullfloorsVideo),
        'showrooms': (Showroomsform, ShowroomsImage, ShowroomsVideo),
        'wholebuilding': (Wholebuildingform, WholebuildingImage, WholebuildingVideo),
        'supermarket': (Supermarketform, SupermarketImage, SupermarketVideo),
        'foreign': (Foreignform, ForeignImage, ForeignVideo),
        'shared': (Sharedform, SharedImage, SharedVideo),
        'suits': (Suitsform, SuitsImage, SuitsVideo),
        'chalet': (ChaletForm, ChaletImage, ChaletVideo),
    }

    if product_type not in FORM_MAP:
        messages.error(request, "Invalid property type.")
        return None

    FormClass, ImageModel, VideoModel = FORM_MAP[product_type]

    # Build POST data
    post_data = QueryDict(mutable=True)
    for key, value in form_data.items():
        if key not in ['csrfmiddlewaretoken', 'product_type']:
            post_data[key] = value

    # Build FILES
    files_dict = MultiValueDict()

    for file in temp_files:
        path = file.get('temp_path')
        name = file.get('original_name')
        field = file.get('field_name')

        if path and default_storage.exists(path):
            with default_storage.open(path, 'rb') as f:
                uploaded = SimpleUploadedFile(name, f.read())
                files_dict.appendlist(field, uploaded)

    form = FormClass(post_data, files_dict)

    if not form.is_valid():
        print("FORM ERRORS:", form.errors)
        messages.error(request, "Form validation failed.")
        return None

    obj = form.save(commit=False)
    obj.user = user
    obj.status = status  # ← CHANGE THIS: Use the parameter, not hardcoded 'pending'
    obj.posting_method = posting_method
    obj.save()
    form.save_m2m()

    # Save Images
    for img in files_dict.getlist('images'):
        image_obj = ImageModel.objects.create(image=img)
        obj.images.add(image_obj)

    # Save Videos
    for vid in files_dict.getlist('videos'):
        video_obj = VideoModel.objects.create(video=vid)
        obj.videos.add(video_obj)

    # Cleanup temp files
    for file in temp_files:
        path = file.get('temp_path')
        if path and default_storage.exists(path):
            default_storage.delete(path)

    if 'temp_property_data' in request.session:
        del request.session['temp_property_data']

    return obj


# ============================================
# MAIN LISTINGSUB VIEW
# ============================================
@login_required
def listingsub(request):
    user = request.user
    credits = get_or_create_user_credits(user)

    governate = Governate.objects.all()
    district = District.objects.all()
    cities = Cities.objects.all()
    nearby_locations = NearbyLocation.objects.all()
    main_amenities = MainAmenities.objects.all()
    additional_amenities = AdditionalAmenities.objects.all()

    # ============================================
    # STEP 1: POSTING METHOD + BOOST DURATION
    # ============================================
    if request.method == 'POST' and 'posting_method' in request.POST:
        posting_method = request.POST.get('posting_method')
        temp_data = request.session.get('temp_property_data')

        if not temp_data:
            messages.error(request, "Session expired. Please try again.")
            return redirect('listingsub')

        product_type = temp_data.get('product_type')
        form_data = temp_data.get('form_data')
        temp_files = temp_data.get('temp_files', [])
        
        # Boost duration (only matters for boosted)
        boost_duration = int(request.POST.get('boost_duration', 7))
        if boost_duration not in [7, 14, 30]:
            boost_duration = 7
        
        category_type = get_category_type(product_type)

        # ========== EXCLUSIVE LISTING ==========
        if posting_method == 'exclusive':
            if category_type != 'property':
                messages.error(request, "Exclusive listing is only available for properties.")
                return redirect('listingsub')

            from django.urls import reverse
            from .models import CreditPackage
            EXCLUSIVE_COST = 25

            # --- Has 25 credits: deduct + create as pending_exclusive (no payment) ---
            if credits.purchased_listing_credits >= EXCLUSIVE_COST:
                obj = process_property_registration(
                    request, product_type, form_data, temp_files,
                    'exclusive', status='pending_exclusive'
                )
                if not obj:
                    messages.error(request, "Failed to create exclusive listing.")
                    return redirect('listingsub')

                credits.purchased_listing_credits -= EXCLUSIVE_COST
                credits.save(update_fields=['purchased_listing_credits'])

                CreditTransaction.objects.create(
                    user=user,
                    transaction_type='usage',
                    listing_credits_change=-EXCLUSIVE_COST,
                    listing_id=obj.id,
                    listing_type=obj._meta.model_name,
                    description=f"Exclusive listing #{obj.id}: {EXCLUSIVE_COST} credits used (awaiting admin approval)",
                )
                notify_admin_exclusive_request(obj, user, product_type)
                messages.success(
                    request,
                    f"✅ {EXCLUSIVE_COST} credits used. Your exclusive listing was sent to admin "
                    f"for approval. Remaining: {credits.purchased_listing_credits} credits."
                )
                return redirect(adss, user_id=user.id)

            # --- No credits: stash ad, pay 25 OMR, create AFTER payment succeeds ---
            request.session['pending_exclusive_property_ad'] = {
                'product_type': product_type,
                'form_data': form_data,
                'temp_files': temp_files,
            }

            exclusive_package, _ = CreditPackage.objects.get_or_create(
                name="25 OMR Exclusive Package",
                defaults={
                    'package_type': 'listing',
                    'listing_credits': EXCLUSIVE_COST,
                    'price_omr': Decimal('25.000'),
                    'vat_percentage': Decimal('5.00'),
                    'is_active': True,
                },
            )

            messages.info(
                request,
                "Complete the 25 OMR payment and your exclusive listing will be sent to admin for approval."
            )
            return redirect(
                f"{reverse('buy_credits', args=[exclusive_package.id])}"
                f"?next={reverse('continue_exclusive_property_posting')}"
            )
        
        # ========== NORMAL & BOOSTED - DEDUCT CREDITS AT POSTING WITH SESSION STORAGE ==========
        else:
            # Credit checks with session storage
            if posting_method == 'normal':
                if not credits.can_post_listing('normal'):
                    # Store ad data for later auto-posting
                    request.session['pending_normal_property_ad'] = {
                        'product_type': product_type,
                        'form_data': form_data,
                        'temp_files': temp_files,
                    }
                    messages.info(request, "You don't have enough listing credits. Please purchase credits – your ad will be posted automatically.")
                    return redirect(f"{reverse('credit_packages')}?next={reverse('continue_normal_property_posting')}")
            
            elif posting_method == 'boosted':
                # First check listing credits
                if not credits.can_post_listing('normal'):
                    request.session['pending_boost_property_ad'] = {
                        'product_type': product_type,
                        'form_data': form_data,
                        'temp_files': temp_files,
                        'boost_duration': boost_duration,
                    }
                    messages.info(request, "You don't have enough listing credits. Please purchase credits – your boosted ad will be posted automatically.")
                    return redirect(f"{reverse('credit_packages')}?next={reverse('continue_boost_property_posting')}")
                
                # Then check boost days
                if credits.boost_days_available < boost_duration:
                    request.session['pending_boost_property_ad'] = {
                        'product_type': product_type,
                        'form_data': form_data,
                        'temp_files': temp_files,
                        'boost_duration': boost_duration,
                    }
                    messages.info(request, f"You need {boost_duration} boost days but have only {credits.boost_days_available}. Purchase boost credits – your ad will be posted automatically.")
                    return redirect(f"{reverse('credit_packages')}?next={reverse('continue_boost_property_posting')}")
            
            # If we reach here, credits are sufficient – proceed with immediate deduction
            if posting_method == 'normal':
                success, msg = credits.use_listing_credit('normal')
                if not success:
                    messages.error(request, f"❌ {msg}")
                    return redirect('credit_packages')
            else:  # boosted
                success, msg = credits.use_listing_credit('normal')
                if success:
                    boost_success, boost_msg = credits.use_boost_credit(boost_duration)
                    if not boost_success:
                        messages.error(request, f"❌ {boost_msg}")
                        return redirect('credit_packages')
                else:
                    messages.error(request, f"❌ {msg}")
                    return redirect('credit_packages')
            
            # Create listing
            obj = process_property_registration(request, product_type, form_data, temp_files, posting_method, status='pending')
            if obj:
                ListingUsage.objects.create(
                    user=user,
                    listing_type=obj._meta.model_name,
                    listing_id=obj.id,
                    credit_source='free' if credits.available_free_listings + 1 > credits.free_listings_used else 'purchased',
                    expires_at=timezone.now() + timedelta(days=45)
                )
                
                if posting_method == 'boosted':
                    BoostUsage.objects.create(
                        user=user,
                        listing_type=obj._meta.model_name,
                        listing_id=obj.id,
                        boost_days=boost_duration,
                        expires_at=timezone.now() + timedelta(days=boost_duration),
                        is_active=True
                    )
                    messages.success(request, f"✅ Boosted ad submitted! {msg} and {boost_msg}")
                else:
                    messages.success(request, f"✅ Normal ad submitted! {msg}")
                
                return redirect(adss, user_id=user.id)
            else:
                # Refund if creation failed
                if posting_method == 'normal':
                    credits.purchased_listing_credits += 1
                else:
                    credits.purchased_listing_credits += 1
                    credits.boost_days_available += boost_duration
                credits.save()
                messages.error(request, "Failed to create listing. Credits refunded.")
                return redirect('listingsub')

    # ============================================
    # STEP 2: FORM SUBMISSION
    # ============================================
    if request.method == 'POST' and 'product_type' in request.POST:
        product_type = request.POST.get('product_type')
        category_type = get_category_type(product_type)

        temp_files = []
        if request.FILES:
            from django.core.files.base import ContentFile
            for field_name, file_list in request.FILES.lists():
                for file in file_list:
                    temp_path = default_storage.save(f'temp/{user.id}_{file.name}', ContentFile(file.read()))
                    temp_files.append({'field_name': field_name, 'original_name': file.name, 'temp_path': temp_path})

        request.session['temp_property_data'] = {
            'product_type': product_type,
            'form_data': request.POST.dict(),
            'temp_files': temp_files
        }

        return render(request, 'select_posting_method.html', {
            'property_type_display': get_property_type_display(product_type),
            'temp_data': {
                'property_title': request.POST.get('property_title', ''),
                'price': request.POST.get('price', '')
            },
            'product_type': product_type,
            'category_type': category_type,
            'credits': credits,
            'free_credits_left': credits.available_free_listings,
            'purchased_credits_left': credits.purchased_listing_credits,
            'boost_days_left': credits.boost_days_available,
        })

    # ============================================
    # STEP 3: GET REQUEST
    # ============================================
    return render(request, 'subcategory.html', {
        'land_form': LandForm(),
        'villa_form': Villaform(),
        'apartment_form': ApartmentForm(),
        'commercial_form': CommercialForm(),
        'farm_form': FarmForm(),
        'factory_form': FactoryForm(),
        'complex_form': ComplexForm(),
        'clinic_form': ClinicForm(),
        'hostel_form': HostelForm(),
        'office_form': OfficeForm(),
        'shop_form': ShopForm(),
        'cafe_form': CafeForm(),
        'staff_form': StaffForm(),
        'warehouse_form': WarehouseForm(),
        'townhouse_form': Townhouseform(),
        'fullfloors_form': Fullfloorsform(),
        'showrooms_form': Showroomsform(),
        'wholebuilding_form': Wholebuildingform(),
        'supermarket_form': Supermarketform(),
        'foreign_form': Foreignform(),
        'shared_form': Sharedform(),
        'suits_form': Suitsform(),
        'additional_amenities': additional_amenities,
        'main_amenities': main_amenities,
        'nearby_locations': nearby_locations,
        'governate': governate,
        'district': district,
        'cities': cities,
        'countries': countries,
        'credits': credits,
        'free_credits_left': credits.available_free_listings,
        'purchased_credits_left': credits.purchased_listing_credits,
        'boost_days_left': credits.boost_days_available,
    })
