def get_motors_category_type(product_type):
    """Determine if motor type is premium (can use exclusive) or standard"""
    
    # Premium types (can use exclusive)
    premium_types = [
        'automobile', 'motorcycle', 'boat', 'heavy_vehicle'
    ]
    
    if product_type in premium_types:
        return 'premium'
    else:
        return 'standard'


def get_motors_type_display(product_type):
    """Get display name for motor types"""
    return {
        'automobile': 'Automobile',
        'motorcycle': 'Motorcycle',
        'scooter': 'Scooter',
        'quadbikes': 'Quad Bike',
        'helmetclothes': 'Helmet & Clothes',
        'boat': 'Boat',
        'number_plate': 'Number Plate',
        'auto_accessory_part': 'Auto Accessory/Part',
        'tires_caps': 'Tires & Caps',
        'junk_car': 'Junk Car',
        'heavy_vehicle': 'Heavy Vehicle',
        'car_repair': 'Car Repair & Maintenance',
    }.get(product_type, product_type.title())


def notify_admin_exclusive_request_motors(property_obj, user, product_type):
    """Send email notification for exclusive requests"""
    from django.core.mail import send_mail
    from django.conf import settings
    from django.contrib.auth import get_user_model
    
    User = get_user_model()
    
    admin_emails = list(
        User.objects.filter(is_superuser=True)
        .exclude(email='')
        .values_list('email', flat=True)
    )
    
    if not admin_emails:
        return
    
    # Get title field (different models have different field names)
    title = getattr(property_obj, 'title', getattr(property_obj, 'car_title', 'N/A'))
    price = getattr(property_obj, 'price', 'N/A')
    
    send_mail(
        f"Exclusive Listing Request: {title}",
        f"""
User: {user.username} (ID: {user.id})
Email: {user.email}

Product Details:
- Type: {product_type}
- Title: {title}
- Price: {price} OMR
- Product ID: {property_obj.id}

Please review this exclusive listing request.

Best regards,
System
""",
        settings.DEFAULT_FROM_EMAIL,
        admin_emails,
        fail_silently=True,
    )


