# UNIVERSAL MOTORS REGISTRATION HANDLER
# ============================================
def process_motors_registration(request, product_type, form_data, temp_files, posting_method, status='pending'):
    from django.http import QueryDict
    from django.utils.datastructures import MultiValueDict
    from django.core.files.uploadedfile import SimpleUploadedFile
    from django.core.files.storage import default_storage
    
    user = request.user
    
    # Map product types to their Form, Image, Video models
    FORM_MAP = {
        'automobile': (CarForm, AutomobileImage, AutomobileVideo),
        'motorcycle': (BikeForm, MotorcycleImage, MotorcycleVideo),
        'scooter': (ScooterForm, ScooterImage, ScooterVideo),
        'quadbikes': (QuadbikesForm, QuadbikesImage, QuadbikesVideo),
        'helmetclothes': (HelmetClothesForm, HelmetClothesImage, HelmetClothesVideo),
        'boat': (BoatForm, BoatImage, BoatVideo),
        'number_plate': (NumberPlateForm, None, None),
        'auto_accessory_part': (AutoAccessoryPartForm, AutoAccessoryPartImage, AutoAccessoryPartVideo),
        'tires_caps': (TiresAndCapsForm, TiresAndCapsImage, TiresAndCapsVideo),
        'junk_car': (JunkCarForm, JunkCarImage, JunkCarVideo),
        'heavy_vehicle': (HeavyVehicleForm, HeavyVehicleImage, HeavyVehicleVideo),
        'car_repair': (CarRepairMaintenanceForm, CarRepairImage, CarRepairVideo),
    }
    
    if product_type not in FORM_MAP:
        messages.error(request, "Invalid product type.")
        return None
    
    FormClass, ImageModel, VideoModel = FORM_MAP[product_type]
    
    # Build POST data (excluding csrf and product_type)
    post_data = QueryDict(mutable=True)
    for key, value in form_data.items():
        if key not in ['csrfmiddlewaretoken', 'product_type']:
            post_data[key] = value
    
    # Build FILES data from temp files
    files_dict = MultiValueDict()
    
    for file in temp_files:
        path = file.get('temp_path')
        name = file.get('original_name')
        field = file.get('field_name')
        
        if path and default_storage.exists(path):
            with default_storage.open(path, 'rb') as f:
                uploaded = SimpleUploadedFile(name, f.read())
                files_dict.appendlist(field, uploaded)
    
    # Create and validate form
    form = FormClass(post_data, files_dict)
    
    if not form.is_valid():
        print(f"FORM ERRORS for {product_type}:", form.errors)
        messages.error(request, f"Form validation failed.")
        return None
    
    # Save the main object
    obj = form.save(commit=False)
    obj.user = user
    obj.status = status
    obj.posting_method = posting_method
    
    # Handle city field if it exists
    if hasattr(obj, 'city'):
        city_id = form_data.get('city')
        if city_id:
            try:
                obj.city = Cities.objects.get(id=city_id)
            except (Cities.DoesNotExist, ValueError):
                pass
    
    # Handle latitude/longitude if they exist
    if hasattr(obj, 'latitude'):
        obj.latitude = form_data.get('latitude') or None
    if hasattr(obj, 'longitude'):
        obj.longitude = form_data.get('longitude') or None
    
    obj.save()
    form.save_m2m()
    
    # Save images if the model has images
    if ImageModel:
        for img in files_dict.getlist('images'):
            try:
                image_obj = ImageModel.objects.create(image=img)
                obj.images.add(image_obj)
            except Exception as e:
                print(f"Error saving image: {e}")
    
    # Save videos if the model has videos
    if VideoModel:
        for vid in files_dict.getlist('videos'):
            try:
                if vid:
                    video_obj = VideoModel.objects.create(video=vid)
                    obj.videos.add(video_obj)
            except Exception as e:
                print(f"Error saving video: {e}")
    
    # Cleanup temp files
    for file in temp_files:
        path = file.get('temp_path')
        if path and default_storage.exists(path):
            default_storage.delete(path)
    
    # Cleanup session data
    if 'temp_motors_data' in request.session:
        del request.session['temp_motors_data']
    if 'pending_motors' in request.session:
        del request.session['pending_motors']
    
    # Get display name for success message
    display_name = get_motors_type_display(product_type)
    messages.success(request, f"{display_name} registered successfully!")
    
    return obj


