@login_required
def listingsub1(request):
    user = request.user
    credits = get_or_create_user_credits(user)
    
    regions = Region.objects.all()
    governate = Governate.objects.all()
    district = District.objects.all()
    cities = Cities.objects.all()
    interior_options = InteriorOptions.objects.all()
    exterior_options = ExteriorOptions.objects.all()
    technology_options = TechnologyOptions.objects.all()

    # STEP 1: POSTING METHOD + BOOST DURATION
    if request.method == 'POST' and 'posting_method' in request.POST:
        posting_method = request.POST.get('posting_method')
        temp_data = request.session.get('temp_motors_data')
        if not temp_data:
            messages.error(request, "Session expired. Please try again.")
            return redirect('listingsub1')
        
        product_type = temp_data.get('product_type')
        form_data = temp_data.get('form_data')
        temp_files = temp_data.get('temp_files', [])
        
        # Boost duration (default 7, can be 7/14/30)
        boost_duration = int(request.POST.get('boost_duration', 7))
        if boost_duration not in [7, 14, 30]:
            boost_duration = 7
        
        # ========== CREDIT CHECKS WITH SESSION STORAGE ==========
        if posting_method == 'normal':
            if not credits.can_post_listing('normal'):
                request.session['pending_normal_motors_ad'] = {
                    'product_type': product_type,
                    'form_data': form_data,
                    'temp_files': temp_files,
                }
                messages.info(request, "You don't have enough listing credits. Please purchase credits – your ad will be posted automatically.")
                return redirect(f"{reverse('credit_packages')}?next={reverse('continue_normal_motors_posting')}")
        
        elif posting_method == 'boosted':
            # First check listing credits
            if not credits.can_post_listing('normal'):
                request.session['pending_boost_motors_ad'] = {
                    'product_type': product_type,
                    'form_data': form_data,
                    'temp_files': temp_files,
                    'boost_duration': boost_duration,
                }
                messages.info(request, "You don't have enough listing credits. Please purchase credits – your boosted ad will be posted automatically.")
                return redirect(f"{reverse('credit_packages')}?next={reverse('continue_boost_motors_posting')}")
            
            # Then check boost days
            if credits.boost_days_available < boost_duration:
                request.session['pending_boost_motors_ad'] = {
                    'product_type': product_type,
                    'form_data': form_data,
                    'temp_files': temp_files,
                    'boost_duration': boost_duration,
                }
                messages.info(request, f"You need {boost_duration} boost days but have only {credits.boost_days_available}. Purchase boost credits – your ad will be posted automatically.")
                return redirect(f"{reverse('credit_packages')}?next={reverse('continue_boost_motors_posting')}")
        
        elif posting_method == 'exclusive':
            if credits.purchased_listing_credits <= 0:
                messages.error(request, "❌ Exclusive listings require purchased credits. Please buy a package.")
                return redirect('credit_packages')
        # =========================================================
        
        category_type = get_motors_category_type(product_type)
        
        # ---------- NORMAL POSTING ----------
        if posting_method == 'normal':
            obj = process_motors_registration(request, product_type, form_data, temp_files, 'normal', status='pending')
            if obj:
                success, msg = credits.use_listing_credit('normal')
                if success:
                    ListingUsage.objects.create(
                        user=user,
                        listing_type=obj._meta.model_name,
                        listing_id=obj.id,
                        credit_source='free' if credits.available_free_listings + 1 > credits.free_listings_used else 'purchased',
                        expires_at=timezone.now() + timedelta(days=45)
                    )
                    messages.success(request, f"✅ {msg}")
                else:
                    messages.warning(request, f"⚠️ {msg}")
                return redirect(adss, user_id=user.id)
            else:
                messages.error(request, "Failed to create listing. Please try again.")
                return redirect('listingsub1')
        
        # ---------- BOOSTED POSTING ----------
        elif posting_method == 'boosted':
            obj = process_motors_registration(request, product_type, form_data, temp_files, 'boosted', status='pending')
            if obj:
                success, msg = credits.use_listing_credit('normal')
                if success:
                    ListingUsage.objects.create(
                        user=user,
                        listing_type=obj._meta.model_name,
                        listing_id=obj.id,
                        credit_source='free' if credits.available_free_listings + 1 > credits.free_listings_used else 'purchased',
                        expires_at=timezone.now() + timedelta(days=45)
                    )
                    boost_success, boost_msg = credits.use_boost_credit(boost_duration)
                    if boost_success:
                        BoostUsage.objects.create(
                            user=user,
                            listing_type=obj._meta.model_name,
                            listing_id=obj.id,
                            boost_days=boost_duration,
                            expires_at=timezone.now() + timedelta(days=boost_duration),
                            is_active=True
                        )
                        messages.success(request, f"✅ {msg} and {boost_msg}")
                    else:
                        messages.warning(request, f"✅ {msg} but {boost_msg}")
                else:
                    messages.warning(request, f"⚠️ {msg}")
                return redirect(adss, user_id=user.id)
            else:
                messages.error(request, "Failed to create boosted listing. Please try again.")
                return redirect('listingsub1')
        
        # ---------- EXCLUSIVE POSTING ----------
        elif posting_method == 'exclusive':
            if category_type == 'premium':
                obj = process_motors_registration(request, product_type, form_data, temp_files, 'exclusive', status='pending_exclusive')
                if obj:
                    success, msg = credits.use_listing_credit('exclusive')
                    if success:
                        ListingUsage.objects.create(
                            user=user,
                            listing_type=obj._meta.model_name,
                            listing_id=obj.id,
                            credit_source='purchased',
                            expires_at=timezone.now() + timedelta(days=45)
                        )
                        messages.success(request, f"✅ {msg}")
                    else:
                        messages.warning(request, f"⚠️ {msg}")
                    notify_admin_exclusive_request_motors(obj, user, product_type)
                    messages.success(request, "Exclusive request sent to admin for approval.")
                    return redirect(adss, user_id=user.id)
                else:
                    messages.error(request, "Failed to create exclusive listing.")
                    return redirect('listingsub1')
            else:
                messages.error(request, "Exclusive listing is only available for premium motor vehicles.")
                return redirect('listingsub1')
        
        messages.error(request, "Something went wrong. Please try again.")
        return redirect('listingsub1')
    
    # STEP 2: FORM SUBMISSION (user fills the ad form)
    if request.method == 'POST' and 'product_type' in request.POST:
        product_type = request.POST.get('product_type')
        category_type = get_motors_category_type(product_type)
        temp_files = []
        if request.FILES:
            for field_name, file_list in request.FILES.lists():
                for file in file_list:
                    temp_path = default_storage.save(f'temp/motors_{user.id}_{file.name}', ContentFile(file.read()))
                    temp_files.append({'field_name': field_name, 'original_name': file.name, 'temp_path': temp_path})
        request.session['temp_motors_data'] = {
            'product_type': product_type,
            'form_data': request.POST.dict(),
            'temp_files': temp_files
        }
        title = request.POST.get('title', request.POST.get('car_title', ''))
        return render(request, 'select_posting_method.html', {
            'property_type_display': get_motors_type_display(product_type),
            'temp_data': {'property_title': title, 'price': request.POST.get('price', '')},
            'product_type': product_type,
            'category_type': category_type,
            'credits': credits,
            'free_credits_left': credits.available_free_listings,
            'purchased_credits_left': credits.purchased_listing_credits,
            'boost_days_left': credits.boost_days_available,
        })
    
    # STEP 3: GET REQUEST - Show all forms
    return render(request, 'motors.html', {
        'automobile_form': CarForm(),
        'motorcycle_form': BikeForm(),
        'scooter_form': ScooterForm(),
        'quadbikes_form': QuadbikesForm(),
        'helmetclothes_form': HelmetClothesForm(),
        'boat_form': BoatForm(),
        'number_plate_form': NumberPlateForm(),
        'auto_accessory_part_form': AutoAccessoryPartForm(),
        'tires_caps_form': TiresAndCapsForm(),
        'junkcar_form': JunkCarForm(),
        'heavy_vehicle_form': HeavyVehicleForm(),
        'car_repair_form': CarRepairMaintenanceForm(),
        'regions': regions,
        'governate': governate,
        'district': district,
        'cities': cities,
        'interior_options': interior_options,
        'exterior_options': exterior_options,
        'technology_options': technology_options,
        'credits': credits,
        'free_credits_left': credits.available_free_listings,
        'purchased_credits_left': credits.purchased_listing_credits,
        'boost_days_left': credits.boost_days_available,
    })

    
