def product_detail(request, product_type, product_id):
    """Display product detail and handle boost POST requests (AJAX or form)"""
    model = PRODUCT_MODEL_MAP.get(product_type.lower())
    if not model:
        return render(request, '404.html', status=404)

    product = get_object_or_404(model, id=product_id)

    # ----- Handle Boost POST -----
    if request.method == 'POST' and request.user.is_authenticated:
        # Detect AJAX
        is_ajax = request.headers.get('X-Requested-With') == 'XMLHttpRequest'
        # Check if this is a boost action
        if request.POST.get('action') == 'boost' or is_ajax:
            return _process_boost_request(request, product_type, product, model)

    # ----- GET request: build context -----
    # Get user credits (if logged in)
    credits = None
    boost_days_available = 0
    if request.user.is_authenticated:
        credits = get_or_create_user_credits(request.user)
        boost_days_available = credits.boost_days_available

    # Check active boost
    boost = BoostUsage.objects.filter(
        listing_type=product_type.lower(),
        listing_id=product.id,
        is_active=True
    ).first()

    is_boosted = False
    boost_days_left = 0
    if boost:
        boost.update_boost_status()  # Deactivate if expired
        if boost.is_active:
            is_boosted = True
            boost_days_left = boost.days_remaining
        else:
            boost = None

    user_is_owner = request.user.is_authenticated and product.user == request.user
    product_status = getattr(product, 'status', None)
    cutoff_date = timezone.now() - timedelta(days=45)

    # Determine if product is expired (status='expired' or approved but older than 45 days)
    is_expired = False
    if product_status == 'expired':
        is_expired = True
    elif product_status == 'approved' and product.created_at < cutoff_date:
        is_expired = True

    # Eligibility: owner, approved, not expired, not boosted
    can_boost = (
        user_is_owner and
        not is_boosted and
        product_status == 'approved' and
        not is_expired
    )

    # Button state and text
    boost_button_disabled = True
    boost_button_text = "Boost"

    if not user_is_owner:
        boost_button_text = "Boost (not yours)"
    elif is_boosted:
        boost_button_text = f"Boosted ({boost_days_left}d left)"
    elif product_status == 'pending':
        boost_button_text = "Pending Approval"
    elif product_status == 'rejected':
        boost_button_text = "Rejected"
    elif product_status == 'soldout':
        boost_button_text = "Sold Out"
    elif is_expired:
        boost_button_text = "Expired"
    elif can_boost:
        boost_button_text = "Boost"
        boost_button_disabled = False
    else:
        boost_button_text = "Boost"

    # Images & videos
    images = product.images.all() if hasattr(product, 'images') else None
    videos = product.videos.all() if hasattr(product, 'videos') else None

    context = {
        'product_type': product_type,
        'product': product,
        'images': images,
        'videos': videos,
        # Boost related
        'is_boosted': is_boosted,
        'boost_days_left': boost_days_left,
        'user_is_owner': user_is_owner,
        'can_boost': can_boost,
        'boost_days_available': boost_days_available,
        'boost_button_disabled': boost_button_disabled,
        'boost_button_text': boost_button_text,
        'product_status': product_status,
        'is_expired': is_expired,
    }
    return render(request, 'product_detail.html', context)


def _process_boost_request(request, product_type, product, model):
    """
    Internal helper to process boost POST (AJAX or normal form).
    Returns JsonResponse for AJAX, or redirect for normal POST.
    """
    # Get days from POST data
    days = request.POST.get('days')
    if days is None:
        try:
            data = json.loads(request.body)
            days = data.get('days')
        except:
            days = None

    try:
        days = int(days)
    except (TypeError, ValueError):
        days = 7

    if days not in [7, 14, 30]:
        error = "Invalid boost duration. Choose 7, 14, or 30 days."
        if request.headers.get('X-Requested-With') == 'XMLHttpRequest':
            return JsonResponse({'success': False, 'message': error}, status=400)
        messages.error(request, error)
        return redirect('product_detail', product_type=product_type, product_id=product.id)

    # Ownership check
    if product.user != request.user:
        error = "You don't own this listing."
        if request.headers.get('X-Requested-With') == 'XMLHttpRequest':
            return JsonResponse({'success': False, 'message': error}, status=403)
        messages.error(request, error)
        return redirect('product_detail', product_type=product_type, product_id=product.id)

    # Status and expiry checks
    product_status = getattr(product, 'status', None)
    cutoff_date = timezone.now() - timedelta(days=45)
    is_expired = False
    if product_status == 'expired':
        is_expired = True
    elif product_status == 'approved' and product.created_at < cutoff_date:
        is_expired = True

    if product_status != 'approved':
        error = "Only approved listings can be boosted."
        if request.headers.get('X-Requested-With') == 'XMLHttpRequest':
            return JsonResponse({'success': False, 'message': error}, status=400)
        messages.error(request, error)
        return redirect('product_detail', product_type=product_type, product_id=product.id)

    if is_expired:
        error = "This listing is expired and cannot be boosted."
        if request.headers.get('X-Requested-With') == 'XMLHttpRequest':
            return JsonResponse({'success': False, 'message': error}, status=400)
        messages.error(request, error)
        return redirect('product_detail', product_type=product_type, product_id=product.id)

    # Check existing active boost
    existing_boost = BoostUsage.objects.filter(
        user=request.user,
        listing_type=product_type.lower(),
        listing_id=product.id,
        is_active=True
    ).first()

    if existing_boost and existing_boost.is_boost_active():
        error = f"This ad is already boosted! Expires in {existing_boost.days_remaining} days."
        if request.headers.get('X-Requested-With') == 'XMLHttpRequest':
            return JsonResponse({'success': False, 'message': error}, status=400)
        messages.warning(request, error)
        return redirect('product_detail', product_type=product_type, product_id=product.id)

    # Deduct boost days
    credits = get_or_create_user_credits(request.user)
    if credits.boost_days_available < days:
        error = f"Insufficient boost days. Need {days}, you have {credits.boost_days_available}."
        if request.headers.get('X-Requested-With') == 'XMLHttpRequest':
            return JsonResponse({'success': False, 'message': error}, status=400)
        messages.error(request, error)
        return redirect('credit_packages')

    success, msg = credits.use_boost_credit(days)
    if not success:
        if request.headers.get('X-Requested-With') == 'XMLHttpRequest':
            return JsonResponse({'success': False, 'message': msg}, status=400)
        messages.error(request, msg)
        return redirect('product_detail', product_type=product_type, product_id=product.id)

    # Apply or extend boost
    if existing_boost:
        existing_boost.expires_at = timezone.now() + timedelta(days=days)
        existing_boost.is_active = True
        existing_boost.boost_days = days
        existing_boost.save(update_fields=['expires_at', 'is_active', 'boost_days'])
        CreditTransaction.objects.create(
            user=request.user,
            transaction_type='usage',
            boost_days_change=-days,
            description=f"Extended boost for {product_type} #{product.id} by {days} days"
        )
        success_msg = f"Boost extended by {days} days!"
    else:
        if hasattr(product, 'posting_method'):
            product.posting_method = 'boosted'
            product.save(update_fields=['posting_method'])
        BoostUsage.objects.create(
            user=request.user,
            listing_type=product_type.lower(),
            listing_id=product.id,
            boost_days=days,
            expires_at=timezone.now() + timedelta(days=days),
            is_active=True
        )
        CreditTransaction.objects.create(
            user=request.user,
            transaction_type='usage',
            boost_days_change=-days,
            description=f"Boosted {product_type} #{product.id} for {days} days"
        )
        success_msg = f"Your ad is now BOOSTED for {days} days!"

    if request.headers.get('X-Requested-With') == 'XMLHttpRequest':
        return JsonResponse({
            'success': True,
            'message': success_msg,
            'days_remaining': days,
            'boost_days_left': credits.boost_days_available
        })
    messages.success(request, success_msg)
    return redirect('product_detail', product_type=product_type, product_id=product.id)

