@never_cache
@login_required
@user_passes_test(lambda u: u.is_staff or u.is_superuser)
def add_user(request):
    if request.method == 'POST':
        form = userForm(request.POST, request.FILES)
        if form.is_valid():
            form.save()
            messages.success(request, 'User added successfully.')
            return redirect('user')
        else:
            messages.error(request, 'Please correct the errors below.')
    else:
        form = userForm()
    
    return render(request, 'admin1/user/adduser.html', {'form': form})


@never_cache
@login_required
@user_passes_test(lambda u: u.is_staff or u.is_superuser)
def edit_user(request, user_id):
    user = get_object_or_404(CustomUser, pk=user_id)
    
    if request.method == 'POST':
        form = userForm(request.POST, request.FILES, instance=user)
        if form.is_valid():
            form.save()
            messages.success(request, f'User {user.username} updated successfully.')
            return redirect('user')
        else:
            messages.error(request, 'Please correct the errors below.')
    else:
        form = userForm(instance=user)
    
    return render(request, 'admin1/user/edituser.html', {'form': form, 'user': user})


@never_cache
@login_required
@user_passes_test(lambda u: u.is_staff or u.is_superuser)
def delete_user(request, user_id):
    user = get_object_or_404(CustomUser, id=user_id)
    
    # Prevent superuser deletion
    if user.is_superuser:
        messages.error(request, 'Superusers cannot be deleted.')
        return redirect('user')
    
    if request.method == 'POST':
        username = user.username
        user.delete()
        messages.success(request, f'User {username} deleted successfully.')
        return redirect('user')
    
    return render(request, 'admin1/user/deleteuser.html', {'user': user})


@never_cache
@login_required
@user_passes_test(lambda u: u.is_staff or u.is_superuser)
def view_user(request, pk):
    user = get_object_or_404(CustomUser, pk=pk)
    data = {
        'id': user.id,
        'username': user.username,
        'email': user.email,
        'phone': user.phone or '',
        'whatsapp': user.whatsapp or '',
        'address': user.address or '',
        'user_type': user.user_type,
        'is_active': user.is_active,
        'is_suspended': user.is_suspended,
        'is_approved': user.is_approved,
        'date_joined': user.date_joined.strftime('%Y-%m-%d %H:%M:%S') if user.date_joined else '',
        'last_login': user.last_login.strftime('%Y-%m-%d %H:%M:%S') if user.last_login else '',
        'image': user.image.url if user.image else None,
        'nationality': str(user.nationality) if user.nationality else '',
        'gender': user.gender or '',
        'dob': user.dob.strftime('%Y-%m-%d') if user.dob else '',
        'suspension_reason': user.suspension_reason or '',
    }
    return JsonResponse(data)

