def notify_admin_exclusive_request_classified(obj, user, product_type):
    """
    Send notification to admin about exclusive listing request.
    Implement based on your notification system (email, database, etc.)
    """
    from django.core.mail import send_mail
    from django.conf import settings
    
    subject = f"Exclusive Listing Request: {get_classified_type_display(product_type)}"
    message = f"""
User: {user.email} (ID: {user.id})
Product Type: {get_classified_type_display(product_type)}
Listing ID: {obj.id}
Title: {getattr(obj, 'title', getattr(obj, 'listing_title', 'N/A'))}
Price: {getattr(obj, 'price', 'N/A')}

Please review this listing for exclusive approval.
"""
    
    # Only send if you have admin emails configured
    if hasattr(settings, 'ADMIN_EMAILS') and settings.ADMIN_EMAILS:
        send_mail(
            subject,
            message,
            settings.DEFAULT_FROM_EMAIL,
            settings.ADMIN_EMAILS,
            fail_silently=True,
        )


def save_ticketvoucher_media(listing, files, media_type="image"):
    """
    Helper to save multiple images/videos and link them to a listing.
    """
    if media_type == "image":
        for file in files:
            image = TicketVoucherImage.objects.create(image=file)
            listing.images.add(image)
    elif media_type == "video":
        for file in files:
            video = TicketVoucherVideo.objects.create(video=file)
            listing.videos.add(video)



