@login_required
def listingcommunity(request):
    user = request.user
    credits = get_or_create_user_credits(user)
    
    regions = Region.objects.all()
    governate = Governate.objects.all()
    district = District.objects.all()
    cities = Cities.objects.all()

    # ============================================
    # STEP 1: POSTING METHOD + BOOST DURATION SELECTION
    # ============================================
    if request.method == 'POST' and 'posting_method' in request.POST:
        posting_method = request.POST.get('posting_method')
        temp_data = request.session.get('temp_community_data')
        
        if not temp_data:
            messages.error(request, "Session expired. Please try again.")
            return redirect('listingcommunity')
        
        product_type = temp_data.get('product_type')
        form_data = temp_data.get('form_data')
        temp_files = temp_data.get('temp_files', [])
        
        # Get boost duration (only matters for boosted)
        boost_duration = int(request.POST.get('boost_duration', 7))
        if boost_duration not in [7, 14, 30]:
            boost_duration = 7
        
        # ========== CREDIT CHECKS WITH SESSION STORAGE ==========
        if posting_method == 'normal':
            if not credits.can_post_listing('normal'):
                # Store ad data for later auto-posting
                request.session['pending_normal_ad'] = {
                    'product_type': product_type,
                    'form_data': form_data,
                    'temp_files': temp_files,
                }
                messages.info(request, "You don't have enough listing credits. Please purchase credits – your ad will be posted automatically.")
                return redirect(f"{reverse('credit_packages')}?next={reverse('continue_normal_posting')}")
        
        elif posting_method == 'boosted':
            # First check listing credits
            if not credits.can_post_listing('normal'):
                request.session['pending_boost_ad'] = {
                    'product_type': product_type,
                    'form_data': form_data,
                    'temp_files': temp_files,
                    'boost_duration': boost_duration,
                }
                messages.info(request, "You don't have enough listing credits. Please purchase credits – your boosted ad will be posted automatically.")
                return redirect(f"{reverse('credit_packages')}?next={reverse('continue_boost_posting')}")
            
            # Then check boost days
            if credits.boost_days_available < boost_duration:
                request.session['pending_boost_ad'] = {
                    'product_type': product_type,
                    'form_data': form_data,
                    'temp_files': temp_files,
                    'boost_duration': boost_duration,
                }
                messages.info(request, f"You need {boost_duration} boost days but have only {credits.boost_days_available}. Purchase boost credits – your ad will be posted automatically.")
                return redirect(f"{reverse('credit_packages')}?next={reverse('continue_boost_posting')}")
        
        elif posting_method == 'exclusive':
            if credits.purchased_listing_credits <= 0:
                messages.error(request, "❌ Exclusive listings require purchased credits. Please buy a package.")
                return redirect('credit_packages')
        # =========================================================
        
        category_type = get_community_category_type(product_type)
        
        # ---------- NORMAL POSTING ----------
        if posting_method == 'normal':
            obj = process_community_registration(request, product_type, form_data, temp_files, 'normal', status='pending')
            if obj:
                success, msg = credits.use_listing_credit('normal')
                if success:
                    ListingUsage.objects.create(
                        user=user,
                        listing_type=obj._meta.model_name,
                        listing_id=obj.id,
                        credit_source='free' if credits.available_free_listings + 1 > credits.free_listings_used else 'purchased',
                        expires_at=timezone.now() + timedelta(days=45)
                    )
                    messages.success(request, f"✅ {msg}")
                else:
                    messages.warning(request, f"⚠️ {msg}")
                return redirect(adss, user_id=user.id)
            else:
                messages.error(request, "Failed to create listing. Please try again.")
                return redirect('listingcommunity')
        
        # ---------- BOOSTED POSTING ----------
        elif posting_method == 'boosted':
            obj = process_community_registration(request, product_type, form_data, temp_files, 'boosted', status='pending')
            if obj:
                success, msg = credits.use_listing_credit('normal')
                if success:
                    ListingUsage.objects.create(
                        user=user,
                        listing_type=obj._meta.model_name,
                        listing_id=obj.id,
                        credit_source='free' if credits.available_free_listings + 1 > credits.free_listings_used else 'purchased',
                        expires_at=timezone.now() + timedelta(days=45)
                    )
                    # Deduct boost days immediately
                    boost_success, boost_msg = credits.use_boost_credit(boost_duration)
                    if boost_success:
                        BoostUsage.objects.create(
                            user=user,
                            listing_type=obj._meta.model_name,
                            listing_id=obj.id,
                            boost_days=boost_duration,
                            expires_at=timezone.now() + timedelta(days=boost_duration),
                            is_active=True
                        )
                        messages.success(request, f"✅ {msg} and {boost_msg}")
                    else:
                        messages.warning(request, f"✅ {msg} but {boost_msg}")
                else:
                    messages.warning(request, f"⚠️ {msg}")
                return redirect(adss, user_id=user.id)
            else:
                messages.error(request, "Failed to create boosted listing. Please try again.")
                return redirect('listingcommunity')
        
        # ---------- EXCLUSIVE POSTING ----------
        elif posting_method == 'exclusive':
            if category_type == 'premium':
                obj = process_community_registration(request, product_type, form_data, temp_files, 'exclusive', status='pending_exclusive')
                if obj:
                    success, msg = credits.use_listing_credit('exclusive')
                    if success:
                        ListingUsage.objects.create(
                            user=user,
                            listing_type=obj._meta.model_name,
                            listing_id=obj.id,
                            credit_source='purchased',
                            expires_at=timezone.now() + timedelta(days=45)
                        )
                        messages.success(request, f"✅ {msg}")
                    else:
                        messages.warning(request, f"⚠️ {msg}")
                    notify_admin_exclusive_request_community(obj, user, product_type)
                    messages.success(request, "Exclusive request sent to admin for approval.")
                    return redirect(adss, user_id=user.id)
                else:
                    messages.error(request, "Failed to create exclusive listing. Please try again.")
                    return redirect('listingcommunity')
            else:
                messages.error(request, "Exclusive listing is only available for premium service categories.")
                return redirect('listingcommunity')
        
        messages.error(request, "Something went wrong. Please try again.")
        return redirect('listingcommunity')
    
    # ============================================
    # STEP 2: FORM SUBMISSION (user fills the ad form)
    # ============================================
    if request.method == 'POST' and 'product_type' in request.POST:
        product_type = request.POST.get('product_type')
        category_type = get_community_category_type(product_type)
        temp_files = []
        if request.FILES:
            for field_name, file_list in request.FILES.lists():
                for file in file_list:
                    temp_path = default_storage.save(f'temp/community_{user.id}_{file.name}', ContentFile(file.read()))
                    temp_files.append({'field_name': field_name, 'original_name': file.name, 'temp_path': temp_path})
        request.session['temp_community_data'] = {
            'product_type': product_type,
            'form_data': request.POST.dict(),
            'temp_files': temp_files
        }
        title = request.POST.get('title', request.POST.get('service_title', ''))
        return render(request, 'select_posting_method.html', {
            'property_type_display': get_community_type_display(product_type),
            'temp_data': {'property_title': title, 'price': request.POST.get('price', '')},
            'product_type': product_type,
            'category_type': category_type,
            'credits': credits,
            'free_credits_left': credits.available_free_listings,
            'purchased_credits_left': credits.purchased_listing_credits,
            'boost_days_left': credits.boost_days_available,
        })
    
    # ============================================
    # STEP 3: GET REQUEST - Show all forms
    # ============================================
    return render(request, 'registrationcommunity.html', {
        'service_form': AutoServiceListingForm(),
        'consultancy_form': ConsultancyServiceListingForm(),
        'domestic_form': DomesticServiceListingForm(),
        'event_form': EventEntertainmentServiceForm(),
        'health_form': HealthWellbeingServiceForm(),
        'home_form': HomeMaintenanceServiceListingForm(),
        'movers_form': MoversServiceListingForm(),
        'restoration_form': RestorationServiceListingForm(),
        'tutors_form': TutorsServiceListingForm(),
        'web_form': WebComputerServiceListingForm(),
        'freelancers_form': FreelancersServiceListingForm(),
        'other_form': OtherServiceListingForm(),
        'regions': regions,
        'governate': governate,
        'district': district,
        'cities': cities,
        'credits': credits,
        'free_credits_left': credits.available_free_listings,
        'purchased_credits_left': credits.purchased_listing_credits,
        'boost_days_left': credits.boost_days_available,
    })

# ============================================================
# HELPER FUNCTIONS
# ============================================================

def get_community_category_type(product_type):
    """Determine if product type is premium (can use exclusive) or standard"""
    premium_types = [
        'auto_service', 'consultancy_service', 'web_computer_service'
    ]
    return 'premium' if product_type in premium_types else 'standard'

def process_community_registration(request, product_type, form_data, temp_files, posting_method, status='pending'):
    """Universal handler for all community service types"""
    user = request.user
    
    FORM_MAP = {
        'auto_service': (AutoServiceListingForm, AutoServiceListing, AutoServiceImage, AutoServiceVideo),
        'consultancy_service': (ConsultancyServiceListingForm, ConsultancyServiceListing, ConsultancyServiceImage, ConsultancyServiceVideo),
        'domestic_service': (DomesticServiceListingForm, DomesticServiceListing, DomesticServiceImage, DomesticServiceVideo),
        'event_service': (EventEntertainmentServiceForm, EventEntertainmentServiceListing, EventEntertainmentServiceImage, EventEntertainmentServiceVideo),
        'health_service': (HealthWellbeingServiceForm, HealthWellbeingServiceListing, HealthWellbeingServiceImage, HealthWellbeingServiceVideo),
        'home_maintenance_service': (HomeMaintenanceServiceListingForm, HomeMaintenanceServiceListing, HomeMaintenanceServiceImage, HomeMaintenanceServiceVideo),
        'movers_service': (MoversServiceListingForm, MoversServiceListing, MoversServiceImage, MoversServiceVideo),
        'restoration_service': (RestorationServiceListingForm, RestorationServiceListing, RestorationServiceImage, RestorationServiceVideo),
        'tutors_service': (TutorsServiceListingForm, TutorsServiceListing, TutorsServiceImage, TutorsServiceVideo),
        'web_computer_service': (WebComputerServiceListingForm, WebComputerServiceListing, WebComputerServiceImage, WebComputerServiceVideo),
        'freelancers_service': (FreelancersServiceListingForm, FreelancersServiceListing, FreelancersServiceImage, FreelancersServiceVideo),
        'other_service': (OtherServiceListingForm, OtherServiceListing, OtherServiceImage, OtherServiceVideo),
    }
    
    if product_type not in FORM_MAP:
        messages.error(request, "Invalid product type.")
        return None
    
    FormClass, ModelClass, ImageModel, VideoModel = FORM_MAP[product_type]
    
    # Build POST data
    post_data = QueryDict(mutable=True)
    for key, value in form_data.items():
        if key not in ['csrfmiddlewaretoken', 'product_type']:
            post_data[key] = value
    
    # Build FILES data from temp files
    files_dict = MultiValueDict()
    for file in temp_files:
        path = file.get('temp_path')
        name = file.get('original_name')
        field = file.get('field_name')
        if path and default_storage.exists(path):
            with default_storage.open(path, 'rb') as f:
                uploaded = SimpleUploadedFile(name, f.read())
                files_dict.appendlist(field, uploaded)
    
    form = FormClass(post_data, files_dict)
    if not form.is_valid():
        print(f"FORM ERRORS for {product_type}:", form.errors)
        messages.error(request, f"Form validation failed: {dict(form.errors)}")
        return None
    
    obj = form.save(commit=False)
    obj.user = user
    obj.status = status
    obj.posting_method = posting_method
    
    # Handle city field
    if hasattr(obj, 'city'):
        city_id = form_data.get('city')
        if city_id:
            try:
                obj.city = Cities.objects.get(id=city_id)
            except (Cities.DoesNotExist, ValueError):
                pass
    
    obj.save()
    form.save_m2m()
    
    # Save images (required)
    images = files_dict.getlist('images')
    if not images:
        messages.error(request, "At least one image is required.")
        return None
    
    for img in images:
        try:
            if img:
                image_obj = ImageModel.objects.create(image=img)
                if hasattr(obj, 'images'):
                    obj.images.add(image_obj)
        except Exception as e:
            print(f"Error saving image: {e}")
    
    # Save videos (optional)
    videos = files_dict.getlist('videos')
    for vid in videos:
        try:
            if vid:
                video_obj = VideoModel.objects.create(video=vid)
                if hasattr(obj, 'videos'):
                    obj.videos.add(video_obj)
        except Exception as e:
            print(f"Error saving video: {e}")
    
    # Cleanup temp files
    for file in temp_files:
        path = file.get('temp_path')
        if path and default_storage.exists(path):
            default_storage.delete(path)
    
    # Cleanup session
    if 'temp_community_data' in request.session:
        del request.session['temp_community_data']
    if 'pending_community' in request.session:
        del request.session['pending_community']
    
    display_name = get_community_type_display(product_type)
    messages.success(request, f"{display_name} registered successfully!")
    
    return obj

def get_community_type_display(product_type):
    return {
        'auto_service': 'Auto Service',
        'consultancy_service': 'Consultancy Service',
        'domestic_service': 'Domestic Service',
        'event_service': 'Event & Entertainment Service',
        'health_service': 'Health & Wellbeing Service',
        'home_maintenance_service': 'Home Maintenance Service',
        'movers_service': 'Movers & Removals Service',
        'restoration_service': 'Restoration & Repairs Service',
        'tutors_service': 'Tutors & Classes Service',
        'web_computer_service': 'Web & Computer Service',
        'freelancers_service': 'Freelancers Service',
        'other_service': 'Other Service',
    }.get(product_type, product_type.title())

