@login_required
def register_company(request, user_id):
    user = get_object_or_404(CustomUser, id=user_id)

    # Dropdown datasets
    regions = Region.objects.all()
    governate = Governate.objects.all()
    district = District.objects.all()
    cities = Cities.objects.all()

    # Check if the user already has a company
    existing_company = Company.objects.filter(user=user).first()
    if existing_company:
        messages.warning(request, "You can only register a single company.")
        return redirect(' shboard', user_id=user.id, company_id=existing_company.id)

    if request.method == 'POST':
        form = CompanyRegistrationForm(request.POST, request.FILES, user=user)
        if form.is_valid():
            company = form.save(commit=False)
            company.user = user
            company.status = 'pending'  # New companies default to Pending
            company.save()
            messages.success(request, "Your company has been registered and is pending approval.")
            return redirect('company_dashboard', user_id=user.id, company_id=company.id)
        else:
            print(form.errors)  # Debug
            messages.error(request, "Please correct the errors below.")
    else:
        form = CompanyRegistrationForm(user=user)

    return render(request, 'Job/company_registration.html', {
        'form': form,
        'has_company': existing_company is not None,
        'regions': regions,
        'governate': governate,
        'district': district,
        'cities': cities,
    })

    
from django.shortcuts import render, redirect, get_object_or_404
from django.contrib import messages
from django.contrib.auth.decorators import login_required
from django.db import transaction
from .models import JobPost, Company, JobApplication, JobCategory
from .forms import JobPostForm

@login_required
def company_dashboard(request, user_id, company_id):
    if request.user.id != int(user_id):
        raise PermissionDenied("You don't have permission to view this dashboard")
    
    user = get_object_or_404(CustomUser, id=user_id)
    company = get_object_or_404(Company, user=user, id=company_id)

    job_posts = JobPost.objects.none()
    applications = JobApplication.objects.none()
    job_categories = JobCategory.objects.all()
    form = JobPostForm()

    if company.status == 'approved':
        job_posts = JobPost.objects.filter(company=company)\
                        .select_related('job_category')\
                        .order_by('-posted_on')
        applications = JobApplication.objects.filter(job__company=company)\
                          .select_related('user', 'job')

        if request.method == 'POST':
            print("=== FORM SUBMISSION DETECTED ===")  # Debug
            form = JobPostForm(request.POST)
            print(f"Form valid: {form.is_valid()}")  # Debug
            print(f"Form errors: {form.errors}")  # Debug
            
            if form.is_valid():
                try:
                    with transaction.atomic():
                        job_post = form.save(commit=False)
                        job_post.company = company
                        job_post.user = request.user
                        # Make sure this field exists in your model, otherwise remove it
                        # job_post.status = 'pending'  
                        job_post.save()
                        print(f"Job post saved successfully: {job_post.title}")  # Debug
                        messages.success(request, "Job post created successfully!")
                        return redirect('company_dashboard', user_id=user_id, company_id=company_id)
                except Exception as e:
                    print(f"Error saving job post: {str(e)}")  # Debug
                    messages.error(request, f"Error creating job post: {str(e)}")
            else:
                print("Form validation failed!")  # Debug
                for field, errors in form.errors.items():
                    for error in errors:
                        messages.error(request, f"{field}: {error}")
        else:
            form = JobPostForm(initial={
                'contact_email': company.email,
            })

    context = {
        'company': company,
        'job_posts': job_posts,
        'applications': applications,
        'form': form,
        'job_categories': job_categories,
    }
    
    return render(request, 'Job/company_dashboard.html', context)

# View to approve a job application
@login_required
def approve_application(request, application_id):
    application = get_object_or_404(JobApplication, id=application_id)

    if application.status == 'pending':
        application.status = 'approved'
        application.save()
        messages.success(request, f"Application from {application.name} has been approved.")
    else:
        messages.warning(request, "Application has already been processed.")

    return redirect('company_dashboard', user_id=request.user.id, company_id=application.company.id)

# View to reject a job application
@login_required
def reject_application(request, application_id):
    application = get_object_or_404(JobApplication, id=application_id)

    if application.status == 'pending':
        application.status = 'rejected'
        application.save()
        messages.success(request, f"Application from {application.name} has been rejected.")
    else:
        messages.warning(request, "Application has already been processed.")

    return redirect('company_dashboard', user_id=request.user.id, company_id=application.company.id)



def mark_sold_out(request, product_type, product_id):
    if request.method == 'POST':  # Only allow POST requests for status change
        model_map = {
            'land': Land,
            'villa': Villa,
            'automobile': Automobile,
            'commercial': Commercial,
            'motorcycle':Motorcycle,
            'scooter':Scooter,
            'helmetclothes':HelmetClothes,
            'quadbikes':Quadbikes,
            'heavyvehicle':HeavyVehicle,
            'boat':Boat,
            'autoaccessorypart':AutoAccessoryPart,
            'numberplate':NumberPlate,
            'farm': Farm,
           'apartment': Apartment,
            'factory': Factory,
            'complexes': Complex,
            'clinic': Clinic,
            'hostel': Hostel,
            'office': Office,
            'shop': Shop,

            'cafe': Cafe,
            'warehouse': Warehouse,
            'staff': Staff,
            'townhouse': Townhouse,
            'fullfloors': Fullfloors,
            'showrooms': Showrooms,
            'wholebuilding': Wholebuilding,
            'supermarket': Supermarket,
            'foreign': Foreign,
            'fitness': Fitness,
            'pet': Pet,
            'book': Book,
            'appliance': Appliance,
            'fashion': Fashion,
            'toys': Toys,
            'food': Food,
            'business': Business,
            'education': Education,
            'service': Service,
            'mobile': Mobile,
            'tablet': Tablet,
            'smartwatch': SmartWatch,
            'headset': Headset,
            'cover': Cover,
            'accessory': Accessory,
            'mobilesim': MobileSIM,
            'computer': Computer,
            'sound': Sound,
        }

        model = model_map.get(product_type)
        if not model:
            return render(request, '404.html', status=404)

        product = get_object_or_404(model, id=product_id)

        # Check if the model has a status field
        if hasattr(product, 'status'):
            product.status = 'soldout'
            product.save()
            messages.success(request, f'{product_type.capitalize()} with ID {product_id} has been marked as Sold Out.')
            return redirect(adss, user_id=request.user.id)  # Redirect to the list view
        else:
            messages.error(request, f'{product_type.capitalize()} does not support marking as Sold Out.')
            return redirect(adss, user_id=request.user.id)

    return render(request, '404.html', status=404)

