def get_product_info(product_type, product_id, receiver=None):
    """
    Get product info (title and image) for any product type
    """
    if not product_type or not product_id or product_type == 'general' or product_id == 'None':
        return None
    
    if product_type not in PRODUCT_MODELS:
        return None
    
    model_info = PRODUCT_MODELS[product_type]
    
    try:
        from django.apps import apps
        Model = apps.get_model('oman_app', model_info['model'])
        
        # Get product - don't filter by user to allow viewing any product
        try:
            product = Model.objects.get(id=product_id)
        except Model.DoesNotExist:
            print(f"Product not found: {product_type} {product_id}")
            return None
        
        # Get title
        title = getattr(product, model_info['title_field'], 'No title')
        
        # Try multiple ways to get image
        image_url = ''
        
        # Method 1: Direct image field on product
        for field_name in ['image', 'image1', 'main_image', 'photo', 'picture']:
            if hasattr(product, field_name):
                field = getattr(product, field_name)
                if field and hasattr(field, 'url'):
                    image_url = field.url
                    break
        
        # Method 2: Image relation
        if not image_url and model_info['image_relation']:
            try:
                images = getattr(product, model_info['image_relation']).all()
                if images.exists():
                    first_image = images.first()
                    for field_name in ['image', 'image1', 'main_image', 'photo', 'picture', 'file']:
                        if hasattr(first_image, field_name):
                            field = getattr(first_image, field_name)
                            if field and hasattr(field, 'url'):
                                image_url = field.url
                                break
            except Exception as e:
                print(f"Error getting images: {e}")
        
        # Get price
        price = ''
        for price_field in ['price', 'property_price', 'cost', 'amount', 'value']:
            if hasattr(product, price_field):
                price_value = getattr(product, price_field)
                if price_value:
                    price = price_value
                    break
        
        # Get year
        year = getattr(product, 'year', '')
        
        # Get make/brand/model
        make = getattr(product, 'make', '') or getattr(product, 'brand', '') or getattr(product, 'model', '')
        
        # ✅ GET STATUS - Try different possible status field names
        status = 'active'  # default
        for status_field in ['status', 'listing_status', 'product_status']:
            if hasattr(product, status_field):
                status_value = getattr(product, status_field)
                if status_value:
                    status = status_value
                    break
        
        # ✅ If product has an 'is_sold' boolean field
        if hasattr(product, 'is_sold') and product.is_sold:
            status = 'soldout'
        
        # Generate detail URL
        from django.urls import reverse
        detail_url = ''
        try:
            detail_url = reverse(f'{product_type}_details', args=[product_id])
        except:
            pass
        
        return {
            'title': str(title),
            'image_url': image_url,
            'price': str(price) if price else '',
            'year': str(year) if year else '',
            'make': str(make) if make else '',
            'type': product_type,
            'id': product_id,
            'detail_url': detail_url,
            'status': status,  # ✅ ADD THIS
        }
        
    except Exception as e:
        print(f"Error in get_product_info for {product_type} {product_id}: {e}")
        import traceback
        traceback.print_exc()
        return None

@login_required
def user_chat_view(request, receiver_id=None):
    """Main chat view that handles ALL chats - both product-specific and general"""
    # Get product info from query parameters
    product_id = request.GET.get('product_id')
    product_type = request.GET.get('product_type')
    
    # Check if we're in product-specific mode
    product_specific_mode = product_id is not None and product_type is not None and product_id != '' and product_type != '' and product_type != 'general'
    
    users = User.objects.exclude(id=request.user.id).exclude(is_superuser=True)
    receiver = None
    messages = []
    current_product_info = None
    
    if receiver_id:
        receiver = get_object_or_404(User, id=receiver_id, is_superuser=False)
        
        # Handle both product chats and general chats
        if product_specific_mode:
            # Generate chat session ID for product chat
            user_ids = sorted([str(request.user.id), str(receiver.id)])
            chat_session_id = f"{user_ids[0]}_{user_ids[1]}_{product_type}_{product_id}"
            
            # Get messages for THIS SPECIFIC PRODUCT CHAT
            all_messages = ChatMessage.objects.filter(
                chat_session_id=chat_session_id
            ).order_by('timestamp')
            
            # Filter out messages deleted for the current user
            messages = []
            for msg in all_messages:
                if not msg.is_deleted_for_user(request.user):
                    messages.append(msg)
            
            # Get current product info (now includes detail_url and status)
            current_product_info = get_product_info(product_type, product_id, None)
            
            # Check if there's already a chat for this exact product
            has_existing_chat = ChatMessage.objects.filter(
                chat_session_id=chat_session_id
            ).exists()
            
            # Only create auto message if it's truly a new chat for this product
            if current_product_info and not has_existing_chat:
                auto_message = f"I'm interested in: {current_product_info['title']}"
                ChatMessage.objects.create(
                    sender=request.user,
                    receiver=receiver,
                    message=auto_message,
                    is_admin_chat=False,
                    product_id=product_id,
                    product_type=product_type
                )
        else:
            # Get messages for GENERAL CHAT (no product)
            all_messages = ChatMessage.objects.filter(
                Q(sender=request.user, receiver=receiver) | 
                Q(sender=receiver, receiver=request.user),
                is_admin_chat=False,
                product_id__isnull=True,
                product_type__isnull=True
            ).order_by('timestamp')
            
            # Filter out messages deleted for the current user
            messages = []
            for msg in all_messages:
                if not msg.is_deleted_for_user(request.user):
                    messages.append(msg)
            
            current_product_info = None

        # Mark received messages as read for this chat (excluding deleted ones)
        if product_specific_mode:
            # Get IDs of messages deleted for the current user
            deleted_message_ids = DeletedMessage.objects.filter(
                deleted_by=request.user
            ).values_list('message_id', flat=True)
            
            ChatMessage.objects.filter(
                chat_session_id=chat_session_id,
                sender=receiver,
                receiver=request.user,
                is_read=False,
                is_admin_chat=False
            ).exclude(
                id__in=deleted_message_ids
            ).exclude(
                is_deleted_for_everyone=True
            ).update(is_read=True)
        else:
            # Get IDs of messages deleted for the current user
            deleted_message_ids = DeletedMessage.objects.filter(
                deleted_by=request.user
            ).values_list('message_id', flat=True)
            
            ChatMessage.objects.filter(
                sender=receiver,
                receiver=request.user,
                is_admin_chat=False,
                product_id__isnull=True,
                product_type__isnull=True,
                is_read=False
            ).exclude(
                id__in=deleted_message_ids
            ).exclude(
                is_deleted_for_everyone=True
            ).update(is_read=True)

    # Handle message send (AJAX)
    if request.method == "POST" and receiver:
        message_text = request.POST.get("message", "").strip()
        product_id = request.POST.get("product_id")
        product_type = request.POST.get("product_type")
        
        if message_text:
            # Handle empty product_id or product_type for general chats
            if not product_id or not product_type or product_id == 'None' or product_type == 'general' or product_id == '':
                product_id = None
                product_type = None
            
            msg = ChatMessage.objects.create(
                sender=request.user,
                receiver=receiver,
                message=message_text,
                is_admin_chat=False,
                product_id=product_id,
                product_type=product_type
            )
            
            return JsonResponse({
                "message": msg.message,
                "timestamp": msg.timestamp.strftime("%Y-%m-%d %H:%M"),
                "sender_id": msg.sender.id,
                "message_id": msg.id
            })
        
        return JsonResponse({"error": "Message cannot be empty"}, status=400)

    # Get IDs of messages deleted by the current user
    deleted_message_ids = DeletedMessage.objects.filter(
        deleted_by=request.user
    ).values_list('message_id', flat=True)

    # FOR PRODUCT OWNER: When viewing product-specific chats, ONLY show users who have messaged about THIS product
    if product_specific_mode:
        # Get ONLY users who have chatted about THIS SPECIFIC product
        product_chat_users = ChatMessage.objects.filter(
            Q(sender=request.user) | Q(receiver=request.user),
            is_admin_chat=False,
            product_id=product_id,
            product_type=product_type
        ).exclude(
            # Exclude messages deleted for the current user
            id__in=deleted_message_ids
        ).exclude(
            is_deleted_for_everyone=True
        ).values_list('sender', 'receiver').distinct()
        
        user_ids_for_this_product = set()
        for sender_id, receiver_id_val in product_chat_users:
            if sender_id != request.user.id:
                user_ids_for_this_product.add(sender_id)
            if receiver_id_val != request.user.id:
                user_ids_for_this_product.add(receiver_id_val)
        
        # IMPORTANT: ONLY show users who have chatted about THIS SPECIFIC product
        users_with_chats = users.filter(id__in=user_ids_for_this_product)
        
        # Also, when in product-specific mode, we should ONLY show chats for THIS product
        user_chats = {}
        for user in users_with_chats:
            user_chats[user.id] = []
            
            # Check if there are any visible messages for this chat
            user_ids = sorted([str(request.user.id), str(user.id)])
            chat_session_id = f"{user_ids[0]}_{user_ids[1]}_{product_type}_{product_id}"
            
            # Get all messages for this chat
            all_messages = ChatMessage.objects.filter(chat_session_id=chat_session_id)
            
            # Check if there's at least one message not deleted for the current user
            has_visible_messages = False
            for msg in all_messages:
                if not msg.is_deleted_for_user(request.user):
                    has_visible_messages = True
                    break
            
            # Only include chat if there are visible messages
            if has_visible_messages:
                product_info = get_product_info(product_type, product_id, None)
                
                if product_info:
                    # Count unread messages for this specific product chat (excluding deleted)
                    unread_count = ChatMessage.objects.filter(
                        chat_session_id=chat_session_id,
                        sender=user,
                        receiver=request.user,
                        is_read=False,
                        is_admin_chat=False
                    ).exclude(
                        id__in=deleted_message_ids
                    ).exclude(
                        is_deleted_for_everyone=True
                    ).count()
                    
                    # Get last message for preview (excluding deleted)
                    last_message = ChatMessage.objects.filter(
                        chat_session_id=chat_session_id
                    ).exclude(
                        id__in=deleted_message_ids
                    ).exclude(
                        is_deleted_for_everyone=True
                    ).order_by('-timestamp').first()
                    
                    # ✅ ADDED STATUS FIELD HERE
                    user_chats[user.id].append({
                        'product_id': product_id,
                        'product_type': product_type,
                        'title': product_info['title'],
                        'image_url': product_info['image_url'],
                        'price': product_info.get('price', ''),
                        'year': product_info.get('year', ''),
                        'make': product_info.get('make', ''),
                        'detail_url': product_info.get('detail_url', ''),
                        'status': product_info.get('status', 'active'),  # ✅ ADD THIS LINE
                        'unread_count': unread_count,
                        'last_message': last_message.message if last_message else '',
                        'last_message_time': last_message.timestamp.isoformat() if last_message else timezone.now().isoformat(),
                        'is_general': False,
                        'is_owner': True,
                        'is_current_product': True
                    })
        
        # Remove users with no visible chats
        user_chats = {k: v for k, v in user_chats.items() if v}
    
    else:
        # FOR NON-PRODUCT-SPECIFIC MODE: Show ALL chats with deleted filtering
        # Get all users that have any chats with current user (excluding deleted)
        all_chat_users = ChatMessage.objects.filter(
            Q(sender=request.user) | Q(receiver=request.user),
            is_admin_chat=False
        ).exclude(
            id__in=deleted_message_ids
        ).exclude(
            is_deleted_for_everyone=True
        ).values_list('sender', 'receiver').distinct()
        
        user_ids_with_chats = set()
        for sender_id, receiver_id_val in all_chat_users:
            if sender_id != request.user.id:
                user_ids_with_chats.add(sender_id)
            if receiver_id_val != request.user.id:
                user_ids_with_chats.add(receiver_id_val)
        
        # Filter users to only those with chats
        users_with_chats = users.filter(id__in=user_ids_with_chats)
        
        # Build chat list for ALL conversations
        user_chats = {}
        for user in users_with_chats:
            user_chats[user.id] = []
            
            # Check for GENERAL CHAT with this user
            general_messages = ChatMessage.objects.filter(
                Q(sender=request.user, receiver=user) | 
                Q(sender=user, receiver=request.user),
                is_admin_chat=False,
                product_id__isnull=True,
                product_type__isnull=True
            )
            
            # Check if there are any visible general messages
            has_visible_general = False
            for msg in general_messages:
                if not msg.is_deleted_for_user(request.user):
                    has_visible_general = True
                    break
            
            if has_visible_general:
                # Get unread count for general chat (excluding deleted)
                unread_count = ChatMessage.objects.filter(
                    sender=user,
                    receiver=request.user,
                    is_read=False,
                    is_admin_chat=False,
                    product_id__isnull=True,
                    product_type__isnull=True
                ).exclude(
                    id__in=deleted_message_ids
                ).exclude(
                    is_deleted_for_everyone=True
                ).count()
                
                # Get last message for preview (excluding deleted)
                last_message = ChatMessage.objects.filter(
                    Q(sender=request.user, receiver=user) | 
                    Q(sender=user, receiver=request.user),
                    is_admin_chat=False,
                    product_id__isnull=True,
                    product_type__isnull=True
                ).exclude(
                    id__in=deleted_message_ids
                ).exclude(
                    is_deleted_for_everyone=True
                ).order_by('-timestamp').first()
                
                user_chats[user.id].append({
                    'product_id': None,
                    'product_type': 'general',
                    'title': 'General Chat',
                    'image_url': '',
                    'price': '',
                    'year': '',
                    'make': '',
                    'detail_url': '',
                    'status': 'active',  # ✅ ADD THIS (general chats don't have status)
                    'unread_count': unread_count,
                    'last_message': last_message.message if last_message else '',
                    'last_message_time': last_message.timestamp.isoformat() if last_message else timezone.now().isoformat(),
                    'is_general': True,
                    'is_product_owner': False
                })
            
            # Get all PRODUCT CHATS with this user - FIX: Use distinct on product_id and product_type
            product_chats_qs = ChatMessage.objects.filter(
                Q(sender=request.user, receiver=user) | 
                Q(sender=user, receiver=request.user),
                is_admin_chat=False,
                product_id__isnull=False,
                product_type__isnull=False
            ).values('product_id', 'product_type').distinct()
            
            for chat in product_chats_qs:
                # Check if there are any visible messages for this product chat
                user_ids = sorted([str(request.user.id), str(user.id)])
                chat_session_id = f"{user_ids[0]}_{user_ids[1]}_{chat['product_type']}_{chat['product_id']}"
                
                product_messages = ChatMessage.objects.filter(chat_session_id=chat_session_id)
                
                # Check if there's at least one visible message
                has_visible_product = False
                for msg in product_messages:
                    if not msg.is_deleted_for_user(request.user):
                        has_visible_product = True
                        break
                
                if has_visible_product:
                    product_info = get_product_info(chat['product_type'], chat['product_id'], None)
                    
                    if product_info:
                        # Count unread messages for this specific product chat (excluding deleted)
                        unread_count = ChatMessage.objects.filter(
                            chat_session_id=chat_session_id,
                            sender=user,
                            receiver=request.user,
                            is_read=False,
                            is_admin_chat=False
                        ).exclude(
                            id__in=deleted_message_ids
                        ).exclude(
                            is_deleted_for_everyone=True
                        ).count()
                        
                        # Get last message for preview (excluding deleted)
                        last_message = ChatMessage.objects.filter(
                            chat_session_id=chat_session_id
                        ).exclude(
                            id__in=deleted_message_ids
                        ).exclude(
                            is_deleted_for_everyone=True
                        ).order_by('-timestamp').first()
                        
                        # Check if this product belongs to the current user (owner)
                        is_owner = False
                        try:
                            from django.apps import apps
                            Model = apps.get_model('oman_app', PRODUCT_MODELS[chat['product_type']]['model'])
                            product = Model.objects.filter(id=chat['product_id'], user=request.user).first()
                            is_owner = product is not None
                        except:
                            pass
                        
                        # ✅ ADDED STATUS FIELD HERE
                        user_chats[user.id].append({
                            'product_id': chat['product_id'],
                            'product_type': chat['product_type'],
                            'title': product_info['title'],
                            'image_url': product_info['image_url'],
                            'price': product_info.get('price', ''),
                            'year': product_info.get('year', ''),
                            'make': product_info.get('make', ''),
                            'detail_url': product_info.get('detail_url', ''),
                            'status': product_info.get('status', 'active'),  # ✅ ADD THIS LINE
                            'unread_count': unread_count,
                            'last_message': last_message.message if last_message else '',
                            'last_message_time': last_message.timestamp.isoformat() if last_message else timezone.now().isoformat(),
                            'is_general': False,
                            'is_owner': is_owner,
                            'is_current_product': False
                        })
        
        # Remove users with no visible chats
        user_chats = {k: v for k, v in user_chats.items() if v}

    # Sort chats for each user
    for user_id in user_chats:
        user_chats[user_id].sort(
            key=lambda x: x.get('last_message_time', timezone.now()),
            reverse=True
        )

    # FIX: Unread counts for user list (total per user, excluding deleted)
    # This ensures unread counts are accurate and don't include deleted messages
    unread_counts = {}
    for user_id, chats in user_chats.items():
        total_unread = sum(chat['unread_count'] for chat in chats)
        if total_unread > 0:
            unread_counts[user_id] = total_unread

    return render(request, "chat.html", {
        "users": users_with_chats,
        "user_chats": user_chats,
        "receiver": receiver,
        "messages": messages,
        "unread_counts": unread_counts,
        "product_info": current_product_info,
        "product_type": product_type,
        "product_id": product_id,
        "product_specific_mode": product_specific_mode,
    })

@login_required
@require_POST
def mark_messages_read(request, user_id):
    """Mark all messages from a user as read"""
    try:
        product_id = request.POST.get('product_id')
        product_type = request.POST.get('product_type')
        
        # Get IDs of messages deleted by the current user
        deleted_message_ids = DeletedMessage.objects.filter(
            deleted_by=request.user
        ).values_list('message_id', flat=True)
        
        # Handle both product chats and general chats
        if product_id and product_type and product_id != 'None' and product_type != 'general' and product_id != '':
            # Generate chat_session_id for product chat
            user_ids = sorted([str(request.user.id), str(user_id)])
            chat_session_id = f"{user_ids[0]}_{user_ids[1]}_{product_type}_{product_id}"
            
            # Mark messages as read for this specific product chat
            updated = ChatMessage.objects.filter(
                chat_session_id=chat_session_id,
                sender_id=user_id,
                receiver=request.user,
                is_read=False,
                is_admin_chat=False
            ).exclude(
                id__in=deleted_message_ids
            ).exclude(
                is_deleted_for_everyone=True
            ).update(is_read=True)
        else:
            # Mark messages as read for general chat
            updated = ChatMessage.objects.filter(
                sender_id=user_id,
                receiver=request.user,
                is_read=False,
                is_admin_chat=False,
                product_id__isnull=True,
                product_type__isnull=True
            ).exclude(
                id__in=deleted_message_ids
            ).exclude(
                is_deleted_for_everyone=True
            ).update(is_read=True)
        
        return JsonResponse({
            'success': True,
            'marked_read': updated
        })
        
    except Exception as e:
        return JsonResponse({
            'success': False,
            'error': str(e)
        }, status=500)

@login_required
def check_new_messages(request, receiver_id):
    """Check for new messages from a specific user (updated to handle blocked users and deleted messages)"""
    product_id = request.GET.get('product_id')
    product_type = request.GET.get('product_type')
    
    # Check if user is blocked
    is_blocked = BlockedUser.objects.filter(
        user=request.user,
        blocked_user_id=receiver_id
    ).exists()
    
    is_blocked_by_other = BlockedUser.objects.filter(
        user_id=receiver_id,
        blocked_user=request.user
    ).exists()
    
    # Get IDs of messages deleted by the current user
    deleted_message_ids = DeletedMessage.objects.filter(
        deleted_by=request.user
    ).values_list('message_id', flat=True)
    
    # Handle both product chats and general chats
    if product_id and product_type and product_id != 'None' and product_type != 'general' and product_id != '':
        # Generate chat_session_id for product chat
        user_ids = sorted([str(request.user.id), str(receiver_id)])
        chat_session_id = f"{user_ids[0]}_{user_ids[1]}_{product_type}_{product_id}"
        
        # Check for specific product chat (excluding deleted messages)
        new_messages = ChatMessage.objects.filter(
            chat_session_id=chat_session_id,
            sender_id=receiver_id,
            receiver=request.user,
            is_read=False,
            is_admin_chat=False,
            is_deleted_for_everyone=False
        ).exclude(
            id__in=deleted_message_ids
        )
        
        # Get the last message for preview
        last_message = ChatMessage.objects.filter(
            chat_session_id=chat_session_id,
            is_deleted_for_everyone=False
        ).exclude(
            id__in=deleted_message_ids
        ).order_by('-timestamp').first()
        
    else:
        # Check for general chat (no product)
        new_messages = ChatMessage.objects.filter(
            sender_id=receiver_id,
            receiver=request.user,
            is_read=False,
            is_admin_chat=False,
            product_id__isnull=True,
            product_type__isnull=True,
            is_deleted_for_everyone=False
        ).exclude(
            id__in=deleted_message_ids
        )
        
        # Get the last message for preview
        last_message = ChatMessage.objects.filter(
            (Q(sender=request.user, receiver_id=receiver_id) | 
             Q(sender_id=receiver_id, receiver=request.user)),
            is_admin_chat=False,
            product_id__isnull=True,
            product_type__isnull=True,
            is_deleted_for_everyone=False
        ).exclude(
            id__in=deleted_message_ids
        ).order_by('-timestamp').first()
    
    # Mark messages as read when checking
    if new_messages.exists():
        message_ids = list(new_messages.values_list('id', flat=True))
        new_messages.update(is_read=True)
        
        return JsonResponse({
            'has_new': True,
            'count': new_messages.count(),
            'sender_id': receiver_id,
            'message_ids': message_ids,
            'is_blocked': is_blocked,
            'is_blocked_by_other': is_blocked_by_other,
            'last_message': last_message.message if last_message else '',
            'last_message_time': last_message.timestamp.strftime("%H:%M") if last_message else ''
        })
    
    return JsonResponse({
        'has_new': False,
        'count': 0,
        'sender_id': receiver_id,
        'is_blocked': is_blocked,
        'is_blocked_by_other': is_blocked_by_other,
        'last_message': last_message.message if last_message else '',
        'last_message_time': last_message.timestamp.strftime("%H:%M") if last_message else ''
    })

@login_required
def check_chat_exists(request, receiver_id):
    """Check if a chat already exists for this product"""
    product_id = request.GET.get('product_id')
    product_type = request.GET.get('product_type')
    
    if not product_id or not product_type:
        return JsonResponse({'error': 'Product info missing'}, status=400)
    
    # Generate chat session ID
    user_ids = sorted([str(request.user.id), str(receiver_id)])
    chat_session_id = f"{user_ids[0]}_{user_ids[1]}_{product_type}_{product_id}"
    
    # Check if chat exists (excluding deleted messages)
    deleted_message_ids = DeletedMessage.objects.filter(
        deleted_by=request.user
    ).values_list('message_id', flat=True)
    
    exists = ChatMessage.objects.filter(
        chat_session_id=chat_session_id
    ).exclude(
        id__in=deleted_message_ids
    ).exclude(
        is_deleted_for_everyone=True
    ).exists()
    
    return JsonResponse({
        'exists': exists,
        'chat_session_id': chat_session_id
    })

@login_required
def get_chat_messages(request, receiver_id):
    """Get chat messages for popup (handles BOTH product and general chats)"""
    product_id = request.GET.get('product_id')
    product_type = request.GET.get('product_type')

    # PRODUCT CHAT
    if product_id and product_type and product_id not in ('', 'None') and product_type not in ('', 'general'):
        user_ids = sorted([str(request.user.id), str(receiver_id)])
        chat_session_id = f"{user_ids[0]}_{user_ids[1]}_{product_type}_{product_id}"
        all_messages = ChatMessage.objects.filter(
            chat_session_id=chat_session_id
        ).order_by('timestamp')
    # GENERAL CHAT
    else:
        all_messages = ChatMessage.objects.filter(
            Q(sender=request.user, receiver_id=receiver_id) |
            Q(sender_id=receiver_id, receiver=request.user),
            is_admin_chat=False,
            product_id__isnull=True,
            product_type__isnull=True
        ).order_by('timestamp')

    messages_data = []
    for msg in all_messages:
        if msg.is_deleted_for_user(request.user) and not msg.is_deleted_for_everyone:
            continue
        if msg.is_deleted_for_everyone:
            messages_data.append({
                'id': msg.id,
                'text': '[This message has been deleted]',
                'time': msg.timestamp.strftime("%H:%M"),
                'is_sent': msg.sender.id == request.user.id,
                'date': msg.timestamp.strftime("%Y-%m-%d"),
                'is_deleted': True,
                'sender_id': msg.sender.id,
                'receiver_id': msg.receiver.id,
                'can_delete_for_everyone': False
            })
        else:
            messages_data.append({
                'id': msg.id,
                'text': msg.message,
                'time': msg.timestamp.strftime("%H:%M"),
                'is_sent': msg.sender.id == request.user.id,
                'date': msg.timestamp.strftime("%Y-%m-%d"),
                'is_deleted': False,
                'sender_id': msg.sender.id,
                'receiver_id': msg.receiver.id,
                'can_delete_for_everyone': msg.sender.id == request.user.id
            })

    return JsonResponse({'messages': messages_data, 'count': len(messages_data)})

@login_required
@require_POST
def delete_message(request, message_id):
    """Delete a message (for self or everyone)"""
    try:
        message = ChatMessage.objects.get(id=message_id)
        
        # Check if user is authorized to delete this message
        if message.sender != request.user and message.receiver != request.user:
            return JsonResponse({'success': False, 'error': 'Not authorized'}, status=403)
        
        data = json.loads(request.body)
        delete_for_everyone = data.get('delete_for_everyone', False)
        
        if delete_for_everyone:
            # Only sender can delete for everyone
            if message.sender != request.user:
                return JsonResponse({'success': False, 'error': 'Only sender can delete for everyone'}, status=403)
            
            message.delete_for_everyone()
            return JsonResponse({
                'success': True, 
                'deleted_for_everyone': True,
                'message': 'Message deleted for everyone'
            })
        else:
            # Delete for self
            message.delete_for_user(request.user)
            return JsonResponse({
                'success': True, 
                'deleted_for_everyone': False,
                'message': 'Message deleted'
            })
            
    except ChatMessage.DoesNotExist:
        return JsonResponse({'success': False, 'error': 'Message not found'}, status=404)
    except Exception as e:
        return JsonResponse({'success': False, 'error': str(e)}, status=500)

@login_required
@require_POST
def block_user(request, user_id):
    """Block a user"""
    try:
        from django.contrib.auth import get_user_model
        User = get_user_model()
        
        user_to_block = User.objects.get(id=user_id)
        
        # Can't block yourself
        if user_to_block == request.user:
            return JsonResponse({'success': False, 'error': 'Cannot block yourself'}, status=400)
        
        # Check if already blocked
        if BlockedUser.objects.filter(user=request.user, blocked_user=user_to_block).exists():
            return JsonResponse({'success': False, 'error': 'User already blocked'}, status=400)
        
        # Create block
        BlockedUser.objects.create(
            user=request.user,
            blocked_user=user_to_block
        )
        
        return JsonResponse({
            'success': True,
            'message': f'User {user_to_block.username} has been blocked'
        })
        
    except User.DoesNotExist:
        return JsonResponse({'success': False, 'error': 'User not found'}, status=404)
    except Exception as e:
        return JsonResponse({'success': False, 'error': str(e)}, status=500)

