@login_required
@require_POST
def delete_chat(request, user_id):
    """Delete entire chat with a user"""
    try:
        from django.contrib.auth import get_user_model
        User = get_user_model()
        
        product_id = request.POST.get('product_id')
        product_type = request.POST.get('product_type')
        
        # Validate that the other user exists
        other_user = User.objects.get(id=user_id)
        
        # IMPORTANT: We need to identify WHICH chat to delete
        # If product_id and product_type are provided and not empty/general, delete specific product chat
        if product_id and product_type and product_id != 'None' and product_type != 'general' and product_id != '':
            # Delete specific product chat using chat_session_id
            user_ids = sorted([str(request.user.id), str(user_id)])
            chat_session_id = f"{user_ids[0]}_{user_ids[1]}_{product_type}_{product_id}"
            
            # Get messages for this specific product chat
            messages = ChatMessage.objects.filter(chat_session_id=chat_session_id)
            
            chat_type = f"product chat ({product_type})"
            chat_identifier = f"product_{product_type}_{product_id}"
            
        elif product_type == 'general':
            # Delete general chat
            messages = ChatMessage.objects.filter(
                (Q(sender=request.user, receiver_id=user_id) | 
                 Q(sender_id=user_id, receiver=request.user)),
                product_id__isnull=True,
                product_type__isnull=True
            )
            
            chat_type = "general chat"
            chat_identifier = "general"
            
        else:
            # If no specific product info, return error - we need to know which chat to delete
            return JsonResponse({
                'success': False, 
                'error': 'Please specify which chat to delete (product or general)'
            }, status=400)
        
        # Count messages before deletion
        message_count = messages.count()
        
        if message_count == 0:
            return JsonResponse({
                'success': False, 
                'error': f'No messages found in this {chat_type}'
            }, status=404)
        
        # Soft delete each message for the current user
        deleted_count = 0
        for message in messages:
            if not message.is_deleted_for_user(request.user):  # Only delete if not already deleted
                message.delete_for_user(request.user)
                deleted_count += 1
        
        return JsonResponse({
            'success': True,
            'message': f'{chat_type.capitalize()} with {other_user.username} deleted successfully ({deleted_count} messages)',
            'deleted_count': deleted_count,
            'chat_identifier': chat_identifier,
            'user_id': user_id,
            'product_id': product_id,
            'product_type': product_type
        })
        
    except User.DoesNotExist:
        return JsonResponse({'success': False, 'error': 'User not found'}, status=404)
    except Exception as e:
        import traceback
        traceback.print_exc()
        return JsonResponse({'success': False, 'error': str(e)}, status=500)
    

@login_required
def product_inquiries_view(request, product_id, product_type):
    """View all inquiries for a specific product in a single unified interface"""
    
    # Verify the product exists and belongs to the current user
    if product_type not in PRODUCT_MODELS:
        return redirect('user_chat')
    
    model_info = PRODUCT_MODELS[product_type]
    
    try:
        from django.apps import apps
        Model = apps.get_model('oman_app', model_info['model'])
        
        # Get the product and verify ownership
        product = Model.objects.get(id=product_id, user=request.user)
    except Model.DoesNotExist:
        # Product doesn't exist or doesn't belong to user
        return redirect('user_chat')
    
    # Get product info for display
    product_info = get_product_info(product_type, product_id, None)
    
    # Get IDs of messages deleted by the current user
    deleted_message_ids = DeletedMessage.objects.filter(
        deleted_by=request.user
    ).values_list('message_id', flat=True)
    
    # Get ALL messages about this product (excluding deleted ones)
    all_messages = ChatMessage.objects.filter(
        product_id=product_id,
        product_type=product_type,
        is_admin_chat=False
    ).exclude(
        id__in=deleted_message_ids
    ).exclude(
        is_deleted_for_everyone=True
    ).select_related('sender', 'receiver').order_by('timestamp')
    
    # Group messages by user (the other participant)
    conversations = {}
    users_in_chat = set()
    unread_total = 0
    
    for msg in all_messages:
        # Determine the other user (not the owner)
        if msg.sender == request.user:
            other_user = msg.receiver
        else:
            other_user = msg.sender
        
        users_in_chat.add(other_user)
        
        # Generate unique chat ID for this conversation
        user_ids = sorted([str(request.user.id), str(other_user.id)])
        chat_session_id = f"{user_ids[0]}_{user_ids[1]}_{product_type}_{product_id}"
        
        if other_user.id not in conversations:
            conversations[other_user.id] = {
                'user': other_user,
                'messages': [],
                'unread_count': 0,
                'last_message': None,
                'last_message_time': None,
                'chat_session_id': chat_session_id,
                'product_title': product_info['title'] if product_info else 'Product',
                'product_image': product_info.get('image_url', '') if product_info else '',
                'product_price': product_info.get('price', '') if product_info else ''
            }
        
        conversations[other_user.id]['messages'].append(msg)
        
        # Update last message
        conversations[other_user.id]['last_message'] = msg.message
        conversations[other_user.id]['last_message_time'] = msg.timestamp
        
        # Count unread messages for this user (excluding deleted)
        if msg.receiver == request.user and not msg.is_read:
            conversations[other_user.id]['unread_count'] += 1
            unread_total += 1
    
    # Mark all messages as read when viewing (excluding deleted)
    ChatMessage.objects.filter(
        product_id=product_id,
        product_type=product_type,
        receiver=request.user,
        is_read=False
    ).exclude(
        id__in=deleted_message_ids
    ).exclude(
        is_deleted_for_everyone=True
    ).update(is_read=True)
    
    # Sort conversations by most recent message
    sorted_conversations = sorted(
        conversations.values(),
        key=lambda x: x['last_message_time'] if x['last_message_time'] else timezone.now(),
        reverse=True
    )
    
    # Prepare messages data for JavaScript with unique identifiers
    messages_data = {}
    for user_id, conv in conversations.items():
        messages_data[user_id] = {
            'username': conv['user'].username,
            'user_image': conv['user'].image.url if hasattr(conv['user'], 'image') and conv['user'].image else '',
            'chat_session_id': conv['chat_session_id'],
            'messages': [
                {
                    'id': msg.id,
                    'text': msg.message,
                    'time': msg.timestamp.strftime("%H:%M"),
                    'date': msg.timestamp.strftime("%Y-%m-%d"),
                    'is_sent': msg.sender.id == request.user.id,
                    'sender': msg.sender.username,
                    'is_deleted': False,
                    'can_delete_for_everyone': msg.sender.id == request.user.id
                }
                for msg in conv['messages']
            ]
        }
    
    context = {
        'product': product,
        'product_info': product_info,
        'product_type': product_type,
        'product_id': product_id,
        'conversations': sorted_conversations,
        'messages_data_json': json.dumps(messages_data),
        'users_in_chat': list(users_in_chat),
        'total_inquiries': len(users_in_chat),
        'total_messages': all_messages.count(),
        'unread_total': unread_total,
    }
    
    return render(request, 'product_inquiries.html', context)



