from django.http import JsonResponse
from django.contrib.auth.decorators import login_required
from django.views.decorators.http import require_POST
from django.shortcuts import get_object_or_404
from django.db import IntegrityError
from .models import ChatMessage, BlockedUser, DeletedMessage
import json

@login_required
@require_POST
def block_user(request, user_id):
    """Block a user"""
    try:
        user_to_block = get_object_or_404(User, id=user_id)
        
        # Don't allow blocking yourself
        if user_to_block == request.user:
            return JsonResponse({
                'success': False, 
                'error': 'You cannot block yourself'
            }, status=400)
        
        # Create block record
        block, created = BlockedUser.objects.get_or_create(
            user=request.user,
            blocked_user=user_to_block
        )
        
        if created:
            return JsonResponse({
                'success': True,
                'message': f'You have blocked {user_to_block.username}',
                'is_blocked': True,
                'username': user_to_block.username
            })
        else:
            return JsonResponse({
                'success': True,
                'message': f'{user_to_block.username} is already blocked',
                'is_blocked': True,
                'username': user_to_block.username
            })
            
    except Exception as e:
        return JsonResponse({
            'success': False, 
            'error': str(e)
        }, status=500)

