from django.http import JsonResponse
from django.contrib.auth.decorators import login_required

@login_required
def check_all_new_messages(request):
    """Check for new messages from all users and return updated list"""
    try:
        # Get IDs of messages deleted by the current user
        deleted_message_ids = DeletedMessage.objects.filter(
            deleted_by=request.user
        ).values_list('message_id', flat=True)
        
        # Find all users who have sent new messages to the current user
        # that haven't been read and aren't deleted
        new_messages = ChatMessage.objects.filter(
            receiver=request.user,
            is_read=False,
            is_deleted_for_everyone=False
        ).exclude(
            id__in=deleted_message_ids
        ).select_related('sender')
        
        # Get unique sender IDs
        updated_users = list(new_messages.values_list('sender_id', flat=True).distinct())
        
        # For each user, also get the product info if it's a product chat
        user_product_info = {}
        for msg in new_messages:
            if msg.product_id and msg.product_type:
                key = f"{msg.sender_id}_{msg.product_type}_{msg.product_id}"
                if key not in user_product_info:
                    user_product_info[key] = {
                        'user_id': msg.sender_id,
                        'product_type': msg.product_type,
                        'product_id': msg.product_id,
                        'last_message': msg.message
                    }
        
        return JsonResponse({
            'success': True,
            'updated_users': updated_users,
            'product_info': list(user_product_info.values())
        })
    except Exception as e:
        print(f"Error in check_all_new_messages: {e}")
        return JsonResponse({
            'success': False,
            'error': str(e)
        })
@login_required
def get_recent_chats(request, user_id):
    """Get recent chats for a user (used for updating UI)"""
    try:
        # Get IDs of messages deleted by the current user
        deleted_message_ids = DeletedMessage.objects.filter(
            deleted_by=request.user
        ).values_list('message_id', flat=True)
        
        # Get all chats with this user that have recent activity
        chats = []
        
        # Check for general chat
        general_messages = ChatMessage.objects.filter(
            Q(sender=request.user, receiver_id=user_id) | 
            Q(sender_id=user_id, receiver=request.user),
            product_id__isnull=True,
            product_type__isnull=True,
            is_deleted_for_everyone=False
        ).exclude(
            id__in=deleted_message_ids
        ).order_by('-timestamp')
        
        if general_messages.exists():
            last_msg = general_messages.first()
            chats.append({
                'product_type': 'general',
                'product_id': '',
                'last_message': last_msg.message if last_msg else '',
                'last_time': last_msg.timestamp.isoformat() if last_msg else ''
            })
        
        # Check for product chats
        product_chats = ChatMessage.objects.filter(
            Q(sender=request.user, receiver_id=user_id) | 
            Q(sender_id=user_id, receiver=request.user),
            product_id__isnull=False,
            product_type__isnull=False,
            is_deleted_for_everyone=False
        ).exclude(
            id__in=deleted_message_ids
        ).values('product_type', 'product_id').distinct()
        
        for chat in product_chats:
            user_ids = sorted([str(request.user.id), str(user_id)])
            chat_session_id = f"{user_ids[0]}_{user_ids[1]}_{chat['product_type']}_{chat['product_id']}"
            
            last_msg = ChatMessage.objects.filter(
                chat_session_id=chat_session_id,
                is_deleted_for_everyone=False
            ).exclude(
                id__in=deleted_message_ids
            ).order_by('-timestamp').first()
            
            if last_msg:
                chats.append({
                    'product_type': chat['product_type'],
                    'product_id': chat['product_id'],
                    'last_message': last_msg.message,
                    'last_time': last_msg.timestamp.isoformat()
                })
        
        return JsonResponse({
            'success': True,
            'chats': chats
        })
        
    except Exception as e:
        print(f"Error in get_recent_chats: {e}")
        return JsonResponse({
            'success': False,
            'error': str(e)
        })


