@login_required
def admin_chat_list_view(request):
    if not request.user.is_superuser:
        return redirect('login')

    # Users who have ADMIN chats with admin
    users_with_messages = CustomUser.objects.filter(
        received_messages__sender=request.user,
        received_messages__is_admin_chat=True
    ).distinct()

    users_with_messages = users_with_messages.union(
        CustomUser.objects.filter(
            sent_messages__receiver=request.user,
            sent_messages__is_admin_chat=True
        ).distinct()
    )

    chat_list = []

    for user in users_with_messages:
        last_message = ChatMessage.objects.filter(
            sender__in=[user, request.user],
            receiver__in=[user, request.user],
            is_admin_chat=True
        ).order_by('-timestamp').first()

        chat_list.append({
            'user': user,
            'last_message': last_message
        })

    return render(
        request,
        'admin1/admin_chat_list.html',
        {'chat_list': chat_list}
    )


@login_required
def admin_chat_view(request, user_id):
    if not request.user.is_superuser:
        return redirect('login')

    user = get_object_or_404(CustomUser, id=user_id)

    if request.method == 'POST':
        message = request.POST.get('message', '').strip()
        if message:
            ChatMessage.objects.create(
                sender=request.user,
                receiver=user,
                message=message,
                is_admin_chat=True   # 👈 critical
            )

            return JsonResponse({
                'message': message,
                'sender': 'sent',
                'timestamp': 'Just now'
            })

    # ONLY admin chat messages
    messages = ChatMessage.objects.filter(
        sender__in=[request.user, user],
        receiver__in=[request.user, user],
        is_admin_chat=True
    ).order_by('timestamp')

    return render(
        request,
        'admin1/admin_chat.html',
        {
            'messages': messages,
            'user': user
        }
    )
