    # views.py - Update your browseads11 function
def browseads11(request, category, id):
    category = category.lower()

    # Same mapping style as index2
    ad_model_mapping = {
        'automobile': Automobile,
        'automobiles': Automobile,
        'motorcycle': Motorcycle,
        'motorcycles': Motorcycle,
        'scooter': Scooter,
        'scooters': Scooter,
        'junkcars': JunkCar,
        'quadbikes': Quadbikes,
        'helmetclothes': HelmetClothes,
        'helmet': HelmetClothes,
        'heavyvehicle': HeavyVehicle,
        'heavy_vehicles': HeavyVehicle,
        'boats': Boat,
        'boat': Boat,
        'accessoriesparts': AutoAccessoryPart,
        'accessoriespart': AutoAccessoryPart,
        'tiresandcaps': TiresAndCaps,
        'tiresandcap': TiresAndCaps,
        'car_repair': CarRepairMaintenance,
        'driving_training': DrivingTraining,
        'numberplate': NumberPlate,
    }

    # Handle special "motors" category → check all motor-related models
    if category == 'motors':
        categories = [
            'automobiles', 'motorcycles', 'scooter', 'junkcars',
            'helmetclothes', 'heavy_vehicles', 'boats',
            'accessoriesparts', 'tiresandcaps'
        ]
    else:
        categories = [category]

    ad = None
    found_category = None

    # Try fetching ad from the mapped model(s)
    for cat in categories:
        model = ad_model_mapping.get(cat)
        if not model:
            continue
        try:
            ad = model.objects.get(id=id, status='approved')
            found_category = cat
            break
        except model.DoesNotExist:
            continue

    if not ad:
        raise Http404("No matching ad found")

    # ========== GET ALL IMAGES FOR THE AD ==========
    images = []
    if hasattr(ad, 'images') and ad.images.exists():
        # Get ALL images for the carousel
        images = [{"image": img.image.url} for img in ad.images.all()]
    elif hasattr(ad, 'main_image') and ad.main_image:
        # Fallback to single main image
        images = [{"image": ad.main_image.url}]
    
    # Get main image URL (first image)
    main_image_url = images[0]["image"] if images else "/static/assets/images/resource/default.jpg"
    
    # Convert images to JSON string for the template
    images_json = json.dumps(images)
    
    # ========== RECENTLY VIEWED TRACKING ==========
    # Get title based on ad type
    title = ""
    if hasattr(ad, 'make') and hasattr(ad, 'model'):
        title = f"{ad.make} {ad.model}"
    elif hasattr(ad, 'product_name'):
        title = ad.product_name
    elif hasattr(ad, 'title'):
        title = ad.title
    elif hasattr(ad, 'name'):
        title = ad.name
    else:
        title = f"{found_category.capitalize()} #{ad.id}"
    
    # Get city name
    city_name = ""
    if hasattr(ad, 'city') and ad.city:
        city_name = ad.city.name
    
    # Get listing type (for rent/sell)
    listing_type = ""
    if hasattr(ad, 'listing_type'):
        listing_type = ad.listing_type
    
    # Get motor-specific fields
    make = ""
    model_name = ""
    year = ""
    regional_spec = ""
    
    if hasattr(ad, 'make'):
        make = ad.make
    if hasattr(ad, 'model'):
        model_name = ad.model
    if hasattr(ad, 'year'):
        year = ad.year
    if hasattr(ad, 'regional_spec'):
        regional_spec = ad.regional_spec
    
    # Determine product category for tracking
    product_category = found_category  # e.g., 'automobile', 'motorcycle', etc.
    
    product_data = {
        'title': title,
        'price': ad.price if hasattr(ad, 'price') else 0,
        'main_image': main_image_url,
        'images_json': images_json,  # ADD THIS - store all images
        'city': city_name,
        'url': request.build_absolute_uri(),  # Use full URL
        'listing_type': listing_type,
        'display_category': 'Motors',  # ADD THIS for category grouping
        'make': make,  # ADD THIS
        'model': model_name,  # ADD THIS
        'year': year,  # ADD THIS
        'regional_spec': regional_spec,  # ADD THIS
    }
    
    # Track the viewed product
    track_recently_viewed(request, str(ad.id), product_category, product_data)
    # ========== END RECENTLY VIEWED TRACKING ==========

    # Get governates for dropdowns
    governates = Governate.objects.prefetch_related(
        Prefetch('districts', queryset=District.objects.all())
    ).all()

    # Ads for right-side banners
    advertisement = Advertisement.objects.filter(
        category=AdvertisementCategory.REAL_ESTATE, 
        is_active=True
    )

    # Features (if ad has this relation)
    features = ad.features.all() if hasattr(ad, 'features') else []

    # Location display string
    location_display = ""
    if ad.city and ad.city.district and ad.city.district.governate:
        location_display = (
            f"{ad.city.name}, {ad.city.district.name}, {ad.city.district.governate.name}"
        )

    # Videos (safe default empty list)
    videos = ad.videos.all() if hasattr(ad, 'videos') else []

    # Category label for template
    category_listing_label = found_category.capitalize() if found_category else "Ad"

    # Determine if it's a rent listing
    is_rent = False
    if hasattr(ad, 'listing_type'):
        is_rent = ad.listing_type == 'rent'

    context = {
        'ad': ad,
        'governates': governates,
        'advertisement': advertisement,
        'features': features,
        'videos': videos,
        'main_image': main_image_url,
        'images_json': images_json,  # ADD THIS to context
        'images': images,  # ADD THIS for debugging if needed
        'category_listing_label': category_listing_label,
        'location_display': location_display,
        'error': None if ad else 'Advertisement not found',
        'is_rent': is_rent,

        # Flags for template conditionals
        'is_car': isinstance(ad, Automobile),
        'is_motorcycle': isinstance(ad, Motorcycle),
        'is_scooter': isinstance(ad, Scooter),
        'is_quadbike': isinstance(ad, Quadbikes),
        'is_accessory': isinstance(ad, AutoAccessoryPart),
        'is_boat': isinstance(ad, Boat),
        'is_heavyvehicle': isinstance(ad, HeavyVehicle),
        'is_helmetclothes': isinstance(ad, HelmetClothes),
        'is_junkcars': isinstance(ad, JunkCar),
        'is_tiresandcaps': isinstance(ad, TiresAndCaps),
        'is_car_repair': isinstance(ad, CarRepairMaintenance),
        'is_driving_training': isinstance(ad, DrivingTraining),
        'is_numberplate': isinstance(ad, NumberPlate),
    }

    return render(request, 'browse-ads-11.html', context)

from django.contrib.auth import get_user_model
from django.contrib.auth.decorators import login_required
from django.shortcuts import get_object_or_404, redirect, render
from django.contrib import messages
from django.contrib.auth import get_user_model

@login_required
def edit_company(request, user_id, company_id):
    User = get_user_model()  # Get custom user model
    user = get_object_or_404(User, id=user_id)

    # Dropdown datasets
    regions = Region.objects.all()
    governates = Governate.objects.all()
    districts = District.objects.all()
    cities = Cities.objects.all()

    company = get_object_or_404(Company, id=company_id, user=user)

    if request.method == 'POST':
        form = CompanyRegistrationForm(request.POST, request.FILES, instance=company)
        if form.is_valid():
            form.save()
            messages.success(request, "Company details updated successfully.")
            return redirect('company_dashboard', user_id=user.id, company_id=company.id)
        else:
            messages.error(request, "Please correct the errors below.")
    else:
        form = CompanyRegistrationForm(instance=company)

    context = {
        'form': form,
        'company': company,
        'regions': regions,
        'governates': governates,
        'districts': districts,
        'cities': cities,
    }
    return render(request, 'Job/edit_company.html', context)

from django.shortcuts import redirect, get_object_or_404
from django.http import JsonResponse

def delete_company(request, company_id):
    if request.method == 'POST':  # change DELETE → POST
        company = get_object_or_404(Company, id=company_id)
        company.delete()
        return redirect('we_are_hiring')  # use your URL name string
    return JsonResponse({'error': 'Invalid request method.'}, status=400)


from django.contrib.auth.decorators import login_required, user_passes_test
from django.core.paginator import Paginator
from django.db.models import Q
from .models import Company
@login_required
@user_passes_test(lambda u: u.is_staff, login_url='admin:login')
def company_list_view(request):
    # Get search query parameter
    search_query = request.GET.get('search', '').strip()
    
    # Base queryset - using id for ordering instead of created_at
    queryset = Company.objects.select_related('user').order_by('-id')
    
    # Apply search filter if query exists
    if search_query:
        queryset = queryset.filter(
            Q(company_name__icontains=search_query) |
            Q(user__username__icontains=search_query) |
            Q(trade_license__icontains=search_query) |
            Q(city__name__icontains=search_query)
        )
    
    # Status filter
    status_filter = request.GET.get('status')
    if status_filter in ['pending', 'approved', 'rejected']:
        queryset = queryset.filter(status=status_filter)
    
    # Pagination
    paginator = Paginator(queryset, 25)  # Show 25 companies per page
    page_number = request.GET.get('page')
    page_obj = paginator.get_page(page_number)
    
    # Counts for status tabs
    counts = {
        'all': Company.objects.count(),
        'pending': Company.objects.filter(status='pending').count(),
        'approved': Company.objects.filter(status='approved').count(),
        'rejected': Company.objects.filter(status='rejected').count(),
    }
    
    context = {
        'companies': page_obj,
        'search_query': search_query,
        'status_filter': status_filter,
        'counts': counts,
        'status_choices': Company.STATUS_CHOICES,
    }
    
    return render(request, 'admin1/company/company.html', context)

@login_required
@user_passes_test(lambda u: u.is_staff, login_url='admin:login')
def approve_company(request, company_id):
    company = get_object_or_404(Company, id=company_id)
    company.status = 'approved'
    company.save()
    messages.success(request, f"Company '{company.company_name}' has been approved.")
    return redirect('company_list')

@login_required
@user_passes_test(lambda u: u.is_staff, login_url='admin:login')
def reject_company(request, company_id):
    company = get_object_or_404(Company, id=company_id)
    company.status = 'rejected'
    company.save()
    messages.warning(request, f"Company '{company.company_name}' has been rejected.")
    return redirect('company_list')

