    def get_coordinates(item):
        """Safely get coordinates from any model with latitude/longitude fields"""
        lat = None
        lng = None
        
        # Check common field names for latitude
        lat_fields = ['latitude', 'lat', 'lat_field', 'latitude_field']
        for field in lat_fields:
            if hasattr(item, field) and getattr(item, field):
                try:
                    lat = float(getattr(item, field))
                    break
                except (ValueError, TypeError):
                    pass
        
        # Check common field names for longitude
        lng_fields = ['longitude', 'lng', 'long', 'lng_field', 'longitude_field']
        for field in lng_fields:
            if hasattr(item, field) and getattr(item, field):
                try:
                    lng = float(getattr(item, field))
                    break
                except (ValueError, TypeError):
                    pass
        
        # If no coordinates found, try to get from city
        if (lat is None or lng is None) and hasattr(item, 'city') and item.city:
            city = item.city
            # Try to get coordinates from city
            if hasattr(city, 'latitude') and city.latitude:
                try:
                    lat = float(city.latitude)
                except (ValueError, TypeError):
                    pass
            if hasattr(city, 'longitude') and city.longitude:
                try:
                    lng = float(city.longitude)
                except (ValueError, TypeError):
                    pass
            
            # Try alternative field names on city
            if (lat is None or lng is None) and hasattr(city, 'lat') and city.lat:
                try:
                    lat = float(city.lat)
                except (ValueError, TypeError):
                    pass
            if (lat is None or lng is None) and hasattr(city, 'lng') and city.lng:
                try:
                    lng = float(city.lng)
                except (ValueError, TypeError):
                    pass
        
        # Validate coordinates - Oman bounds
        if lat and lng:
            try:
                lat = float(lat)
                lng = float(lng)
                # Oman bounds: lat 16.5-26.5, lng 52.0-60.0
                if (lat != 0 and lng != 0 and 
                    -90 <= lat <= 90 and -180 <= lng <= 180 and
                    16.5 <= lat <= 26.5 and 52.0 <= lng <= 60.0):
                    return lat, lng
            except (ValueError, TypeError):
                pass
        
        return None, None

    def get_default_coordinates(city_name):
        """Get default coordinates for a city in Oman"""
        # Default coordinates for major cities in Oman
        city_coords = {
            'muscat': (23.5880, 58.3829),
            'seeb': (23.6700, 58.1891),
            'salalah': (17.0151, 54.0924),
            'sohar': (24.3423, 56.7293),
            'nizwa': (22.9171, 57.5300),
            'sur': (22.5700, 59.5289),
            'ibri': (23.2257, 56.5157),
            'barka': (23.6787, 57.8853),
            'rustaq': (23.3908, 57.4244),
            'khasab': (26.1798, 56.2426),
        }
        
        if city_name:
            city_lower = city_name.lower().strip()
            for key, coords in city_coords.items():
                if key in city_lower:
                    return coords
        
        # Default to Muscat if no match
        return (23.5880, 58.3829)

    def create_location_data(item, category_key, category_display, lat, lng, extra=None):
        nonlocal total_approved_count, total_with_coordinates
        
        total_approved_count += 1
        
        images = []
        if hasattr(item, 'images'):
            for img in item.images.all()[:5]:
                if hasattr(img, 'image') and img.image:
                    try:
                        images.append(img.image.url)
                    except:
                        pass
        
        if not images:
            images = ['/static/images/placeholder.jpg']
        
        # Get city name
        city_name = ''
        if hasattr(item, 'city') and item.city:
            city_name = item.city.name if hasattr(item.city, 'name') else str(item.city)
        elif hasattr(item, 'city_name') and item.city_name:
            city_name = item.city_name
        
        # Get title
        title = None
        if hasattr(item, 'title') and item.title:
            title = item.title
        elif hasattr(item, 'product_name') and item.product_name:
            title = item.product_name
        elif hasattr(item, 'service_title') and item.service_title:
            title = item.service_title
        elif hasattr(item, 'name') and item.name:
            title = item.name
        else:
            title = f"{category_display} #{item.id}"
        
        # Get price
        price_val = getattr(item, 'price', None)
        if price_val:
            try:
                price = f"{int(float(price_val)):,} OMR"
            except:
                price = str(price_val)
        else:
            price = "Contact for price"
        
        try:
            redirect_url = reverse('map_product_redirect', kwargs={'product_type': category_key, 'product_id': item.id})
        except:
            redirect_url = f"/map-product/{category_key}/{item.id}/"
        
        # If coordinates are missing, use default based on city
        if lat is None or lng is None:
            lat, lng = get_default_coordinates(city_name)
            print(f"  Using default coordinates for {title} at {city_name}: ({lat}, {lng})")
        
        location_data = {
            'id': item.id,
            'lat': lat,
            'lng': lng,
            'has_coordinates': lat is not None and lng is not None,
            'category': category_key,
            'category_display': category_display,
            'redirect_url': redirect_url,
            'title': title,
            'name': title,
            'price': price,
            'image_url': images[0] if images else '/static/images/placeholder.jpg',
            'images': images if images else ['/static/images/placeholder.jpg'],
            'location_text': city_name,
            'city': city_name,
            'city_name': city_name,
            'listing_type': getattr(item, 'listing_type', 'sale'),
            'user_id': str(item.user.id) if hasattr(item, 'user') and item.user else None,
            'username': item.user.username if hasattr(item, 'user') and item.user else 'Seller',
        }
        
        if extra:
            location_data.update(extra)
        
        # Track valid coordinates
        if lat is not None and lng is not None:
            total_with_coordinates += 1
        else:
            missing_coordinates_list.append(f"{category_key} ID:{item.id} - {title} - {city_name}")
            # Set default coordinates as fallback
            if lat is None or lng is None:
                lat, lng = get_default_coordinates(city_name)
                location_data['lat'] = lat
                location_data['lng'] = lng
                location_data['has_coordinates'] = True
        
        return location_data

