def complex_details(request, id):
    advertisement = Advertisement.objects.filter(
        category=AdvertisementCategory.REAL_ESTATE, 
        is_active=True
    )
    complex = get_object_or_404(
        Complex.objects.prefetch_related('nearby_location', 'main_amenities', 'additional_amenities'),
        id=id
    )
    track_product_view(request, complex)

    # ========== RECENTLY VIEWED TRACKING ==========
    # Get all images for the complex
    images = []
    if hasattr(complex, 'images') and complex.images.exists():
        images = [{"image": img.image.url} for img in complex.images.all()]
    elif hasattr(complex, 'main_image') and complex.main_image:
        images = [{"image": complex.main_image.url}]
    
    # Get main image URL
    main_image_url = images[0]["image"] if images else "/static/assets/images/resource/default.jpg"
    
    # Convert images to JSON string
    images_json = json.dumps(images)
    
    # Get title
    title = ""
    if hasattr(complex, 'property_title') and complex.property_title:
        title = complex.property_title
    elif hasattr(complex, 'title') and complex.title:
        title = complex.title
    else:
        title = f"Complex #{complex.id}"
    
    # Get city name
    city_name = ""
    if hasattr(complex, 'city') and complex.city:
        city_name = complex.city.name
    
    # Get price
    price = complex.price if hasattr(complex, 'price') else 0
    
    product_data = {
        'title': title,
        'price': price,
        'main_image': main_image_url,
        'images_json': images_json,
        'city': city_name,
        'url': request.build_absolute_uri(),
        'listing_type': '',
        'display_category': 'Real Estate',
        'brand': '',
        'category_type': 'complex',
    }
    
    # Track the recently viewed product
    track_recently_viewed(request, str(complex.id), 'complex', product_data)
    # ========== END RECENTLY VIEWED TRACKING ==========

    if request.method == 'POST':
        reason = request.POST.get('reason')
        description = request.POST.get('description', '')

        if reason:
            ProductReport.objects.create(
                reporter=request.user if request.user.is_authenticated else None,
                reason=reason,
                description=description,
                content_type=ContentType.objects.get_for_model(Complex),
                object_id=complex.id
            )
            messages.success(request, "Thank you. Your report has been submitted.")
            return redirect('complex_details', id=complex.id)

        messages.error(request, "Please select a valid reason to report.")
    
    # Get governates for filters (if needed)
    governates = Governate.objects.prefetch_related(
        Prefetch('districts', queryset=District.objects.all())
    ).all()
    
    # Check if favorited
    is_favorited = False
    if request.user.is_authenticated:
        content_type = ContentType.objects.get_for_model(complex)
        is_favorited = Favorite.objects.filter(
            user=request.user,
            content_type=content_type,
            object_id=complex.id
        ).exists()
    
    # Get videos if available
    videos = complex.videos.all() if hasattr(complex, 'videos') else []
    
    # Location display string
    location_display = ""
    if complex.city and complex.city.district and complex.city.district.governate:
        location_display = f"{complex.city.name}, {complex.city.district.name}, {complex.city.district.governate.name}"
    
    # ========== GET COORDINATES FOR MAP ==========
    # Try to get coordinates from complex first, then fallback to city, then default
    latitude = None
    longitude = None
    
    # Check if complex has coordinates
    if hasattr(complex, 'latitude') and complex.latitude and hasattr(complex, 'longitude') and complex.longitude:
        latitude = float(complex.latitude)
        longitude = float(complex.longitude)
        print(f"Using complex coordinates: {latitude}, {longitude}")
    
    # Fallback to city coordinates if available
    elif complex.city:
        if hasattr(complex.city, 'latitude') and complex.city.latitude and hasattr(complex.city, 'longitude') and complex.city.longitude:
            latitude = float(complex.city.latitude)
            longitude = float(complex.city.longitude)
            print(f"Using city coordinates: {latitude}, {longitude}")
        else:
            # If city doesn't have coordinates, use geocoding or default
            try:
                from geopy.geocoders import GoogleV3
                geolocator = GoogleV3(api_key='YOUR_GOOGLE_API_KEY')  # Replace with your API key
                location = geolocator.geocode(f"{complex.city.name}, Egypt")
                if location:
                    latitude = location.latitude
                    longitude = location.longitude
                    print(f"Geocoded coordinates: {latitude}, {longitude}")
                else:
                    # Default to Egypt center
                    latitude = 26.8206
                    longitude = 30.8025
            except Exception as e:
                print(f"Geocoding failed: {e}")
                # Default to Egypt center
                latitude = 26.8206
                longitude = 30.8025
    else:
        # Default to Egypt center
        latitude = 26.8206
        longitude = 30.8025
        print("Using default coordinates for Egypt")
    
    # Convert to string for template
    lat_str = str(latitude) if latitude else "26.8206"
    lng_str = str(longitude) if longitude else "30.8025"
    
    # Create map URL
    map_url = f"https://www.google.com/maps?q={lat_str},{lng_str}&hl=en&z=15&output=embed"
    directions_url = f"https://www.google.com/maps/dir/?api=1&destination={lat_str},{lng_str}"

    return render(request, 'estate/complex_details.html', {
        'complex': complex,
        'advertisement': advertisement,
        'governates': governates,
        'main_image_url': main_image_url,
        'images_json': images_json,
        'images': images,
        'videos': videos,
        'location_display': location_display,
        'is_favorited': is_favorited,
        'favorite_product_type': 'complex',
        # Location data for map
        'latitude': lat_str,
        'longitude': lng_str,
        'map_url': map_url,
        'directions_url': directions_url,
        'location_name': location_display or complex.city.name if complex.city else "Location",
    })

def clinic(request):
    # --- Location hierarchy ---
    governates = Governate.objects.prefetch_related(
        Prefetch('districts', queryset=District.objects.all())
    ).all()

    # --- Advertisement / Amenities ---
    advertisement = Advertisement.objects.filter(
        category=AdvertisementCategory.REAL_ESTATE, 
        is_active=True
    )

    # --- Get all filter parameters (MULTI-SELECT LIKE VILLA/WHOLEBUILDING) ---
    selected_governate_params = request.GET.getlist('governate')
    selected_district_params = request.GET.getlist('district')
    selected_cities = request.GET.getlist('city')
    name_query = request.GET.get('name', '')
    banners = Banner.objects.filter(category='real_estate', is_active=True)

    price_from = request.GET.get('price_from')
    price_to = request.GET.get('price_to')
    furnished = request.GET.get('furnished')
    rental_period = request.GET.get('rental_period')
    lister_type = request.GET.get('lister_type')
    property_mortgage = request.GET.get('property_mortgage')
    payment_method = request.GET.get('payment_method')
    facade = request.GET.get('facade')
    floors = request.GET.get('floors')
    
    # Multi-select amenities
    selected_main_amenities = request.GET.getlist('main_amenity')
    selected_additional_amenities = request.GET.getlist('additional_amenity')
    selected_nearby = request.GET.getlist('nearby')
    
    surface_area_from = request.GET.get('surface_area_from')
    surface_area_to = request.GET.get('surface_area_to')
    listing_type = request.GET.get('listing_type')
    sort_by = request.GET.get('sort', 'newest')

    # --- Get available amenities for the template ---
    main_amenities_list = MainAmenities.objects.all()
    additional_amenities_list = AdditionalAmenities.objects.all()
    nearby_locations_list = NearbyLocation.objects.all()

    # ========== EXPIRY CUTOFF (45 days) ==========
    cutoff_date = timezone.now() - timedelta(days=45)

    # --- Base queryset (approved + not expired) ---
    queryset = Clinic.objects.filter(
        status='approved',
        created_at__gte=cutoff_date
    ).select_related('city')

    # --- Check if any filters are applied ---
    has_filters = any([
        selected_governate_params, selected_district_params, selected_cities,
        name_query, price_from, price_to, furnished, rental_period,
        lister_type, property_mortgage, payment_method, facade, floors,
        selected_main_amenities, selected_additional_amenities, selected_nearby,
        surface_area_from, surface_area_to, listing_type
    ])

    # --- Location filters ---
    if selected_cities:
        queryset = queryset.filter(city_id__in=selected_cities)
    elif selected_district_params:
        cities = Cities.objects.filter(district_id__in=selected_district_params)
        queryset = queryset.filter(city_id__in=cities.values_list('id', flat=True))
    elif selected_governate_params:
        cities = Cities.objects.filter(district__governate_id__in=selected_governate_params)
        queryset = queryset.filter(city_id__in=cities.values_list('id', flat=True))

    # Dropdown linkage
    districts = District.objects.filter(governate_id__in=selected_governate_params) if selected_governate_params else None

    # --- Core filters ---
    if name_query:
        queryset = queryset.filter(
            Q(property_title__icontains=name_query) |
            Q(description__icontains=name_query)
        )

    if listing_type and listing_type != "all":
        queryset = queryset.filter(listing_type=listing_type)

    # --- Range filters with proper error handling ---
    try:
        if price_from:
            queryset = queryset.filter(price__gte=float(price_from))
        if price_to:
            queryset = queryset.filter(price__lte=float(price_to))
    except (ValueError, TypeError):
        pass

    try:
        if surface_area_from:
            queryset = queryset.filter(plot_area__gte=float(surface_area_from))
        if surface_area_to:
            queryset = queryset.filter(plot_area__lte=float(surface_area_to))
    except (ValueError, TypeError):
        pass

    # --- Multi-select filters ---
    if furnished:
        queryset = queryset.filter(furnished__in=furnished.split(','))
    if floors:
        queryset = queryset.filter(floors__in=floors.split(','))
    if rental_period:
        queryset = queryset.filter(rental_period__in=rental_period.split(','))
    if facade:
        queryset = queryset.filter(facade__in=facade.split(','))

    # --- Single select filters ---
    if lister_type and lister_type != "all":
        queryset = queryset.filter(lister_type=lister_type)
    if property_mortgage and property_mortgage != "all":
        queryset = queryset.filter(property_mortgage=property_mortgage)
    if payment_method and payment_method != "all":
        queryset = queryset.filter(payment_method=payment_method)

    # --- Amenities filters ---
    if selected_main_amenities:
        queryset = queryset.filter(main_amenities__name__in=selected_main_amenities).distinct()
    if selected_additional_amenities:
        queryset = queryset.filter(additional_amenities__name__in=selected_additional_amenities).distinct()
    if selected_nearby:
        queryset = queryset.filter(nearby_location__name__in=selected_nearby).distinct()

    # --- Convert queryset to list for Python sorting ---
    clinics = list(queryset)

    # ========== ADD BOOST INFORMATION FOR MAIN RESULTS ==========
    if clinics:
        clinic_ids = [c.id for c in clinics]
        boosts = BoostUsage.objects.filter(
            listing_type='clinic',   # adjust if your model uses a different string
            listing_id__in=clinic_ids,
            is_active=True
        )
        boost_dict = {b.listing_id: b for b in boosts}
        for c in clinics:
            boost = boost_dict.get(c.id)
            if boost and boost.is_boost_active():
                c.is_boosted = True
                c.boost_days_left = boost.days_remaining
            else:
                c.is_boosted = False
                c.boost_days_left = 0

    # --------- SORTING FUNCTION ---------
    def sort_items(data_list, sort_key):
        if sort_key == 'price_asc':
            data_list.sort(key=lambda x: x.price or 0)
        elif sort_key == 'price_desc':
            data_list.sort(key=lambda x: x.price or 0, reverse=True)
        elif sort_key == 'oldest':
            data_list.sort(key=lambda x: x.created_at)
        else:  # newest
            data_list.sort(key=lambda x: x.created_at, reverse=True)
        return data_list

    # --- Sort main results ---
    clinics = sort_items(clinics, sort_by)

    # ========== FIXED: RELATED PROPERTIES (45-day cutoff + boost) ==========
    related_clinics = []
    related_clinics_count = 0
    if has_filters and len(clinics) == 0:
        related_queryset = Clinic.objects.filter(
            status='approved',
            created_at__gte=cutoff_date   # <-- added cutoff date
        ).order_by('-created_at')[:6]

        related_clinics = list(related_queryset)

        # Add boost info and images for related items
        if related_clinics:
            rel_ids = [r.id for r in related_clinics]
            rel_boosts = BoostUsage.objects.filter(
                listing_type='clinic',
                listing_id__in=rel_ids,
                is_active=True
            )
            rel_boost_dict = {b.listing_id: b for b in rel_boosts}
            for r in related_clinics:
                boost = rel_boost_dict.get(r.id)
                if boost and boost.is_boost_active():
                    r.is_boosted = True
                    r.boost_days_left = boost.days_remaining
                else:
                    r.is_boosted = False
                    r.boost_days_left = 0
                r.images_json = json.dumps([img.image.url for img in r.images.all()])

        # Sort related also
        related_clinics = sort_items(related_clinics, sort_by)
        related_clinics_count = len(related_clinics)

    # --- Add images JSON for main results ---
    for clinic in clinics:
        clinic.images_json = json.dumps([img.image.url for img in clinic.images.all()])

    total_count = len(clinics)

    # --- Pagination ---
    current_params = request.GET.copy()
    if 'page' in current_params:
        del current_params['page']

    paginator = Paginator(clinics, 6)
    page_number = request.GET.get('page', 1)
    try:
        page_obj = paginator.get_page(page_number)
    except EmptyPage:
        page_obj = paginator.get_page(paginator.num_pages)

    # --- Breadcrumb data ---
    selected_governate_objs = Governate.objects.filter(id__in=selected_governate_params) if selected_governate_params else []
    selected_district_objs = District.objects.filter(id__in=selected_district_params) if selected_district_params else []
    selected_city_objs = Cities.objects.filter(id__in=selected_cities) if selected_cities else []

    # --- Filter options for template ---
    listing_types = [("all", "All")] + list(Clinic.TRANSACTION_CHOICES)
    furnished_options = [("all", "All")] + list(Clinic.FURNISHED_CHOICES)
    rental_period_options = [("all", "All")] + list(Clinic.RENTAL_PERIOD_CHOICES)
    lister_type_options = [("all", "All")] + list(Clinic.LISTER_TYPE_CHOICES)
    property_mortgage_options = [("all", "All")] + list(Clinic.PROPERTY_MORTGAGE_CHOICES)
    floors_options = [("all", "All")] + list(Clinic.FLOOR_CHOICES)

    # --- FINAL CONTEXT ---
    context = {
        'results': clinics,
        'page_obj': page_obj,
        'current_params': current_params.urlencode(),
        
        'governates': governates,
        'districts': districts,
        'banners' : banners,
        
        'selected_governate_objs': selected_governate_objs,
        'selected_district_objs': selected_district_objs,
        'selected_city_objs': selected_city_objs,
        
        'selected_governate': selected_governate_objs.first() if selected_governate_objs else None,
        'selected_governate_param': selected_governate_params[0] if selected_governate_params else None,
        
        # Fields clinics don't have (for template compatibility):
        'bedrooms': None,
        'bathrooms': None,
        'building': None,
        'land_area_from': None,
        'land_area_to': None,
        'property_type': None,
        
        'furnished': furnished,
        'facade': facade,
        'floors': floors,
        'rental_period': rental_period,
        
        'listing_type': listing_type,
        'lister_type': lister_type,
        'property_mortgage': property_mortgage,
        'payment_method': payment_method,
        
        'main_amenity': selected_main_amenities,
        'additional_amenity': selected_additional_amenities,
        'nearby': selected_nearby,
        
        'surface_area_from': surface_area_from,
        'surface_area_to': surface_area_to,
        'price_from': price_from,
        'price_to': price_to,
        
        'name_query': name_query,
        
        'advertisement': advertisement,
        'main_amenities_list': main_amenities_list,
        'additional_amenities_list': additional_amenities_list,
        'nearby_locations_list': nearby_locations_list,
        
        'current_sort': sort_by,
        'sort_options': [
            {'value': 'newest', 'label': 'Newest First'},
            {'value': 'oldest', 'label': 'Oldest First'},
            {'value': 'price_asc', 'label': 'Price: Low to High'},
            {'value': 'price_desc', 'label': 'Price: High to Low'},
        ],
        
        'listing_types': listing_types,
        'furnished_options': furnished_options,
        'rental_period_options': rental_period_options,
        'lister_type_options': lister_type_options,
        'property_mortgage_options': property_mortgage_options,
        'floors_options': floors_options,
        
        'total_count': total_count,
        'formatted_url_name': request.resolver_match.url_name.replace('_', ' ').title(),
        
        'related_clinics': related_clinics,
        'related_clinics_count': related_clinics_count,
        'show_related': has_filters and len(clinics) == 0,
        
        'selected_main_amenities': selected_main_amenities,
        'selected_additional_amenities': selected_additional_amenities,
        'selected_nearby': selected_nearby,
    }

    # --- AJAX Partial Render ---
    if request.headers.get('X-Requested-With') == 'XMLHttpRequest':
        ajax_context = {
            'results': clinics,
            'page_obj': page_obj,
            'current_params': current_params.urlencode(),
            'total_count': total_count,
            'formatted_url_name': request.resolver_match.url_name.replace("_", " ").title(),
            'show_related': has_filters and len(clinics) == 0,
            'related_clinics': related_clinics,
            'related_clinics_count': related_clinics_count,
            'selected_governate_objs': selected_governate_objs,
            'selected_district_objs': selected_district_objs,
            'selected_city_objs': selected_city_objs,
        }
        return render(request, 'estate/clinic_list_partial.html', ajax_context)

    return render(request, 'estate/clinic.html', context)

