def motorcycle_details(request, id):
    advertisement = Advertisement.objects.filter(
        category=AdvertisementCategory.MOTORS, 
        is_active=True
    )
    motorcycle = get_object_or_404(Motorcycle, id=id)
    track_product_view(request, motorcycle)

    # ========== RECENTLY VIEWED TRACKING ==========
    # Get all images for the motorcycle
    images = []
    if hasattr(motorcycle, 'images') and motorcycle.images.exists():
        images = [{"image": img.image.url} for img in motorcycle.images.all()]
    elif hasattr(motorcycle, 'main_image') and motorcycle.main_image:
        images = [{"image": motorcycle.main_image.url}]
    
    # Get main image URL
    main_image_url = images[0]["image"] if images else "/static/assets/images/resource/default.jpg"
    
    # Convert images to JSON string
    images_json = json.dumps(images)
    
    # Get title
    title = ""
    if hasattr(motorcycle, 'name') and motorcycle.name:
        title = motorcycle.name
    elif hasattr(motorcycle, 'model') and motorcycle.model:
        title = f"{motorcycle.make} {motorcycle.model}" if hasattr(motorcycle, 'make') else motorcycle.model
    else:
        title = f"Motorcycle #{motorcycle.id}"
    
    # Get city name
    city_name = ""
    if hasattr(motorcycle, 'city') and motorcycle.city:
        city_name = motorcycle.city.name
    
    # Get price
    price = motorcycle.price if hasattr(motorcycle, 'price') else 0
    
    # Get brand
    brand = ""
    if hasattr(motorcycle, 'make') and motorcycle.make:
        brand = motorcycle.make.name if hasattr(motorcycle.make, 'name') else str(motorcycle.make)
    
    product_data = {
        'title': title,
        'price': price,
        'main_image': main_image_url,
        'images_json': images_json,
        'city': city_name,
        'url': request.build_absolute_uri(),
        'listing_type': '',
        'display_category': 'Motors',
        'brand': brand,
        'category_type': 'motorcycle',
        'year': motorcycle.year if hasattr(motorcycle, 'year') else '',
        'mileage': motorcycle.mileage if hasattr(motorcycle, 'mileage') else '',
    }
    
    # Track the recently viewed product
    track_recently_viewed(request, str(motorcycle.id), 'motorcycle', product_data)
    # ========== END RECENTLY VIEWED TRACKING ==========

    # Handle report submission
    if request.method == 'POST' and 'report_submit' in request.POST:
        reason = request.POST.get('reason')
        description = request.POST.get('description', '')

        if reason:
            ProductReport.objects.create(
                reporter=request.user if request.user.is_authenticated else None,
                reason=reason,
                description=description,
                content_type=ContentType.objects.get_for_model(motorcycle),
                object_id=motorcycle.id
            )
            messages.success(request, "Thank you for reporting. We'll review it shortly.")
            return redirect(request.path)
        else:
            messages.error(request, "Please select a valid reason for the report.")
    
    # Get governates for filters (if needed)
    governates = Governate.objects.prefetch_related(
        Prefetch('districts', queryset=District.objects.all())
    ).all()
    
    # Check if favorited
    is_favorited = False
    if request.user.is_authenticated:
        content_type = ContentType.objects.get_for_model(motorcycle)
        is_favorited = Favorite.objects.filter(
            user=request.user,
            content_type=content_type,
            object_id=motorcycle.id
        ).exists()
    
    # Get videos if available
    videos = motorcycle.videos.all() if hasattr(motorcycle, 'videos') else []
    
    # Location display string
    location_display = ""
    if motorcycle.city and motorcycle.city.district and motorcycle.city.district.governate:
        location_display = f"{motorcycle.city.name}, {motorcycle.city.district.name}, {motorcycle.city.district.governate.name}"
    
    # ========== GET COORDINATES FOR MAP ==========
    # Try to get coordinates from motorcycle first, then fallback to city, then default
    latitude = None
    longitude = None
    
    # Check if motorcycle has coordinates
    if hasattr(motorcycle, 'latitude') and motorcycle.latitude and hasattr(motorcycle, 'longitude') and motorcycle.longitude:
        latitude = float(motorcycle.latitude)
        longitude = float(motorcycle.longitude)
        print(f"Using motorcycle coordinates: {latitude}, {longitude}")
    
    # Fallback to city coordinates if available
    elif motorcycle.city:
        if hasattr(motorcycle.city, 'latitude') and motorcycle.city.latitude and hasattr(motorcycle.city, 'longitude') and motorcycle.city.longitude:
            latitude = float(motorcycle.city.latitude)
            longitude = float(motorcycle.city.longitude)
            print(f"Using city coordinates: {latitude}, {longitude}")
        else:
            # If city doesn't have coordinates, use geocoding or default
            try:
                from geopy.geocoders import GoogleV3
                geolocator = GoogleV3(api_key='YOUR_GOOGLE_API_KEY')  # Replace with your API key
                location = geolocator.geocode(f"{motorcycle.city.name}, Egypt")
                if location:
                    latitude = location.latitude
                    longitude = location.longitude
                    print(f"Geocoded coordinates: {latitude}, {longitude}")
                else:
                    # Default to Egypt center
                    latitude = 26.8206
                    longitude = 30.8025
            except Exception as e:
                print(f"Geocoding failed: {e}")
                # Default to Egypt center
                latitude = 26.8206
                longitude = 30.8025
    else:
        # Default to Egypt center
        latitude = 26.8206
        longitude = 30.8025
        print("Using default coordinates for Egypt")
    
    # Convert to string for template
    lat_str = str(latitude) if latitude else "26.8206"
    lng_str = str(longitude) if longitude else "30.8025"
    
    # Create map URL
    map_url = f"https://www.google.com/maps?q={lat_str},{lng_str}&hl=en&z=15&output=embed"
    directions_url = f"https://www.google.com/maps/dir/?api=1&destination={lat_str},{lng_str}"

    return render(request, 'Motors/motorcycle_details.html', {
        'motorcycle': motorcycle,
        'advertisement': advertisement,
        'governates': governates,
        'main_image_url': main_image_url,
        'images_json': images_json,
        'images': images,
        'videos': videos,
        'location_display': location_display,
        'is_favorited': is_favorited,
        'favorite_product_type': 'motorcycle',
        # Location data for map
        'latitude': lat_str,
        'longitude': lng_str,
        'map_url': map_url,
        'directions_url': directions_url,
        'location_name': location_display or motorcycle.city.name if motorcycle.city else "Location",
    })

# Define the model mapping at the top of your views file
MOTORCYCLE_MODEL_MAPPING = {
    'motorcycle': Motorcycle,
    'scooter': Scooter,
    'quadbike': Quadbikes,
    'helmetclothes': HelmetClothes,
}

def motorcyclemain(request):

    # --- LOCATION & GENERAL SETUP ---
    governates = Governate.objects.prefetch_related(
        Prefetch('districts', queryset=District.objects.all())
    ).all()

    advertisement = Advertisement.objects.filter(
        category=AdvertisementCategory.MOTORS, 
        is_active=True
    )

    # --- FILTER PARAMETERS (aligned with vehiclerent style) ---
    selected_governate_params = request.GET.getlist('governate')
    selected_district_params = request.GET.getlist('district')
    selected_cities = request.GET.getlist('city')

    make = request.GET.get('make')
    name = request.GET.get('name')
    trim = request.GET.get('trim')
    condition = request.GET.get('condition')
    price_from = request.GET.get('price_from')
    price_to = request.GET.get('price_to')
    year_from = request.GET.get('year_from')
    year_to = request.GET.get('year_to')
    kilometer_ranges = request.GET.get('kilometer_range')
    listing_type = request.GET.get('listing_type')
    lister_type = request.GET.get('lister_type')
    body_type = request.GET.get('body_type')
    banners = Banner.objects.filter(category='motors', is_active=True)
    payment_method = request.GET.get('payment_method')
    rental_period = request.GET.get('rental_period')
    engine_capacity_ranges = request.GET.get('engine_capacity')
    features = request.GET.getlist('features')
    product_type = request.GET.get('product_type')
    model_type = request.GET.get('model_type')
    sort_by = request.GET.get('sort', 'newest')

    # --- CHECK IF ANY FILTERS APPLIED (aligned format) ---
    has_filters = any([
        selected_governate_params, selected_district_params, selected_cities,
        make, name, trim, condition, price_from, price_to, year_from, year_to,
        kilometer_ranges, listing_type, lister_type, body_type,
        payment_method, rental_period, engine_capacity_ranges, features,
        product_type, model_type
    ])

    # --- SELECTED LOCATIONS FOR DISPLAY (aligned with vehiclerent) ---
    selected_governate_objs = Governate.objects.filter(id__in=selected_governate_params)
    selected_district_objs = District.objects.filter(id__in=selected_district_params)
    selected_city_objs = Cities.objects.filter(id__in=selected_cities)
    
    selected_governate = selected_governate_objs.first() if selected_governate_objs else None
    
    districts = None
    if selected_governate_params:
        districts = District.objects.filter(governate_id__in=selected_governate_params)

    cutoff_date = timezone.now() - timedelta(days=45)

    # --- MAIN RESULT LIST ---
    combined_results = []
    model_counts = {}
    total_count = 0

    # -----------------------------------------------------------
    # MAIN LOOP — PROCESS ALL MODELS
    # -----------------------------------------------------------

    for model_name, model_class in MOTORCYCLE_MODEL_MAPPING.items():

        if model_type and model_type != model_name:
            continue

        queryset = model_class.objects.filter(
            status='approved',
            created_at__gte=cutoff_date
        ).select_related('city')

        # --- LOCATION FILTERING (aligned with vehiclerent pattern) ---
        if selected_cities:
            queryset = queryset.filter(city_id__in=selected_cities)
        elif selected_district_params:
            cities = Cities.objects.filter(district_id__in=selected_district_params)
            queryset = queryset.filter(city_id__in=cities)
        elif selected_governate_params:
            cities = Cities.objects.filter(district__governate_id__in=selected_governate_params)
            queryset = queryset.filter(city_id__in=cities)

        # --- MODEL–SPECIFIC FILTERING ---
        if model_name == "motorcycle":
            if make:
                queryset = queryset.filter(make__in=make.split(','))
            if name:
                queryset = queryset.filter(model__in=name.split(','))
            if trim:
                queryset = queryset.filter(trim__iexact=trim)
            if body_type:
                queryset = queryset.filter(body_type__in=body_type.split(','))
            if features:
                for feature in features:
                    queryset = queryset.filter(features__id=feature)

        elif model_name == "scooter":
            if make:
                queryset = queryset.filter(make__in=make.split(','))
            if name:
                queryset = queryset.filter(model__in=name.split(','))

        elif model_name == "quadbike":
            if product_type:
                queryset = queryset.filter(types=product_type)

        elif model_name == "helmetclothes":
            if product_type:
                queryset = queryset.filter(helmetcloth_type=product_type)

        # --- COMMON FILTERS ---
        if condition:
            queryset = queryset.filter(condition=condition)

        if listing_type and hasattr(model_class, 'listing_type'):
            queryset = queryset.filter(listing_type=listing_type)

        if lister_type and hasattr(model_class, 'lister_type'):
            queryset = queryset.filter(lister_type=lister_type)

        if payment_method and hasattr(model_class, 'payment_method'):
            queryset = queryset.filter(payment_method=payment_method)

        if rental_period and hasattr(model_class, 'rental_period'):
            queryset = queryset.filter(rental_period__in=rental_period.split(','))

        # --- PRICE FILTER ---
        try:
            if price_from:
                queryset = queryset.filter(price__gte=float(price_from))
            if price_to:
                queryset = queryset.filter(price__lte=float(price_to))
        except (ValueError, TypeError):
            pass

        # --- YEAR FILTER ---
        if hasattr(model_class, 'year'):
            try:
                if year_from:
                    queryset = queryset.filter(year__gte=int(year_from))
                if year_to:
                    queryset = queryset.filter(year__lte=int(year_to))
            except (ValueError, TypeError):
                pass

        # --- KILOMETER FILTER ---
        if hasattr(model_class, 'kilometers'):
            if kilometer_ranges:
                km_values = kilometer_ranges.split(',')
                km_query = Q()
                for km_range in km_values:
                    km_query |= Q(kilometers=km_range)
                queryset = queryset.filter(km_query)

        # --- ENGINE CAPACITY ---
        if hasattr(model_class, 'engine_capacity') and engine_capacity_ranges:
            engine_query = Q()
            for r in engine_capacity_ranges.split(','):
                try:
                    start, end = (r.split('-') + [None])[:2]
                    if end:
                        engine_query |= Q(engine_capacity__gte=float(start), engine_capacity__lte=float(end))
                    else:
                        engine_query |= Q(engine_capacity__gte=float(start))
                except (ValueError, TypeError):
                    continue
            queryset = queryset.filter(engine_query)

        # --- ADD RESULTS ---
        items = list(queryset)
        for item in items:
            if hasattr(item, 'images'):
                imgs = item.images.all()
            elif hasattr(item, 'motorcycleimage_set'):
                imgs = item.motorcycleimage_set.all()
            elif hasattr(item, 'scooterimage_set'):
                imgs = item.scooterimage_set.all()
            else:
                imgs = []
            
            item.images_json = json.dumps([img.image.url for img in imgs])
            item.model_type = model_name

        combined_results.extend(items)
        model_counts[model_name] = len(items)
        total_count += len(items)

    # --- BOOST INFO FOR MAIN RESULTS ---
    if combined_results:
        items_by_type = {}
        for item in combined_results:
            listing_type = item.model_type
            if listing_type == 'quadbike':
                listing_type = 'quadbikes'
            items_by_type.setdefault(listing_type, []).append(item)

        boost_dict = {}
        for listing_type, items_list in items_by_type.items():
            ids = [it.id for it in items_list]
            boosts = BoostUsage.objects.filter(
                listing_type=listing_type,
                listing_id__in=ids,
                is_active=True
            )
            for b in boosts:
                boost_dict[(b.listing_type, b.listing_id)] = b

        for item in combined_results:
            lt = item.model_type
            if lt == 'quadbike':
                lt = 'quadbikes'
            key = (lt, item.id)
            boost = boost_dict.get(key)
            if boost and boost.is_boost_active():
                item.is_boosted = True
                item.boost_days_left = boost.days_remaining
            else:
                item.is_boosted = False
                item.boost_days_left = 0

    # -----------------------------------------------------------
    # FIXED: RELATED PRODUCTS (45‑day cutoff + boost info)
    # -----------------------------------------------------------
    related_motorcycle_products = []
    if has_filters and not combined_results:

        # Fetch ALL approved items, but **respect the 45‑day expiry**
        related_qs = []
        for model_name, model_class in MOTORCYCLE_MODEL_MAPPING.items():
            related_qs.extend(
                list(model_class.objects.filter(
                    status='approved',
                    created_at__gte=cutoff_date      # ← 45‑day limit added
                ))
            )

        # --- SORT RELATED PRODUCTS ---
        if sort_by == 'price_asc':
            related_qs.sort(key=lambda x: x.price or 0)
        elif sort_by == 'price_desc':
            related_qs.sort(key=lambda x: x.price or 0, reverse=True)
        elif sort_by == 'oldest':
            related_qs.sort(key=lambda x: x.created_at)
        else:
            related_qs.sort(key=lambda x: x.created_at, reverse=True)

        # Take only top 6
        related_motorcycle_products = related_qs[:6]

        # Add boost info for related products
        if related_motorcycle_products:
            # Group by type for boost lookup
            rel_by_type = {}
            for item in related_motorcycle_products:
                lt = next(
                    (n for n, cls in MOTORCYCLE_MODEL_MAPPING.items() if isinstance(item, cls)),
                    "motorcycle"
                )
                item.model_type = lt
                if lt == 'quadbike':
                    lt = 'quadbikes'
                rel_by_type.setdefault(lt, []).append(item)

            rel_boost_dict = {}
            for lt, items_list in rel_by_type.items():
                ids = [it.id for it in items_list]
                boosts = BoostUsage.objects.filter(
                    listing_type=lt,
                    listing_id__in=ids,
                    is_active=True
                )
                for b in boosts:
                    rel_boost_dict[(b.listing_type, b.listing_id)] = b

            for item in related_motorcycle_products:
                lt = item.model_type
                if lt == 'quadbike':
                    lt = 'quadbikes'
                key = (lt, item.id)
                boost = rel_boost_dict.get(key)
                if boost and boost.is_boost_active():
                    item.is_boosted = True
                    item.boost_days_left = boost.days_remaining
                else:
                    item.is_boosted = False
                    item.boost_days_left = 0

                # Attach images JSON (already done for main results, but needed here)
                if hasattr(item, 'images'):
                    imgs = item.images.all()
                elif hasattr(item, 'motorcycleimage_set'):
                    imgs = item.motorcycleimage_set.all()
                elif hasattr(item, 'scooterimage_set'):
                    imgs = item.scooterimage_set.all()
                else:
                    imgs = []
                item.images_json = json.dumps([img.image.url for img in imgs])

    # --- SORT MAIN RESULTS ---
    if sort_by == 'price_asc':
        combined_results.sort(key=lambda x: x.price or 0)
    elif sort_by == 'price_desc':
        combined_results.sort(key=lambda x: x.price or 0, reverse=True)
    elif sort_by == 'oldest':
        combined_results.sort(key=lambda x: x.created_at)
    else:
        combined_results.sort(key=lambda x: x.created_at, reverse=True)

    # --- PAGINATION ---
    current_params = request.GET.copy()
    current_params.pop('page', None)

    paginator = Paginator(combined_results, 12)
    page_number = request.GET.get('page')
    try:
        page_obj = paginator.get_page(page_number)
    except EmptyPage:
        page_obj = paginator.get_page(paginator.num_pages)

    # --- FINAL CONTEXT ---
    context = {
        'results': combined_results,
        'page_obj': page_obj,
        'current_params': current_params.urlencode(),

        'related_motorcycle_products': related_motorcycle_products,
        'show_related': has_filters and not combined_results,

        'governates': governates,
        'districts': districts,
        'selected_governate_objs': selected_governate_objs,
        'selected_district_objs': selected_district_objs,
        'selected_city_objs': selected_city_objs,
        'selected_governate': selected_governate,
        'selected_governate_param': selected_governate_params[0] if selected_governate_params else None,

        'make': make,
        'name': name,
        'trim': trim,
        'condition': condition,
        'price_from': price_from,
        'price_to': price_to,
        'year_from': year_from,
        'year_to': year_to,
        'kilometer_ranges': kilometer_ranges,
        'body_type': body_type,
        'listing_type': listing_type,
        'engine_capacity_ranges': engine_capacity_ranges,
        'payment_method': payment_method,
        'rental_period': rental_period,
        'product_type': product_type,
        'features': features,
        'model_type': model_type,
        'banners': banners,

        'current_sort': sort_by,
        'advertisement': advertisement,
        'total_count': total_count,
        'model_counts': model_counts,
        'model_mapping': MOTORCYCLE_MODEL_MAPPING,
        
        'sort_options': [
            {'value': 'newest', 'label': 'Newest First'},
            {'value': 'oldest', 'label': 'Oldest First'},
            {'value': 'price_asc', 'label': 'Price: Low to High'},
            {'value': 'price_desc', 'label': 'Price: High to Low'},
        ],
        
        'formatted_url_name': "Motorcycles",
    }

    # AJAX
    if request.headers.get('X-Requested-With') == 'XMLHttpRequest':
        return render(request, 'Motors/motorcyclemain_list_partial.html', context)

    return render(request, 'Motors/motorcyclemain.html', context)
