def scooter_details(request, id):
    advertisement = Advertisement.objects.filter(
        category=AdvertisementCategory.MOTORS, 
        is_active=True
    )
    scooter = get_object_or_404(Scooter, id=id)
    track_product_view(request, scooter)

    # ========== RECENTLY VIEWED TRACKING ==========
    # Get all images for the scooter
    images = []
    if hasattr(scooter, 'images') and scooter.images.exists():
        images = [{"image": img.image.url} for img in scooter.images.all()]
    elif hasattr(scooter, 'main_image') and scooter.main_image:
        images = [{"image": scooter.main_image.url}]
    
    # Get main image URL
    main_image_url = images[0]["image"] if images else "/static/assets/images/resource/default.jpg"
    
    # Convert images to JSON string
    images_json = json.dumps(images)
    
    # Get title
    title = ""
    if hasattr(scooter, 'name') and scooter.name:
        title = scooter.name
    elif hasattr(scooter, 'model') and scooter.model:
        title = f"{scooter.make} {scooter.model}" if hasattr(scooter, 'make') else scooter.model
    else:
        title = f"Scooter #{scooter.id}"
    
    # Get city name
    city_name = ""
    if hasattr(scooter, 'city') and scooter.city:
        city_name = scooter.city.name
    
    # Get price
    price = scooter.price if hasattr(scooter, 'price') else 0
    
    # Get brand
    brand = ""
    if hasattr(scooter, 'make') and scooter.make:
        brand = scooter.make.name if hasattr(scooter.make, 'name') else str(scooter.make)
    
    product_data = {
        'title': title,
        'price': price,
        'main_image': main_image_url,
        'images_json': images_json,
        'city': city_name,
        'url': request.build_absolute_uri(),
        'listing_type': '',
        'display_category': 'Motors',
        'brand': brand,
        'category_type': 'scooter',
        'year': scooter.year if hasattr(scooter, 'year') else '',
        'mileage': scooter.mileage if hasattr(scooter, 'mileage') else '',
    }
    
    # Track the recently viewed product
    track_recently_viewed(request, str(scooter.id), 'scooter', product_data)
    # ========== END RECENTLY VIEWED TRACKING ==========

    # Handle report submission
    if request.method == 'POST' and 'report_submit' in request.POST:
        reason = request.POST.get('reason')
        description = request.POST.get('description', '')

        if reason:
            ProductReport.objects.create(
                reporter=request.user if request.user.is_authenticated else None,
                reason=reason,
                description=description,
                content_type=ContentType.objects.get_for_model(scooter),
                object_id=scooter.id
            )
            messages.success(request, "Thank you for reporting. We'll review it shortly.")
            return redirect(request.path)
        else:
            messages.error(request, "Please select a valid reason for the report.")
    
    # Get governates for filters (if needed)
    governates = Governate.objects.prefetch_related(
        Prefetch('districts', queryset=District.objects.all())
    ).all()
    
    # Check if favorited
    is_favorited = False
    if request.user.is_authenticated:
        content_type = ContentType.objects.get_for_model(scooter)
        is_favorited = Favorite.objects.filter(
            user=request.user,
            content_type=content_type,
            object_id=scooter.id
        ).exists()
    
    # Get videos if available
    videos = scooter.videos.all() if hasattr(scooter, 'videos') else []
    
    # Location display string
    location_display = ""
    if scooter.city and scooter.city.district and scooter.city.district.governate:
        location_display = f"{scooter.city.name}, {scooter.city.district.name}, {scooter.city.district.governate.name}"
    
    # ========== GET COORDINATES FOR MAP ==========
    # Try to get coordinates from scooter first, then fallback to city, then default
    latitude = None
    longitude = None
    
    # Check if scooter has coordinates
    if hasattr(scooter, 'latitude') and scooter.latitude and hasattr(scooter, 'longitude') and scooter.longitude:
        latitude = float(scooter.latitude)
        longitude = float(scooter.longitude)
        print(f"Using scooter coordinates: {latitude}, {longitude}")
    
    # Fallback to city coordinates if available
    elif scooter.city:
        if hasattr(scooter.city, 'latitude') and scooter.city.latitude and hasattr(scooter.city, 'longitude') and scooter.city.longitude:
            latitude = float(scooter.city.latitude)
            longitude = float(scooter.city.longitude)
            print(f"Using city coordinates: {latitude}, {longitude}")
        else:
            # If city doesn't have coordinates, use geocoding or default
            try:
                from geopy.geocoders import GoogleV3
                geolocator = GoogleV3(api_key='YOUR_GOOGLE_API_KEY')  # Replace with your API key
                location = geolocator.geocode(f"{scooter.city.name}, Egypt")
                if location:
                    latitude = location.latitude
                    longitude = location.longitude
                    print(f"Geocoded coordinates: {latitude}, {longitude}")
                else:
                    # Default to Egypt center
                    latitude = 26.8206
                    longitude = 30.8025
            except Exception as e:
                print(f"Geocoding failed: {e}")
                # Default to Egypt center
                latitude = 26.8206
                longitude = 30.8025
    else:
        # Default to Egypt center
        latitude = 26.8206
        longitude = 30.8025
        print("Using default coordinates for Egypt")
    
    # Convert to string for template
    lat_str = str(latitude) if latitude else "26.8206"
    lng_str = str(longitude) if longitude else "30.8025"
    
    # Create map URL
    map_url = f"https://www.google.com/maps?q={lat_str},{lng_str}&hl=en&z=15&output=embed"
    directions_url = f"https://www.google.com/maps/dir/?api=1&destination={lat_str},{lng_str}"

    return render(request, 'Motors/scooter_details.html', {
        'scooter': scooter,
        'advertisement': advertisement,
        'governates': governates,
        'main_image_url': main_image_url,
        'images_json': images_json,
        'images': images,
        'videos': videos,
        'location_display': location_display,
        'is_favorited': is_favorited,
        'favorite_product_type': 'scooter',
        # Location data for map
        'latitude': lat_str,
        'longitude': lng_str,
        'map_url': map_url,
        'directions_url': directions_url,
        'location_name': location_display or scooter.city.name if scooter.city else "Location",
    })

