def tiresandcaps_details(request, id):
    advertisement = Advertisement.objects.filter(
        category=AdvertisementCategory.MOTORS, 
        is_active=True
    )
    tiresandcaps = get_object_or_404(TiresAndCaps, id=id)
    track_product_view(request, tiresandcaps)

    # ========== RECENTLY VIEWED TRACKING ==========
    # Get all images for the tires and caps
    images = []
    if hasattr(tiresandcaps, 'images') and tiresandcaps.images.exists():
        images = [{"image": img.image.url} for img in tiresandcaps.images.all()]
    elif hasattr(tiresandcaps, 'main_image') and tiresandcaps.main_image:
        images = [{"image": tiresandcaps.main_image.url}]
    
    # Get main image URL
    main_image_url = images[0]["image"] if images else "/static/assets/images/resource/default.jpg"
    
    # Convert images to JSON string
    images_json = json.dumps(images)
    
    # Get title
    title = ""
    if hasattr(tiresandcaps, 'name') and tiresandcaps.name:
        title = tiresandcaps.name
    elif hasattr(tiresandcaps, 'title') and tiresandcaps.title:
        title = tiresandcaps.title
    else:
        title = f"Tires & Caps #{tiresandcaps.id}"
    
    # Get city name
    city_name = ""
    if hasattr(tiresandcaps, 'city') and tiresandcaps.city:
        city_name = tiresandcaps.city.name
    
    # Get price
    price = tiresandcaps.price if hasattr(tiresandcaps, 'price') else 0
    
    # Get brand
    brand = ""
    if hasattr(tiresandcaps, 'brand') and tiresandcaps.brand:
        brand = tiresandcaps.brand.name if hasattr(tiresandcaps.brand, 'name') else str(tiresandcaps.brand)
    
    product_data = {
        'title': title,
        'price': price,
        'main_image': main_image_url,
        'images_json': images_json,
        'city': city_name,
        'url': request.build_absolute_uri(),
        'listing_type': '',
        'display_category': 'Motors',
        'brand': brand,
        'category_type': 'tiresandcaps',
        'year': tiresandcaps.year if hasattr(tiresandcaps, 'year') else '',
    }
    
    # Track the recently viewed product
    track_recently_viewed(request, str(tiresandcaps.id), 'tiresandcaps', product_data)
    # ========== END RECENTLY VIEWED TRACKING ==========

    # Handle report submission
    if request.method == 'POST' and 'report_submit' in request.POST:
        reason = request.POST.get('reason')
        description = request.POST.get('description', '')

        if reason:
            ProductReport.objects.create(
                reporter=request.user if request.user.is_authenticated else None,
                reason=reason,
                description=description,
                content_type=ContentType.objects.get_for_model(tiresandcaps),
                object_id=tiresandcaps.id
            )
            messages.success(request, "Thank you for reporting. We'll review it shortly.")
            return redirect(request.path)
        else:
            messages.error(request, "Please select a valid reason for the report.")
    
    # Get governates for filters (if needed)
    governates = Governate.objects.prefetch_related(
        Prefetch('districts', queryset=District.objects.all())
    ).all()
    
    # Check if favorited
    is_favorited = False
    if request.user.is_authenticated:
        content_type = ContentType.objects.get_for_model(tiresandcaps)
        is_favorited = Favorite.objects.filter(
            user=request.user,
            content_type=content_type,
            object_id=tiresandcaps.id
        ).exists()
    
    # Get videos if available
    videos = tiresandcaps.videos.all() if hasattr(tiresandcaps, 'videos') else []
    
    # Location display string
    location_display = ""
    if tiresandcaps.city and tiresandcaps.city.district and tiresandcaps.city.district.governate:
        location_display = f"{tiresandcaps.city.name}, {tiresandcaps.city.district.name}, {tiresandcaps.city.district.governate.name}"
    
    # ========== GET COORDINATES FOR MAP ==========
    # Try to get coordinates from tiresandcaps first, then fallback to city, then default
    latitude = None
    longitude = None
    
    # Check if tiresandcaps has coordinates
    if hasattr(tiresandcaps, 'latitude') and tiresandcaps.latitude and hasattr(tiresandcaps, 'longitude') and tiresandcaps.longitude:
        latitude = float(tiresandcaps.latitude)
        longitude = float(tiresandcaps.longitude)
        print(f"Using tiresandcaps coordinates: {latitude}, {longitude}")
    
    # Fallback to city coordinates if available
    elif tiresandcaps.city:
        if hasattr(tiresandcaps.city, 'latitude') and tiresandcaps.city.latitude and hasattr(tiresandcaps.city, 'longitude') and tiresandcaps.city.longitude:
            latitude = float(tiresandcaps.city.latitude)
            longitude = float(tiresandcaps.city.longitude)
            print(f"Using city coordinates: {latitude}, {longitude}")
        else:
            # If city doesn't have coordinates, use geocoding or default
            try:
                from geopy.geocoders import GoogleV3
                geolocator = GoogleV3(api_key='YOUR_GOOGLE_API_KEY')  # Replace with your API key
                location = geolocator.geocode(f"{tiresandcaps.city.name}, Egypt")
                if location:
                    latitude = location.latitude
                    longitude = location.longitude
                    print(f"Geocoded coordinates: {latitude}, {longitude}")
                else:
                    # Default to Egypt center
                    latitude = 26.8206
                    longitude = 30.8025
            except Exception as e:
                print(f"Geocoding failed: {e}")
                # Default to Egypt center
                latitude = 26.8206
                longitude = 30.8025
    else:
        # Default to Egypt center
        latitude = 26.8206
        longitude = 30.8025
        print("Using default coordinates for Egypt")
    
    # Convert to string for template
    lat_str = str(latitude) if latitude else "26.8206"
    lng_str = str(longitude) if longitude else "30.8025"
    
    # Create map URL
    map_url = f"https://www.google.com/maps?q={lat_str},{lng_str}&hl=en&z=15&output=embed"
    directions_url = f"https://www.google.com/maps/dir/?api=1&destination={lat_str},{lng_str}"

    return render(request, 'Motors/tiresandcaps_details.html', {
        'tiresandcaps': tiresandcaps,
        'advertisement': advertisement,
        'governates': governates,
        'main_image_url': main_image_url,
        'images_json': images_json,
        'images': images,
        'videos': videos,
        'location_display': location_display,
        'is_favorited': is_favorited,
        'favorite_product_type': 'tiresandcaps',
        # Location data for map
        'latitude': lat_str,
        'longitude': lng_str,
        'map_url': map_url,
        'directions_url': directions_url,
        'location_name': location_display or tiresandcaps.city.name if tiresandcaps.city else "Location",
    })

def helmetclothes(request):
    # Get all governates with their districts
    governates = Governate.objects.prefetch_related(
        Prefetch('districts', queryset=District.objects.all())
    ).all()
    
    advertisement = Advertisement.objects.filter(
        category=AdvertisementCategory.REAL_ESTATE, 
        is_active=True
    )

    # Get all filter parameters from request - UPDATED for multiple selections
    selected_governate_params = request.GET.getlist('governate')
    selected_district_params = request.GET.getlist('district')
    selected_cities = request.GET.getlist('city')
    make = request.GET.get('make')
    name = request.GET.get('name')
    trim = request.GET.get('trim')
    condition = request.GET.get('condition')
    helmetcloth_type = request.GET.get('helmetcloth_type')
    price_from = request.GET.get('price_from')
    price_to = request.GET.get('price_to')
    year_from = request.GET.get('year_from')
    year_to = request.GET.get('year_to')
    kilometer_ranges = request.GET.get('kilometer_range')
    listing_type = request.GET.get('listing_type')
    lister_type = request.GET.get('lister_type')
    payment_method = request.GET.get('payment_method')
    banners = Banner.objects.filter(category='motors', is_active=True)
    rental_period = request.GET.get('rental_period')
    engine_capacity_ranges = request.GET.get('engine_capacity')
    features = request.GET.getlist('features')
    sort_by = request.GET.get('sort', 'newest')

    # Check if any filters are applied
    has_filters = any([
        selected_governate_params, selected_district_params, selected_cities,
        make, name, trim, condition, helmetcloth_type, price_from, price_to,
        year_from, year_to, kilometer_ranges, listing_type,
        lister_type, payment_method, rental_period, engine_capacity_ranges, features
    ])

    # Initialize selected objects for display - UPDATED for multiple selections
    selected_governate_objs = Governate.objects.filter(id__in=selected_governate_params) if selected_governate_params else []
    selected_district_objs = District.objects.filter(id__in=selected_district_params) if selected_district_params else []
    selected_city_objs = Cities.objects.filter(id__in=selected_cities) if selected_cities else []

    # For backward compatibility - single selection display
    selected_governate = selected_governate_objs.first() if selected_governate_objs else None

    # Base queryset for helmet clothes
    cutoff_date = timezone.now() - timedelta(days=45)
    queryset = HelmetClothes.objects.filter(
        status='approved',
        created_at__gte=cutoff_date
    ).select_related('city')

    # Store original queryset for related products
    original_queryset = queryset

    # Apply location filters - UPDATED for multiple selections
    if selected_cities:
        queryset = queryset.filter(city_id__in=selected_cities)
    elif selected_district_params:
        cities = Cities.objects.filter(district_id__in=selected_district_params)
        queryset = queryset.filter(city_id__in=cities.values_list('id', flat=True))
    elif selected_governate_params:
        cities = Cities.objects.filter(district__governate_id__in=selected_governate_params)
        queryset = queryset.filter(city_id__in=cities.values_list('id', flat=True))

    # Apply helmet clothes specific filters
    if make:
        queryset = queryset.filter(make__in=make.split(','))
    if name:
        queryset = queryset.filter(model__in=name.split(','))
    if trim:
        queryset = queryset.filter(trim__iexact=trim)
    if features:
        for feature in features:
            queryset = queryset.filter(features__id=feature)

    # Common filters
    if condition:
        queryset = queryset.filter(condition__in=condition.split(','))
    if listing_type:
        queryset = queryset.filter(listing_type=listing_type)
    if lister_type and lister_type != "all":
        queryset = queryset.filter(lister_type=lister_type)
    if payment_method:
        queryset = queryset.filter(payment_method=payment_method)
    if helmetcloth_type:
        queryset = queryset.filter(helmetcloth_type__in=helmetcloth_type.split(','))
    if rental_period:
        queryset = queryset.filter(rental_period__in=rental_period.split(','))

    # Price range
    try:
        if price_from:
            queryset = queryset.filter(price__gte=int(price_from))
        if price_to:
            queryset = queryset.filter(price__lte=int(price_to))
    except (ValueError, TypeError):
        pass

    # Year range
    if year_from:
        queryset = queryset.filter(year__gte=year_from)
    if year_to:
        queryset = queryset.filter(year__lte=year_to)

    if kilometer_ranges:
        # Handle multiple kilometer ranges from checkboxes
        km_values = kilometer_ranges.split(',')
        km_query = Q()
        for km_range in km_values:
            km_query |= Q(kilometers=km_range)
        queryset = queryset.filter(km_query)

    # Engine capacity filter
    if engine_capacity_ranges:
        engine_filters = engine_capacity_ranges.split(',')
        engine_query = Q()
        for range_str in engine_filters:
            if range_str == '0-1499':
                engine_query |= Q(engine_capacity__gte=0, engine_capacity__lte=1499)
            elif range_str == '1500-1999':
                engine_query |= Q(engine_capacity__gte=1500, engine_capacity__lte=1999)
            elif range_str == '2000-2499':
                engine_query |= Q(engine_capacity__gte=2000, engine_capacity__lte=2499)
            elif range_str == '2500+':
                engine_query |= Q(engine_capacity__gte=2500)
        queryset = queryset.filter(engine_query)

    # Convert queryset to list to allow Python processing
    helmetclothes = list(queryset)

    # Add boost information to each helmet/clothes item
    item_ids = [h.id for h in helmetclothes]
    boosts = BoostUsage.objects.filter(
        listing_type='helmetclothes',
        listing_id__in=item_ids,
        is_active=True
    )
    boost_dict = {b.listing_id: b for b in boosts}

    for h in helmetclothes:
        boost = boost_dict.get(h.id)
        if boost and boost.is_boost_active():
            h.is_boosted = True
            h.boost_days_left = boost.days_remaining
        else:
            h.is_boosted = False
            h.boost_days_left = 0
    
    # Process main results images
    for item in helmetclothes:
        item.images_json = json.dumps([img.image.url for img in item.images.all()])

    total_count = len(helmetclothes)

    # ========== FIXED: RELATED PRODUCTS (45-day cutoff + boost info) ==========
    related_helmetclothes = []
    related_helmetclothes_count = 0
    if has_filters and len(helmetclothes) == 0:
        # Apply 45-day expiry to related products, same as main queryset
        related_queryset = HelmetClothes.objects.filter(
            status='approved',
            created_at__gte=cutoff_date   # <-- added cutoff date
        )
        
        # Convert to list for Python sorting
        related_helmetclothes = list(related_queryset)
        
        # Apply sorting to related helmet clothes
        if sort_by == 'price_asc':
            related_helmetclothes.sort(key=lambda x: x.price or 0)
        elif sort_by == 'price_desc':
            related_helmetclothes.sort(key=lambda x: x.price or 0, reverse=True)
        elif sort_by == 'oldest':
            related_helmetclothes.sort(key=lambda x: x.created_at)
        else:  # newest (default)
            related_helmetclothes.sort(key=lambda x: x.created_at, reverse=True)
        
        # Take only 6 after sorting
        related_helmetclothes = related_helmetclothes[:6]
        related_helmetclothes_count = len(related_helmetclothes)
        
        # Add boost information for related items
        if related_helmetclothes:
            rel_ids = [r.id for r in related_helmetclothes]
            rel_boosts = BoostUsage.objects.filter(
                listing_type='helmetclothes',
                listing_id__in=rel_ids,
                is_active=True
            )
