    title = ""
    if hasattr(quadbikes, 'name') and quadbikes.name:
        title = quadbikes.name
    elif hasattr(quadbikes, 'model') and quadbikes.model:
        title = f"{quadbikes.make} {quadbikes.model}" if hasattr(quadbikes, 'make') else quadbikes.model
    else:
        title = f"Quadbike #{quadbikes.id}"
    
    # Get city name
    city_name = ""
    if hasattr(quadbikes, 'city') and quadbikes.city:
        city_name = quadbikes.city.name
    
