def heavyvehicle_details(request, id):
    heavyvehicle = get_object_or_404(HeavyVehicle, id=id)
    advertisement = Advertisement.objects.filter(
        category=AdvertisementCategory.MOTORS, 
        is_active=True
    )
    track_product_view(request, heavyvehicle)

    # ========== RECENTLY VIEWED TRACKING ==========
    # Get all images for the heavy vehicle
    images = []
    if hasattr(heavyvehicle, 'images') and heavyvehicle.images.exists():
        images = [{"image": img.image.url} for img in heavyvehicle.images.all()]
    elif hasattr(heavyvehicle, 'main_image') and heavyvehicle.main_image:
        images = [{"image": heavyvehicle.main_image.url}]
    
    # Get main image URL
    main_image_url = images[0]["image"] if images else "/static/assets/images/resource/default.jpg"
    
    # Convert images to JSON string
    images_json = json.dumps(images)
    
    # Get title
    title = ""
    if hasattr(heavyvehicle, 'name') and heavyvehicle.name:
        title = heavyvehicle.name
    elif hasattr(heavyvehicle, 'model') and heavyvehicle.model:
        title = f"{heavyvehicle.make} {heavyvehicle.model}" if hasattr(heavyvehicle, 'make') else heavyvehicle.model
    else:
        title = f"Heavy Vehicle #{heavyvehicle.id}"
    
    # Get city name
    city_name = ""
    if hasattr(heavyvehicle, 'city') and heavyvehicle.city:
        city_name = heavyvehicle.city.name
    
    # Get price
    price = heavyvehicle.price if hasattr(heavyvehicle, 'price') else 0
    
    # Get brand
    brand = ""
    if hasattr(heavyvehicle, 'make') and heavyvehicle.make:
        brand = heavyvehicle.make.name if hasattr(heavyvehicle.make, 'name') else str(heavyvehicle.make)
    
    product_data = {
        'title': title,
        'price': price,
        'main_image': main_image_url,
        'images_json': images_json,
        'city': city_name,
        'url': request.build_absolute_uri(),
        'listing_type': '',
        'display_category': 'Motors',
        'brand': brand,
        'category_type': 'heavyvehicle',
        'year': heavyvehicle.year if hasattr(heavyvehicle, 'year') else '',
    }
    
    # Track the recently viewed product
    track_recently_viewed(request, str(heavyvehicle.id), 'heavyvehicle', product_data)
    # ========== END RECENTLY VIEWED TRACKING ==========

    # Handle report submission
    if request.method == 'POST' and 'report_submit' in request.POST:
        reason = request.POST.get('reason')
        description = request.POST.get('description', '')

        if reason:
            ProductReport.objects.create(
                reporter=request.user if request.user.is_authenticated else None,
                reason=reason,
                description=description,
                content_type=ContentType.objects.get_for_model(heavyvehicle),
                object_id=heavyvehicle.id
            )
            messages.success(request, "Thank you for reporting. We'll review it shortly.")
            return redirect(request.path)
        else:
            messages.error(request, "Please select a valid reason for the report.")
    
    # Get governates for filters (if needed)
    governates = Governate.objects.prefetch_related(
        Prefetch('districts', queryset=District.objects.all())
    ).all()
    
    # Check if favorited
    is_favorited = False
    if request.user.is_authenticated:
        content_type = ContentType.objects.get_for_model(heavyvehicle)
        is_favorited = Favorite.objects.filter(
            user=request.user,
            content_type=content_type,
            object_id=heavyvehicle.id
        ).exists()
    
    # Get videos if available
    videos = heavyvehicle.videos.all() if hasattr(heavyvehicle, 'videos') else []
    
    # Location display string
    location_display = ""
    if heavyvehicle.city and heavyvehicle.city.district and heavyvehicle.city.district.governate:
        location_display = f"{heavyvehicle.city.name}, {heavyvehicle.city.district.name}, {heavyvehicle.city.district.governate.name}"
    
    # ========== GET COORDINATES FOR MAP ==========
    # Try to get coordinates from heavyvehicle first, then fallback to city, then default
    latitude = None
    longitude = None
    
    # Check if heavyvehicle has coordinates
    if hasattr(heavyvehicle, 'latitude') and heavyvehicle.latitude and hasattr(heavyvehicle, 'longitude') and heavyvehicle.longitude:
        latitude = float(heavyvehicle.latitude)
        longitude = float(heavyvehicle.longitude)
        print(f"Using heavyvehicle coordinates: {latitude}, {longitude}")
    
    # Fallback to city coordinates if available
    elif heavyvehicle.city:
        if hasattr(heavyvehicle.city, 'latitude') and heavyvehicle.city.latitude and hasattr(heavyvehicle.city, 'longitude') and heavyvehicle.city.longitude:
            latitude = float(heavyvehicle.city.latitude)
            longitude = float(heavyvehicle.city.longitude)
            print(f"Using city coordinates: {latitude}, {longitude}")
        else:
            # If city doesn't have coordinates, use geocoding or default
            try:
                from geopy.geocoders import GoogleV3
                geolocator = GoogleV3(api_key='YOUR_GOOGLE_API_KEY')  # Replace with your API key
                location = geolocator.geocode(f"{heavyvehicle.city.name}, Egypt")
                if location:
                    latitude = location.latitude
                    longitude = location.longitude
                    print(f"Geocoded coordinates: {latitude}, {longitude}")
                else:
                    # Default to Egypt center
                    latitude = 26.8206
                    longitude = 30.8025
            except Exception as e:
                print(f"Geocoding failed: {e}")
                # Default to Egypt center
                latitude = 26.8206
                longitude = 30.8025
    else:
        # Default to Egypt center
        latitude = 26.8206
        longitude = 30.8025
        print("Using default coordinates for Egypt")
    
    # Convert to string for template
    lat_str = str(latitude) if latitude else "26.8206"
    lng_str = str(longitude) if longitude else "30.8025"
    
    # Create map URL
    map_url = f"https://www.google.com/maps?q={lat_str},{lng_str}&hl=en&z=15&output=embed"
    directions_url = f"https://www.google.com/maps/dir/?api=1&destination={lat_str},{lng_str}"

    return render(request, 'Motors/heavyvehicle_details.html', {
        'heavyvehicle': heavyvehicle,
        'advertisement': advertisement,
        'governates': governates,
        'main_image_url': main_image_url,
        'images_json': images_json,
        'images': images,
        'videos': videos,
        'location_display': location_display,
        'is_favorited': is_favorited,
        'favorite_product_type': 'heavyvehicle',
        # Location data for map
        'latitude': lat_str,
        'longitude': lng_str,
        'map_url': map_url,
        'directions_url': directions_url,
        'location_name': location_display or heavyvehicle.city.name if heavyvehicle.city else "Location",
    })

