from django.contrib.auth.decorators import login_required
from django.shortcuts import render, redirect
from django.contrib import messages
from django.core.files.base import ContentFile
from django.core.files.uploadedfile import SimpleUploadedFile
from django.utils.datastructures import MultiValueDict
from django.http import QueryDict
from django.core.files.storage import default_storage
from django.utils import timezone
from datetime import timedelta

from .models import (
    DrivingTraining, DrivingTrainingImage, Region, Governate, District, Cities,
    get_or_create_user_credits, ListingUsage, BoostUsage, CreditTransaction
)
from .forms import DrivingTrainingForm


@login_required
def register_driving_training(request):
    user = request.user
    
    # ========== GET OR CREATE USER CREDITS ==========
    from .models import get_or_create_user_credits, ListingUsage, BoostUsage
    from django.utils import timezone
    from datetime import timedelta
    
    credits = get_or_create_user_credits(user)
    # ================================================
    
    regions = Region.objects.all()
    governate = Governate.objects.all()
    district = District.objects.all()
    cities = Cities.objects.all()

    # ============================================
    # STEP 1: POSTING METHOD SELECTION
    # ============================================
    if request.method == 'POST' and 'posting_method' in request.POST:
        posting_method = request.POST.get('posting_method')
        temp_data = request.session.get('temp_driving_data')
        
        if not temp_data:
            messages.error(request, "Session expired. Please try again.")
            return redirect('register_driving_training')
        
        product_type = temp_data.get('product_type')
        form_data = temp_data.get('form_data')
        temp_files = temp_data.get('temp_files', [])
        
        # ========== CREDIT CHECK BEFORE POSTING ==========
        if posting_method == 'normal':
            if not credits.can_post_listing('normal'):
                messages.error(request, "❌ You don't have enough listing credits. Please buy a package.")
                return redirect('credit_packages')
                
        elif posting_method == 'boosted':
            if not credits.can_post_listing('normal'):
                messages.error(request, "❌ You don't have enough listing credits. Please buy a package.")
                return redirect('credit_packages')
            if credits.boost_days_available < 7:
                messages.error(request, "❌ You don't have enough boost days (need 7 days). Please buy a boost package.")
                return redirect('credit_packages')
                
        elif posting_method == 'exclusive':
            if credits.purchased_listing_credits <= 0:
                messages.error(request, "❌ Exclusive listings require purchased credits. Please buy a package.")
                return redirect('credit_packages')
        # ==================================================
        
        if posting_method == 'normal':
            obj = process_driving_registration(request, form_data, temp_files, 'normal', status='pending')
            if obj:
                # ========== DEDUCT LISTING CREDIT ==========
                success, msg = credits.use_listing_credit('normal')
                if success:
                    ListingUsage.objects.create(
                        user=user,
                        listing_type=obj._meta.model_name,  # Changed: use canonical model name
                        listing_id=obj.id,
                        credit_source='free' if credits.available_free_listings + 1 > credits.free_listings_used else 'purchased',
                        expires_at=timezone.now() + timedelta(days=45)
                    )
                    messages.success(request, f"✅ {msg}")
                else:
                    messages.warning(request, f"⚠️ {msg}")
                # ============================================
                messages.success(request, "Driving training registered successfully!")
                return redirect(adss, user_id=user.id)
            else:
                messages.error(request, "Failed to create listing. Please try again.")
                return redirect('register_driving_training')
        
        elif posting_method == 'boosted':
            obj = process_driving_registration(request, form_data, temp_files, 'boosted', status='pending')
            if obj:
                # ========== DEDUCT LISTING CREDIT ==========
                success, msg = credits.use_listing_credit('normal')
                if success:
                    ListingUsage.objects.create(
                        user=user,
                        listing_type=obj._meta.model_name,  # Changed: use canonical model name
                        listing_id=obj.id,
                        credit_source='free' if credits.available_free_listings + 1 > credits.free_listings_used else 'purchased',
                        expires_at=timezone.now() + timedelta(days=45)
                    )
                    
                    # ========== DEDUCT BOOST CREDIT (7 days) ==========
                    boost_success, boost_msg = credits.use_boost_credit(7)
                    if boost_success:
                        BoostUsage.objects.create(
                            user=user,
                            listing_type=obj._meta.model_name,  # Changed: use canonical model name
                            listing_id=obj.id,
                            boost_days=7,
                            expires_at=timezone.now() + timedelta(days=7),
                            is_active=True
                        )
                        messages.success(request, f"✅ {msg} and {boost_msg}")
                    else:
                        messages.warning(request, f"✅ {msg} but {boost_msg}")
                    # ===================================================
                else:
                    messages.warning(request, f"⚠️ {msg}")
                # ===================================================
                messages.success(request, "Driving training registered successfully!")
                return redirect(adss, user_id=user.id)
            else:
                messages.error(request, "Failed to create boosted listing. Please try again.")
                return redirect('register_driving_training')
        
        elif posting_method == 'exclusive':
            obj = process_driving_registration(
                request,
                form_data,
                temp_files,
                'exclusive',
                status='pending_exclusive'
            )
            if obj:
                # ========== DEDUCT PURCHASED CREDIT FOR EXCLUSIVE ==========
                success, msg = credits.use_listing_credit('exclusive')
                if success:
                    ListingUsage.objects.create(
                        user=user,
                        listing_type=obj._meta.model_name,  # Changed: use canonical model name
                        listing_id=obj.id,
                        credit_source='purchased',
                        expires_at=timezone.now() + timedelta(days=45)
                    )
                    messages.success(request, f"✅ {msg}")
                else:
                    messages.warning(request, f"⚠️ {msg}")
                # ===========================================================
                messages.success(request, "Exclusive request sent to admin.")
                return redirect(adss, user_id=user.id)
            else:
                messages.error(request, "Failed to create exclusive listing. Please try again.")
                return redirect('register_driving_training')
        
        messages.error(request, "Something went wrong.")
        return redirect('register_driving_training')
    
    # ============================================
    # STEP 2: FORM SUBMISSION
    # ============================================
    if request.method == 'POST' and 'product_type' in request.POST:
        product_type = request.POST.get('product_type')
        
        temp_files = []
        
        if request.FILES:
            for field_name, file_list in request.FILES.lists():
                for file in file_list:
                    temp_path = default_storage.save(
                        f'temp/driving_{user.id}_{file.name}',
                        ContentFile(file.read())
                    )
                    
                    temp_files.append({
                        'field_name': field_name,
                        'original_name': file.name,
                        'temp_path': temp_path
                    })
        
        request.session['temp_driving_data'] = {
            'product_type': product_type,
            'form_data': request.POST.dict(),
            'temp_files': temp_files
        }
        
        title = request.POST.get('title', request.POST.get('trainer_name', ''))
        
        return render(request, 'select_posting_method.html', {
            'property_type_display': 'Driving Training',
            'temp_data': {
                'property_title': title,
                'price': request.POST.get('price', '')
            },
            'product_type': product_type,
            'category_type': 'standard',
            # ========== PASS CREDITS TO TEMPLATE ==========
            'credits': credits,
            'free_credits_left': credits.available_free_listings,
            'purchased_credits_left': credits.purchased_listing_credits,
            'boost_days_left': credits.boost_days_available,
            # =============================================
        })
    
    # ============================================
    # STEP 3: GET REQUEST - Show form
    # ============================================
    form = DrivingTrainingForm()
    
    return render(request, "Motors/drive.html", {
        "form": form,
        "regions": regions,
        "governate": governate,
        "district": district,
        "cities": cities,
        # ========== PASS CREDITS TO TEMPLATE ==========
        'credits': credits,
        'free_credits_left': credits.available_free_listings,
        'purchased_credits_left': credits.purchased_listing_credits,
        'boost_days_left': credits.boost_days_available,
        # =============================================
    })

# ============================================
# PROCESS DRIVING REGISTRATION
# ============================================
def process_driving_registration(request, form_data, temp_files, posting_method, status='pending'):
    user = request.user
    
    post_data = QueryDict(mutable=True)
    for key, value in form_data.items():
        if key not in ['csrfmiddlewaretoken', 'product_type']:
            post_data[key] = value
    
    files_dict = MultiValueDict()
    
    for file in temp_files:
        path = file.get('temp_path')
        name = file.get('original_name')
        field = file.get('field_name')
        
        if path and default_storage.exists(path):
            with default_storage.open(path, 'rb') as f:
                uploaded = SimpleUploadedFile(name, f.read())
                files_dict.appendlist(field, uploaded)
    
    form = DrivingTrainingForm(post_data, files_dict)
    
    if not form.is_valid():
        print("FORM ERRORS:", form.errors)
        messages.error(request, f"Form validation failed: {dict(form.errors)}")
        return None
    
    training = form.save(commit=False)
    training.user = user
    training.status = status
    training.posting_method = posting_method
    
    city_id = form_data.get('city')
    if city_id:
        try:
            training.city = Cities.objects.get(id=city_id)
        except Cities.DoesNotExist:
            messages.error(request, "Selected city not found.")
            return None
    
    training.save()
    form.save_m2m()
    
    images = files_dict.getlist('images')
    
    if not images:
        messages.error(request, "Please upload at least one image.")
        return None
    
    for img in images:
        if img:
            image_obj = DrivingTrainingImage.objects.create(image=img)
            training.images.add(image_obj)
    
    for file in temp_files:
        path = file.get('temp_path')
        if path and default_storage.exists(path):
            default_storage.delete(path)
    
    if 'temp_driving_data' in request.session:
        del request.session['temp_driving_data']
    if 'pending_driving' in request.session:
        del request.session['pending_driving']
    
    return training

def driving_training(request):
    governates = Governate.objects.prefetch_related(
        Prefetch('districts', queryset=District.objects.all())
    ).all()

    # Get filter options
    advertisement = Advertisement.objects.filter(
        category=AdvertisementCategory.REAL_ESTATE, 
        is_active=True
    )

    # Get all filter parameters - UPDATED for multiple selections
    selected_governate_params = request.GET.getlist('governate')
    selected_district_params = request.GET.getlist('district')
    selected_cities = request.GET.getlist('city')
    trainer_name = request.GET.get('trainer_name')
    trainer_gender = request.GET.get('trainer_gender')
    transmission = request.GET.get('transmission')
    body_type = request.GET.get('body_type')
    payment_method = request.GET.get('payment_method')
    price_from = request.GET.get('price_from')
    price_to = request.GET.get('price_to')
    year_from = request.GET.get('year_from')
    year_to = request.GET.get('year_to')
    banners = Banner.objects.filter(category='motors', is_active=True)
    language = request.GET.get('language')
    sort_by = request.GET.get('sort', 'newest')

    # Check if any filters are applied
    has_filters = any([
        selected_governate_params, selected_district_params, selected_cities,
        trainer_name, trainer_gender, transmission, body_type, payment_method,
        price_from, price_to, year_from, year_to, language
    ])

    # ========== 45‑DAY EXPIRY CUTOFF ==========
    cutoff_date = timezone.now() - timedelta(days=45)

    # Base queryset (approved + not expired)
    queryset = DrivingTraining.objects.filter(
        status='approved',
        created_at__gte=cutoff_date
    ).select_related('city')

    # Location filters - UPDATED for multiple selections
    if selected_cities:
        queryset = queryset.filter(city_id__in=selected_cities)
    elif selected_district_params:
        cities = Cities.objects.filter(district_id__in=selected_district_params)
        queryset = queryset.filter(city_id__in=cities.values_list('id', flat=True))
    elif selected_governate_params:
        cities = Cities.objects.filter(district__governate_id__in=selected_governate_params)
        queryset = queryset.filter(city_id__in=cities.values_list('id', flat=True))

    # Dropdown support - UPDATED for multiple selections
    districts = District.objects.filter(governate_id__in=selected_governate_params) if selected_governate_params else None

    # Driving training specific filters
    if trainer_name:
        queryset = queryset.filter(trainer_name__icontains=trainer_name)
    if trainer_gender:
        queryset = queryset.filter(trainer_gender__in=trainer_gender.split(','))
    if transmission and transmission != "all":
        queryset = queryset.filter(transmission=transmission)
    if body_type:
        queryset = queryset.filter(body_type__in=body_type.split(','))
    if payment_method:
        queryset = queryset.filter(payment_method=payment_method)
    if language:
        queryset = queryset.filter(language__icontains=language)

    # Ranges
    try:
        if price_from:
            queryset = queryset.filter(price__gte=float(price_from))
        if price_to:
            queryset = queryset.filter(price__lte=float(price_to))
    except (ValueError, TypeError):
        pass

    if year_from:
        queryset = queryset.filter(model_year__gte=year_from)
    if year_to:
        queryset = queryset.filter(model_year__lte=year_to)

    # Convert queryset to list to allow Python processing
    driving_trainings = list(queryset)

    # ========== ADD BOOST INFORMATION FOR MAIN RESULTS ==========
    if driving_trainings:
        dt_ids = [dt.id for dt in driving_trainings]
        boosts = BoostUsage.objects.filter(
            listing_type='drivingtraining',   # adjust if different in your model
            listing_id__in=dt_ids,
            is_active=True
        )
        boost_dict = {b.listing_id: b for b in boosts}
        for dt in driving_trainings:
            boost = boost_dict.get(dt.id)
            if boost and boost.is_boost_active():
                dt.is_boosted = True
                dt.boost_days_left = boost.days_remaining
            else:
                dt.is_boosted = False
                dt.boost_days_left = 0
    # ============================================================

    # Process main results images
    for training in driving_trainings:
        training.images_json = json.dumps([img.image.url for img in training.images.all()])

    total_count = len(driving_trainings)

    # ========== FIXED: RELATED PRODUCTS (45-day cutoff + boost info) ==========
    related_driving_trainings = []
    related_driving_trainings_count = 0
    if has_filters and len(driving_trainings) == 0:
        # Apply 45-day expiry to related products, same as main queryset
        related_queryset = DrivingTraining.objects.filter(
            status='approved',
            created_at__gte=cutoff_date   # <-- added cutoff date
        )
        
        # Convert to list for Python sorting
        related_driving_trainings = list(related_queryset)
        
        # Apply sorting to related driving trainings
        if sort_by == 'price_asc':
            related_driving_trainings.sort(key=lambda x: x.price or 0)
        elif sort_by == 'price_desc':
            related_driving_trainings.sort(key=lambda x: x.price or 0, reverse=True)
        elif sort_by == 'oldest':
            related_driving_trainings.sort(key=lambda x: x.created_at)
        else:  # newest (default)
            related_driving_trainings.sort(key=lambda x: x.created_at, reverse=True)
        
        # Take only 6 after sorting
        related_driving_trainings = related_driving_trainings[:6]
        related_driving_trainings_count = len(related_driving_trainings)
        
        # Add boost information for related items
        if related_driving_trainings:
            rel_ids = [r.id for r in related_driving_trainings]
            rel_boosts = BoostUsage.objects.filter(
                listing_type='drivingtraining',
                listing_id__in=rel_ids,
                is_active=True
            )
            rel_boost_dict = {b.listing_id: b for b in rel_boosts}
            for r in related_driving_trainings:
                boost = rel_boost_dict.get(r.id)
                if boost and boost.is_boost_active():
                    r.is_boosted = True
                    r.boost_days_left = boost.days_remaining
                else:
                    r.is_boosted = False
                    r.boost_days_left = 0
                r.images_json = json.dumps([img.image.url for img in r.images.all()])
    # =========================================================================

    # Sorting for main results
    if sort_by == 'price_asc':
        driving_trainings.sort(key=lambda x: x.price or 0)
    elif sort_by == 'price_desc':
        driving_trainings.sort(key=lambda x: x.price or 0, reverse=True)
    elif sort_by == 'oldest':
        driving_trainings.sort(key=lambda x: x.created_at)
    else:  # newest
        driving_trainings.sort(key=lambda x: x.created_at, reverse=True)

    # Pagination for main results
    current_params = request.GET.copy()
    if 'page' in current_params:
        del current_params['page']

    paginator = Paginator(driving_trainings, 6)
    page_number = request.GET.get('page')
    try:
        page_obj = paginator.get_page(page_number)
    except EmptyPage:
        page_obj = paginator.get_page(paginator.num_pages)

    # Get selected objects for breadcrumb - UPDATED for multiple selections
    selected_governate_objs = Governate.objects.filter(id__in=selected_governate_params) if selected_governate_params else []
    selected_district_objs = District.objects.filter(id__in=selected_district_params) if selected_district_params else []
    selected_city_objs = Cities.objects.filter(id__in=selected_cities) if selected_cities else []

    # Context - UPDATED with proper breadcrumb data and related products
    context = {
        'results': driving_trainings,
        'page_obj': page_obj,
        'current_params': current_params.urlencode(),
        'category_counts': {
            'motorcycles': Motorcycle.objects.filter(status='approved').count(),
            'automobiles_sell': Automobile.objects.filter(status='approved', listing_type='sell').count(),
            'automobiles_rent': Automobile.objects.filter(status='approved', listing_type='rent').count(),
            'heavy_vehicles': HeavyVehicle.objects.filter(status='approved').count(),
            'boats': Boat.objects.filter(status='approved').count(),
            'accessoriesparts': AutoAccessoryPart.objects.filter(status='approved').count(),
            'number_plate': NumberPlate.objects.filter(status='approved').count(),
            'driving_training': DrivingTraining.objects.filter(status='approved').count(),
        },
        'governates': governates,
        'districts': districts,
        
        # UPDATED: Proper breadcrumb data for multiple selections
        'selected_governate_objs': selected_governate_objs,
        'selected_district_objs': selected_district_objs,
        'selected_city_objs': selected_city_objs,
        
        # Keep these for backward compatibility if needed elsewhere
        'selected_governate': selected_governate_objs.first() if selected_governate_objs else None,
        'selected_governate_param': selected_governate_params[0] if selected_governate_params else None,
        
        'advertisement': advertisement,
        'trainer_name': trainer_name,
        'trainer_gender': trainer_gender,
        'transmission': transmission,
        'body_type': body_type,
        'payment_method': payment_method,
        'price_from': price_from,
        'price_to': price_to,
        'year_from': year_from,
        'year_to': year_to,
        'banners' : banners,
        'language': language,
        'current_sort': sort_by,
        'sort_options': [
            {'value': 'newest', 'label': 'Newest First'},
            {'value': 'oldest', 'label': 'Oldest First'},
            {'value': 'price_asc', 'label': 'Price: Low to High'},
            {'value': 'price_desc', 'label': 'Price: High to Low'},
        ],
        'total_count': total_count,
        'formatted_url_name': request.resolver_match.url_name.replace("_", " ").title(),
        
        # Filter choices for template
        'gender_choices': ['Male', 'Female', 'Other'],
        'transmission_choices': ['Automatic', 'Manual'],
        'body_type_choices': ['Sedan', 'Hatchback', 'Small Truck', 'Large Truck', 'Motorcycle'],
        'payment_method_choices': ['cash', 'installments'],
        
        # Related products data
        'related_driving_trainings': related_driving_trainings,
        'related_driving_trainings_count': related_driving_trainings_count,
        'show_related': has_filters and len(driving_trainings) == 0,
    }

    if request.headers.get('X-Requested-With') == 'XMLHttpRequest':
        return render(request, 'Drive/driving_list_partial.html', context)

    return render(request, 'Drive/training.html', context)
def driving_details(request, id):
    driving = get_object_or_404(DrivingTraining, id=id)
    advertisement = Advertisement.objects.filter(
        category=AdvertisementCategory.MOTORS, 
        is_active=True
    )
    track_product_view(request, driving)

    # ========== RECENTLY VIEWED TRACKING ==========
    # Get all images for the driving training
    images = []
    if hasattr(driving, 'images') and driving.images.exists():
        images = [{"image": img.image.url} for img in driving.images.all()]
    elif hasattr(driving, 'main_image') and driving.main_image:
        images = [{"image": driving.main_image.url}]
    
    # Get main image URL
    main_image_url = images[0]["image"] if images else "/static/assets/images/resource/default.jpg"
    
    # Convert images to JSON string
    images_json = json.dumps(images)
    
    # Get title
    title = ""
    if hasattr(driving, 'title') and driving.title:
        title = driving.title
    elif hasattr(driving, 'name') and driving.name:
        title = driving.name
    else:
        title = f"Driving Training #{driving.id}"
    
    # Get city name
    city_name = ""
    if hasattr(driving, 'city') and driving.city:
        city_name = driving.city.name
    
    # Get price
    price = driving.price if hasattr(driving, 'price') else 0
    
    # Get brand/instructor
    brand = ""
    if hasattr(driving, 'instructor_name') and driving.instructor_name:
        brand = driving.instructor_name
    elif hasattr(driving, 'brand') and driving.brand:
        brand = driving.brand.name if hasattr(driving.brand, 'name') else str(driving.brand)
    
    product_data = {
        'title': title,
        'price': price,
        'main_image': main_image_url,
        'images_json': images_json,
        'city': city_name,
        'url': request.build_absolute_uri(),
        'listing_type': '',
        'display_category': 'Driving Training',
        'brand': brand,
        'category_type': 'drivingtraining',
    }
    
    # Track the recently viewed product
    track_recently_viewed(request, str(driving.id), 'drivingtraining', product_data)
    # ========== END RECENTLY VIEWED TRACKING ==========

    # Calculate total media count safely
    images_count = driving.images.all().count() if hasattr(driving, 'images') else 0
    videos_count = driving.videos.all().count() if hasattr(driving, 'videos') else 0
    total_media_count = images_count + videos_count

    # Handle report submission
    if request.method == 'POST' and 'report_submit' in request.POST:
        reason = request.POST.get('reason')
        description = request.POST.get('description', '')

        if reason:
            ProductReport.objects.create(
                reporter=request.user if request.user.is_authenticated else None,
                reason=reason,
                description=description,
                content_type=ContentType.objects.get_for_model(driving),
                object_id=driving.id
            )
            messages.success(request, "Thank you for reporting. We'll review it shortly.")
            return redirect(request.path)
        else:
            messages.error(request, "Please select a valid reason for the report.")
    
    # Get governates for filters (if needed)
    governates = Governate.objects.prefetch_related(
        Prefetch('districts', queryset=District.objects.all())
    ).all()
    
    # Check if favorited
    is_favorited = False
    if request.user.is_authenticated:
        content_type = ContentType.objects.get_for_model(driving)
        is_favorited = Favorite.objects.filter(
            user=request.user,
            content_type=content_type,
            object_id=driving.id
        ).exists()
    
    # Get videos if available
    videos = driving.videos.all() if hasattr(driving, 'videos') else []
    
    # Location display string
    location_display = ""
    if driving.city and driving.city.district and driving.city.district.governate:
        location_display = f"{driving.city.name}, {driving.city.district.name}, {driving.city.district.governate.name}"
    
    # ========== GET COORDINATES FOR MAP ==========
    # Try to get coordinates from driving first, then fallback to city, then default
    latitude = None
    longitude = None
    
    # Check if driving has coordinates
    if hasattr(driving, 'latitude') and driving.latitude and hasattr(driving, 'longitude') and driving.longitude:
        latitude = float(driving.latitude)
        longitude = float(driving.longitude)
        print(f"Using driving coordinates: {latitude}, {longitude}")
    
    # Fallback to city coordinates if available
    elif driving.city:
        if hasattr(driving.city, 'latitude') and driving.city.latitude and hasattr(driving.city, 'longitude') and driving.city.longitude:
            latitude = float(driving.city.latitude)
            longitude = float(driving.city.longitude)
            print(f"Using city coordinates: {latitude}, {longitude}")
        else:
            # If city doesn't have coordinates, use geocoding or default
            try:
                from geopy.geocoders import GoogleV3
                geolocator = GoogleV3(api_key='YOUR_GOOGLE_API_KEY')  # Replace with your API key
                location = geolocator.geocode(f"{driving.city.name}, Egypt")
                if location:
                    latitude = location.latitude
                    longitude = location.longitude
                    print(f"Geocoded coordinates: {latitude}, {longitude}")
                else:
                    # Default to Egypt center
                    latitude = 26.8206
                    longitude = 30.8025
            except Exception as e:
                print(f"Geocoding failed: {e}")
                # Default to Egypt center
                latitude = 26.8206
                longitude = 30.8025
    else:
        # Default to Egypt center
        latitude = 26.8206
        longitude = 30.8025
        print("Using default coordinates for Egypt")
    
    # Convert to string for template
    lat_str = str(latitude) if latitude else "26.8206"
    lng_str = str(longitude) if longitude else "30.8025"
    
    # Create map URL
    map_url = f"https://www.google.com/maps?q={lat_str},{lng_str}&hl=en&z=15&output=embed"
    directions_url = f"https://www.google.com/maps/dir/?api=1&destination={lat_str},{lng_str}"

    return render(request, 'Drive/driving_details.html', {
        'driving': driving,
        'advertisement': advertisement,
        'total_media_count': total_media_count,
        'images_count': images_count,
        'videos_count': videos_count,
        'governates': governates,
        'main_image_url': main_image_url,
        'images_json': images_json,
        'images': images,
        'videos': videos,
        'location_display': location_display,
        'is_favorited': is_favorited,
        'favorite_product_type': 'drivingtraining',
        # Location data for map
        'latitude': lat_str,
        'longitude': lng_str,
        'map_url': map_url,
        'directions_url': directions_url,
        'location_name': location_display or driving.city.name if driving.city else "Location",
    })
    
from django.contrib.admin.views.decorators import staff_member_required
from django.contrib.contenttypes.models import ContentType
from django.core.paginator import Paginator
from django.shortcuts import render, get_object_or_404, redirect
from django.contrib import messages
from django.utils import timezone
from django.db.models import Count, Q
from django.http import JsonResponse
from .models import ProductReport

@staff_member_required
def product_reports_admin(request):
    """Admin view to manage product reports"""
    
    # Get filter parameters
    status_filter = request.GET.get('status', '')
    reason_filter = request.GET.get('reason', '')
    date_from = request.GET.get('date_from', '')
    date_to = request.GET.get('date_to', '')
    search_query = request.GET.get('search', '')
    
    # Base queryset with optimizations
    reports_list = ProductReport.objects.select_related(
        'reporter', 
        'reviewed_by',
        'content_type'
    ).order_by('-created_at')
    
    # Apply filters
    if status_filter and status_filter != 'all':
        reports_list = reports_list.filter(status=status_filter)
    
    if reason_filter:
        reports_list = reports_list.filter(reason=reason_filter)
    
    if date_from:
        reports_list = reports_list.filter(created_at__date__gte=date_from)
    
    if date_to:
        reports_list = reports_list.filter(created_at__date__lte=date_to)
    
    if search_query:
        reports_list = reports_list.filter(
            Q(id__icontains=search_query) |
            Q(reporter__username__icontains=search_query) |
            Q(reporter__email__icontains=search_query) |
            Q(description__icontains=search_query)
        )
    
    # Get statistics for dashboard
    total_reports = ProductReport.objects.count()
    stats = {
        'pending': ProductReport.objects.filter(status='pending').count(),
        'under_review': ProductReport.objects.filter(status='under_review').count(),
        'resolved': ProductReport.objects.filter(status='resolved').count(),
        'dismissed': ProductReport.objects.filter(status='dismissed').count(),
        'action_taken': ProductReport.objects.filter(status='action_taken').count(),
    }
    
    # Recent activity
    recent_actions = ProductReport.objects.exclude(
        reviewed_by__isnull=True
    ).select_related('reviewed_by').order_by('-reviewed_at')[:5]
    
    # Pagination
    paginator = Paginator(reports_list, 15)
    page_number = request.GET.get('page')
    reports = paginator.get_page(page_number)
    
    context = {
        'reports': reports,
        'stats': stats,
        'total_reports': total_reports,
        'recent_actions': recent_actions,
        'status_filter': status_filter,
        'reason_filter': reason_filter,
        'date_from': date_from,
        'date_to': date_to,
        'search_query': search_query,
        'status_choices': ProductReport.REPORT_STATUS,
        'reason_choices': ProductReport.REPORT_REASONS,
    }
    
    return render(request, 'admin1/product_reports.html', context)


@staff_member_required
def product_report_detail(request, report_id):
    """View details of a specific report"""
    report = get_object_or_404(
        ProductReport.objects.select_related('reporter', 'reviewed_by', 'content_type'),
        id=report_id
    )
    
    # Try to get the reported object
    try:
        product = report.reported_object
        # Get similar reports for this product
        similar_reports = ProductReport.objects.filter(
            content_type=report.content_type,
            object_id=report.object_id
        ).exclude(id=report.id).order_by('-created_at')[:3]
    except Exception:
        product = None
        similar_reports = []
    
    context = {
        'report': report,
        'product': product,
        'similar_reports': similar_reports,
        'product_type': report.content_type.model if report.content_type else 'unknown',
    }
    
    return render(request, 'admin1/report_detail.html', context)


@staff_member_required
def handle_product_report(request, report_id):
    """Handle actions on a reported product"""
    
    report = get_object_or_404(ProductReport, id=report_id)
    
    if request.method == 'POST':
        action = request.POST.get('action')
        admin_notes = request.POST.get('admin_notes', '')
        
        # Store product reference before any potential deletion
        product = None
        product_exists = False
        
        try:
            product = report.reported_object
            if product:
                product_exists = True
        except Exception:
            product_exists = False
            product = None
        
        # Update report metadata
        report.reviewed_by = request.user
        report.reviewed_at = timezone.now()
        report.admin_notes = admin_notes
        
        # Handle different actions
        if action == 'dismiss':
            report.status = 'dismissed'
            report.action_taken = 'Report dismissed'
            messages.success(request, f'Report #{report_id} has been dismissed.', extra_tags='success')
            
        elif action == 'review':
            report.status = 'under_review'
            report.action_taken = 'Under review'
            messages.info(request, f'Report #{report_id} marked as under review.', extra_tags='info')
            
        elif action == 'hide':
            if product_exists and product:
                try:
                    if hasattr(product, 'is_hidden'):
                        product.is_hidden = True
                        product.save()
                        report.status = 'action_taken'
                        report.action_taken = 'Product hidden'
                        messages.success(request, 'Product has been hidden successfully.', extra_tags='success')
                    elif hasattr(product, 'status'):
                        product.status = 'hidden'
                        product.save()
                        report.status = 'action_taken'
                        report.action_taken = 'Product hidden'
                        messages.success(request, 'Product has been hidden successfully.', extra_tags='success')
                    else:
                        messages.error(request, 'This product type does not support hiding.', extra_tags='error')
                except Exception as e:
                    messages.error(request, f'Error hiding product: {str(e)}', extra_tags='error')
            else:
                messages.error(request, 'Product no longer exists or cannot be accessed.', extra_tags='error')
        
        elif action == 'delete_ad':  # NEW ACTION - Delete Ad regardless of status
            if product_exists and product:
                try:
                    # Store product name for success message
                    product_name = str(product)
                    if hasattr(product, 'property_title'):
                        product_name = product.property_title
                    elif hasattr(product, 'title'):
                        product_name = product.title
                    elif hasattr(product, 'name'):
                        product_name = product.name
                    
                    # Delete the product/ad
                    product.delete()
                    
                    # Update report status based on current state
                    report.status = 'action_taken'
                    report.action_taken = f'Ad deleted by admin: {product_name}'
                    
                    messages.success(
                        request, 
                        f'Ad "{product_name}" has been permanently deleted. Report #{report_id} has been updated.',
                        extra_tags='success'
                    )
                except Exception as e:
                    messages.error(request, f'Could not delete this ad: {str(e)}', extra_tags='error')
                    report.status = report.status  # Keep original status
            else:
                messages.error(request, 'Ad no longer exists or cannot be accessed.', extra_tags='error')
                
        elif action == 'delete':
            if product_exists and product:
                try:
                    product_name = str(product)
                    product.delete()
                    report.status = 'action_taken'
                    report.action_taken = 'Product deleted'
                    messages.success(request, f'Product "{product_name}" has been deleted.', extra_tags='success')
                except Exception as e:
                    messages.error(request, f'Could not delete this product: {str(e)}', extra_tags='error')
            else:
                messages.error(request, 'Product no longer exists or cannot be accessed.', extra_tags='error')
                
        elif action == 'warn_user':
            if product_exists and product and hasattr(product, 'user') and product.user:
                try:
                    # Here you would implement notification/email sending
                    report.status = 'under_review'
                    report.action_taken = 'User warned'
                    messages.success(request, 'Warning has been sent to the product owner.', extra_tags='success')
                except Exception as e:
                    messages.error(request, f'Error sending warning: {str(e)}', extra_tags='error')
            else:
                messages.warning(request, 'Cannot warn owner - product or owner not found.', extra_tags='warning')
        
        elif action == 'resolve':
            report.status = 'resolved'
            report.action_taken = 'Report resolved'
            messages.success(request, f'Report #{report_id} has been resolved.', extra_tags='success')
        
        # Save the report
        try:
            report.save()
        except Exception as e:
            messages.error(request, f'Error saving report: {str(e)}', extra_tags='error')
        
        # Check if this is an AJAX request
        if request.headers.get('X-Requested-With') == 'XMLHttpRequest':
            return JsonResponse({
                'status': 'success',
                'message': 'Action completed successfully',
                'report_status': report.status
            })
        
        return redirect('product_reports_admin')
    
    return redirect('product_report_detail', report_id=report.id)


@staff_member_required
def bulk_report_action(request):
    """Handle bulk actions on multiple reports"""
    if request.method == 'POST':
        action = request.POST.get('bulk_action')
        report_ids = request.POST.getlist('report_ids')
        
        if not report_ids:
            messages.warning(request, 'No reports selected.', extra_tags='warning')
            return redirect('product_reports_admin')
        
        reports = ProductReport.objects.filter(id__in=report_ids)
        
        if action == 'delete_reports':
            # Delete only the reports, not the products
            count = reports.delete()[0]
            messages.success(request, f'{count} report(s) have been deleted.', extra_tags='success')
        
        elif action == 'mark_review':
            count = reports.update(
                status='under_review',
                reviewed_by=request.user,
                reviewed_at=timezone.now()
            )
            messages.success(request, f'{count} report(s) marked as under review.', extra_tags='success')
        
        elif action == 'mark_resolved':
            count = reports.update(
                status='resolved',
                reviewed_by=request.user,
                reviewed_at=timezone.now()
            )
            messages.success(request, f'{count} report(s) marked as resolved.', extra_tags='success')
        
        return redirect('product_reports_admin')
    
    return redirect('product_reports_admin')


