def jobseeker_list(request):

    # ---------------------------------------------------------
    # MASTER DATA
    # ---------------------------------------------------------
    governates = Governate.objects.prefetch_related(
        Prefetch('districts', queryset=District.objects.all())
    )

    categories = JobCategory.objects.all()
    companies = Company.objects.all()

    # ---------------------------------------------------------
    # GET FILTER PARAMS
    # ---------------------------------------------------------
    selected_governate_params = request.GET.getlist('governate')
    selected_district_params = request.GET.getlist('district')
    selected_cities = request.GET.getlist('city')

    selected_category = request.GET.get('category')
    selected_company = request.GET.get('company')
    selected_expected_salaries = request.GET.getlist('expected_salary')
    banners = Banner.objects.filter(category='job', is_active=True)
    selected_notice_periods = request.GET.getlist('notice_period')
    selected_job_types = request.GET.getlist('job_type')
    selected_experiences = request.GET.getlist('experience')
    selected_genders = request.GET.getlist('gender')

    education_level = request.GET.get('education_level')
    nationality = request.GET.get('nationality')
    keyword = request.GET.get('keyword', '')
    sort_by = request.GET.get('sort', 'newest')

    # Multiple category support
    selected_categories = request.GET.get('job_category', '')
    selected_categories = [int(c) for c in selected_categories.split(',') if c.isdigit()]
    if selected_category and selected_category.isdigit() and int(selected_category) not in selected_categories:
        selected_categories.append(int(selected_category))

    # ---------------------------------------------------------
    # SELECTED OBJECTS (BREADCRUMB)
    # ---------------------------------------------------------
    selected_governate_objs = Governate.objects.filter(id__in=selected_governate_params)
    selected_district_objs = District.objects.filter(id__in=selected_district_params)
    selected_city_objs = Cities.objects.filter(id__in=selected_cities)

    selected_governate = selected_governate_objs.first()

    # ---------------------------------------------------------
    # BASE JOBSEEKER QUERYSET (FOR LISTING)
    # ---------------------------------------------------------
    queryset = JobSeeker.objects.select_related(
        'user', 'city'
    ).prefetch_related(
        Prefetch(
            'profiles',
            queryset=JobSeekerProfile.objects.select_related('job_category')
        ),
        'skills'
    ).filter(is_completed=True)

    # ---------------------------------------------------------
    # LOCATION FILTERS
    # ---------------------------------------------------------
    if selected_cities:
        queryset = queryset.filter(city_id__in=selected_cities)
    elif selected_district_params:
        cities = Cities.objects.filter(district_id__in=selected_district_params)
        queryset = queryset.filter(city_id__in=cities)
    elif selected_governate_params:
        cities = Cities.objects.filter(district__governate_id__in=selected_governate_params)
        queryset = queryset.filter(city_id__in=cities)

    districts = District.objects.filter(governate_id__in=selected_governate_params)

    # ---------------------------------------------------------
    # ADDITIONAL FILTERS
    # ---------------------------------------------------------
    if selected_job_types:
        queryset = queryset.filter(commitment__in=selected_job_types)

    if selected_expected_salaries:
        queryset = queryset.filter(expected_salary__in=selected_expected_salaries)

    if selected_categories:
        queryset = queryset.filter(profiles__job_category_id__in=selected_categories)

    if selected_company:
        queryset = queryset.filter(current_company__icontains=selected_company)

    if education_level:
        queryset = queryset.filter(education_level__in=education_level.split(','))

    if selected_notice_periods:
        queryset = queryset.filter(notice_period__in=selected_notice_periods)

    if selected_experiences:
        queryset = queryset.filter(work_experience__in=selected_experiences)

    if nationality:
        queryset = queryset.filter(nationality__icontains=nationality)

    if selected_genders and 'any' not in selected_genders:
        queryset = queryset.filter(gender__in=selected_genders)

    # ---------------------------------------------------------
    # KEYWORD SEARCH
    # ---------------------------------------------------------
    if keyword:
        queryset = queryset.filter(
            Q(user__first_name__icontains=keyword) |
            Q(user__last_name__icontains=keyword) |
            Q(headline__icontains=keyword) |
            Q(profiles__job_category__name__icontains=keyword) |
            Q(nationality__icontains=keyword) |
            Q(skills__name__icontains=keyword)
        )

    queryset = queryset.distinct()

    # ---------------------------------------------------------
    # TRACK IF FILTERS ARE APPLIED
    # ---------------------------------------------------------
    has_filters = any([
        selected_governate_params, selected_district_params, selected_cities,
        selected_categories, selected_company, selected_expected_salaries,
        selected_notice_periods, selected_job_types, selected_experiences,
        selected_genders, education_level, nationality, keyword
    ])

    # ---------------------------------------------------------
    # SORTING
    # ---------------------------------------------------------
    if sort_by == 'oldest':
        queryset = queryset.order_by('id')
    elif sort_by == 'name':
        queryset = queryset.order_by('user__first_name')
    elif sort_by in ['salary_low', 'salary_high']:
        salary_order = {
            'less_than_2000': 1,
            '2000_3999': 2,
            '4000_5999': 3,
            '6000_7999': 4,
            '8000_11999': 5,
            '12000_19999': 6,
            '20000_plus': 7,
            'negotiable': 8
        }
        queryset = queryset.annotate(
            salary_order=Case(
                *[When(expected_salary=k, then=v) for k, v in salary_order.items()],
                default=0,
                output_field=IntegerField()
            )
        ).order_by('salary_order' if sort_by == 'salary_low' else '-salary_order')
    else:
        queryset = queryset.order_by('-id')

    # ---------------------------------------------------------
    # RELATED JOBSEEKERS (when no results found)
    # ---------------------------------------------------------
    related_jobseekers = []
    related_jobseekers_count = 0
    total_count_before_pagination = queryset.count()

    if has_filters and total_count_before_pagination == 0:
        # Try to find related jobseekers based on similar criteria
        related_queryset = JobSeeker.objects.filter(is_completed=True)
        
        # If location was selected, prioritize same area
        if selected_cities:
            related_queryset = related_queryset.filter(city_id__in=selected_cities)
        elif selected_district_params:
            cities = Cities.objects.filter(district_id__in=selected_district_params)
            related_queryset = related_queryset.filter(city_id__in=cities)
        elif selected_governate_params:
            cities = Cities.objects.filter(district__governate_id__in=selected_governate_params)
            related_queryset = related_queryset.filter(city_id__in=cities)
        
        # If categories were selected, prioritize same category
        if selected_categories and not related_queryset.exists():
            related_queryset = JobSeeker.objects.filter(
                is_completed=True,
                profiles__job_category_id__in=selected_categories
            ).distinct()
        
        # If job types were selected, prioritize same job type
        if selected_job_types and not related_queryset.exists():
            related_queryset = JobSeeker.objects.filter(
                is_completed=True,
                commitment__in=selected_job_types
            )
        
        # If still no results, get latest jobseekers
        if not related_queryset.exists():
            related_queryset = JobSeeker.objects.filter(is_completed=True)
        
        # Apply sorting to related jobseekers
        if sort_by == 'oldest':
            related_queryset = related_queryset.order_by('id')
        elif sort_by == 'name':
            related_queryset = related_queryset.order_by('user__first_name')
        else:
            related_queryset = related_queryset.order_by('-id')
        
        related_jobseekers = list(related_queryset[:6])
        related_jobseekers_count = len(related_jobseekers)

    # ---------------------------------------------------------
    # PAGINATION (USER BASED)
    # ---------------------------------------------------------
    paginator = Paginator(queryset, 10)
    page_number = request.GET.get('page')

    try:
        page_obj = paginator.get_page(page_number)
    except EmptyPage:
        page_obj = paginator.get_page(paginator.num_pages)

    # ---------------------------------------------------------
    # JOBSEEKER + PRIMARY PROFILE
    # ---------------------------------------------------------
    jobseekers_with_primary_profile = []
    for jobseeker in page_obj:
        jobseekers_with_primary_profile.append({
            'jobseeker': jobseeker,
            'primary_profile': jobseeker.profiles.first()
        })

    # ---------------------------------------------------------
    # CATEGORY-BASED ADS COUNT (IMPORTANT FIX)
    # ---------------------------------------------------------
    profile_count_queryset = JobSeekerProfile.objects.filter(
        jobseeker__is_completed=True
    )

    if selected_categories:
        profile_count_queryset = profile_count_queryset.filter(
            job_category_id__in=selected_categories
        )

    if selected_cities:
        profile_count_queryset = profile_count_queryset.filter(
            jobseeker__city_id__in=selected_cities
        )
    elif selected_district_params:
        cities = Cities.objects.filter(district_id__in=selected_district_params)
        profile_count_queryset = profile_count_queryset.filter(
            jobseeker__city_id__in=cities
        )
    elif selected_governate_params:
        cities = Cities.objects.filter(district__governate_id__in=selected_governate_params)
        profile_count_queryset = profile_count_queryset.filter(
            jobseeker__city_id__in=cities
        )

    if keyword:
        profile_count_queryset = profile_count_queryset.filter(
            Q(jobseeker__user__first_name__icontains=keyword) |
            Q(jobseeker__user__last_name__icontains=keyword) |
            Q(jobseeker__headline__icontains=keyword) |
            Q(job_category__name__icontains=keyword)
        )

    total_count = profile_count_queryset.count()

    # ---------------------------------------------------------
    # BREADCRUMB LABEL (FIXED - Safe attribute access)
    # ---------------------------------------------------------
    breadcrumb_label = None
    
    if selected_job_types:
        breadcrumb_label = ", ".join(t.replace("_", " ").title() for t in selected_job_types)
    
    elif selected_categories:
        category_names = JobCategory.objects.filter(id__in=selected_categories).values_list('name', flat=True)
        breadcrumb_label = " / ".join(category_names)
    
    elif selected_city_objs:
        # FIXED: Safe attribute access for city names
        city_names = []
        for city in selected_city_objs:
            if hasattr(city, 'city_name'):
                city_names.append(city.city_name)
            elif hasattr(city, 'name'):
                city_names.append(city.name)
            else:
                city_names.append(str(city))
        breadcrumb_label = " / ".join(city_names)
    
    elif selected_district_objs:
        # FIXED: Safe attribute access for district names
        district = selected_district_objs.first()
        if hasattr(district, 'district_name'):
            breadcrumb_label = district.district_name
        elif hasattr(district, 'name'):
            breadcrumb_label = district.name
        else:
            breadcrumb_label = str(district)
    
    elif selected_governate_objs:
        # FIXED: Safe attribute access for governate names
        governate = selected_governate_objs.first()
        if hasattr(governate, 'governate_name'):
            breadcrumb_label = governate.governate_name
        elif hasattr(governate, 'name'):
            breadcrumb_label = governate.name
        else:
            breadcrumb_label = str(governate)
    
    elif selected_company:
        breadcrumb_label = selected_company
    
    elif keyword:
        breadcrumb_label = f"Search: {keyword}"
    
    else:
        breadcrumb_label = "All Job Seekers"

    # ---------------------------------------------------------
    # SORT OPTIONS
    # ---------------------------------------------------------
    sort_options = [
        {'value': 'newest', 'label': 'Newest First'},
        {'value': 'oldest', 'label': 'Oldest First'},
        {'value': 'name', 'label': 'Name (A-Z)'},
        {'value': 'salary_low', 'label': 'Expected Salary: Low to High'},
        {'value': 'salary_high', 'label': 'Expected Salary: High to Low'},
    ]

    # ---------------------------------------------------------
    # CONTEXT
    # ---------------------------------------------------------
    context = {
        'governates': governates,
        'districts': districts,
        'jobseekers_with_profiles': jobseekers_with_primary_profile,
        'page_obj': page_obj,
        'categories': categories,
        'companies': companies,
        'selected_categories': selected_categories,
        'selected_company': selected_company,
        'education_level': education_level,
        'keyword': keyword,
        'banners' : banners,
        'current_sort': sort_by,
        'sort_options': sort_options,
        'total_count': total_count,
        'breadcrumb_label': breadcrumb_label,
        
        # Selected objects for template
        'selected_governate_objs': selected_governate_objs,
        'selected_district_objs': selected_district_objs,
        'selected_city_objs': selected_city_objs,
        'selected_governate': selected_governate,
        
        # Filter values for preserving in template
        'selected_governate_params': selected_governate_params,
        'selected_district_params': selected_district_params,
        'selected_cities': selected_cities,
        'selected_job_types': selected_job_types,
        'selected_expected_salaries': selected_expected_salaries,
        'selected_notice_periods': selected_notice_periods,
        'selected_experiences': selected_experiences,
        'selected_genders': selected_genders,
        'nationality': nationality,
        
        # Related jobseekers for when no results
        'related_jobseekers': related_jobseekers,
        'related_jobseekers_count': related_jobseekers_count,
        'show_related': has_filters and total_count_before_pagination == 0,
        
        # Track if filters are applied
        'has_filters': has_filters,
    }

    if request.headers.get('X-Requested-With') == 'XMLHttpRequest':
        return render(request, 'Jobseeker/jobseeker_list_partial.html', context)

    return render(request, 'Jobseeker/jobseeker_list.html', context)


@login_required
def jobseeker_detail(request, pk, profile_pk=None):
    """
    Detailed view for a single job seeker
    - If profile_pk is provided: show specific profile
    - If no profile_pk: show first profile
    """
    try:
        jobseeker = JobSeeker.objects.select_related(
            'user', 
            'city'
        ).prefetch_related(
            Prefetch(
                'profiles',
                queryset=JobSeekerProfile.objects.select_related('job_category')
                                                  .prefetch_related('profile_skills')
            ),
            'skills'
        ).get(pk=pk)
    except JobSeeker.DoesNotExist:
        messages.error(request, "Job seeker not found.")
        return redirect('jobseeker_list')
    
    # Get all profiles for this job seeker
    profiles = jobseeker.profiles.all()
    
    # Determine which profile to show
    profile = None
    if profile_pk:
        # Show specific profile
        try:
            profile = profiles.get(pk=profile_pk)
        except JobSeekerProfile.DoesNotExist:
            messages.error(request, "Profile not found.")
            return redirect('jobseeker_detail', pk=pk)
    elif profiles.exists():
        # Show first profile by default
        profile = profiles.first()
    
    context = {
        'jobseeker': jobseeker,
        'profiles': profiles,
        'profile': profile,  # The specific profile being viewed
    }
    
    return render(request, 'Jobseeker/jobseeker_detail.html', context)


@login_required
def delete_jobseeker_profile(request):
    try:
        jobseeker = JobSeeker.objects.get(user=request.user)
        jobseeker.delete()
        messages.success(request, "Your job seeker profile has been deleted successfully.")
    except JobSeeker.DoesNotExist:
        messages.error(request, "Job seeker profile not found.")
    
    return redirect('index')



