# -------------------------------------------------------ADMIN CHAT MONITOR----------------------------------------------------------
# Add these imports at the top of your views.py if not already present
from django.contrib.admin.views.decorators import staff_member_required
from django.db.models import Count, Q, Max
from django.core.paginator import Paginator
from django.http import JsonResponse, HttpResponseForbidden
from django.shortcuts import render, get_object_or_404
from django.utils import timezone
from datetime import timedelta
import json
from django.contrib.auth import get_user_model

User = get_user_model()

@staff_member_required
def admin_chat_monitor(request):
    """
    Superuser dashboard to monitor all chat activity
    """
    # Ensure only superusers can access
    if not request.user.is_superuser:
        return HttpResponseForbidden("Access denied")
    
    # Get filter parameters
    date_filter = request.GET.get('date', 'all')
    search_query = request.GET.get('search', '')
    
    # Base queryset for all chat messages
    base_queryset = ChatMessage.objects.select_related('sender', 'receiver')
    
    # Apply date filter
    if date_filter == 'today':
        base_queryset = base_queryset.filter(timestamp__date=timezone.now().date())
    elif date_filter == 'week':
        week_ago = timezone.now() - timedelta(days=7)
        base_queryset = base_queryset.filter(timestamp__gte=week_ago)
    elif date_filter == 'month':
        month_ago = timezone.now() - timedelta(days=30)
        base_queryset = base_queryset.filter(timestamp__gte=month_ago)
    
    # Apply search filter
    if search_query:
        base_queryset = base_queryset.filter(
            Q(sender__username__icontains=search_query) |
            Q(receiver__username__icontains=search_query) |
            Q(message__icontains=search_query)
        )
    
    # Get recent messages (ordered by most recent)
    recent_messages = base_queryset.order_by('-timestamp')[:100]
    
    # Get all users with chat activity
    chat_users = User.objects.filter(
        Q(sent_messages__isnull=False) | Q(received_messages__isnull=False)
    ).distinct().annotate(
        total_sent=Count('sent_messages'),
        total_received=Count('received_messages'),
        last_activity=Max('sent_messages__timestamp')
    ).order_by('-last_activity')
    
    # Get chat statistics
    stats = {
        'total_messages': ChatMessage.objects.count(),
        'total_users': chat_users.count(),
        'messages_today': ChatMessage.objects.filter(
            timestamp__date=timezone.now().date()
        ).count(),
        'messages_week': ChatMessage.objects.filter(
            timestamp__gte=timezone.now() - timedelta(days=7)
        ).count(),
        'deleted_messages': ChatMessage.objects.filter(
            is_deleted_for_everyone=True
        ).count(),
        'blocked_users': BlockedUser.objects.count(),
    }
    
    # Get most active chats
    active_chats = base_queryset.values(
        'sender__username', 'receiver__username'
    ).annotate(
        count=Count('id'),
        last_message=Max('timestamp')
    ).order_by('-count')[:10]
    
    context = {
        'recent_messages': recent_messages,
        'chat_users': chat_users,
        'stats': stats,
        'active_chats': active_chats,
        'date_filter': date_filter,
        'search_query': search_query,
    }
    
    return render(request, 'admin1/chat/chat_monitor.html', context)


@staff_member_required
def admin_user_chats(request, user_id):
    """
    View all chats for a specific user
    """
    if not request.user.is_superuser:
        return HttpResponseForbidden("Access denied")

    user = get_object_or_404(User, id=user_id)

    # Get all messages involving this user
    all_messages = ChatMessage.objects.filter(
        Q(sender=user) | Q(receiver=user)
    ).select_related('sender', 'receiver').order_by('-timestamp')

    # Group by conversation
    conversations = {}
    
    for msg in all_messages:
        # Determine the other user in the conversation
        other_user = msg.receiver if msg.sender == user else msg.sender
        
        # Create a unique key for this conversation
        if msg.product_id and msg.product_type:
            # Product chat
            conv_key = f"{other_user.id}_{msg.product_type}_{msg.product_id}"
            conv_type = 'product'
        else:
            # General chat
            conv_key = f"{other_user.id}_general"
            conv_type = 'general'
        
        if conv_key not in conversations:
            conversations[conv_key] = {
                'other_user': other_user,
                'messages': [],
                'total_messages': 0,
                'first_message': msg.timestamp,
                'last_message': msg.timestamp,
                'product_type': msg.product_type if conv_type == 'product' else None,
                'product_id': msg.product_id if conv_type == 'product' else None,
                'conversation_type': conv_type,
            }
        
        conversations[conv_key]['messages'].append(msg)
        conversations[conv_key]['total_messages'] += 1
        
        if msg.timestamp < conversations[conv_key]['first_message']:
            conversations[conv_key]['first_message'] = msg.timestamp
        if msg.timestamp > conversations[conv_key]['last_message']:
            conversations[conv_key]['last_message'] = msg.timestamp
    
    # Sort messages within each conversation (oldest first)
    for conv in conversations.values():
        conv['messages'].sort(key=lambda x: x.timestamp)
    
    # Convert to list and sort by last message (newest first)
    conversation_list = list(conversations.values())
    conversation_list.sort(key=lambda x: x['last_message'], reverse=True)
    
    # Paginate
    paginator = Paginator(conversation_list, 5)
    page = request.GET.get('page', 1)
    conversations_page = paginator.get_page(page)
    
    context = {
        'target_user': user,
        'conversations': conversations_page,
        'total_messages': all_messages.count(),
        'total_conversations': len(conversation_list),
    }
    
    return render(request, 'admin1/chat/user_chats.html', context)


@staff_member_required
def admin_delete_message(request, message_id):
    """
    Superuser can delete inappropriate messages
    """
    if not request.user.is_superuser:
        return JsonResponse({'success': False, 'error': 'Unauthorized'}, status=403)
    
    if request.method != 'POST':
        return JsonResponse({'success': False, 'error': 'Method not allowed'}, status=405)
    
    message = get_object_or_404(ChatMessage, id=message_id)
    
    try:
        data = json.loads(request.body)
        reason = data.get('reason', '')
        
        # Log the deletion (you can also save this to a database log)
        print(f"[ADMIN ACTION] {request.user.username} deleted message {message_id} from {message.sender.username}. Reason: {reason}")
        
        # Delete for everyone
        message.delete_for_everyone()
        
        return JsonResponse({
            'success': True,
            'message': 'Message deleted successfully'
        })
        
    except Exception as e:
        return JsonResponse({'success': False, 'error': str(e)}, status=500)


@staff_member_required
def admin_chat_stats(request):
    """
    AJAX endpoint to get chat statistics for charts
    """
    if not request.user.is_superuser:
        return JsonResponse({'error': 'Unauthorized'}, status=403)
    
    # Get last 7 days data
    dates = []
    message_counts = []
    user_counts = []
    
    for i in range(6, -1, -1):
        date = timezone.now().date() - timedelta(days=i)
        dates.append(date.strftime('%Y-%m-%d'))
        
        # Count messages on this date
        count = ChatMessage.objects.filter(
            timestamp__date=date
        ).count()
        message_counts.append(count)
        
        # Count active users on this date
        active_users = ChatMessage.objects.filter(
            timestamp__date=date
        ).values('sender').distinct().count()
        user_counts.append(active_users)
    
    # Get top chatters
    top_chatters = User.objects.annotate(
        message_count=Count('sent_messages')
    ).order_by('-message_count')[:10].values('username', 'message_count')
    
    # Get product type distribution
    product_types = ChatMessage.objects.filter(
        product_type__isnull=False
    ).exclude(
        product_type=''
    ).values('product_type').annotate(
        count=Count('id')
    ).order_by('-count')[:10]
    
    return JsonResponse({
        'dates': dates,
        'message_counts': message_counts,
        'user_counts': user_counts,
        'top_chatters': list(top_chatters),
        'product_types': list(product_types),
        'total_messages': ChatMessage.objects.count(),
        'total_users': User.objects.filter(
            Q(sent_messages__isnull=False) | Q(received_messages__isnull=False)
        ).distinct().count(),
    })


from django.utils import timezone
from django.contrib.auth import get_user_model
from django.shortcuts import get_object_or_404
from django.http import JsonResponse
from django.contrib.admin.views.decorators import staff_member_required

User = get_user_model()


@staff_member_required
def admin_block_user(request, user_id):
    """
    Admin blocks a user from chatting with anyone
    """

    if not request.user.is_superuser:
        return JsonResponse({'success': False, 'error': 'Unauthorized'}, status=403)

    if request.method != 'POST':
        return JsonResponse({'success': False, 'error': 'Method not allowed'}, status=405)

    try:
        user_to_block = get_object_or_404(User, id=user_id)

        if user_to_block.is_chat_blocked:
            return JsonResponse({
                'success': False,
                'error': 'User already blocked'
            }, status=400)

        user_to_block.is_chat_blocked = True
        user_to_block.chat_blocked_at = timezone.now()
        user_to_block.save()

        return JsonResponse({
            'success': True,
            'message': f'{user_to_block.username} has been blocked from chat',
            'action': 'blocked'
        })

    except Exception as e:
        return JsonResponse({'success': False, 'error': str(e)}, status=500)


@staff_member_required
def admin_unblock_user(request, user_id):
    """
    Admin unblocks a user from chat
    """

    if not request.user.is_superuser:
        return JsonResponse({'success': False, 'error': 'Unauthorized'}, status=403)

    if request.method != 'POST':
        return JsonResponse({'success': False, 'error': 'Method not allowed'}, status=405)

    try:
        user_to_unblock = get_object_or_404(User, id=user_id)

        if not user_to_unblock.is_chat_blocked:
            return JsonResponse({
                'success': False,
                'error': 'User is not blocked'
            }, status=400)

        user_to_unblock.is_chat_blocked = False
        user_to_unblock.chat_blocked_at = None
        user_to_unblock.save()

        return JsonResponse({
            'success': True,
            'message': f'{user_to_unblock.username} has been unblocked',
            'action': 'unblocked'
        })

    except Exception as e:
        return JsonResponse({'success': False, 'error': str(e)}, status=500)


@staff_member_required
def admin_check_block_status(request, user_id):

    if not request.user.is_superuser:
        return JsonResponse({'error': 'Unauthorized'}, status=403)

    try:
        user = get_object_or_404(User, id=user_id)

        return JsonResponse({
            'success': True,
            'is_blocked': user.is_chat_blocked
        })

    except Exception as e:
        return JsonResponse({'success': False, 'error': str(e)}, status=500)


@staff_member_required
def admin_blocked_users(request):

    if not request.user.is_superuser:
        return HttpResponseForbidden("Access denied")

    blocked_users = User.objects.filter(
        is_chat_blocked=True
    ).order_by('-chat_blocked_at')

    paginator = Paginator(blocked_users, 10)
    page = request.GET.get('page')
    blocked_page = paginator.get_page(page)

    context = {
        'blocked_users': blocked_page,
        'total_blocked': blocked_users.count(),
    }

    return render(request, 'admin1/chat/blocked_users.html', context)

@staff_member_required
def admin_chat_analytics(request):
    """
    Comprehensive Chat Analytics Dashboard
    """
    if not request.user.is_superuser:
        return HttpResponseForbidden("Access denied")
    
    # Get date range filter
    days = int(request.GET.get('days', 30))
    start_date = timezone.now() - timedelta(days=days)
    
    # ========== OVERALL STATISTICS ==========
    total_messages = ChatMessage.objects.count()
    total_conversations = ChatMessage.objects.values('chat_session_id').distinct().count()
    total_users = User.objects.filter(
        Q(sent_messages__isnull=False) | Q(received_messages__isnull=False)
    ).distinct().count()
    total_blocked = BlockedUser.objects.count()
    
    # Messages over time (daily)
    daily_stats = []
    for i in range(days, -1, -1):
        date = timezone.now().date() - timedelta(days=i)
        count = ChatMessage.objects.filter(timestamp__date=date).count()
        daily_stats.append({
            'date': date.strftime('%Y-%m-%d'),
            'count': count
        })
    
    # ========== USER ENGAGEMENT ==========
    # Top 10 most active users
    top_users = User.objects.annotate(
        message_count=Count('sent_messages')
    ).filter(message_count__gt=0).order_by('-message_count')[:10]
    
    # User engagement distribution
    user_engagement = {
        'very_active': User.objects.annotate(
            count=Count('sent_messages')
        ).filter(count__gte=100).count(),
        'active': User.objects.annotate(
            count=Count('sent_messages')
        ).filter(count__gte=50, count__lt=100).count(),
        'moderate': User.objects.annotate(
            count=Count('sent_messages')
        ).filter(count__gte=10, count__lt=50).count(),
        'low': User.objects.annotate(
            count=Count('sent_messages')
        ).filter(count__gte=1, count__lt=10).count(),
    }
    
    # ========== PRODUCT ANALYTICS ==========
    # Messages by product type
    product_stats = ChatMessage.objects.filter(
        product_type__isnull=False
    ).exclude(
        product_type=''
    ).values('product_type').annotate(
        message_count=Count('id'),
        unique_chats=Count('chat_session_id', distinct=True)
    ).order_by('-message_count')[:15]
    
    # Top products by chat volume
    top_products = []
    for stat in product_stats[:5]:
        top_products.append({
            'type': stat['product_type'],
            'messages': stat['message_count'],
            'chats': stat['unique_chats']
        })
    
    # ========== TIME ANALYTICS ==========
    # Hourly distribution (24 hours)
    hourly_distribution = []
    for hour in range(24):
        count = ChatMessage.objects.filter(
            timestamp__hour=hour
        ).count()
        hourly_distribution.append({
            'hour': f"{hour:02d}:00",
            'count': count
        })
    
    # Weekday distribution
    weekday_names = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday', 'Sunday']
    weekday_distribution = []
    for i, day in enumerate(weekday_names):
        count = ChatMessage.objects.filter(
            timestamp__week_day=i+2  # Django week_day: 1=Sunday, 2=Monday, etc.
        ).count()
        weekday_distribution.append({
            'day': day,
            'count': count
        })
    
    # ========== CONVERSATION METRICS ==========
    # Average messages per conversation
    conversations = ChatMessage.objects.values('chat_session_id').annotate(
        msg_count=Count('id')
    )
    
    if conversations:
        avg_messages = sum(c['msg_count'] for c in conversations) / len(conversations)
        max_messages = max(c['msg_count'] for c in conversations)
    else:
        avg_messages = 0
        max_messages = 0
    
    # ========== TREND ANALYSIS ==========
    # Growth rate (compare last 7 days with previous 7 days)
    last_week = ChatMessage.objects.filter(
        timestamp__gte=timezone.now() - timedelta(days=7)
    ).count()
    previous_week = ChatMessage.objects.filter(
        timestamp__gte=timezone.now() - timedelta(days=14),
        timestamp__lt=timezone.now() - timedelta(days=7)
    ).count()
    
    if previous_week > 0:
        growth_rate = ((last_week - previous_week) / previous_week) * 100
    else:
        growth_rate = 0
    
    context = {
        # Overall stats
        'total_messages': total_messages,
        'total_conversations': total_conversations,
        'total_users': total_users,
        'total_blocked': total_blocked,
        'avg_messages': round(avg_messages, 1),
        'max_messages': max_messages,
        'growth_rate': round(growth_rate, 1),
        
        # Data for charts
        'daily_stats': json.dumps(daily_stats),
        'hourly_distribution': json.dumps(hourly_distribution),
        'weekday_distribution': json.dumps(weekday_distribution),
        'product_stats': json.dumps(list(product_stats)),
        'top_users': top_users,
        'user_engagement': user_engagement,
        'top_products': top_products,
        
        # Filter
        'days': days,
    }
    
    return render(request, 'admin1/chat/chat_analytics.html', context)



