from django.shortcuts import render, redirect, get_object_or_404
from django.contrib import messages
from .models import FAQ


# =========================
# ADMIN FAQ LIST PAGE
# =========================
@login_required
def faq_list(request):
    faqs = FAQ.objects.all().order_by('-created_at')
    return render(request, 'admin1/FAQ/faq.html', {'faqs': faqs})


# =========================
# ADD FAQ
# =========================
def add_faq(request):
    if request.method == "POST":
        question = request.POST.get('question')
        answer = request.POST.get('answer')
        is_active = True if request.POST.get('is_active') == 'on' else False

        if question and answer:
            FAQ.objects.create(
                question=question,
                answer=answer,
                is_active=is_active
            )
            messages.success(request, "FAQ added successfully.")
        else:
            messages.error(request, "All fields are required.")

    return redirect('faq_list')


# =========================
# EDIT FAQ
# =========================
def edit_faq(request, id):
    faq = get_object_or_404(FAQ, id=id)

    if request.method == "POST":
        faq.question = request.POST.get('question')
        faq.answer = request.POST.get('answer')
        faq.is_active = True if request.POST.get('is_active') == 'on' else False
        faq.save()
        messages.success(request, "FAQ updated successfully.")

    return redirect('faq_list')


# =========================
# DELETE FAQ
# =========================
def delete_faq(request, id):
    faq = get_object_or_404(FAQ, id=id)

    if request.method == "POST":
        faq.delete()
        messages.success(request, "FAQ deleted successfully.")

    return redirect('faq_list')


# =========================
# TOGGLE ACTIVE / INACTIVE
# =========================
def toggle_faq_status(request, id):
    faq = get_object_or_404(FAQ, id=id)

    if request.method == "POST":
        faq.is_active = not faq.is_active
        faq.save()
        messages.success(request, "FAQ status updated.")

    return redirect('faq_list')

# =========================
# PUBLIC FAQ PAGE
# =========================
def public_faq(request):
    faqs = FAQ.objects.filter(is_active=True).order_by('created_at')  # Remove the minus sign
    return render(request, 'faq/public_faq.html', {'faqs': faqs})

