    if request.method == "POST":
        title = request.POST.get('title')
        content = request.POST.get('content')  # Preserve exact formatting
        category = request.POST.get('category')
        image = request.FILES.get('image')
        is_active = True if request.POST.get('is_active') == 'on' else False

        if title and content and image and category:
            Blog.objects.create(
                title=title,
                content=content,  # Keep as is with all formatting
                category=category,
                image=image,
                is_active=is_active
            )
            messages.success(request, "Blog added successfully.")
        else:
            messages.error(request, "All fields (title, content, image, category) are required.")

    return redirect('blog_list')


