def property_edit_view(request, property_type, pk):
    # Mapping of property_type strings to model classes
    model_map = {
        'land': Land,
        'villa': Villa,
        'commercial': Commercial,
        'farm': Farm,
        'apartment': Apartment,
        'factory': Factory,
        'complexes': Complex,
        'clinic': Clinic,
        'hostel': Hostel,
        'office': Office,
        'shop': Shop,
        'cafe': Cafe,
        'staff': Staff,
        'warehouse': Warehouse,
        'townhouse': Townhouse,
        'fullfloors': Fullfloors,
        'showrooms': Showrooms,
        'wholebuilding': Wholebuilding,
        'supermarket': Supermarket,
        'foreign': Foreign,
        'shared': Shared,
        'suits': Suits,
        'automobile': Automobile,
        'motorcycle': Motorcycle,
        'scooter': Scooter,
        'helmetclothes': HelmetClothes,
        'quadbikes': Quadbikes,
        'heavyvehicle': HeavyVehicle,
        'accessoriesparts': AutoAccessoryPart,
        'numberplate': NumberPlate,
        'boat': Boat,
        'sports_car': SportsCar,
        'part': Part,
        'fashion': Fashion,
        'toys': Toys,
        'food': Food,
        'fitness': Fitness,
        'junkcar': JunkCar,
        'tiresandcaps': TiresAndCaps,
        'carrepair': CarRepairMaintenance,
        'drivingtraining': DrivingTraining,
        'computerlisting': ComputerListing,
        'businessindustriallisting': BusinessIndustrialListing,
        'petlisting': PetListing,
        'sportslisting': SportsListing,
        'musicallisting': MusicalListing,
        'gaminglisting': GamingListing,
        'ticketvoucherlisting': TicketVoucherListing,
        'collectiblelisting': CollectibleListing,
        'bookslisting': BooksListing,
        'musiclisting': MusicListing,
        'dvdsmovieslisting': DVDsMoviesListing,
        'furniturehomegardenlisting': FurnitureHomeGardenListing,
        'babyitemslisting': BabyItemsListing,
        'toyslisting': ToysListing,
        'lostfound': LostFoundListing,
        'cameralisting': CameraListing,
        'jewelrylisting': JewelryListing,
        'homeappliancelisting': HomeApplianceListing,
        'clothingaccessorieslisting': ClothingAccessoriesListing,
        'electronicslisting': ElectronicsListing,
        'pet': Pet,
        'book': Book,
        'appliance': Appliance,
        'business': Business,
        'education': Education,
        'service': Service,
        'mobile': Mobile,
        'tablet': Tablet,
        'smartwatch': SmartWatch,
        'headset': Headset,
        'cover': Cover,
        'accessory': Accessory,
        'mobilesim': MobileSIM,
        'computer': Computer,
        'sound': Sound,
        'training': DrivingTraining,  # alias
        'autoservicelisting': AutoServiceListing,
        'consultancyservicelisting': ConsultancyServiceListing,
        'domesticservicelisting': DomesticServiceListing,
        'evententertainmentservicelisting': EventEntertainmentServiceListing,
        'healthwellbeingservicelisting': HealthWellbeingServiceListing,
        'homemaintenanceservicelisting': HomeMaintenanceServiceListing,
        'moversservicelisting': MoversServiceListing,
        'restorationservicelisting': RestorationServiceListing,
        'tutorsservicelisting': TutorsServiceListing,
        'webcomputerservicelisting': WebComputerServiceListing,
        'freelancersservicelisting': FreelancersServiceListing,
        'otherservicelisting': OtherServiceListing,
    }

    if property_type not in model_map:
        messages.error(request, "Invalid property type.")
        return redirect('admin_dashboard')

    model = model_map[property_type]
    product = get_object_or_404(model, id=pk)

    # --------------------------------------------------------------
    # 1. Build fields for the template (excluding 'id' and 'user')
    # --------------------------------------------------------------
    fields = []
    for field in product._meta.fields:
        if field.name in ['id', 'user']:
            continue

        field_info = {
            'name': field.name,
            'verbose_name': field.verbose_name or field.name.replace('_', ' ').title(),
            'type': field.get_internal_type(),
            'value': getattr(product, field.name),
            'choices': field.choices if field.choices else None,
            'is_relation': field.is_relation,
            'null': field.null,
            'blank': field.blank,
            'help_text': field.help_text,
        }

        # For ForeignKey fields, get all possible choices
        if field.is_relation and field.many_to_one:
            related_model = field.related_model
            # Skip user-related fields
            if related_model.__name__ == 'User' or field.name == 'user':
                continue
            field_info['related_choices'] = related_model.objects.all()

        fields.append(field_info)

    # --------------------------------------------------------------
    # 2. ManyToMany fields (excluding 'user' and the special ones we handle separately)
    # --------------------------------------------------------------
    many_to_many_fields = []
    for field in product._meta.many_to_many:
        if field.name == 'user':
            continue
        # We'll handle 'images' and 'videos' separately in the POST logic
        if field.name in ['images', 'videos']:
            continue

        field_info = {
            'name': field.name,
            'verbose_name': field.verbose_name or field.name.replace('_', ' ').title(),
            'value': getattr(product, field.name).all(),
            'related_choices': field.related_model.objects.all(),
        }
        many_to_many_fields.append(field_info)

    # --------------------------------------------------------------
    # 3. Handle POST request
    # --------------------------------------------------------------
    if request.method == 'POST':
        try:
            # Update regular fields (skip id, user)
            for field in product._meta.fields:
                field_name = field.name
                if field_name in ['id', 'user']:
                    continue

                post_value = request.POST.get(field_name)

                if post_value is not None:
                    # Handle empty string for nullable fields
                    if post_value == '' and field.null:
                        setattr(product, field_name, None)
                    elif post_value == '' and not field.null:
                        continue

                    # Boolean field
                    elif field.get_internal_type() == 'BooleanField':
                        setattr(product, field_name, post_value == 'on' or post_value == 'True')

                    # Integer fields
                    elif field.get_internal_type() in ['IntegerField', 'PositiveIntegerField']:
                        try:
                            setattr(product, field_name, int(post_value) if post_value else None)
                        except ValueError:
                            pass

                    # Decimal field
                    elif field.get_internal_type() == 'DecimalField':
                        try:
                            setattr(product, field_name, float(post_value) if post_value else None)
                        except ValueError:
                            pass

                    # ForeignKey relation
                    elif field.is_relation:
                        if post_value:
                            try:
                                related_model = field.related_model
                                if related_model.__name__ == 'User' or field_name == 'user':
                                    continue
                                related_obj = related_model.objects.get(id=post_value)
                                setattr(product, field_name, related_obj)
                            except:
                                pass

                    # File / Image fields (single, not ManyToMany)
                    elif field.get_internal_type() in ['FileField', 'ImageField']:
                        if field_name in request.FILES:
                            setattr(product, field_name, request.FILES[field_name])

                    # All other fields (CharField, TextField, DateField, etc.)
                    else:
                        setattr(product, field_name, post_value)

            # Update standard ManyToMany fields (excluding images/videos)
            for field in product._meta.many_to_many:
                field_name = field.name
                if field_name in ['user', 'images', 'videos']:
                    continue

                post_values = request.POST.getlist(field_name)
                if post_values:
                    getattr(product, field_name).set(post_values)

            # ----------------------------------------------------------
            # 4. Handle images (ManyToMany) – delete checked, add new
            # ----------------------------------------------------------
            if hasattr(product, 'images'):
                # Delete selected images
                delete_image_ids = request.POST.getlist('delete_images')
                if delete_image_ids:
                    product.images.filter(id__in=delete_image_ids).delete()

                # Upload new images
                new_images = request.FILES.getlist('new_images')
                for uploaded_file in new_images:
                    # Get the through model (e.g., LandImage, VillaImage, etc.)
                    image_model = product.images.model
                    new_image = image_model(image=uploaded_file)
                    new_image.save()  # the watermark will be applied in the model's save()
                    product.images.add(new_image)

            # ----------------------------------------------------------
            # 5. Handle videos (ManyToMany) – delete checked, add new
            # ----------------------------------------------------------
            if hasattr(product, 'videos'):
                delete_video_ids = request.POST.getlist('delete_videos')
                if delete_video_ids:
                    product.videos.filter(id__in=delete_video_ids).delete()

                new_videos = request.FILES.getlist('new_videos')
                for uploaded_file in new_videos:
                    video_model = product.videos.model
                    new_video = video_model(video=uploaded_file)
                    new_video.save()
                    product.videos.add(new_video)

            # Save the product (after all modifications)
            product.save()

            messages.success(request, f"The {property_type} has been updated successfully.")
            return redirect('property_detail', property_type=property_type, pk=product.id)

        except Exception as e:
            messages.error(request, f"Error updating product: {str(e)}")

    # --------------------------------------------------------------
    # 6. Prepare additional context for the template
    # --------------------------------------------------------------
    # For images and videos, we need to pass the existing ones
    existing_images = product.images.all() if hasattr(product, 'images') else []
    existing_videos = product.videos.all() if hasattr(product, 'videos') else []

    return render(request, 'admin1/property_edit.html', {
        'product': product,
        'product_type': property_type,
        'fields': fields,
        'many_to_many_fields': many_to_many_fields,
        'existing_images': existing_images,
        'existing_videos': existing_videos,
    })

