User = get_user_model()

@never_cache
@staff_member_required
def ad_analytics(request):
    """
    Comprehensive analytics dashboard for all ads (Admin View)
    """
    # Get date range filters
    days = request.GET.get('days', '30')
    if days == 'all':
        start_date = datetime(2000, 1, 1)  # or a very old date
        days_param = 'all'
    else:
        days = int(days)
        days_param = days
    
    user_filter = request.GET.get('user', '')
    
    # Calculate date range
    end_date = timezone.now()
    if days != 'all':
        start_date = end_date - timedelta(days=days)
    else:
        start_date = datetime(2000, 1, 1, tzinfo=timezone.get_current_timezone())
    
    # All listing models
    models = [
        'Land', 'Villa', 'Automobile', 'Commercial', 'Farm', 'Chalet',
        'Fashion', 'Toys', 'Food', 'Pet', 'Book', 'Appliance',
        'Fitness', 'Business', 'Education', 'Service',
        'Mobile', 'Computer', 'Sound', 'Motorcycle', 'Scooter', 'Boat',
        'HeavyVehicle', 'AutoAccessoryPart', 'NumberPlate',
        'DrivingTraining', 'Apartment', 'Factory', 'Complex',
        'Clinic', 'Hostel', 'Office', 'Shop', 'Cafe', 'Staff',
        'Warehouse', 'Townhouse', 'Fullfloors', 'Showrooms',
        'Wholebuilding', 'Supermarket', 'Foreign', 'Part', 'SportsCar',
        'ComputerListing', 'BusinessIndustrialListing', 'PetListing', 'SportsListing',
        'MusicalListing', 'GamingListing', 'TicketVoucherListing', 'CollectibleListing',
        'BooksListing', 'MusicListing', 'DVDsMoviesListing', 'FurnitureHomeGardenListing',
        'BabyItemsListing', 'ToysListing', 'AutoServiceListing', 'ConsultancyServiceListing',
        'DomesticServiceListing', 'EventEntertainmentServiceListing', 'HealthWellbeingServiceListing',
        'HomeMaintenanceServiceListing', 'MoversServiceListing', 'RestorationServiceListing',
        'TutorsServiceListing', 'WebComputerServiceListing', 'FreelancersServiceListing',
        'OtherServiceListing', 'Tablet', 'SmartWatch', 'Headset', 'Cover',
        'Accessory', 'MobileSIM', 'LostFoundListing', 'CameraListing',
        'JewelryListing', 'HomeApplianceListing', 'ClothingAccessoriesListing',
        'ElectronicsListing', 'HelmetClothes', 'Quadbikes',
        'TiresAndCaps', 'JunkCar', 'Shared', 'Suits', 'CarRepairMaintenance'
    ]

    # Initialize data structures
    total_ads = 0
    pending_ads = 0
    approved_ads = 0
    rejected_ads = 0
    soldout_ads = 0
    total_value = 0
    ads_with_price = 0
    
    # Daily stats for chart
    daily_stats_dict = {}
    # Hourly distribution
    hourly_distribution = [0] * 24
    # Weekday distribution
    weekday_distribution = [0] * 7
    # Product category stats
    product_stats_dict = defaultdict(lambda: {'ads': 0, 'value': 0})
    # User engagement
    user_ads_count = defaultdict(int)
    user_engagement = {'very_active': 0, 'active': 0, 'moderate': 0, 'low': 0}
    # Top users by ads
    top_users_list = []
    # User list for dropdown
    user_list = []
    # Category performance
    category_performance = defaultdict(lambda: {'total': 0, 'approved': 0, 'pending': 0, 'rejected': 0, 'avg_price': 0})
    # Price ranges
    price_ranges = {
        '0_100': 0,
        '101_500': 0,
        '501_1000': 0,
        '1001_5000': 0,
        '5000_plus': 0
    }
    # Recent activities
    recent_activities = []
    
    # Weekday names
    weekday_names = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday', 'Sunday']
    
    # Process each model
    for model_name in models:
        try:
            model = apps.get_model('oman_app', model_name)
            
            # Get all ads
            queryset = model.objects.all()
            
            # Apply user filter if specified
            if user_filter and user_filter.isdigit():
                queryset = queryset.filter(user_id=user_filter)
            
            # Count by status
            total_ads += queryset.count()
            pending_ads += queryset.filter(status='pending').count()
            approved_ads += queryset.filter(status='approved').count()
            rejected_ads += queryset.filter(status='rejected').count()
            soldout_ads += queryset.filter(status='soldout').count()
            
            # Price calculations
            if hasattr(model, 'price'):
                price_qs = queryset.exclude(price__isnull=True).exclude(price=0)
                ads_with_price += price_qs.count()
                
                # Total value
                price_sum = price_qs.aggregate(Sum('price'))['price__sum']
                if price_sum:
                    total_value += float(price_sum)
                
                # Price ranges
                for ad in price_qs:
                    if ad.price <= 100:
                        price_ranges['0_100'] += 1
                    elif ad.price <= 500:
                        price_ranges['101_500'] += 1
                    elif ad.price <= 1000:
                        price_ranges['501_1000'] += 1
                    elif ad.price <= 5000:
                        price_ranges['1001_5000'] += 1
                    else:
                        price_ranges['5000_plus'] += 1
                
                # Category performance with price
                price_avg = price_qs.aggregate(Avg('price'))['price__avg']
                if price_avg:
                    category_performance[model_name]['avg_price'] = float(price_avg)
            
            # Daily stats (if created_at exists)
            if hasattr(model, 'created_at'):
                daily_ads = queryset.filter(created_at__gte=start_date, created_at__lte=end_date)
                
                for ad in daily_ads:
                    date_key = ad.created_at.date().isoformat()
                    daily_stats_dict[date_key] = daily_stats_dict.get(date_key, 0) + 1
                    
                    # Hourly distribution
                    hour = ad.created_at.hour
                    hourly_distribution[hour] += 1
                    
                    # Weekday distribution (0 = Monday, 6 = Sunday)
                    weekday = ad.created_at.weekday()
                    weekday_distribution[weekday] += 1
                    
                    # Product stats
                    product_stats_dict[model_name]['ads'] += 1
                    if hasattr(ad, 'price') and ad.price:
                        product_stats_dict[model_name]['value'] += float(ad.price)
                    
                    # User engagement
                    if hasattr(ad, 'user_id') and ad.user_id:
                        user_ads_count[ad.user_id] += 1
                        
                        # Add to recent activities
                        if len(recent_activities) < 50:
                            recent_activities.append({
                                'time': ad.created_at,
                                'user_id': ad.user_id,
                                'action': 'Posted new ad',
                                'category': model_name,
                                'status': getattr(ad, 'status', 'unknown')
                            })
            
            # Category performance counts
            category_performance[model_name]['total'] = queryset.count()
            category_performance[model_name]['approved'] = queryset.filter(status='approved').count()
            category_performance[model_name]['pending'] = queryset.filter(status='pending').count()
            category_performance[model_name]['rejected'] = queryset.filter(status='rejected').count()
            
        except LookupError:
            continue
        except Exception as e:
            logger.error(f"Error processing {model_name} for analytics: {e}")
            continue
    
    # Process user engagement levels
    for user_id, count in user_ads_count.items():
        if count >= 100:
            user_engagement['very_active'] += 1
        elif count >= 50:
            user_engagement['active'] += 1
        elif count >= 10:
            user_engagement['moderate'] += 1
        elif count >= 1:
            user_engagement['low'] += 1
    
    # Get top users and user list
    User = get_user_model()
    
    # Get all users with ads for dropdown
    users_with_ads = User.objects.filter(id__in=user_ads_count.keys())
    for user in users_with_ads:
        user_list.append({
            'id': user.id,
            'username': user.username,
            'email': user.email,
            'ad_count': user_ads_count.get(user.id, 0)
        })
    
    # Get top users with details
    for user_id, count in sorted(user_ads_count.items(), key=lambda x: x[1], reverse=True)[:10]:
        try:
            user = User.objects.get(id=user_id)
            
            # Safely get user name fields - CustomUser might not have first_name/last_name
            # Use username as fallback
            display_name = user.username
            
            top_users_list.append({
                'id': user_id,
                'username': user.username,
                'email': user.email,
                'ad_count': count,
                'display_name': display_name
            })
            
        except User.DoesNotExist:
            continue
    
    # Prepare daily stats for chart
    daily_stats = []
    current_date = start_date.date()
    end_date_date = end_date.date()
    
    while current_date <= end_date_date:
        daily_stats.append({
            'date': current_date.strftime('%Y-%m-%d'),
            'count': daily_stats_dict.get(current_date.isoformat(), 0)
        })
        current_date += timedelta(days=1)
    
    # Prepare hourly data for chart
    hourly_data = [{'hour': f'{i:02d}:00', 'count': hourly_distribution[i]} for i in range(24)]
    
    # Prepare weekday data
    weekday_data = [{'day': weekday_names[i], 'count': weekday_distribution[i]} for i in range(7)]
    
    # Prepare product stats for chart
    product_stats = []
    for model_name, stats in sorted(product_stats_dict.items(), key=lambda x: x[1]['ads'], reverse=True)[:10]:
        product_stats.append({
            'product_type': model_name,
            'ad_count': stats['ads'],
            'total_value': round(stats['value'], 2)
        })
    
    # Calculate growth rate (compare last 7 days with previous 7 days)
    last_7_days = 0
    prev_7_days = 0
    
    for i in range(7):
        last_7_days += daily_stats_dict.get((end_date - timedelta(days=i)).date().isoformat(), 0)
        prev_7_days += daily_stats_dict.get((end_date - timedelta(days=i+7)).date().isoformat(), 0)
    
    if prev_7_days > 0:
        growth_rate = round(((last_7_days - prev_7_days) / prev_7_days) * 100, 1)
    else:
        growth_rate = 100 if last_7_days > 0 else 0
    
    # Prepare top categories for display
    top_categories = []
    for k, v in sorted(category_performance.items(), key=lambda x: x[1]['total'], reverse=True)[:10]:
        top_categories.append({
            'name': k,
            'ads': v['total'],
            'approved': v['approved'],
            'avg_price': float(v['avg_price']) if v['avg_price'] else 0
        })
    
    # Calculate average price
    avg_price = float(total_value / ads_with_price) if ads_with_price > 0 else 0
    
    # Calculate approval rate
    approval_rate = round((approved_ads / total_ads * 100), 1) if total_ads > 0 else 0
    
    # Calculate price range percentages
    total_priced_ads = sum(price_ranges.values())
    price_ranges_with_percent = {}
    for key, value in price_ranges.items():
        price_ranges_with_percent[key] = value
        price_ranges_with_percent[f'{key}_percent'] = round((value / total_priced_ads * 100), 1) if total_priced_ads > 0 else 0
    
    # Sort recent activities by time
    recent_activities.sort(key=lambda x: x['time'], reverse=True)
    
    # Add user details to recent activities
    for activity in recent_activities[:10]:
        try:
            user = User.objects.get(id=activity['user_id'])
            activity['user'] = user.username
            activity['user_email'] = user.email
        except:
            activity['user'] = 'Unknown'
            activity['user_email'] = ''
    
    # Prepare context
    context = {
        'days': days_param,
        'selected_user': user_filter,
        'total_ads': total_ads,
        'pending_ads': pending_ads,
        'approved_ads': approved_ads,
        'rejected_ads': rejected_ads,
        'soldout_ads': soldout_ads,
        'total_value': float(total_value),
        'avg_price': avg_price,
        'approval_rate': approval_rate,
        'total_users_with_ads': len(user_ads_count),
        'avg_ads_per_user': round(float(total_ads) / len(user_ads_count), 2) if len(user_ads_count) > 0 else 0,
        'active_users_today': len(set([a['user_id'] for a in recent_activities if a['time'].date() == end_date.date()])),
        'growth_rate': growth_rate,
        'daily_stats': json.dumps(daily_stats),
        'hourly_distribution': json.dumps(hourly_data),
        'weekday_distribution': json.dumps(weekday_data),
        'product_stats': json.dumps(product_stats),
        'user_engagement': user_engagement,
        'top_users': top_users_list[:5],
        'user_list': sorted(user_list, key=lambda x: x['ad_count'], reverse=True),
        'top_categories': top_categories,
        'price_ranges': price_ranges_with_percent,
        'recent_activities': recent_activities[:10],
        'conversion_rate': approval_rate,  # Using approval rate as conversion rate
        'avg_response_time': 'N/A',  # You can calculate this if you have response time data
    }
    
    return render(request, 'admin1/Ads/ad_analytics.html', context)


@never_cache
@login_required
def user_ad_analytics(request, user_id=None):
    """
    Individual user ad analytics - accessible by admin for any user or by users for themselves
    """
    # Determine which user to show analytics for
    if request.user.is_staff and user_id:
        # Admin viewing another user's analytics
        target_user = User.objects.get(id=user_id)
    else:
        # User viewing their own analytics
        target_user = request.user
        user_id = request.user.id
    
    # Get date range filters
    days = int(request.GET.get('days', 30))
    
    # Calculate date range
    end_date = timezone.now()
    start_date = end_date - timedelta(days=days)
    
    # All listing models
    models = [
        'Land', 'Villa', 'Automobile', 'Commercial', 'Farm', 'Chalet',
        'Fashion', 'Toys', 'Food', 'Pet', 'Book', 'Appliance',
        'Fitness', 'Business', 'Education', 'Service',
        'Mobile', 'Computer', 'Sound', 'Motorcycle', 'Scooter', 'Boat',
        'HeavyVehicle', 'AutoAccessoryPart', 'NumberPlate',
        'DrivingTraining', 'Apartment', 'Factory', 'Complex',
        'Clinic', 'Hostel', 'Office', 'Shop', 'Cafe', 'Staff',
        'Warehouse', 'Townhouse', 'Fullfloors', 'Showrooms',
        'Wholebuilding', 'Supermarket', 'Foreign', 'Part', 'SportsCar',
        'ComputerListing', 'BusinessIndustrialListing', 'PetListing', 'SportsListing',
        'MusicalListing', 'GamingListing', 'TicketVoucherListing', 'CollectibleListing',
        'BooksListing', 'MusicListing', 'DVDsMoviesListing', 'FurnitureHomeGardenListing',
        'BabyItemsListing', 'ToysListing', 'AutoServiceListing', 'ConsultancyServiceListing',
        'DomesticServiceListing', 'EventEntertainmentServiceListing', 'HealthWellbeingServiceListing',
        'HomeMaintenanceServiceListing', 'MoversServiceListing', 'RestorationServiceListing',
        'TutorsServiceListing', 'WebComputerServiceListing', 'FreelancersServiceListing',
        'OtherServiceListing', 'Tablet', 'SmartWatch', 'Headset', 'Cover',
        'Accessory', 'MobileSIM', 'LostFoundListing', 'CameraListing',
        'JewelryListing', 'HomeApplianceListing', 'ClothingAccessoriesListing',
        'ElectronicsListing', 'HelmetClothes', 'Quadbikes',
        'TiresAndCaps', 'JunkCar', 'Shared', 'Suits', 'CarRepairMaintenance'
    ]

    # Initialize user analytics data
    user_analytics = {
        'user': {
            'id': target_user.id,
            'username': target_user.username,
            'email': target_user.email,
            'display_name': target_user.username,
            'date_joined': target_user.date_joined.strftime('%Y-%m-%d') if hasattr(target_user, 'date_joined') else 'N/A',
            'last_login': target_user.last_login.strftime('%Y-%m-%d %H:%M') if target_user.last_login else 'Never',
        },
        'overview': {
            'total_ads': 0,
            'pending_ads': 0,
            'approved_ads': 0,
            'rejected_ads': 0,
            'soldout_ads': 0,
            'total_value': 0,
            'avg_price': 0,
            'approval_rate': 0,
        },
        'daily_stats': {},
        'category_breakdown': defaultdict(lambda: {'total': 0, 'approved': 0, 'pending': 0, 'value': 0}),
        'recent_ads': [],
        'performance': {
            'best_category': {'name': '', 'count': 0},
            'most_expensive_ad': {'title': '', 'price': 0, 'category': ''},
            'oldest_ad': {'title': '', 'date': '', 'category': ''},
        },
        'activity_pattern': {
            'hourly': [0] * 24,
            'weekly': [0] * 7,
        }
    }
    
    # Process each model for this user
    all_user_ads = []
    
    for model_name in models:
        try:
            model = apps.get_model('oman_app', model_name)
            
            # Filter by user
            if hasattr(model, 'user'):
                user_ads = model.objects.filter(user=target_user)
            else:
                continue
            
            # Count by status
            user_analytics['overview']['total_ads'] += user_ads.count()
            user_analytics['overview']['pending_ads'] += user_ads.filter(status='pending').count()
            user_analytics['overview']['approved_ads'] += user_ads.filter(status='approved').count()
            user_analytics['overview']['rejected_ads'] += user_ads.filter(status='rejected').count()
            user_analytics['overview']['soldout_ads'] += user_ads.filter(status='soldout').count()
            
            # Category breakdown
            user_analytics['category_breakdown'][model_name]['total'] += user_ads.count()
            user_analytics['category_breakdown'][model_name]['approved'] += user_ads.filter(status='approved').count()
            user_analytics['category_breakdown'][model_name]['pending'] += user_ads.filter(status='pending').count()
            
            # Price calculations
            if hasattr(model, 'price'):
                price_ads = user_ads.exclude(price__isnull=True).exclude(price=0)
                price_sum = price_ads.aggregate(Sum('price'))['price__sum']
                if price_sum:
                    user_analytics['overview']['total_value'] += float(price_sum)
                    user_analytics['category_breakdown'][model_name]['value'] += float(price_sum)
            
            # Daily stats and recent ads
            if hasattr(model, 'created_at'):
                recent = user_ads.filter(created_at__gte=start_date).order_by('-created_at')[:10]
                
                for ad in recent:
                    date_key = ad.created_at.date().isoformat()
                    user_analytics['daily_stats'][date_key] = user_analytics['daily_stats'].get(date_key, 0) + 1
                    
                    # Activity patterns
                    hour = ad.created_at.hour
                    user_analytics['activity_pattern']['hourly'][hour] += 1
                    
                    weekday = ad.created_at.weekday()
                    user_analytics['activity_pattern']['weekly'][weekday] += 1
                
                # Collect recent ads for display
                for ad in user_ads.order_by('-created_at')[:20]:
                    all_user_ads.append({
                        'id': ad.id,
                        'title': getattr(ad, 'name', getattr(ad, 'title', 'N/A')),
                        'category': model_name,
                        'status': getattr(ad, 'status', 'unknown'),
                        'price': float(getattr(ad, 'price', 0)) if getattr(ad, 'price', 0) else 0,
                        'created_at': ad.created_at.strftime('%Y-%m-%d %H:%M') if ad.created_at else 'N/A',
                        'model_name': model_name.lower()
                    })
                    
                    # Track performance metrics
                    if hasattr(ad, 'price') and ad.price:
                        if ad.price > user_analytics['performance']['most_expensive_ad']['price']:
                            user_analytics['performance']['most_expensive_ad'] = {
                                'title': getattr(ad, 'name', getattr(ad, 'title', 'N/A')),
                                'price': float(ad.price),
                                'category': model_name
                            }
            
        except LookupError:
            continue
        except Exception as e:
            logger.error(f"Error processing {model_name} for user analytics: {e}")
            continue
    
    # Calculate approval rate
    if user_analytics['overview']['total_ads'] > 0:
        user_analytics['overview']['approval_rate'] = round(
            (user_analytics['overview']['approved_ads'] / user_analytics['overview']['total_ads']) * 100, 1
        )
        user_analytics['overview']['avg_price'] = round(
            user_analytics['overview']['total_value'] / user_analytics['overview']['total_ads'], 2
        )
    
    # Find best category
    for cat_name, stats in user_analytics['category_breakdown'].items():
        if stats['total'] > user_analytics['performance']['best_category']['count']:
            user_analytics['performance']['best_category'] = {
                'name': cat_name,
                'count': stats['total'],
                'approved': stats['approved']
            }
    
    # Sort recent ads
    user_analytics['recent_ads'] = sorted(
        all_user_ads, 
        key=lambda x: x['created_at'], 
        reverse=True
    )[:20]
    
    # Calculate peak posting hour
    hourly_pattern = user_analytics['activity_pattern']['hourly']
    if hourly_pattern and any(hourly_pattern):
        peak_hour = hourly_pattern.index(max(hourly_pattern))
    else:
        peak_hour = None
    
    # Prepare daily stats for chart
    daily_stats_list = []
    current_date = start_date.date()
    while current_date <= end_date.date():
        daily_stats_list.append({
            'date': current_date.strftime('%Y-%m-%d'),
            'count': user_analytics['daily_stats'].get(current_date.isoformat(), 0)
        })
        current_date += timedelta(days=1)
    
    # Prepare category data for chart
    category_list = []
    for cat_name, stats in sorted(
        user_analytics['category_breakdown'].items(), 
        key=lambda x: x[1]['total'], 
        reverse=True
    )[:10]:
        if stats['total'] > 0:
            category_list.append({
                'name': cat_name,
                'total': stats['total'],
                'approved': stats['approved'],
                'value': round(stats['value'], 2)
            })
    
    # Weekday names
    weekday_names = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday', 'Sunday']
    
    context = {
        'days': days,
        'user_analytics': user_analytics,
        'daily_stats': json.dumps(daily_stats_list),
        'hourly_distribution': json.dumps([
            {'hour': f'{i:02d}:00', 'count': user_analytics['activity_pattern']['hourly'][i]} 
            for i in range(24)
        ]),
        'weekday_distribution': json.dumps([
            {'day': weekday_names[i], 'count': user_analytics['activity_pattern']['weekly'][i]} 
            for i in range(7)
        ]),
        'category_stats': json.dumps(category_list),
        'is_admin': request.user.is_staff,
        'peak_hour': peak_hour,
    }
    
    template = 'admin1/Ads/user_ad_analytics.html' if request.user.is_staff else 'user_ad_analytics.html'
    return render(request, template, context)

@never_cache
@staff_member_required
def ad_performance_detail(request, ad_id, model_name):
    """
    Detailed analytics for a specific ad
    """
    try:
        model = apps.get_model('oman_app', model_name)
        ad = model.objects.get(id=ad_id)
        
        # Get similar ads in same category
        similar_ads = []
        if hasattr(ad, 'price') and ad.price:
            similar = model.objects.filter(
                status='approved',
                price__range=(ad.price * 0.7, ad.price * 1.3)
            ).exclude(id=ad.id)[:5]
            similar_ads = similar
        
        performance_data = {
            'ad': ad,
            'model_name': model_name,
            'similar_ads': similar_ads,
        }
        
        return render(request, 'admin1/Ads/ad_performance_detail.html', performance_data)
        
    except (LookupError, model.DoesNotExist):
        messages.error(request, "Ad not found.")
        return redirect('ad_analytics')


