@staff_member_required
def user_activity_log(request):
    """
    COMPREHENSIVE user activity log that tracks EVERYTHING:
    - User registrations and logins
    - All listing creations (100+ models)
    - Favorites
    - Product reports
    - Chat messages
    - Job applications
    - Follow actions
    - Profile views
    - Company registrations
    - Job posts
    """
    
    # Get filter parameters
    user_id = request.GET.get('user_id')
    action_type = request.GET.get('action_type')
    date_from = request.GET.get('date_from')
    date_to = request.GET.get('date_to')
    search = request.GET.get('search', '').strip()
    model_type = request.GET.get('model_type')
    
    # Convert user_id to int if provided
    try:
        if user_id:
            user_id = int(user_id)
        else:
            user_id = None
    except (ValueError, TypeError):
        user_id = None
    
    # Parse dates safely
    try:
        if date_from:
            date_from = datetime.strptime(date_from, '%Y-%m-%d').date()
        if date_to:
            date_to = datetime.strptime(date_to, '%Y-%m-%d').date()
    except (ValueError, TypeError):
        date_from = None
        date_to = None
    
    # =========================================================================
    # 1. COLLECT ALL ACTIVITIES FROM ALL SOURCES
    # =========================================================================
    activities = []
    
    # -------------------------------------------------------------------------
    # 1.1 USER ACCOUNT ACTIVITIES
    # -------------------------------------------------------------------------
    print("Processing user account activities...")
    
    # User registrations
    users_qs = CustomUser.objects.all().select_related()
    if search:
        users_qs = users_qs.filter(Q(username__icontains=search) | Q(email__icontains=search))
    if date_from:
        users_qs = users_qs.filter(date_joined__date__gte=date_from)
    if date_to:
        users_qs = users_qs.filter(date_joined__date__lte=date_to)
    if user_id:
        users_qs = users_qs.filter(id=user_id)
    
    for user in users_qs:
        activities.append({
            'id': f"user_reg_{user.id}",
            'timestamp': user.date_joined,
            'user': user,
            'user_id': user.id,
            'username': user.username,
            'user_email': user.email,
            'user_type': user.user_type,
            'action_type': 'user_registration',
            'action': 'User Registered',
            'description': f"New account created",
            'details': {
                'email': user.email,
                'user_type': user.user_type,
                'is_approved': user.is_approved,
                'is_active': user.is_active
            },
            'ip_address': None,
            'icon': 'user-plus',
            'color': 'success',
            'model_name': 'CustomUser',
            'object_id': user.id,
            'url': reverse('user_activity_detail', args=[user.id])
        })
    
    # User logins
    login_users = CustomUser.objects.exclude(last_login__isnull=True)
    if date_from:
        login_users = login_users.filter(last_login__date__gte=date_from)
    if date_to:
        login_users = login_users.filter(last_login__date__lte=date_to)
    if user_id:
        login_users = login_users.filter(id=user_id)
    
    for user in login_users[:500]:
        if user.last_login:
            activities.append({
                'id': f"user_login_{user.id}_{user.last_login.timestamp()}",
                'timestamp': user.last_login,
                'user': user,
                'user_id': user.id,
                'username': user.username,
                'user_email': user.email,
                'user_type': user.user_type,
                'action_type': 'user_login',
                'action': 'User Login',
                'description': f"Logged into the system",
                'details': {
                    'ip_address': getattr(user, 'last_login_ip', 'Unknown'),
                    'user_agent': getattr(user, 'last_login_user_agent', 'Unknown')
                },
                'ip_address': None,
                'icon': 'sign-in-alt',
                'color': 'info',
                'model_name': 'CustomUser',
                'object_id': user.id,
                'url': reverse('user_activity_detail', args=[user.id])
            })
    
    # -------------------------------------------------------------------------
    # 1.2 ALL LISTING ACTIVITIES (CREATE, UPDATE, DELETE, STATUS CHANGE)
    # -------------------------------------------------------------------------
    print("Processing listing activities from 100+ models...")
    
    # Filter by model type if specified
    if model_type:
        models_to_process = [m for m in ALL_LISTING_MODELS if m.lower() == model_type.lower()]
        if not models_to_process:
            models_to_process = [model_type]  # Try exact match
    else:
        models_to_process = ALL_LISTING_MODELS
    
    for model_name in models_to_process:
        try:
            model = apps.get_model('oman_app', model_name)
            if not model:
                continue
            
            # Get all objects
            queryset = model.objects.all()
            
            # Apply search filter
            if search:
                search_q = Q()
                # Try common text fields
                for field in ['title', 'name', 'property_title', 'description', 'make', 'model', 'headline']:
                    if hasattr(model, field):
                        search_q |= Q(**{f"{field}__icontains": search})
                queryset = queryset.filter(search_q)
            
            # Determine which date field to use (try multiple options)
            date_field = None
            for field in ['created_at', 'posted_on', 'timestamp', 'date_joined', 'created', 'date']:
                if hasattr(model, field):
                    date_field = field
                    break
            
            # Apply date filters using the detected date field
            if date_field:
                if date_from:
                    queryset = queryset.filter(**{f"{date_field}__date__gte": date_from})
                if date_to:
                    queryset = queryset.filter(**{f"{date_field}__date__lte": date_to})
            
            # Apply user filter
            if user_id and hasattr(model, 'user_id'):
                queryset = queryset.filter(user_id=user_id)
            
            # Limit for performance - get most recent first
            if date_field:
                queryset = queryset.order_by(f'-{date_field}')[:100]
            else:
                queryset = queryset.order_by('-id')[:100]
            
            for item in queryset:
                # Get display title
                display_title = "Unknown"
                for field in ['title', 'name', 'property_title', 'headline']:
                    if hasattr(item, field) and getattr(item, field):
                        display_title = getattr(item, field)
                        break
                if display_title == "Unknown" and hasattr(item, 'id'):
                    display_title = f"{model_name} #{item.id}"
                
                # Get timestamp - CRITICAL: Try multiple fields and NEVER default to now()
                timestamp = None
                
                # Try each possible date field in order of preference
                for field in ['created_at', 'posted_on', 'timestamp', 'date_joined', 'created', 'date']:
                    if hasattr(item, field):
                        value = getattr(item, field)
                        if value and isinstance(value, (datetime, timezone.datetime)):
                            timestamp = value
                            break
                
                # If no timestamp found, skip this item (we can't determine when it happened)
                if timestamp is None:
                    continue
                
                # Get user
                item_user = None
                if hasattr(item, 'user') and getattr(item, 'user'):
                    item_user = item.user
                elif hasattr(item, 'user_id') and item.user_id:
                    try:
                        item_user = CustomUser.objects.get(id=item.user_id)
                    except:
                        pass
                
                # Get status
                status = getattr(item, 'status', 'unknown') if hasattr(item, 'status') else 'unknown'
                
                # Get price
                price = None
                if hasattr(item, 'price') and getattr(item, 'price'):
                    price = str(getattr(item, 'price'))
                
                # CREATE ACTIVITY
                activities.append({
                    'id': f"{model_name}_{item.id}",
                    'timestamp': timestamp,
                    'user': item_user,
                    'user_id': item_user.id if item_user else None,
                    'username': item_user.username if item_user else 'System',
                    'user_email': item_user.email if item_user else '',
                    'user_type': item_user.user_type if item_user else 'system',
                    'action_type': 'listing_created',
                    'action': f"{model_name} Created",
                    'description': f"Created {model_name}: {display_title}",
                    'details': {
                        'model': model_name,
                        'id': item.id,
                        'status': status,
                        'price': price,
                        'title': display_title
                    },
                    'icon': 'plus-circle',
                    'color': 'primary',
                    'model_name': model_name,
                    'object_id': item.id,
                    'status': status,
                    'url': reverse('user_activity_detail', args=[item_user.id]) if item_user else None
                })
                
                # If item has status and it's not 'pending', it might have been approved/rejected
                # This requires an 'updated_at' or similar field
                if status != 'pending' and status != 'unknown':
                    # Try to find when status changed - use updated_at if available
                    updated_timestamp = None
                    for field in ['updated_at', 'modified_at', 'updated', 'last_modified']:
                        if hasattr(item, field):
                            value = getattr(item, field)
                            if value and isinstance(value, (datetime, timezone.datetime)):
                                updated_timestamp = value
                                break
                    
                    if updated_timestamp and updated_timestamp != timestamp:
                        activities.append({
                            'id': f"{model_name}_{item.id}_status",
                            'timestamp': updated_timestamp,
                            'user': None,  # Admin who changed it - would need tracking
                            'user_id': None,
                            'username': 'System',
                            'action_type': 'listing_status_changed',
                            'action': f"{model_name} Status Changed",
                            'description': f"Status changed to {status}: {display_title}",
                            'details': {
                                'model': model_name,
                                'id': item.id,
                                'new_status': status,
                                'previous_status': 'pending',  # This is assumed
                                'title': display_title
                            },
                            'icon': 'exchange-alt',
                            'color': 'warning',
                            'model_name': model_name,
                            'object_id': item.id,
                            'url': None
                        })
                
        except LookupError:
            continue
        except Exception as e:
            print(f"Error processing {model_name}: {e}")
            continue
    
    # -------------------------------------------------------------------------
    # 1.3 FAVORITE ACTIVITIES
    # -------------------------------------------------------------------------
    print("Processing favorite actions...")
    try:
        favorites = Favorite.objects.all().select_related('user', 'content_type')
        
        if search:
            favorites = favorites.filter(
                Q(user__username__icontains=search) | 
                Q(content_type__model__icontains=search)
            )
        if date_from:
            favorites = favorites.filter(created_at__date__gte=date_from)
        if date_to:
            favorites = favorites.filter(created_at__date__lte=date_to)
        if user_id:
            favorites = favorites.filter(user_id=user_id)
        
        for fav in favorites[:500]:
            content_obj = fav.content_object
            content_name = "Unknown"
            content_status = "unknown"
            
            if content_obj:
                # Get name/title
                for field in ['title', 'name', 'property_title', 'headline']:
                    if hasattr(content_obj, field) and getattr(content_obj, field):
                        content_name = getattr(content_obj, field)
                        break
                if content_name == "Unknown" and hasattr(content_obj, 'id'):
                    content_name = f"{fav.content_type.model} #{content_obj.id}"
                
                # Get status
                if hasattr(content_obj, 'status') and getattr(content_obj, 'status'):
                    content_status = getattr(content_obj, 'status')
            
            # Favorite ADDED activity
            activities.append({
                'id': f"favorite_add_{fav.id}",
                'timestamp': fav.created_at,
                'user': fav.user,
                'user_id': fav.user.id if fav.user else None,
                'username': fav.user.username if fav.user else 'Unknown',
                'user_email': fav.user.email if fav.user else '',
                'action_type': 'favorite_added',
                'action': 'Added to Favorites',
                'description': f"Added {fav.content_type.model} to favorites: {content_name}",
                'details': {
                    'content_type': fav.content_type.model,
                    'content_type_id': fav.content_type.id,
                    'object_id': fav.object_id,
                    'content_name': content_name,
                    'content_status': content_status
                },
                'icon': 'heart',
                'color': 'danger',
                'model_name': fav.content_type.model,
                'object_id': fav.object_id,
                'url': reverse('user_activity_detail', args=[fav.user.id]) if fav.user else None
            })
            
    except Exception as e:
        print(f"Error in favorite actions: {e}")
    
    # -------------------------------------------------------------------------
    # 1.4 PRODUCT REPORTS
    # -------------------------------------------------------------------------
    print("Processing product reports...")
    try:
        reports = ProductReport.objects.all().select_related('reporter')
        
        if search:
            reports = reports.filter(Q(reason__icontains=search) | Q(description__icontains=search))
        if date_from:
            reports = reports.filter(created_at__date__gte=date_from)
        if date_to:
            reports = reports.filter(created_at__date__lte=date_to)
        if user_id:
            reports = reports.filter(reporter_id=user_id)
        
        for report in reports[:500]:
            activities.append({
                'id': f"report_{report.id}",
                'timestamp': report.created_at,
                'user': report.reporter,
                'user_id': report.reporter.id if report.reporter else None,
                'username': report.reporter.username if report.reporter else 'Anonymous',
                'user_email': report.reporter.email if report.reporter else '',
                'action_type': 'report_created',
                'action': 'Product Reported',
                'description': f"Reported {report.get_reason_display()}: {report.description[:50]}...",
                'details': {
                    'reason': report.get_reason_display(),
                    'reason_code': report.reason,
                    'description': report.description,
                    'content_type': str(report.content_type),
                    'object_id': report.object_id
                },
                'icon': 'flag',
                'color': 'warning',
                'model_name': 'ProductReport',
                'object_id': report.id,
                'url': reverse('user_activity_detail', args=[report.reporter.id]) if report.reporter else None
            })
    except Exception as e:
        print(f"Error in product reports: {e}")
    
    # -------------------------------------------------------------------------
    # 1.5 CHAT MESSAGES
    # -------------------------------------------------------------------------
    print("Processing chat messages...")
    try:
        messages_qs = ChatMessage.objects.all().select_related('sender', 'receiver')
        
        if search:
            messages_qs = messages_qs.filter(Q(message__icontains=search))
        if date_from:
            messages_qs = messages_qs.filter(timestamp__date__gte=date_from)
        if date_to:
            messages_qs = messages_qs.filter(timestamp__date__lte=date_to)
        if user_id:
            messages_qs = messages_qs.filter(Q(sender_id=user_id) | Q(receiver_id=user_id))
        
        for msg in messages_qs[:500]:
            activities.append({
                'id': f"chat_{msg.id}",
                'timestamp': msg.timestamp,
                'user': msg.sender,
                'user_id': msg.sender.id,
                'username': msg.sender.username,
                'user_email': msg.sender.email,
                'action_type': 'chat_message',
                'action': 'Chat Message',
                'description': f"Message to {msg.receiver.username}: {msg.message[:50]}...",
                'details': {
                    'receiver': msg.receiver.username,
                    'receiver_id': msg.receiver.id,
                    'receiver_email': msg.receiver.email,
                    'message': msg.message[:200],
                    'is_read': msg.is_read,
                    'is_admin_chat': msg.is_admin_chat,
                    'product_id': msg.product_id,
                    'product_type': msg.product_type
                },
                'icon': 'comment',
                'color': 'secondary',
                'model_name': 'ChatMessage',
                'object_id': msg.id,
                'url': reverse('user_activity_detail', args=[msg.sender.id])
            })
    except Exception as e:
        print(f"Error in chat messages: {e}")
    
    # -------------------------------------------------------------------------
    # 1.6 JOB APPLICATIONS
    # -------------------------------------------------------------------------
    print("Processing job applications...")
    try:
        job_apps = JobApplication.objects.all().select_related('user', 'job', 'company')
        
        if search:
            job_apps = job_apps.filter(Q(name__icontains=search) | Q(email__icontains=search))
        if date_from:
            job_apps = job_apps.filter(applied_on__date__gte=date_from)
        if date_to:
            job_apps = job_apps.filter(applied_on__date__lte=date_to)
        if user_id:
            job_apps = job_apps.filter(user_id=user_id)
        
        for app in job_apps[:500]:
            activities.append({
                'id': f"jobapp_{app.id}",
                'timestamp': app.applied_on,
                'user': app.user,
                'user_id': app.user.id,
                'username': app.user.username,
                'user_email': app.user.email,
                'action_type': 'job_application',
                'action': 'Job Application',
                'description': f"Applied for: {app.job.title if app.job else 'Unknown'}",
                'details': {
                    'job': app.job.title if app.job else 'N/A',
                    'job_id': app.job.id if app.job else None,
                    'company': app.company.company_name if app.company else 'N/A',
                    'company_id': app.company.id if app.company else None,
                    'name': app.name,
                    'email': app.email,
                    'phone': app.phone,
                    'status': app.status
                },
                'icon': 'briefcase',
                'color': 'info',
                'model_name': 'JobApplication',
                'object_id': app.id,
                'url': reverse('user_activity_detail', args=[app.user.id]) if app.user else None
            })
    except Exception as e:
        print(f"Error in job applications: {e}")
    
    # -------------------------------------------------------------------------
    # 1.7 FOLLOW ACTIVITIES
    # -------------------------------------------------------------------------
    print("Processing follow actions...")
    try:
        follows = UserFollow.objects.all().select_related('follower', 'following')
        
        if date_from:
            follows = follows.filter(created_at__date__gte=date_from)
        if date_to:
            follows = follows.filter(created_at__date__lte=date_to)
        if user_id:
            follows = follows.filter(Q(follower_id=user_id) | Q(following_id=user_id))
        
        for follow in follows[:500]:
            activities.append({
                'id': f"follow_{follow.id}",
                'timestamp': follow.created_at,
                'user': follow.follower,
                'user_id': follow.follower.id,
                'username': follow.follower.username,
                'user_email': follow.follower.email,
                'action_type': 'follow',
                'action': 'Follow Action',
                'description': f"{follow.follower.username} followed {follow.following.username}",
                'details': {
                    'follower': follow.follower.username,
                    'follower_id': follow.follower.id,
                    'following': follow.following.username,
                    'following_id': follow.following.id,
                    'following_email': follow.following.email
                },
                'icon': 'user-friends',
                'color': 'success',
                'model_name': 'UserFollow',
                'object_id': follow.id,
                'url': reverse('user_activity_detail', args=[follow.follower.id])
            })
    except Exception as e:
        print(f"Error in follow actions: {e}")
    
    # -------------------------------------------------------------------------
    # 1.8 PROFILE VIEWS
    # -------------------------------------------------------------------------
    print("Processing profile views...")
    try:
        profile_views = UserProfileView.objects.all().select_related('viewer', 'profile_owner')
        
        if date_from:
            profile_views = profile_views.filter(viewed_at__date__gte=date_from)
        if date_to:
            profile_views = profile_views.filter(viewed_at__date__lte=date_to)
        if user_id:
            profile_views = profile_views.filter(Q(viewer_id=user_id) | Q(profile_owner_id=user_id))
        
        for view in profile_views[:500]:
            viewer_name = view.viewer.username if view.viewer else 'Anonymous'
            viewer_email = view.viewer.email if view.viewer else ''
            activities.append({
                'id': f"profileview_{view.id}",
                'timestamp': view.viewed_at,
                'user': view.viewer,
                'user_id': view.viewer.id if view.viewer else None,
                'username': viewer_name,
                'user_email': viewer_email,
                'action_type': 'profile_view',
                'action': 'Profile View',
                'description': f"{viewer_name} viewed {view.profile_owner.username}'s profile",
                'details': {
                    'viewer': viewer_name,
                    'viewer_id': view.viewer.id if view.viewer else None,
                    'profile_owner': view.profile_owner.username,
                    'profile_owner_id': view.profile_owner.id,
                    'profile_owner_email': view.profile_owner.email,
                    'ip_address': view.ip_address
                },
                'icon': 'eye',
                'color': 'light',
                'model_name': 'UserProfileView',
                'object_id': view.id,
                'url': reverse('user_activity_detail', args=[view.viewer.id]) if view.viewer else None
            })
    except Exception as e:
        print(f"Error in profile views: {e}")
    
    # -------------------------------------------------------------------------
    # 1.9 COMPANY REGISTRATIONS
    # -------------------------------------------------------------------------
    print("Processing company registrations...")
    try:
        companies = Company.objects.all().select_related('user')
        
        if search:
            companies = companies.filter(Q(company_name__icontains=search))
        if date_from and hasattr(Company, 'created_at'):
            companies = companies.filter(created_at__date__gte=date_from)
        if date_to and hasattr(Company, 'created_at'):
            companies = companies.filter(created_at__date__lte=date_to)
        if user_id:
            companies = companies.filter(user_id=user_id)
        
        for company in companies[:500]:
            # Determine timestamp - try multiple fields
            timestamp = None
            for field in ['created_at', 'registered_on', 'date_joined', 'created']:
                if hasattr(company, field):
                    value = getattr(company, field)
                    if value and isinstance(value, (datetime, timezone.datetime)):
                        timestamp = value
                        break
            
            if timestamp is None:
                continue
            
            activities.append({
                'id': f"company_{company.id}",
                'timestamp': timestamp,
                'user': company.user,
                'user_id': company.user.id if company.user else None,
                'username': company.user.username if company.user else 'Unknown',
                'user_email': company.user.email if company.user else '',
                'action_type': 'company_registration',
                'action': 'Company Registered',
                'description': f"Registered company: {company.company_name}",
                'details': {
                    'company_name': company.company_name,
                    'company_type': company.company_type,
                    'trade_license': company.trade_license,
                    'industry': company.industry,
                    'status': company.status,
                    'email': company.email,
                    'phone': company.phone
                },
                'icon': 'building',
                'color': 'dark',
                'model_name': 'Company',
                'object_id': company.id,
                'url': reverse('user_activity_detail', args=[company.user.id]) if company.user else None
            })
    except Exception as e:
        print(f"Error in company registrations: {e}")
    
    # -------------------------------------------------------------------------
    # 1.10 JOB POSTS
    # -------------------------------------------------------------------------
    print("Processing job posts...")
    try:
        job_posts = JobPost.objects.all().select_related('user', 'company', 'job_category')
        
        if search:
            job_posts = job_posts.filter(Q(title__icontains=search))
        if date_from:
            job_posts = job_posts.filter(posted_on__date__gte=date_from)
        if date_to:
            job_posts = job_posts.filter(posted_on__date__lte=date_to)
        if user_id:
            job_posts = job_posts.filter(user_id=user_id)
        
        for job in job_posts[:500]:
            activities.append({
                'id': f"jobpost_{job.id}",
                'timestamp': job.posted_on,
                'user': job.user,
                'user_id': job.user.id,
                'username': job.user.username,
                'user_email': job.user.email,
                'action_type': 'job_posted',
                'action': 'Job Posted',
                'description': f"Posted job: {job.title}",
                'details': {
                    'title': job.title,
                    'company': job.company.company_name if job.company else 'N/A',
                    'company_id': job.company.id if job.company else None,
                    'category': job.job_category.name if job.job_category else 'N/A',
                    'job_type': job.job_type,
                    'salary': str(job.salary_range) if job.salary_range else 'N/A',
                    'deadline': str(job.application_deadline)
                },
                'icon': 'briefcase',
                'color': 'info',
                'model_name': 'JobPost',
                'object_id': job.id,
                'url': reverse('user_activity_detail', args=[job.user.id])
            })
    except Exception as e:
        print(f"Error in job posts: {e}")
    
    # -------------------------------------------------------------------------
    # 1.11 JOB SEEKER PROFILES (NEW)
    # -------------------------------------------------------------------------
    print("Processing job seeker profiles...")
    try:
        jobseekers = JobSeeker.objects.all().select_related('user', 'city')
        
        if search:
            jobseekers = jobseekers.filter(
                Q(user__username__icontains=search) | 
                Q(headline__icontains=search)
            )
        if date_from and hasattr(JobSeeker, 'created_at'):
            jobseekers = jobseekers.filter(created_at__date__gte=date_from)
        if date_to and hasattr(JobSeeker, 'created_at'):
            jobseekers = jobseekers.filter(created_at__date__lte=date_to)
        if user_id:
            jobseekers = jobseekers.filter(user_id=user_id)
        
        for seeker in jobseekers[:500]:
            # Determine timestamp
            timestamp = None
            for field in ['created_at', 'updated_at']:
                if hasattr(seeker, field):
                    value = getattr(seeker, field)
                    if value and isinstance(value, (datetime, timezone.datetime)):
                        timestamp = value
                        break
            
            if timestamp is None:
                continue
            
            activities.append({
                'id': f"jobseeker_{seeker.id}",
                'timestamp': timestamp,
                'user': seeker.user,
                'user_id': seeker.user.id,
                'username': seeker.user.username,
                'user_email': seeker.user.email,
                'action_type': 'jobseeker_profile',
                'action': 'Job Seeker Profile',
                'description': f"Updated job seeker profile: {seeker.headline or 'No headline'}",
                'details': {
                    'headline': seeker.headline,
                    'experience': seeker.work_experience,
                    'education': seeker.education_level,
                    'expected_salary': seeker.expected_salary,
                    'gender': seeker.gender,
                    'nationality': seeker.nationality
                },
                'icon': 'user-tie',
                'color': 'primary',
                'model_name': 'JobSeeker',
                'object_id': seeker.id,
                'url': reverse('user_activity_detail', args=[seeker.user.id])
            })
    except Exception as e:
        print(f"Error in job seeker profiles: {e}")
    
    # -------------------------------------------------------------------------
    # 1.12 JOB SEEKER PROFILES (SPECIFIC CATEGORY UPDATES)
    # -------------------------------------------------------------------------
    try:
        seeker_profiles = JobSeekerProfile.objects.all().select_related('jobseeker', 'job_category')
        
        if search:
            seeker_profiles = seeker_profiles.filter(
                Q(job_category__name__icontains=search)
            )
        if date_from and hasattr(JobSeekerProfile, 'created_at'):
            seeker_profiles = seeker_profiles.filter(created_at__date__gte=date_from)
        if date_to and hasattr(JobSeekerProfile, 'created_at'):
            seeker_profiles = seeker_profiles.filter(created_at__date__lte=date_to)
        
        for profile in seeker_profiles[:500]:
            # Determine timestamp
            timestamp = None
            for field in ['created_at', 'updated_at']:
                if hasattr(profile, field):
                    value = getattr(profile, field)
                    if value and isinstance(value, (datetime, timezone.datetime)):
                        timestamp = value
                        break
            
            if timestamp is None:
                continue
            
            activities.append({
                'id': f"jobseeker_profile_{profile.id}",
                'timestamp': timestamp,
                'user': profile.jobseeker.user if profile.jobseeker else None,
                'user_id': profile.jobseeker.user.id if profile.jobseeker and profile.jobseeker.user else None,
                'username': profile.jobseeker.user.username if profile.jobseeker and profile.jobseeker.user else 'System',
                'user_email': profile.jobseeker.user.email if profile.jobseeker and profile.jobseeker.user else '',
                'action_type': 'jobseeker_category_added',
                'action': 'Added Job Category',
                'description': f"Added {profile.job_category.name} to job seeker profile",
                'details': {
                    'jobseeker': str(profile.jobseeker),
                    'category': profile.job_category.name,
                    'availability': profile.availability,
                    'rate': profile.rate,
                    'currency': profile.currency
                },
                'icon': 'briefcase',
                'color': 'success',
                'model_name': 'JobSeekerProfile',
                'object_id': profile.id,
                'url': reverse('user_activity_detail', args=[profile.jobseeker.user.id]) if profile.jobseeker and profile.jobseeker.user else None
            })
    except Exception as e:
        print(f"Error in job seeker profiles category: {e}")
    
    # -------------------------------------------------------------------------
    # 1.13 SKILL ADDITIONS
    # -------------------------------------------------------------------------
    try:
        # This is trickier - skills are ManyToMany fields
        # For now, we'll skip detailed skill tracking unless you have a SkillAcquisition model
        pass
    except Exception as e:
        print(f"Error in skill tracking: {e}")
    
    # =========================================================================
    # 2. PROCESS AND SORT ALL ACTIVITIES
    # =========================================================================
    print(f"\nTotal raw activities collected: {len(activities)}")
    
    # Sort by timestamp (newest first)
    try:
        activities.sort(key=lambda x: x['timestamp'], reverse=True)
        print("Sorting successful")
    except Exception as e:
        print(f"Error sorting activities: {e}")
    
    # Apply action type filter
    if action_type and action_type != 'all':
        activities = [a for a in activities if a['action_type'] == action_type]
    
    # =========================================================================
    # 3. PAGINATION
    # =========================================================================
    ITEMS_PER_PAGE = 50
    paginator = Paginator(activities, ITEMS_PER_PAGE)
    page_number = request.GET.get('page', 1)
    
    try:
        page_obj = paginator.get_page(page_number)
    except Exception:
        page_obj = paginator.get_page(1)
    
    # =========================================================================
    # 4. STATISTICS
    # =========================================================================
    total_activities = len(activities)
    
    # Activity counts by type
    activity_counts = {}
    for activity in activities:
        act_type = activity['action_type']
        activity_counts[act_type] = activity_counts.get(act_type, 0) + 1
    
    # Activity in last 24 hours
    last_24h = timezone.now() - timedelta(hours=24)
    activities_24h = sum(1 for a in activities if a['timestamp'] >= last_24h)
    
    # Activity in last 7 days
    last_7d = timezone.now() - timedelta(days=7)
    activities_7d = sum(1 for a in activities if a['timestamp'] >= last_7d)
    
    # Activity in last 30 days
    last_30d = timezone.now() - timedelta(days=30)
    activities_30d = sum(1 for a in activities if a['timestamp'] >= last_30d)
    
    # Unique users with activity
    unique_users = len(set(a['user_id'] for a in activities if a['user_id']))
    
    # Most active users
    user_activity_counts = {}
    for activity in activities:
        if activity['user_id']:
            user_activity_counts[activity['user_id']] = user_activity_counts.get(activity['user_id'], 0) + 1
    
    top_users = []
    for user_id, count in sorted(user_activity_counts.items(), key=lambda x: x[1], reverse=True)[:10]:
        try:
            user = CustomUser.objects.get(id=user_id)
            top_users.append({
                'user': user,
                'username': user.username,
                'email': user.email,
                'count': count,
                'url': reverse('user_activity_detail', args=[user.id])
            })
        except:
            pass
    
    # Activity by model type
    model_counts = {}
    for activity in activities:
        model = activity.get('model_name', 'unknown')
        model_counts[model] = model_counts.get(model, 0) + 1
    
    # =========================================================================
    # 5. USER LIST FOR FILTER DROPDOWN
    # =========================================================================
    try:
        user_list = CustomUser.objects.all().order_by('username')[:500]
    except Exception:
        user_list = []
    
    # =========================================================================
    # 6. MODEL LIST FOR FILTER DROPDOWN
    # =========================================================================
    model_choices = sorted(set(ALL_LISTING_MODELS))
    
    # =========================================================================
    # 7. CONTEXT
    # =========================================================================
    context = {
        'page_obj': page_obj,
        'activities': page_obj.object_list,
        'total_activities': total_activities,
        'activities_24h': activities_24h,
        'activities_7d': activities_7d,
        'activities_30d': activities_30d,
        'unique_users': unique_users,
        'activity_counts': activity_counts,
        'model_counts': model_counts,
        'top_users': top_users,
        'user_list': user_list,
        'model_choices': model_choices,
        
        # Filter values
        'selected_user': str(user_id) if user_id else '',
        'selected_action': action_type if action_type else '',
        'selected_model': model_type if model_type else '',
        'date_from': date_from.isoformat() if date_from else '',
        'date_to': date_to.isoformat() if date_to else '',
        'search': search,
        
        # Action type choices for filter dropdown
        'action_type_choices': [
            ('all', 'All Actions'),
            ('user_registration', 'User Registrations'),
            ('user_login', 'User Logins'),
            ('listing_created', 'Listing Creations'),
            ('listing_status_changed', 'Listing Status Changes'),
            ('favorite_added', 'Favorites Added'),
            ('report_created', 'Product Reports'),
            ('chat_message', 'Chat Messages'),
            ('job_application', 'Job Applications'),
            ('follow', 'Follow Actions'),
            ('profile_view', 'Profile Views'),
            ('company_registration', 'Company Registrations'),
            ('job_posted', 'Job Posts'),
            ('jobseeker_profile', 'Job Seeker Profiles'),
            ('jobseeker_category_added', 'Job Categories Added'),
        ],
        
        # For JSON serialization in charts
        'activity_counts_json': json.dumps(activity_counts),
        'model_counts_json': json.dumps(model_counts),
    }
    
    print(f"Rendering template with {len(activities)} activities")
    
    return render(request, 'admin1/user_activity_log.html', context)

@staff_member_required
def user_activity_detail(request, user_id):
    """View detailed activity for a specific user"""
    user = get_object_or_404(CustomUser, id=user_id)
    
    # Get all activities for this user
    date_from = request.GET.get('date_from')
    date_to = request.GET.get('date_to')
    
    # Parse dates
    try:
        if date_from:
            date_from = datetime.strptime(date_from, '%Y-%m-%d').date()
        if date_to:
            date_to = datetime.strptime(date_to, '%Y-%m-%d').date()
    except:
        date_from = None
        date_to = None
    
    # Collect user-specific activities
    user_activities = []
    
    # 1. User's own registrations (just this user)
    user_activities.append({
        'id': f"user_self_{user.id}",
        'timestamp': user.date_joined,
        'action_type': 'user_registration',
        'action': 'Account Created',
        'description': f"User registered",
        'details': {'email': user.email, 'user_type': user.user_type}
    })
    
    # 2. User's logins
    if user.last_login:
        user_activities.append({
            'id': f"login_{user.id}",
            'timestamp': user.last_login,
            'action_type': 'user_login',
            'action': 'User Login',
            'description': f"Logged into system",
            'details': {}
        })
    
    # 3. User's listing creations (from all models)
    for model_name in ALL_LISTING_MODELS:
        try:
            model = apps.get_model('oman_app', model_name)
            if model and hasattr(model, 'user'):
                queryset = model.objects.filter(user=user)
                
                # Determine which date field to use
                date_field = None
                for field in ['created_at', 'posted_on', 'timestamp', 'date_joined', 'created', 'date']:
                    if hasattr(model, field):
                        date_field = field
                        break
                
                # Apply date filters if possible
                if date_field:
                    if date_from:
                        queryset = queryset.filter(**{f"{date_field}__date__gte": date_from})
                    if date_to:
                        queryset = queryset.filter(**{f"{date_field}__date__lte": date_to})
                
                for item in queryset[:50]:
                    # Get title
                    title = "Unknown"
                    for field in ['title', 'name', 'property_title', 'headline']:
                        if hasattr(item, field) and getattr(item, field):
                            title = getattr(item, field)
                            break
                    
                    # Get timestamp - CRITICAL: Try multiple fields, NEVER default to now()
                    timestamp = None
                    for field in ['created_at', 'posted_on', 'timestamp', 'date_joined', 'created', 'date']:
                        if hasattr(item, field):
                            value = getattr(item, field)
                            if value and isinstance(value, (datetime, timezone.datetime)):
                                timestamp = value
                                break
                    
                    # Skip if no valid timestamp found
                    if timestamp is None:
                        continue
                    
                    user_activities.append({
                        'id': f"{model_name}_{item.id}",
                        'timestamp': timestamp,
                        'action_type': 'listing_created',
                        'action': f"Created {model_name}",
                        'description': f"Created listing: {title}",
                        'details': {
                            'model': model_name,
                            'id': item.id,
                            'status': getattr(item, 'status', 'unknown'),
                            'title': title
                        }
                    })
        except Exception as e:
            print(f"Error in user_activity_detail for {model_name}: {e}")
            continue
    
    # 4. User's favorites
    try:
        favorites = Favorite.objects.filter(user=user)
        
        # Apply date filters if possible
        if date_from:
            favorites = favorites.filter(created_at__date__gte=date_from)
        if date_to:
            favorites = favorites.filter(created_at__date__lte=date_to)
        
        for fav in favorites[:50]:
            content_obj = fav.content_object
            content_name = content_obj.__class__.__name__ if content_obj else "Unknown"
            
            # Get content title if possible
            if content_obj:
                for field in ['title', 'name', 'property_title']:
                    if hasattr(content_obj, field) and getattr(content_obj, field):
                        content_name = getattr(content_obj, field)
                        break
            
            user_activities.append({
                'id': f"fav_{fav.id}",
                'timestamp': fav.created_at,  # This is correct
                'action_type': 'favorite_added',
                'action': 'Added to Favorites',
                'description': f"Favorited {content_name}",
                'details': {
                    'content_type': fav.content_type.model,
                    'object_id': fav.object_id
                }
            })
    except Exception as e:
        print(f"Error in favorites: {e}")
    
    # 5. User's reports
    try:
        reports = ProductReport.objects.filter(reporter=user)
        
        if date_from:
            reports = reports.filter(created_at__date__gte=date_from)
        if date_to:
            reports = reports.filter(created_at__date__lte=date_to)
        
        for report in reports[:50]:
            user_activities.append({
                'id': f"report_{report.id}",
                'timestamp': report.created_at,
                'action_type': 'report_created',
                'action': 'Product Reported',
                'description': f"Reported as {report.get_reason_display()}",
                'details': {
                    'reason': report.get_reason_display(),
                    'description': report.description
                }
            })
    except Exception as e:
        print(f"Error in reports: {e}")
    
    # 6. User's chat messages
    try:
        messages = ChatMessage.objects.filter(Q(sender=user) | Q(receiver=user))
        
        if date_from:
            messages = messages.filter(timestamp__date__gte=date_from)
        if date_to:
            messages = messages.filter(timestamp__date__lte=date_to)
        
        for msg in messages[:50]:
            other_user = msg.receiver if msg.sender == user else msg.sender
            user_activities.append({
                'id': f"chat_{msg.id}",
                'timestamp': msg.timestamp,
                'action_type': 'chat_message',
                'action': 'Chat Message',
                'description': f"Message with {other_user.username}",
                'details': {
                    'with_user': other_user.username,
                    'with_user_id': other_user.id,
                    'message': msg.message[:100],
                    'is_sent': msg.sender == user
                }
            })
    except Exception as e:
        print(f"Error in chat messages: {e}")
    
    # 7. User's job applications
    try:
        applications = JobApplication.objects.filter(user=user)
        
        if date_from:
            applications = applications.filter(applied_on__date__gte=date_from)
        if date_to:
            applications = applications.filter(applied_on__date__lte=date_to)
        
        for app in applications[:50]:
            user_activities.append({
                'id': f"jobapp_{app.id}",
                'timestamp': app.applied_on,
                'action_type': 'job_application',
                'action': 'Job Application',
                'description': f"Applied for: {app.job.title if app.job else 'Unknown'}",
                'details': {
                    'job': app.job.title if app.job else 'N/A',
                    'job_id': app.job.id if app.job else None,
                    'company': app.company.company_name if app.company else 'N/A',
                    'status': app.status
                }
            })
    except Exception as e:
        print(f"Error in job applications: {e}")
    
    # 8. User's follow actions
    try:
        follows_as_follower = UserFollow.objects.filter(follower=user)
        if date_from:
            follows_as_follower = follows_as_follower.filter(created_at__date__gte=date_from)
        if date_to:
            follows_as_follower = follows_as_follower.filter(created_at__date__lte=date_to)
        
        for follow in follows_as_follower[:50]:
            user_activities.append({
                'id': f"follow_out_{follow.id}",
                'timestamp': follow.created_at,
                'action_type': 'follow',
                'action': 'Followed User',
                'description': f"Followed {follow.following.username}",
                'details': {
                    'following': follow.following.username,
                    'following_id': follow.following.id
                }
            })
        
        follows_as_following = UserFollow.objects.filter(following=user)
        if date_from:
            follows_as_following = follows_as_following.filter(created_at__date__gte=date_from)
        if date_to:
            follows_as_following = follows_as_following.filter(created_at__date__lte=date_to)
        
        for follow in follows_as_following[:50]:
            user_activities.append({
                'id': f"follow_in_{follow.id}",
                'timestamp': follow.created_at,
                'action_type': 'follow',
                'action': 'Gained Follower',
                'description': f"Was followed by {follow.follower.username}",
                'details': {
                    'follower': follow.follower.username,
                    'follower_id': follow.follower.id
                }
            })
    except Exception as e:
        print(f"Error in follow actions: {e}")
    
    # 9. Profile views of this user
    try:
        views = UserProfileView.objects.filter(profile_owner=user)
        
        if date_from:
            views = views.filter(viewed_at__date__gte=date_from)
        if date_to:
            views = views.filter(viewed_at__date__lte=date_to)
        
        for view in views[:50]:
            viewer_name = view.viewer.username if view.viewer else 'Anonymous'
            user_activities.append({
                'id': f"viewed_{view.id}",
                'timestamp': view.viewed_at,
                'action_type': 'profile_viewed',
                'action': 'Profile Viewed',
                'description': f"Profile viewed by {viewer_name}",
                'details': {
                    'viewer': viewer_name,
                    'viewer_id': view.viewer.id if view.viewer else None,
                    'ip': view.ip_address
                }
            })
    except Exception as e:
        print(f"Error in profile views: {e}")
    
    # 10. User's company registrations
    try:
        companies = Company.objects.filter(user=user)
        
        for company in companies[:50]:
            # Get timestamp - try multiple fields
            timestamp = None
            for field in ['created_at', 'registered_on', 'created']:
                if hasattr(company, field):
                    value = getattr(company, field)
                    if value and isinstance(value, (datetime, timezone.datetime)):
                        timestamp = value
                        break
            
            if timestamp is None:
                continue
            
            # Apply date filters
            if date_from and timestamp.date() < date_from:
                continue
            if date_to and timestamp.date() > date_to:
                continue
            
            user_activities.append({
                'id': f"company_{company.id}",
                'timestamp': timestamp,
                'action_type': 'company_registration',
                'action': 'Company Registered',
                'description': f"Registered company: {company.company_name}",
                'details': {
                    'company_name': company.company_name,
                    'status': company.status
                }
            })
    except Exception as e:
        print(f"Error in company registrations: {e}")
    
    # 11. User's job posts
    try:
        jobs = JobPost.objects.filter(user=user)
        
        if date_from:
            jobs = jobs.filter(posted_on__date__gte=date_from)
        if date_to:
            jobs = jobs.filter(posted_on__date__lte=date_to)
        
        for job in jobs[:50]:
            user_activities.append({
                'id': f"jobpost_{job.id}",
                'timestamp': job.posted_on,
                'action_type': 'job_posted',
                'action': 'Job Posted',
                'description': f"Posted job: {job.title}",
                'details': {
                    'title': job.title,
                    'company': job.company.company_name if job.company else 'N/A',
                    'job_type': job.job_type
                }
            })
    except Exception as e:
        print(f"Error in job posts: {e}")
    
    # 12. User's job seeker profile
    try:
        jobseeker = JobSeeker.objects.filter(user=user).first()
        if jobseeker:
            # Get timestamp
            timestamp = None
            for field in ['created_at', 'updated_at']:
                if hasattr(jobseeker, field):
                    value = getattr(jobseeker, field)
                    if value and isinstance(value, (datetime, timezone.datetime)):
                        timestamp = value
                        break
            
            if timestamp:
                # Apply date filters
                if date_from and timestamp.date() < date_from:
                    pass
                elif date_to and timestamp.date() > date_to:
                    pass
                else:
                    user_activities.append({
                        'id': f"jobseeker_{jobseeker.id}",
                        'timestamp': timestamp,
                        'action_type': 'jobseeker_profile',
                        'action': 'Job Seeker Profile',
                        'description': f"Created/updated job seeker profile",
                        'details': {
                            'headline': jobseeker.headline,
                            'experience': jobseeker.work_experience,
                            'education': jobseeker.education_level
                        }
                    })
    except Exception as e:
        print(f"Error in job seeker profile: {e}")
    
    # Sort all activities by timestamp (newest first)
    user_activities.sort(key=lambda x: x['timestamp'], reverse=True)
    
    # Pagination
    paginator = Paginator(user_activities, 50)
    page_number = request.GET.get('page', 1)
    page_obj = paginator.get_page(page_number)
    
    context = {
        'target_user': user,
        'page_obj': page_obj,
        'activities': page_obj.object_list,
        'total_activities': len(user_activities),
        'date_from': date_from.isoformat() if date_from else '',
        'date_to': date_to.isoformat() if date_to else '',
    }
    
    return render(request, 'admin1/user_activity_detail.html', context)


@staff_member_required
def model_activity_detail(request, model_name, object_id):
    """View detailed activity for a specific model instance"""
    try:
        model = apps.get_model('oman_app', model_name)
        obj = get_object_or_404(model, id=object_id)
    except:
        return redirect('user_activity_log')
    
    # Collect activities related to this object
    activities = []
    
    # 1. Creation activity
    # Try multiple date fields
    created_timestamp = None
    for field in ['created_at', 'posted_on', 'timestamp', 'date_joined', 'created', 'date']:
        if hasattr(obj, field):
            value = getattr(obj, field)
            if value and isinstance(value, (datetime, timezone.datetime)):
                created_timestamp = value
                break
    
    if created_timestamp:
        # Get title
        title = "Unknown"
        for field in ['title', 'name', 'property_title', 'headline']:
            if hasattr(obj, field) and getattr(obj, field):
                title = getattr(obj, field)
                break
        
        activities.append({
            'id': f"{model_name}_{obj.id}_created",
            'timestamp': created_timestamp,
            'action_type': 'listing_created',
            'action': f"{model_name} Created",
            'description': f"This {model_name} was created",
            'details': {
                'model': model_name,
                'id': obj.id,
                'title': title
            }
        })
    
    # 2. Status changes (if tracked and has updated_at)
    if hasattr(obj, 'status') and hasattr(obj, 'updated_at'):
        updated_timestamp = None
        for field in ['updated_at', 'modified_at', 'updated', 'last_modified']:
            if hasattr(obj, field):
                value = getattr(obj, field)
                if value and isinstance(value, (datetime, timezone.datetime)):
                    updated_timestamp = value
                    break
        
        if updated_timestamp and updated_timestamp != created_timestamp:
            activities.append({
                'id': f"{model_name}_{obj.id}_status",
                'timestamp': updated_timestamp,
                'action_type': 'listing_status_changed',
                'action': f"{model_name} Status Changed",
                'description': f"Status changed to {obj.status}",
                'details': {
                    'new_status': obj.status,
                    'title': title
                }
            })
    
    # 3. Favorites of this object
    try:
        content_type = ContentType.objects.get_for_model(obj)
        favorites = Favorite.objects.filter(content_type=content_type, object_id=obj.id)
        
        for fav in favorites[:100]:
            activities.append({
                'id': f"fav_{fav.id}",
                'timestamp': fav.created_at,  # This is correct
                'action_type': 'favorite_added',
                'action': 'Added to Favorites',
                'description': f"Favorited by {fav.user.username if fav.user else 'Unknown'}",
                'details': {
                    'user': fav.user.username if fav.user else 'Unknown',
                    'user_id': fav.user.id if fav.user else None
                }
            })
    except Exception as e:
        print(f"Error in favorites: {e}")
    
    # 4. Reports of this object
    try:
        content_type = ContentType.objects.get_for_model(obj)
        reports = ProductReport.objects.filter(content_type=content_type, object_id=obj.id)
        
        for report in reports:
            activities.append({
                'id': f"report_{report.id}",
                'timestamp': report.created_at,
                'action_type': 'report_created',
                'action': 'Product Reported',
                'description': f"Reported by {report.reporter.username if report.reporter else 'Anonymous'}",
                'details': {
                    'reporter': report.reporter.username if report.reporter else 'Anonymous',
                    'reporter_id': report.reporter.id if report.reporter else None,
                    'reason': report.get_reason_display(),
                    'description': report.description
                }
            })
    except Exception as e:
        print(f"Error in reports: {e}")
    
    # 5. Chat messages about this object
    try:
        if hasattr(obj, 'id') and hasattr(obj, '_meta'):
            messages = ChatMessage.objects.filter(
                product_id=obj.id,
                product_type=model_name.lower()
            )
            
            for msg in messages[:100]:
                activities.append({
                    'id': f"chat_{msg.id}",
                    'timestamp': msg.timestamp,
                    'action_type': 'chat_message',
                    'action': 'Chat Message',
                    'description': f"Chat between {msg.sender.username} and {msg.receiver.username}",
                    'details': {
                        'sender': msg.sender.username,
                        'sender_id': msg.sender.id,
                        'receiver': msg.receiver.username,
                        'receiver_id': msg.receiver.id,
                        'message': msg.message[:100]
                    }
                })
    except Exception as e:
        print(f"Error in chat messages: {e}")
    
    # 6. Job applications (if this is a job)
    if model_name == 'JobPost' or model_name.lower() == 'jobpost':
        try:
            applications = JobApplication.objects.filter(job=obj)
            for app in applications[:100]:
                activities.append({
                    'id': f"jobapp_{app.id}",
                    'timestamp': app.applied_on,
                    'action_type': 'job_application',
                    'action': 'Job Application',
                    'description': f"Application by {app.name}",
                    'details': {
                        'applicant': app.name,
                        'applicant_id': app.user.id if app.user else None,
                        'email': app.email,
                        'status': app.status
                    }
                })
        except Exception as e:
            print(f"Error in job applications: {e}")
    
    # Sort by timestamp
    activities.sort(key=lambda x: x['timestamp'], reverse=True)
    
    # Pagination
    paginator = Paginator(activities, 50)
    page_number = request.GET.get('page', 1)
    page_obj = paginator.get_page(page_number)
    
    context = {
        'object': obj,
        'model_name': model_name,
        'page_obj': page_obj,
        'activities': page_obj.object_list,
        'total_activities': len(activities),
    }
    
    return render(request, 'admin1/model_activity_detail.html', context)



