from django.contrib.admin.views.decorators import staff_member_required
from django.contrib import messages
from django.shortcuts import render, redirect, get_object_or_404
from django.http import JsonResponse
from django.utils import timezone
from django.views.decorators.http import require_POST
from django.views.decorators.csrf import csrf_protect
import json

from django.utils import timezone
from django.contrib import messages

@login_required
@user_passes_test(lambda u: u.is_staff or u.is_superuser)
def suspend_user(request):

    if request.method == "POST":
        user_id = request.POST.get("user_id")
        reason = request.POST.get("reason")

        try:
            user = CustomUser.objects.get(id=user_id)

            user.is_suspended = True
            user.suspended_at = timezone.now()
            user.suspension_reason = reason
            user.is_active = False   # 🔴 THIS BLOCKS LOGIN

            user.save()

            messages.success(request, f"{user.username} has been suspended.")

        except CustomUser.DoesNotExist:
            messages.error(request, "User not found")

    return redirect("user")

@login_required
@user_passes_test(lambda u: u.is_staff or u.is_superuser)
def unsuspend_user(request, id):

    try:
        user = CustomUser.objects.get(id=id)

        user.is_suspended = False
        user.suspended_at = None
        user.suspension_reason = None
        user.is_active = True   # 🔓 allow login again

        user.save()

        messages.success(request, f"{user.username} has been unsuspended.")

    except CustomUser.DoesNotExist:
        messages.error(request, "User not found")

    return redirect("user")



