def format_currency(value):
    """Format a number as OMR currency."""
    try:
        return f"OMR {float(value):,.3f}"
    except (ValueError, TypeError):
        return "OMR 0.000"

def get_date_range(date_from_str, date_to_str):
    """Parse date strings and return a date range."""
    date_to = timezone.now().date()
    date_from = date_to - timedelta(days=30)  # Default to last 30 days

    if date_from_str:
        try:
            date_from = parse_date(date_from_str)
        except (ValueError, TypeError):
            pass
    if date_to_str:
        try:
            date_to = parse_date(date_to_str)
        except (ValueError, TypeError):
            pass

    # Ensure date_from is not after date_to
    if date_from > date_to:
        date_from, date_to = date_to, date_from

    return date_from, date_to

# ---------- 10.1 Export Data (CSV/Excel) ----------

@staff_member_required
def export_data_view(request):
    """
    View to export data based on selected model and format.
    """
    model_name = request.GET.get('model', '')
    export_format = request.GET.get('format', 'csv')
    date_from_str = request.GET.get('date_from')
    date_to_str = request.GET.get('date_to')
    status = request.GET.get('status', '')

    date_from, date_to = get_date_range(date_from_str, date_to_str)

    if not model_name:
        # If no model is selected, show the export selection page
        model_choices = sorted(get_all_listing_models() + ['CustomUser', 'JobPost', 'JobApplication', 'Company', 'ChatMessage', 'Favorite', 'ProductReport'])
        return render(request, 'admin1/analytics/export_data.html', {
            'model_choices': model_choices,
            'selected_model': model_name,
            'date_from': date_from,
            'date_to': date_to,
            'status': status,
        })

    # Determine the model class
    try:
        if model_name == 'CustomUser':
            model = CustomUser
        elif model_name == 'JobPost':
            model = JobPost
        elif model_name == 'JobApplication':
            model = JobApplication
        elif model_name == 'Company':
            model = Company
        elif model_name == 'ChatMessage':
            model = ChatMessage
        elif model_name == 'Favorite':
            model = Favorite
        elif model_name == 'ProductReport':
            model = ProductReport
        else:
            model = apps.get_model('oman_app', model_name)
    except LookupError:
        messages.error(request, f"Model '{model_name}' not found.")
        return redirect('export_data')

    # Build the queryset
    queryset = model.objects.all()

    # Apply date filter if the model has a date field
    date_field_name = None
    for field in ['created_at', 'posted_on', 'timestamp', 'date_joined', 'created', 'applied_on', 'viewed_at']:
        if hasattr(model, field):
            date_field_name = field
            break

    if date_field_name:
        if date_from:
            queryset = queryset.filter(**{f"{date_field_name}__date__gte": date_from})
        if date_to:
            queryset = queryset.filter(**{f"{date_field_name}__date__lte": date_to})

    # Apply status filter
    if status and hasattr(model, 'status'):
        queryset = queryset.filter(status=status)

    # Get field names for the model
    field_names = [field.name for field in model._meta.fields if field.name not in ['password', 'last_login']]

    # Create the HTTP response based on format
    if export_format == 'csv':
        response = HttpResponse(content_type='text/csv')
        response['Content-Disposition'] = f'attachment; filename="{model_name}_{date_from}_{date_to}.csv"'
        writer = csv.writer(response)
        writer.writerow(field_names)  # Header row

        for obj in queryset.iterator():
            row = []
            for field in field_names:
                value = getattr(obj, field, '')
                if value is None:
                    row.append('')
                elif isinstance(value, (datetime, date)):
                    row.append(value.isoformat())
                else:
                    row.append(str(value))
            writer.writerow(row)

        return response

    elif export_format == 'excel':
        response = HttpResponse(content_type='application/vnd.openxmlformats-officedocument.spreadsheetml.sheet')
        response['Content-Disposition'] = f'attachment; filename="{model_name}_{date_from}_{date_to}.xlsx"'

        wb = openpyxl.Workbook()
        ws = wb.active
        ws.title = f"{model_name} Data"

        # Write header
        header_font = Font(bold=True, color="FFFFFF")
        header_fill = PatternFill(start_color="4F81BD", end_color="4F81BD", fill_type="solid")
        for col_num, field_name in enumerate(field_names, 1):
            cell = ws.cell(row=1, column=col_num, value=field_name.replace('_', ' ').title())
            cell.font = header_font
            cell.fill = header_fill
            cell.alignment = Alignment(horizontal='center')

        # Write data
        for row_num, obj in enumerate(queryset.iterator(), 2):
            for col_num, field in enumerate(field_names, 1):
                value = getattr(obj, field, '')
                if isinstance(value, (datetime, date)):
                    ws.cell(row=row_num, column=col_num, value=value.isoformat())
                else:
                    ws.cell(row=row_num, column=col_num, value=str(value))

        # Auto-adjust column widths
        for col in ws.columns:
            max_length = 0
            column = col[0].column_letter
            for cell in col:
                try:
                    if len(str(cell.value)) > max_length:
                        max_length = len(str(cell.value))
                except:
                    pass
            adjusted_width = (max_length + 2) * 1.2
            ws.column_dimensions[column].width = min(adjusted_width, 50)

        wb.save(response)
        return response

    else:
        messages.error(request, "Invalid export format.")
        return redirect('export_data')

# ---------- 10.2 Revenue Reports ----------

@staff_member_required
def revenue_report_view(request):
    """
    View for revenue reports.
    """
    period = request.GET.get('period', 'month')
    year = int(request.GET.get('year', timezone.now().year))
    month = int(request.GET.get('month', timezone.now().month)) if period == 'day' else None

    # --- Revenue Sources ---
    # 1. Boosted Ads (Placeholder - You'll need a BoostedAd model)
    # 2. Premium Subscriptions (Placeholder - You'll need a Subscription model)
    # 3. Car Reports (Stripe Payments)
    # 4. Featured Listings (Placeholder)

    # For this example, we'll focus on Car Reports and provide placeholders for others.
    revenue_data = []

    # Helper to aggregate revenue from a model
    def get_revenue_from_model(model, date_field, amount_field, period_type):
        queryset = model.objects.all()
        if period_type == 'day':
            queryset = queryset.filter(**{f"{date_field}__year": year, f"{date_field}__month": month})
            data = queryset.annotate(
                period_label=F(date_field),
                revenue=Coalesce(Sum(amount_field), 0.0)
            ).values('period_label', 'revenue')
        else:  # month or year
            data = queryset.annotate(
                year=ExtractYear(date_field),
                month=ExtractMonth(date_field),
                period_label=TruncMonth(date_field)
            ).values('year', 'month', 'period_label').annotate(
                revenue=Coalesce(Sum(amount_field), 0.0)
            ).order_by('year', 'month')
        return data

    # --- Placeholder for future models ---
    # boosted_ads_revenue = get_revenue_from_model(BoostedAd, 'created_at', 'amount', period)
