@staff_member_required
def user_activity_report_view(request):
    """
    View for user activity report.
    """
    date_from_str = request.GET.get('date_from')
    date_to_str = request.GET.get('date_to')
    date_from, date_to = get_date_range(date_from_str, date_to_str)

    user_activity = []

    # Get all users who joined in the date range
    users = CustomUser.objects.filter(date_joined__date__gte=date_from, date_joined__date__lte=date_to)

    for user in users:
        # Count user's activities
        listing_count = 0
        for model_name in get_all_listing_models():
            try:
                model = apps.get_model('oman_app', model_name)
                if hasattr(model, 'user'):
                    listing_count += model.objects.filter(user=user).count()
            except LookupError:
                continue

        favorite_count = Favorite.objects.filter(user=user).count()
        report_count = ProductReport.objects.filter(reporter=user).count()
        chat_count = ChatMessage.objects.filter(Q(sender=user) | Q(receiver=user)).count()

        # Job seeker info
        job_seeker = None
        try:
            job_seeker = JobSeeker.objects.get(user=user)
        except JobSeeker.DoesNotExist:
            pass

        user_activity.append({
            'user': user,
            'date_joined': user.date_joined,
            'last_login': user.last_login,
            'listing_count': listing_count,
            'favorite_count': favorite_count,
            'report_count': report_count,
            'chat_count': chat_count,
            'is_job_seeker': job_seeker is not None,
            'job_seeker_completed': job_seeker.is_completed if job_seeker else False,
        })

    # Sort by date joined (newest first)
    user_activity.sort(key=lambda x: x['date_joined'], reverse=True)

    context = {
        'user_activity': user_activity,
        'date_from': date_from,
        'date_to': date_to,
        'total_users': len(user_activity),
    }
    return render(request, 'admin1/analytics/user_activity_report.html', context)

