@staff_member_required
def category_performance_view(request):
    """
    View for category performance report.
    """
    date_from_str = request.GET.get('date_from')
    date_to_str = request.GET.get('date_to')
    date_from, date_to = get_date_range(date_from_str, date_to_str)

    category_data = defaultdict(lambda: {
        'name': '',
        'total_listings': 0,
        'approved': 0,
        'pending': 0,
        'rejected': 0,
        'soldout': 0,
        'avg_price': 0,
        'total_price': 0,
        'price_count': 0,
    })

    for model_name in get_all_listing_models():
        try:
            model = apps.get_model('oman_app', model_name)
            if not model:
                continue

            # Get a user-friendly category name
            if model_name in ['Automobile', 'Motorcycle', 'Scooter', 'Boat', 'HeavyVehicle',
                              'AutoAccessoryPart', 'NumberPlate', 'DrivingTraining',
                              'HelmetClothes', 'Quadbikes', 'TiresAndCaps', 'JunkCar',
                              'CarRepairMaintenance']:
                cat_name = 'Motors'
            elif model_name in ['Land', 'Villa', 'Apartment', 'Commercial', 'Farm', 'Chalet',
                               'Factory', 'Complex', 'Clinic', 'Hostel', 'Office', 'Shop',
                               'Cafe', 'Staff', 'Warehouse', 'Townhouse', 'Fullfloors',
                               'Showrooms', 'Wholebuilding', 'Supermarket', 'Foreign',
                               'Shared', 'Suits']:
                cat_name = 'Real Estate'
            elif model_name in ['Mobile', 'Tablet', 'SmartWatch', 'Headset', 'Cover',
                               'Accessory', 'MobileSIM']:
                cat_name = 'Mobiles & Tablets'
            elif model_name in ['AutoServiceListing', 'ConsultancyServiceListing',
                               'DomesticServiceListing', 'EventEntertainmentServiceListing',
                               'HealthWellbeingServiceListing', 'HomeMaintenanceServiceListing',
                               'MoversServiceListing', 'RestorationServiceListing',
                               'TutorsServiceListing', 'WebComputerServiceListing',
                               'FreelancersServiceListing', 'OtherServiceListing']:
                cat_name = 'Services'
            else:
                cat_name = 'Other Classifieds'

            category_data[cat_name]['name'] = cat_name

            # Apply date filter if possible
            queryset = model.objects.all()
            if hasattr(model, 'created_at'):
                queryset = queryset.filter(created_at__date__gte=date_from, created_at__date__lte=date_to)

            # Count by status
            category_data[cat_name]['total_listings'] += queryset.count()
            category_data[cat_name]['approved'] += queryset.filter(status='approved').count()
            category_data[cat_name]['pending'] += queryset.filter(status='pending').count()
            category_data[cat_name]['rejected'] += queryset.filter(status='rejected').count()
            category_data[cat_name]['soldout'] += queryset.filter(status='soldout').count()

            # Price aggregation
            if hasattr(model, 'price'):
                price_queryset = queryset.exclude(price__isnull=True).exclude(price=0)
                price_sum = price_queryset.aggregate(Sum('price'))['price__sum']
                price_count = price_queryset.count()

                if price_sum:
                    category_data[cat_name]['total_price'] += float(price_sum)
                    category_data[cat_name]['price_count'] += price_count

        except LookupError:
            continue

    # Calculate average price for each category
    for cat_name, data in category_data.items():
        if data['price_count'] > 0:
            data['avg_price'] = data['total_price'] / data['price_count']
        data['avg_price_formatted'] = format_currency(data['avg_price'])
        data['total_price_formatted'] = format_currency(data['total_price'])

    # Convert to list and sort
    category_list = list(category_data.values())
    category_list.sort(key=lambda x: x['total_listings'], reverse=True)

    context = {
        'category_data': category_list,
        'date_from': date_from,
        'date_to': date_to,
    }
    return render(request, 'admin1/analytics/category_performance.html', context)

