# decorators.py (extracted from your views)
from functools import wraps
from django.shortcuts import redirect
from django.contrib import messages

def admin_or_subadmin_required(permission_section=None, permission_action='view'):
    """
    Decorator for views that need admin or sub-admin access with specific permissions
    - Superusers (admins) have full access automatically
    - Sub-admins need specific permissions
    """
    def decorator(view_func):
        @wraps(view_func)
        def _wrapped_view(request, *args, **kwargs):
            # Not authenticated
            if not request.user.is_authenticated:
                messages.error(request, "Please login to access this page.")
                return redirect('admin')
            
            # Superusers (admins) have full access - no permission checks needed
            if request.user.is_superuser:
                return view_func(request, *args, **kwargs)
            
            # Check if user has subadmin profile
            try:
                subadmin = request.user.subadmin_profile
                if not subadmin.is_active:
                    messages.error(request, "Your sub-admin account is inactive.")
                    return redirect('subadmin_dashboard')
                
                # If permission section is specified, check it
                if permission_section:
                    if not subadmin.has_permission(permission_section, permission_action):
                        messages.error(request, f"You don't have permission to access this section.")
                        return redirect('subadmin_dashboard')
                
                return view_func(request, *args, **kwargs)
                
            except SubAdmin.DoesNotExist:
                messages.error(request, "You are not authorized to access this area.")
                return redirect('admin')
                
        return _wrapped_view
    return decorator


def subadmin_login_required(view_func):
    """Decorator to require sub-admin login (for dashboard)"""
    @wraps(view_func)
    def _wrapped_view(request, *args, **kwargs):
        if request.user.is_superuser:
            return view_func(request, *args, **kwargs)
            
        try:
            subadmin = request.user.subadmin_profile
            if subadmin.is_active:
                return view_func(request, *args, **kwargs)
            messages.error(request, "Your sub-admin account is inactive.")
            return redirect('subadmin_login')
        except SubAdmin.DoesNotExist:
            messages.error(request, "Please login as sub-admin.")
            return redirect('subadmin_login')
            
    return _wrapped_view


def admin_only(view_func):
    """Decorator for views that only superusers (admins) can access"""
    @wraps(view_func)
    def _wrapped_view(request, *args, **kwargs):
        if not request.user.is_authenticated:
            return redirect('admin')
        
        if not request.user.is_superuser:
            messages.error(request, "This section is only accessible by administrators.")
            return redirect('subadmin_dashboard')
        
        return view_func(request, *args, **kwargs)
    return _wrapped_view


# views.py - Sub-admin management (ONLY SUPERUSERS CAN ACCESS)

from django.contrib.admin.views.decorators import staff_member_required
from django.db import transaction
from .models import SubAdmin, SubAdminPermission, CustomUser
from django.views.decorators.cache import never_cache


@never_cache
@admin_only
def subadmin_list(request):
    """List all sub-admins - ONLY SUPERUSERS"""
    subadmins = SubAdmin.objects.select_related('user', 'created_by').all()
    active_count = subadmins.filter(is_active=True).count()
    inactive_count = subadmins.filter(is_active=False).count()
    
    context = {
        'subadmins': subadmins,
        'active_count': active_count,
        'inactive_count': inactive_count,
    }
    return render(request, 'admin1/subadmins/subadmin_list.html', context)

@never_cache
@admin_only
def subadmin_create(request):
    """Create a new sub-admin - ONLY SUPERUSERS"""
    if request.method == 'POST':
        first_name = request.POST.get('first_name', '').strip()
        last_name = request.POST.get('last_name', '').strip()
        username = request.POST.get('username')
        email = request.POST.get('email')
        password = request.POST.get('password')
        confirm_password = request.POST.get('confirm_password')
        is_active = request.POST.get('is_active') == 'on'
        notes = request.POST.get('notes', '')
        
        # Validate names
        if not first_name:
            messages.error(request, "First name is required.")
            return redirect('subadmin_create')
        if not last_name:
            messages.error(request, "Last name is required.")
            return redirect('subadmin_create')
        # Optional: validate only letters/spaces
        import re
        if not re.match(r'^[A-Za-z\s]+$', first_name):
            messages.error(request, "First name can only contain letters and spaces.")
            return redirect('subadmin_create')
        if not re.match(r'^[A-Za-z\s]+$', last_name):
            messages.error(request, "Last name can only contain letters and spaces.")
            return redirect('subadmin_create')
        
        # Validate passwords
        if password != confirm_password:
            messages.error(request, "Passwords do not match.")
            return redirect('subadmin_create')
        
        # Check if user already exists
        if CustomUser.objects.filter(username=username).exists():
            messages.error(request, "Username already exists.")
            return redirect('subadmin_create')
        if CustomUser.objects.filter(email=email).exists():
            messages.error(request, "Email already exists.")
            return redirect('subadmin_create')
        
        try:
            with transaction.atomic():
                # Create user with first_name and last_name
                user = CustomUser.objects.create_user(
                    username=username,
                    email=email,
                    first_name=first_name,
                    last_name=last_name,
                    password=password,
                    user_type='subadmin',
                    is_staff=True,
                    is_active=True
                )
                
                # Create sub-admin profile
                subadmin = SubAdmin.objects.create(
                    user=user,
                    created_by=request.user,
                    is_active=is_active,
                    notes=notes
                )
                
                # Add permissions
                permission_ids = request.POST.getlist('permissions')
                if permission_ids:
                    subadmin.permissions.set(permission_ids)
                
                messages.success(request, f"Sub-admin {username} created successfully!")
                return redirect('subadmin_list')
                
        except Exception as e:
            messages.error(request, f"Error creating sub-admin: {str(e)}")
    
    # GET request – show form
    permissions = SubAdminPermission.objects.all().order_by('section')
    context = {
        'permissions': permissions,
    }
    return render(request, 'admin1/subadmins/subadmin_create.html', context)


@never_cache
@admin_only
def subadmin_edit(request, subadmin_id):
    """Edit an existing sub-admin - ONLY SUPERUSERS"""
    subadmin = get_object_or_404(SubAdmin, id=subadmin_id)
    
    if request.method == 'POST':
        is_active = request.POST.get('is_active') == 'on'
        notes = request.POST.get('notes', '')
        permission_ids = request.POST.getlist('permissions')
        
        try:
            with transaction.atomic():
                # Update sub-admin
                subadmin.is_active = is_active
                subadmin.notes = notes
                subadmin.save()
                
                # Update permissions
                subadmin.permissions.set(permission_ids)
                
                # Update user's is_active status
                subadmin.user.is_active = is_active
                subadmin.user.save()
                
                messages.success(request, f"Sub-admin {subadmin.user.username} updated successfully!")
                return redirect('subadmin_list')
                
        except Exception as e:
            messages.error(request, f"Error updating sub-admin: {str(e)}")
    
    # Get all permissions for the form
    permissions = SubAdminPermission.objects.all().order_by('section')
    
    # Get current permission IDs
    current_permissions = subadmin.permissions.values_list('id', flat=True)
    
    context = {
        'subadmin': subadmin,
        'permissions': permissions,
        'current_permissions': list(current_permissions),
    }
    return render(request, 'admin1/subadmins/subadmin_edit.html', context)


@never_cache
@admin_only
def subadmin_delete(request, subadmin_id):
    """Delete a sub-admin - ONLY SUPERUSERS"""
    subadmin = get_object_or_404(SubAdmin, id=subadmin_id)
    
    if request.method == 'POST':
        username = subadmin.user.username
        try:
            # Delete the user (this will cascade delete subadmin due to OneToOneField)
            subadmin.user.delete()
            messages.success(request, f"Sub-admin {username} deleted successfully!")
        except Exception as e:
            messages.error(request, f"Error deleting sub-admin: {str(e)}")
        
        return redirect('subadmin_list')
    
    return render(request, 'admin1/subadmins/subadmin_confirm_delete.html', {'subadmin': subadmin})


@never_cache
@admin_only
def subadmin_permissions_list(request):
    """List all available permissions - ONLY SUPERUSERS"""
    permissions = SubAdminPermission.objects.all().order_by('section')
    
    context = {
        'permissions': permissions,
    }
    return render(request, 'admin1/subadmins/permissions_list.html', context)


@never_cache
@admin_only
def subadmin_permission_create(request):
    """Create a new permission - ONLY SUPERUSERS"""
    if request.method == 'POST':
        name = request.POST.get('name')
        section = request.POST.get('section')
        description = request.POST.get('description', '')
        can_view = request.POST.get('can_view') == 'on'
        can_edit = request.POST.get('can_edit') == 'on'
        can_delete = request.POST.get('can_delete') == 'on'
        can_approve = request.POST.get('can_approve') == 'on'
        can_create = request.POST.get('can_create') == 'on'
        
        # Check if section already exists
        if SubAdminPermission.objects.filter(section=section).exists():
            messages.error(request, "A permission for this section already exists.")
            return redirect('subadmin_permissions_list')
        
        try:
            SubAdminPermission.objects.create(
                name=name,
                section=section,
                description=description,
                can_view=can_view,
                can_edit=can_edit,
                can_delete=can_delete,
                can_approve=can_approve,
                can_create=can_create
            )
            messages.success(request, f"Permission '{name}' created successfully!")
            return redirect('subadmin_permissions_list')
            
        except Exception as e:
            messages.error(request, f"Error creating permission: {str(e)}")
    
    return render(request, 'admin1/subadmins/permission_create.html')


