@never_cache
@subadmin_login_required
def subadmin_dashboard(request):
    """Dashboard for sub-admins - shows permissions and stats"""
    subadmin = request.user.subadmin_profile
    
    # Helper function to check permissions
    def has_any_permission(sections, actions=['view']):
        for section in sections:
            for action in actions:
                if subadmin.has_permission(section, action):
                    return True
        return False
    
    # Group permissions
    has_location_permission = has_any_permission(['governates', 'districts', 'cities'])
    has_faq_permission = has_any_permission(['faq'])
    has_blog_permission = has_any_permission(['blog'])
    has_banner_permission = has_any_permission(['banner'])
    has_content_permission = has_any_permission(['faq', 'blog', 'banner'])
    has_amenities_permission = has_any_permission(['amenities'])
    has_motors_options_permission = has_any_permission(['interior_options', 'exterior_options', 'technology_options'])
    has_ads_permission = has_any_permission(['advertisement'])
    has_companies_permission = has_any_permission(['companies', 'company_approval'])
    has_jobs_permission = has_any_permission(['job_posts', 'job_categories'])
    has_reported_ads_permission = has_any_permission(['reported_ads'])
    has_user_permission = has_any_permission(['users_view', 'user_reports', 'user_activity'])
    
    # ===== ADS APPROVAL - 5 CATEGORIES =====
    has_properties_approval = subadmin.has_permission('ads_approval_properties', 'view')
    has_vehicles_approval = subadmin.has_permission('ads_approval_vehicles', 'view')
    has_electronics_approval = subadmin.has_permission('ads_approval_electronics', 'view')
    has_classifieds_approval = subadmin.has_permission('ads_approval_classifieds', 'view')
    has_services_approval = subadmin.has_permission('ads_approval_services', 'view')
    
    # Get all sections this subadmin has access to
    accessible_sections = []
    for perm in subadmin.permissions.all():
        if perm.can_view:
            accessible_sections.append(perm.section)
    
