def subadmin_login_view(request):
    """Separate login view for sub-admins"""
    
    # If already logged in, redirect to appropriate dashboard
    if request.user.is_authenticated:
        if request.user.is_superuser:
            return redirect('admin_dashboard')
        try:
            if request.user.subadmin_profile and request.user.subadmin_profile.is_active:
                return redirect('subadmin_dashboard')
        except:
            pass
        return redirect('index')
    
    if request.method == 'POST':
        username = request.POST.get('username')
        password = request.POST.get('password')
        
        user = authenticate(request, username=username, password=password)
        
        if user is not None:
            # Check if user is a sub-admin or superuser
            if user.is_superuser:
                login(request, user)
                messages.success(request, "Welcome back, Admin!")
                return redirect('admin_dashboard')
            
            # Check if user has subadmin profile
            try:
                subadmin = user.subadmin_profile
                if subadmin.is_active:
                    login(request, user)
                    messages.success(request, f"Welcome back, {user.username}!")
                    return redirect('subadmin_dashboard')
                else:
                    messages.error(request, "Your sub-admin account is inactive. Please contact the super-admin.")
            except:
                messages.error(request, "You don't have sub-admin access.")
        else:
            messages.error(request, "Invalid username or password.")
    
    return render(request, 'admin1/subadmins/login.html')


from django.shortcuts import render, redirect, get_object_or_404
from django.contrib import messages
from django.core.exceptions import ValidationError
from .models import Offers


# LIST VIEW
def offers_list(request):
    offers = Offers.objects.all().order_by('-created_at')
    return render(request, 'admin1/offers/offers.html', {'offers': offers})


# ADD
def add_offer(request):
    if request.method == "POST":
        image = request.FILES.get('image')
        phone_number = request.POST.get('phone_number', '').strip()
        whatsapp_number = request.POST.get('whatsapp_number', '').strip()

        if not image:
            messages.error(request, "Image is required")
            return render(request, 'admin1/offers/add_edit_offer.html')
        
        if not phone_number:
            messages.error(request, "Phone number is required")
            return render(request, 'admin1/offers/add_edit_offer.html')
        
        # Validate: exactly 8 digits only
        if not phone_number.isdigit():
            messages.error(request, "Phone number must contain only digits")
            return render(request, 'admin1/offers/add_edit_offer.html')
        
        if len(phone_number) != 8:
            messages.error(request, "Phone number must be exactly 8 digits")
            return render(request, 'admin1/offers/add_edit_offer.html')
        
        # Validate WhatsApp number if provided
        if whatsapp_number:
            if not whatsapp_number.isdigit():
                messages.error(request, "WhatsApp number must contain only digits")
                return render(request, 'admin1/offers/add_edit_offer.html')
            if len(whatsapp_number) != 8:
                messages.error(request, "WhatsApp number must be exactly 8 digits")
                return render(request, 'admin1/offers/add_edit_offer.html')
        
        try:
            Offers.objects.create(
                image=image,
                phone_number=phone_number,
                whatsapp_number=whatsapp_number if whatsapp_number else None
            )
            messages.success(request, "Offer added successfully")
            return redirect('offers_list')
        except ValidationError as e:
            messages.error(request, str(e))
            return render(request, 'admin1/offers/add_edit_offer.html')

    return render(request, 'admin1/offers/add_edit_offer.html')


# EDIT
def edit_offer(request, id):
    offer = get_object_or_404(Offers, id=id)

    if request.method == "POST":
        image = request.FILES.get('image')
        phone_number = request.POST.get('phone_number', '').strip()
        whatsapp_number = request.POST.get('whatsapp_number', '').strip()

        # Validate phone number
        if not phone_number:
            messages.error(request, "Phone number is required")
            return render(request, 'admin1/offers/add_edit_offer.html', {'offer': offer})
        
        if not phone_number.isdigit():
            messages.error(request, "Phone number must contain only digits")
            return render(request, 'admin1/offers/add_edit_offer.html', {'offer': offer})
        
        if len(phone_number) != 8:
            messages.error(request, "Phone number must be exactly 8 digits")
            return render(request, 'admin1/offers/add_edit_offer.html', {'offer': offer})
        
        # Validate WhatsApp number if provided
        if whatsapp_number:
            if not whatsapp_number.isdigit():
                messages.error(request, "WhatsApp number must contain only digits")
                return render(request, 'admin1/offers/add_edit_offer.html', {'offer': offer})
            if len(whatsapp_number) != 8:
                messages.error(request, "WhatsApp number must be exactly 8 digits")
                return render(request, 'admin1/offers/add_edit_offer.html', {'offer': offer})

        if image:
            offer.image = image
        
        offer.phone_number = phone_number
        offer.whatsapp_number = whatsapp_number if whatsapp_number else None
        
        try:
            offer.save()
            messages.success(request, "Offer updated successfully")
            return redirect('offers_list')
        except ValidationError as e:
            messages.error(request, str(e))
            return render(request, 'admin1/offers/add_edit_offer.html', {'offer': offer})

    return render(request, 'admin1/offers/add_edit_offer.html', {'offer': offer})


# DELETE
def delete_offer(request, id):
    offer = get_object_or_404(Offers, id=id)
    offer.delete()
    messages.success(request, "Offer deleted successfully")
    return redirect('offers_list')

from django.shortcuts import render
from .models import Offers
from django.utils.safestring import mark_safe
import json

def offers_gallery(request):
    offers = Offers.objects.all().order_by('-created_at')
    
    # Get selected offer ID from URL parameter
    selected_offer_id = request.GET.get('offer')
    
    # Reorder offers: put selected offer first
    if selected_offer_id:
        try:
            selected_offer = offers.get(id=selected_offer_id)
            # Remove selected offer from queryset and add it at the beginning
            offers_list = list(offers)
            selected_index = None
            for i, offer in enumerate(offers_list):
                if offer.id == int(selected_offer_id):
                    selected_index = i
                    break
            if selected_index is not None:
                selected_offer_obj = offers_list.pop(selected_index)
                offers_list.insert(0, selected_offer_obj)
                offers = offers_list
        except Offers.DoesNotExist:
            pass
    
    # Convert offers to JSON for JavaScript
    offers_data = []
    for offer in offers:
        offers_data.append({
            'id': offer.id,
            'image_url': offer.image.url if offer.image else '',
            'phone_number': offer.phone_number,
            'whatsapp_number': offer.whatsapp_number if offer.whatsapp_number else offer.phone_number,
        })
    
    return render(request, 'offers_gallery.html', {
        'offers': offers,
        'offers_data_json': mark_safe(json.dumps(offers_data)),
        'selected_offer_id': selected_offer_id,  # Pass to template for highlighting
    })


