@login_required
def universal_edit_view(request, property_type, pk):
    """Universal edit view for all property types (mobile, community, and real estate)"""
    
    # Check if property type exists
    if property_type not in MODEL_MAPPING:
        messages.error(request, f"Invalid property type: '{property_type}'")
        return redirect('adss', user_id=request.user.id)
    
    config = MODEL_MAPPING[property_type]
    
    try:
        product = get_object_or_404(config['model'], id=pk)
    except Exception as e:
        messages.error(request, f"Product not found: {str(e)}")
        return redirect('adss', user_id=request.user.id)
    
    # Create form instance with existing data
    form = config['form'](instance=product)
    
    # Get location data
    cities = Cities.objects.all()
    regions = Region.objects.all()
    governate = Governate.objects.all()
    district = District.objects.all()
    
    # Get additional data for property types
    nearby_locations = NearbyLocation.objects.all()
    main_amenities = MainAmenities.objects.all()
    additional_amenities = AdditionalAmenities.objects.all()
    
    # Prepare existing images and videos data
    images_data = []
    videos_data = []
    
    # Handle images
    if hasattr(product, 'images'):
        for img in product.images.all():
            image_url = img.image.url if hasattr(img, 'image') else str(img)
            images_data.append({
                'id': img.id,
                'url': image_url
            })
    
    # Handle videos
    if hasattr(product, 'videos'):
        for vid in product.videos.all():
            video_url = vid.video.url if hasattr(vid, 'video') else str(vid)
            videos_data.append({
                'id': vid.id,
                'url': video_url
            })
    
    # Prepare form initial data
    form_data = {}
    for field in form.fields:
        value = getattr(product, field, None)
        if value is not None:
            if hasattr(value, 'id'):  # For foreign keys
                form_data[field] = value.id
            elif isinstance(value, bool):
                form_data[field] = value
            else:
                form_data[field] = str(value)
    
    if hasattr(product, 'city') and product.city:
        form_data['city'] = product.city.id
    
    # Base context for all templates
    context = {
        'edit_mode': True,
        'edit_product_id': pk,
        'edit_product_type': property_type,
        'edit_modal_id': config['modal_id'],
        'edit_form_data': json.dumps(form_data),
        'edit_images': json.dumps(images_data),
        'edit_videos': json.dumps(videos_data),
        'form': form,
        'product': product,
        'property_type': property_type,
        'cities': cities,
        'regions': regions,
        'governate': governate,
        'district': district,
        'nearby_locations': nearby_locations,
        'main_amenities': main_amenities,
        'additional_amenities': additional_amenities,
    }
    
    # Add type-specific forms to context based on the type
    if config['type'] == 'mobile':
        # Mobile/Electronics forms
        context.update({
            'mobile_form': MobileForm() if property_type != 'mobile' else form,
            'tablet_form': TabletForm() if property_type != 'tablet' else form,
            'smartwatch_form': SmartWatchForm() if property_type != 'smartwatch' else form,
            'headset_form': HeadsetForm() if property_type != 'headset' else form,
            'cover_form': CoverForm() if property_type != 'cover' else form,
            'accessory_form': AccessoryForm() if property_type != 'accessory' else form,
            'mobile_sim_form': MobileSIMForm() if property_type != 'mobilesim' else form,
        })
        # Set the specific form for this property type
        context[f'{property_type}_form'] = form
        
    elif config['type'] == 'community':
        # Service forms
        context.update({
            'service_form': AutoServiceListingForm() if property_type != 'autoservicelisting' else form,
            'consultancy_form': ConsultancyServiceListingForm() if property_type != 'consultancyservicelisting' else form,
            'domestic_form': DomesticServiceListingForm() if property_type != 'domesticservicelisting' else form,
            'event_form': EventEntertainmentServiceForm() if property_type != 'evententertainmentservicelisting' else form,
            'health_form': HealthWellbeingServiceForm() if property_type != 'healthwellbeingservicelisting' else form,
            'home_form': HomeMaintenanceServiceListingForm() if property_type != 'homemaintenanceservicelisting' else form,
            'movers_form': MoversServiceListingForm() if property_type != 'moversservicelisting' else form,
            'restoration_form': RestorationServiceListingForm() if property_type != 'restorationservicelisting' else form,
            'tutors_form': TutorsServiceListingForm() if property_type != 'tutorsservicelisting' else form,
            'web_form': WebComputerServiceListingForm() if property_type != 'webcomputerservicelisting' else form,
            'freelancers_form': FreelancersServiceListingForm() if property_type != 'freelancersservicelisting' else form,
            'other_form': OtherServiceListingForm() if property_type != 'otherservicelisting' else form,
        })
        
    else:  # property (real estate)
        # Real estate forms - add all property forms to context
        context.update({
            'land_form': LandForm() if property_type != 'land' else form,
            'villa_form': Villaform() if property_type != 'villa' else form,
            'commercial_form': CommercialForm() if property_type != 'commercial' else form,
            'chalet_form': ChaletForm() if property_type != 'chalet' else form,
            'farm_form': FarmForm() if property_type != 'farm' else form,
            'apartment_form': ApartmentForm() if property_type != 'apartment' else form,
            'factory_form': FactoryForm() if property_type != 'factory' else form,
            'complex_form': ComplexForm() if property_type != 'complex' else form,
            'clinic_form': ClinicForm() if property_type != 'clinic' else form,
            'hostel_form': HostelForm() if property_type != 'hostel' else form,
            'office_form': OfficeForm() if property_type != 'office' else form,
            'shop_form': ShopForm() if property_type != 'shop' else form,
            'cafe_form': CafeForm() if property_type != 'cafe' else form,
            'staff_form': StaffForm() if property_type != 'staff' else form,
            'warehouse_form': WarehouseForm() if property_type != 'warehouse' else form,
            'townhouse_form': Townhouseform() if property_type != 'townhouse' else form,
            'fullfloors_form': Fullfloorsform() if property_type != 'fullfloors' else form,
            'showrooms_form': Showroomsform() if property_type != 'showrooms' else form,
            'wholebuilding_form': Wholebuildingform() if property_type != 'wholebuilding' else form,
            'supermarket_form': Supermarketform() if property_type != 'supermarket' else form,
            'foreign_form': Foreignform() if property_type != 'foreign' else form,
            'shared_form': Sharedform() if property_type != 'shared' else form,
            'suits_form': Suitsform() if property_type != 'suits' else form,
        })
        # Set the specific form for this property type
        context[f'{property_type}_form'] = form
    
    return render(request, config['template'], context)


