def universal_update_view(request, property_type, pk):
    """Universal update view for all property types (mobile, community, and real estate)"""
    
    if property_type not in MODEL_MAPPING:
        messages.error(request, "Invalid property type.")
        return redirect('adss', user_id=request.user.id)
    
    config = MODEL_MAPPING[property_type]
    product = get_object_or_404(config['model'], id=pk)
    
    if request.method == 'POST':
        form = config['form'](request.POST, request.FILES, instance=product)
        
        if form.is_valid():
            try:
                from django.db import transaction
                
                with transaction.atomic():
                    # Save the product
                    updated_product = form.save(commit=False)
                    
                    # IMPORTANT: For admin updates, preserve the original status
                    # Do NOT change the status - keep whatever it was
                    # updated_product.status = 'pending'  # REMOVE THIS LINE
                    
                    # Handle city/region/governate/district if they exist in the form
                    city_id = request.POST.get('city')
                    if city_id:
                        try:
                            updated_product.city = Cities.objects.get(id=city_id)
                        except Cities.DoesNotExist:
                            pass
                    
                    # Handle governorate if exists
                    governate_id = request.POST.get('governate')
                    if governate_id and hasattr(updated_product, 'governate'):
                        try:
                            updated_product.governate = Governate.objects.get(id=governate_id)
                        except Governate.DoesNotExist:
                            pass
                    
                    # Handle district if exists
                    district_id = request.POST.get('district')
                    if district_id and hasattr(updated_product, 'district'):
                        try:
                            updated_product.district = District.objects.get(id=district_id)
                        except District.DoesNotExist:
                            pass
                    
                    # Handle many-to-many fields (amenities, nearby locations, etc.)
                    if 'main_amenities' in request.POST and hasattr(updated_product, 'main_amenities'):
                        updated_product.main_amenities.set(request.POST.getlist('main_amenities'))
                    
                    if 'additional_amenities' in request.POST and hasattr(updated_product, 'additional_amenities'):
                        updated_product.additional_amenities.set(request.POST.getlist('additional_amenities'))
                    
                    if 'nearby_locations' in request.POST and hasattr(updated_product, 'nearby_locations'):
                        updated_product.nearby_locations.set(request.POST.getlist('nearby_locations'))
                    
                    updated_product.save()
                    
                    # ============================================================
                    # HANDLE IMAGES
                    # ============================================================
                    if config.get('image_relation') and hasattr(updated_product, config['image_relation']):
                        image_relation = getattr(updated_product, config['image_relation'])
                        
                        # Delete marked images
                        delete_image_ids = request.POST.getlist('delete_images')
                        if delete_image_ids:
                            # Convert to integers if they're strings
                            delete_ids = [int(id) for id in delete_image_ids if id]
                            image_relation.filter(id__in=delete_ids).delete()
                        
                        # Handle image order if provided
                        image_order = request.POST.get('image_order', '')
                        if image_order:
                            order_ids = image_order.split(',')
                            # Reorder existing images based on order
                            for index, img_id in enumerate(order_ids):
                                if img_id and not img_id.startswith('new_'):
                                    try:
                                        img = image_relation.get(id=int(img_id))
                                        img.order = index
                                        img.save()
                                    except Exception as e:
                                        print(f"Error ordering image {img_id}: {e}")
                        
                        # Add new images
                        new_images = request.FILES.getlist('images')
                        if new_images and config['image_model']:
                            for img_file in new_images:
                                # Create image object
                                image_obj = config['image_model'].objects.create(image=img_file)
                                # Add to relation
                                image_relation.add(image_obj)
                                
                                # If we have order info, set it
                                if image_order:
                                    # Find position of this new image in order
                                    for index, img_id in enumerate(order_ids):
                                        if img_id.startswith('new_'):
                                            image_obj.order = index
                                            image_obj.save()
                                            break
                    
                    # ============================================================
                    # HANDLE VIDEOS
                    # ============================================================
                    if config.get('video_relation') and hasattr(updated_product, config['video_relation']):
                        video_relation = getattr(updated_product, config['video_relation'])
                        
                        # Delete marked videos
                        delete_video_ids = request.POST.getlist('delete_videos')
                        if delete_video_ids:
                            delete_vids = [int(id) for id in delete_video_ids if id]
                            video_relation.filter(id__in=delete_vids).delete()
                        
                        # Add new videos
                        new_videos = request.FILES.getlist('videos')
                        if new_videos and config['video_model']:
                            for vid_file in new_videos:
                                video_obj = config['video_model'].objects.create(video=vid_file)
                                video_relation.add(video_obj)
                
                # Return JSON response for AJAX requests
                if request.headers.get('X-Requested-With') == 'XMLHttpRequest':
                    return JsonResponse({
                        'success': True,
                        'redirect_url': reverse('adss', kwargs={'user_id': request.user.id}),
                        'message': 'Updated successfully'
                    })
                
                messages.success(request, f"{property_type.replace('_', ' ').title()} updated successfully!")
                return redirect('adss', user_id=request.user.id)
                
            except Exception as e:
                print(f"Update error: {e}")
                import traceback
                traceback.print_exc()
                
                if request.headers.get('X-Requested-With') == 'XMLHttpRequest':
                    return JsonResponse({'error': str(e)}, status=500)
                
                messages.error(request, f"Error updating: {str(e)}")
                return redirect('universal_edit', property_type=property_type, pk=pk)
        else:
            print(f"Form errors: {form.errors}")
            if request.headers.get('X-Requested-With') == 'XMLHttpRequest':
                return JsonResponse({'errors': form.errors}, status=400)
            
            messages.error(request, f"Please correct the errors: {form.errors}")
            return redirect('universal_edit', property_type=property_type, pk=pk)
    
    return redirect('universal_edit', property_type=property_type, pk=pk)


def simple_edit_view(request, property_type, pk):
    """Fallback simple edit view for property types without modals"""
    messages.info(request, f"Editing {property_type} - Please create a dedicated modal for this type")
    return redirect('universal_edit', property_type=property_type, pk=pk)


