User = get_user_model()


def deduct_credits_for_approval(property_obj, admin_user, posting_method):
    """
    Deduct credits when admin approves a listing
    - Normal: 1 credit
    - Boosted: 1 credit + 7 boost days  
    - Exclusive: 25 credits
    """
    from .models import get_or_create_user_credits, ListingUsage, CreditTransaction, BoostUsage
    from decimal import Decimal
    from django.utils import timezone
    from datetime import timedelta
    
    user = property_obj.user
    credits = get_or_create_user_credits(user)
    
    if posting_method == 'exclusive':
        COST_PER_AD = 25
        NEEDS_BOOST = False
    elif posting_method == 'boosted':
        COST_PER_AD = 1
        NEEDS_BOOST = True
        BOOST_DAYS = 7
    else:  # normal
        COST_PER_AD = 1
        NEEDS_BOOST = False
    
    # Check if user has enough credits
    if credits.purchased_listing_credits >= COST_PER_AD:
        # Deduct credits
        credits.purchased_listing_credits -= COST_PER_AD
        credits.save()
        
        # Track usage
        ListingUsage.objects.create(
            user=user,
            listing_type=property_obj.__class__.__name__.lower(),
            listing_id=property_obj.id,
            credit_source='purchased',
            expires_at=timezone.now() + timedelta(days=45)
        )
        
        # Deduct boost days if boosted
        if NEEDS_BOOST:
            if credits.boost_days_available >= BOOST_DAYS:
                credits.boost_days_available -= BOOST_DAYS
                credits.save()
                BoostUsage.objects.create(
                    user=user,
                    listing_type=property_obj.__class__.__name__.lower(),
                    listing_id=property_obj.id,
                    boost_days=BOOST_DAYS,
                    expires_at=timezone.now() + timedelta(days=BOOST_DAYS),
                    is_active=True
                )
            else:
                return False, f"User has insufficient boost days. Need {BOOST_DAYS} days.", None
        
        CreditTransaction.objects.create(
            user=user,
            transaction_type='usage',
            listing_credits_change=-COST_PER_AD,
            description=f"{COST_PER_AD} credits deducted for approved {posting_method} listing: {getattr(property_obj, 'property_title', getattr(property_obj, 'title', 'Untitled'))}"
        )
        
        return True, f"✅ {COST_PER_AD} credits deducted.", None
    
    else:
        # NO CREDITS - Create payment request
        total_amount = Decimal('26.250')
        
        payment_request = UserPaymentRequest.objects.create(
            user=user,
            amount_omr=Decimal('25.000'),
            vat_amount=Decimal('1.250'),
            total_amount=total_amount,
            payment_method='bank_transfer',
            status='pending',
            pending_ad_data=json.dumps({
                'listing_type': property_obj.__class__.__name__.lower(),
                'listing_id': property_obj.id,
                'credits_needed': COST_PER_AD,
                'posting_method': posting_method,
                'property_title': getattr(property_obj, 'property_title', getattr(property_obj, 'title', 'Untitled'))
            })
        )
        
        return False, f"❌ User has insufficient credits. Payment request created.", payment_request


def send_user_payment_required_notification(user, property_obj, amount):
    """Send email to user that payment is required for their ad"""
    from django.core.mail import send_mail
    
    subject = f"Payment Required to Publish Your Ad - {getattr(property_obj, 'property_title', getattr(property_obj, 'title', 'Untitled'))}"
    message = f"""
Dear {user.username},

Your ad "{getattr(property_obj, 'property_title', getattr(property_obj, 'title', 'Untitled'))}" has been reviewed and is ready for publication.

However, you don't have enough credits. Please pay {amount} OMR to publish your ad.

Payment Methods:
- Bank Transfer
- Cash

Once payment is confirmed, your ad will be published immediately.

Best regards,
Admin Team
"""
    send_mail(
        subject,
        message,
        settings.DEFAULT_FROM_EMAIL,
        [user.email],
        fail_silently=True,
    )


def notify_admin_payment_request(payment_request, property_obj):
    """Send email to admin about payment request"""
    from django.core.mail import send_mail
    
    subject = f"Payment Request - User Needs to Pay {payment_request.total_amount} OMR"
    message = f"""
User: {payment_request.user.username} (ID: {payment_request.user.id})
Email: {payment_request.user.email}
Amount: {payment_request.total_amount} OMR
Property: {getattr(property_obj, 'property_title', getattr(property_obj, 'title', 'Untitled'))}
Property ID: {property_obj.id}

Please contact the user to arrange payment.

Once payment is confirmed, mark it as paid in the admin dashboard.
"""
    
    if hasattr(settings, 'ADMIN_EMAILS') and settings.ADMIN_EMAILS:
        send_mail(
            subject,
            message,
            settings.DEFAULT_FROM_EMAIL,
            settings.ADMIN_EMAILS,
            fail_silently=True,
        )


