def refund_exclusive_credit(property_obj):
    """
    Refund the credit used for exclusive listing when rejected or converted to normal
    """
    from .models import get_or_create_user_credits, ListingUsage, CreditTransaction
    
    try:
        user = property_obj.user
        
        # Find the listing usage for this exclusive listing
        listing_usage = ListingUsage.objects.filter(
            user=user,
            listing_type=property_obj.__class__.__name__.lower(),
            listing_id=property_obj.id,
            credit_source='purchased',
            status='active'
        ).first()
        
        if listing_usage:
            # Get user credits
            credits = get_or_create_user_credits(user)
            
            # Refund the purchased credit (25 credits)
            credits.purchased_listing_credits += 25
            credits.save()
            
            # Update listing usage status
            listing_usage.status = 'refunded'
            listing_usage.save()
            
            # Create transaction record for refund
            CreditTransaction.objects.create(
                user=user,
                transaction_type='refund',
                listing_credits_change=25,
                description=f"25 credits refunded for rejected exclusive listing: {getattr(property_obj, 'property_title', getattr(property_obj, 'title', 'Untitled'))} (ID: {property_obj.id})"
            )
            
            return True, "25 credits refunded to user"
        else:
            return False, "No active credit usage found for this listing"
            
    except Exception as e:
        print(f"Refund error: {e}")
        return False, str(e)


def convert_exclusive_to_normal(property_obj, admin_user):
    """
    Convert exclusive listing to normal pending and refund credit
    """
    from .models import get_or_create_user_credits, ListingUsage, CreditTransaction
    
    try:
        user = property_obj.user
        
        # Find the listing usage for this exclusive listing
        listing_usage = ListingUsage.objects.filter(
            user=user,
            listing_type=property_obj.__class__.__name__.lower(),
            listing_id=property_obj.id,
            credit_source='purchased',
            status='active'
        ).first()
        
        if listing_usage:
            # Get user credits
            credits = get_or_create_user_credits(user)
            
            # Refund the purchased credit (25 credits)
            credits.purchased_listing_credits += 25
            credits.save()
            
            # Update listing usage status
            listing_usage.status = 'refunded'
            listing_usage.save()
            
            # Create transaction record for refund
            CreditTransaction.objects.create(
                user=user,
                transaction_type='refund',
                listing_credits_change=25,
                description=f"25 credits refunded - Exclusive listing converted to normal: {getattr(property_obj, 'property_title', getattr(property_obj, 'title', 'Untitled'))} (ID: {property_obj.id})"
            )
            
            # Send notification email to user
            subject = f"Your Exclusive Listing Request Converted - {getattr(property_obj, 'property_title', getattr(property_obj, 'title', 'Untitled'))}"
            message = f"""
Dear {user.username},

Your exclusive listing request for "{getattr(property_obj, 'property_title', getattr(property_obj, 'title', 'Untitled'))}" has been converted to a normal listing by {admin_user.username}.

Your 25 credits have been refunded to your account.

You can edit and repost this as a normal listing.

Best regards,
Admin Team
"""
            send_mail(
                subject,
                message,
                settings.DEFAULT_FROM_EMAIL,
                [user.email],
                fail_silently=True,
            )
            
            return True, "25 credits refunded and listing converted to normal"
        else:
            return False, "No active credit usage found"
            
    except Exception as e:
        print(f"Convert error: {e}")
        return False, str(e)


@staff_member_required
def exclusive_listings(request):
    """View to manage exclusive listing requests - Deduct 25 credits on approval"""
    
    # Check if user has permission (superuser or subadmin with exclusive permission)
    is_superuser = request.user.is_superuser
    has_permission = False
    is_subadmin = False
    
    if not is_superuser:
        try:
            subadmin = request.user.subadmin_profile
            if subadmin.has_permission('ads_approval_exclusive', 'view'):
                has_permission = True
                is_subadmin = True
            elif subadmin.has_permission('ads_approval_properties', 'view'):
                has_permission = True
                is_subadmin = True
        except SubAdmin.DoesNotExist:
            pass
    else:
        has_permission = True
    
    if not has_permission:
        messages.error(request, "You don't have permission to view exclusive listings.")
        return redirect('admin_dashboard')
    
    # Handle bulk actions for exclusive listings
    if request.method == 'POST' and request.headers.get('X-Requested-With') == 'XMLHttpRequest':
        try:
            action = request.POST.get('bulk_action')
            property_type = request.POST.get('property_type')
            
            # Map property types to models (only property types)
            model_map = {
                'land': Land, 'villa': Villa, 'commercial': Commercial,
                'farm': Farm, 'apartment': Apartment, 'factory': Factory,
                'complex': Complex, 'clinic': Clinic, 'hostel': Hostel,
                'office': Office, 'shop': Shop, 'cafe': Cafe, 'staff': Staff,
                'warehouse': Warehouse, 'townhouse': Townhouse, 'fullfloors': Fullfloors,
                'showrooms': Showrooms, 'wholebuilding': Wholebuilding,
                'supermarket': Supermarket, 'foreign': Foreign, 'shared': Shared,
                'suits': Suits,
            }
            
            if property_type in model_map:
                model = model_map[property_type]
                selected_items = request.POST.get('selected_items', '')
                
                if selected_items:
                    ids = [int(id) for id in selected_items.split(',') if id]
                    
                    if action == 'approve_exclusive':
                        approved_count = 0
                        payment_requests = 0
                        
                        for obj_id in ids:
                            obj = model.objects.filter(id=obj_id, status='pending_exclusive').first()
                            if obj:
                                success, msg, payment_request = deduct_credits_for_approval(obj, request.user, 'exclusive')
                                
                                if success:
                                    obj.status = 'exclusive'
                                    obj.save()
                                    approved_count += 1
                                    send_exclusive_approval_notification(obj, request.user, credits_deducted=True)
                                else:
                                    # Payment request created - keep status as pending_exclusive
                                    payment_requests += 1
                                    # Send payment required notification
                                    send_user_payment_required_notification(obj.user, obj, Decimal('26.250'))
                                    # Notify admin
                                    if payment_request:
                                        notify_admin_payment_request(payment_request, obj)
                        
                        if approved_count > 0 and payment_requests > 0:
                            return JsonResponse({
                                'success': True, 
                                'message': f'{approved_count} listing(s) approved with credit deduction. {payment_requests} payment request(s) created.'
                            })
                        elif approved_count > 0:
                            return JsonResponse({
                                'success': True, 
                                'message': f'{approved_count} exclusive listing(s) approved. 25 credits deducted from each.'
                            })
                        elif payment_requests > 0:
                            return JsonResponse({
                                'success': True, 
                                'message': f'{payment_requests} payment request(s) created. Users will be notified to complete payment.'
                            })
                        else:
                            return JsonResponse({'success': False, 'message': 'No items were updated.'})
                    
                    elif action == 'reject_exclusive':
                        affected = 0
                        for obj_id in ids:
                            obj = model.objects.filter(id=obj_id, status='pending_exclusive').first()
                            if obj:
                                obj.status = 'rejected'
                                obj.save()
                                affected += 1
                                send_exclusive_rejection_notification(obj, request.user)
                        
                        if affected > 0:
                            return JsonResponse({
                                'success': True, 
                                'message': f'{affected} exclusive listing(s) rejected. No credits were deducted.'
                            })
                        else:
                            return JsonResponse({'success': False, 'message': 'No items were updated.'})
                    
                    elif action == 'convert_to_normal':
                        affected = 0
                        for obj_id in ids:
                            obj = model.objects.filter(id=obj_id, status='pending_exclusive').first()
                            if obj:
                                obj.status = 'pending'
                                obj.save()
                                affected += 1
                                # Check if credits were already deducted
                                listing_usage = ListingUsage.objects.filter(
                                    listing_type=property_type,
                                    listing_id=obj_id,
                                    status='active'
                                ).first()
                                if listing_usage:
                                    refund_exclusive_credit(obj)
                        
                        if affected > 0:
                            return JsonResponse({
                                'success': True, 
                                'message': f'{affected} listing(s) converted to normal pending.'
                            })
                        else:
                            return JsonResponse({'success': False, 'message': 'No items were updated.'})
                    
                    return JsonResponse({'success': False, 'message': 'No items were updated.'})
            
            return JsonResponse({'success': False, 'message': 'Invalid action or property type'})
            
        except Exception as e:
            return JsonResponse({'success': False, 'message': str(e)})
    
    # Get all exclusive pending listings (only property types)
    exclusive_listings_data = []
    
    # Property models only (where exclusive is available)
    property_models = [
        (Land, 'land', 'Land'), (Villa, 'villa', 'Villa'), 
        (Commercial, 'commercial', 'Commercial'), (Farm, 'farm', 'Farm'),
        (Apartment, 'apartment', 'Apartment'), (Factory, 'factory', 'Factory'),
        (Complex, 'complex', 'Complex'), (Clinic, 'clinic', 'Clinic'),
        (Hostel, 'hostel', 'Hostel'), (Office, 'office', 'Office'),
        (Shop, 'shop', 'Shop'), (Cafe, 'cafe', 'Cafe'),
        (Staff, 'staff', 'Staff'), (Warehouse, 'warehouse', 'Warehouse'),
        (Townhouse, 'townhouse', 'Townhouse'), (Fullfloors, 'fullfloors', 'Fullfloors'),
        (Showrooms, 'showrooms', 'Showrooms'), (Wholebuilding, 'wholebuilding', 'Wholebuilding'),
        (Supermarket, 'supermarket', 'Supermarket'), (Foreign, 'foreign', 'Foreign'),
        (Shared, 'shared', 'Shared'), (Suits, 'suits', 'Suits')
    ]
    
    for model, type_key, display_name in property_models:
        try:
            # Get items with status 'pending_exclusive'
            pending_exclusive = model.objects.filter(status='pending_exclusive').select_related('user')
            for item in pending_exclusive:
                exclusive_listings_data.append({
                    'id': item.id,
                    'type': type_key,
                    'display_type': display_name,
                    'title': getattr(item, 'property_title', getattr(item, 'title', 'Untitled')),
                    'price': getattr(item, 'price', 0),
                    'user': item.user,
                    'user_email': item.user.email,
                    'user_username': item.user.username,
                    'created_at': item.created_at,
                    'status': item.status,
                })
        except Exception as e:
            continue
    
    # Sort by created date (newest first)
    exclusive_listings_data.sort(key=lambda x: x['created_at'], reverse=True)
    
    # Pagination
    paginator = Paginator(exclusive_listings_data, 20)
    page_number = request.GET.get('page')
    page_obj = paginator.get_page(page_number)
    
    context = {
        'exclusive_listings': page_obj,
        'total_count': len(exclusive_listings_data),
        'is_superuser': is_superuser,
        'is_subadmin': is_subadmin,
        'admin_name': request.user.username,
    }
    
    return render(request, 'admin1/exclusive_listings.html', context)

