# views.py
from django.shortcuts import render, redirect, get_object_or_404
from django.contrib import messages
from django.contrib.auth.decorators import login_required
from django.utils.safestring import mark_safe
from .models import PrivacyPolicy


# =========================
# ADMIN PRIVACY POLICY LIST
# =========================
@login_required
def privacy_policy_list(request):
    policies = PrivacyPolicy.objects.all().order_by('-effective_date')
    return render(request, 'admin1/PrivacyPolicy/privacy_policy.html', {'policies': policies})


# =========================
# ADD PRIVACY POLICY
# =========================
@login_required
def add_privacy_policy(request):
    if request.method == "POST":
        title = request.POST.get('title')
        content = request.POST.get('content')
        version = request.POST.get('version')
        effective_date = request.POST.get('effective_date')
        is_active = True if request.POST.get('is_active') == 'on' else False

