# =========================
# TOGGLE ACTIVE STATUS
# =========================
@login_required
def toggle_privacy_policy_status(request, id):
    policy = get_object_or_404(PrivacyPolicy, id=id)

    if request.method == "POST":
        policy.is_active = not policy.is_active
        policy.save()
        
        # If activating this policy, deactivate all others
        if policy.is_active:
            PrivacyPolicy.objects.exclude(id=policy.id).update(is_active=False)
        
        messages.success(request, "Privacy policy status updated.")

    return redirect('privacy_policy_list')


# =========================
# PUBLIC PRIVACY POLICY PAGE
# =========================

def public_privacy_policy(request):
    """Public view for privacy policy with preserved formatting"""
    # Get the active privacy policy
    policy = PrivacyPolicy.objects.filter(is_active=True).first()
    
    # Get all policies for version dropdown
    all_policies = PrivacyPolicy.objects.all().order_by('-effective_date')
    
    # Check if specific version is requested via query parameter
    version_id = request.GET.get('version')
    if version_id:
        try:
            policy = PrivacyPolicy.objects.get(id=version_id)
        except PrivacyPolicy.DoesNotExist:
            # If version not found, fall back to active policy
            policy = PrivacyPolicy.objects.filter(is_active=True).first()
    
    context = {
        'policy': policy,
        'all_policies': all_policies,
    }
    
    return render(request, 'privacy_policy/public_privacy_policy.html', context)


