from django.shortcuts import redirect, render
from django.core.mail import EmailMultiAlternatives
from django.conf import settings
from django.views.decorators.csrf import csrf_exempt
from django.http import JsonResponse
from .models import BusinessCollaboration

def submit_collaboration(request):
    if request.method == "POST":
        name = request.POST.get("name")
        email = request.POST.get("email")
        message = request.POST.get("message")

        # Save to database
        BusinessCollaboration.objects.create(
            name=name,
            email=email,
            message=message
        )

        # ---------- Email sending (your original HTML email) ----------
        subject = f"New Business Collaboration Request 🚀"
        text_content = f"""
        New Collaboration Request

        Name: {name}
        Email: {email}

        Message:
        {message}
        """

        html_content = f"""
<!DOCTYPE html>
<html>
<head>
<meta charset="UTF-8">
</head>
<body style="margin:0; padding:0; background-color:#eef2f5; font-family: 'Segoe UI', Arial, sans-serif;">

<table width="100%" cellpadding="0" cellspacing="0" style="padding: 30px 0;">
<tr>
<td align="center">

    <table width="600" cellpadding="0" cellspacing="0" style="background:#ffffff; border-radius:12px; overflow:hidden; box-shadow:0 6px 20px rgba(0,0,0,0.08);">

        <tr>
            <td style="background: linear-gradient(135deg, #15818E, #0f5f69); padding: 25px; text-align:center;">
                <h2 style="color:#ffffff; margin:0; font-weight:600; letter-spacing:0.5px;">
                    🚀 New Collaboration Request
                </h2>
                <p style="color:#d9f3f6; margin:5px 0 0; font-size:14px;">
                    Someone is interested in working with you
                </p>
            </td>
        </tr>

        <tr>
            <td style="padding: 30px;">

                <p style="font-size:16px; color:#333; margin-bottom:20px;">
                    You've received a new business collaboration inquiry. Details are below:
                </p>

                <table width="100%" cellpadding="0" cellspacing="0" style="border:1px solid #e6e6e6; border-radius:10px; overflow:hidden;">

                    <tr>
                        <td style="padding:15px; background:#fafafa; font-weight:600; width:120px;">Name</td>
                        <td style="padding:15px;">{name}</td>
                    </tr>

                    <tr>
                        <td style="padding:15px; background:#fafafa; font-weight:600;">Email</td>
                        <td style="padding:15px;">
                            <a href="mailto:{email}" style="color:#15818E; text-decoration:none;">
                                {email}
                            </a>
                        </td>
                    </tr>

                    <tr>
                        <td style="padding:15px; background:#fafafa; font-weight:600;">Message</td>
                        <td style="padding:15px; line-height:1.6;">
                            {message}
                        </td>
                    </tr>

                </table>

                <div style="text-align:center; margin-top:30px;">
                    <a href="mailto:{email}" 
                       style="background:#15818E; color:#ffffff; padding:12px 25px; border-radius:6px; text-decoration:none; font-weight:600; display:inline-block;">
                        Reply to {name}
                    </a>
                </div>

                <p style="margin-top:30px; font-size:13px; color:#888; text-align:center;">
                    This message was sent from your website collaboration form.
                </p>

            </td>
        </tr>

    </table>

</td>
</tr>
</table>

</body>
</html>
        """

        email_message = EmailMultiAlternatives(
            subject,
            text_content,
            settings.DEFAULT_FROM_EMAIL,
            [settings.CONTACT_EMAIL],
        )
        email_message.attach_alternative(html_content, "text/html")
        email_message.send()
        # ---------- End email ----------

        # ✅ Set a session flag to show popup on next page load
        request.session['show_success_popup'] = True

        return redirect("/")

    return redirect("/")


# Optional: View to clear the session flag (called by JavaScript after popup is closed)
@csrf_exempt
def clear_popup_flag(request):
    if request.method == "POST":
        if 'show_success_popup' in request.session:
            del request.session['show_success_popup']
        return JsonResponse({'status': 'ok'})
    return JsonResponse({'error': 'Method not allowed'}, status=405)

@login_required
def complete_profile(request):
    """View for admin to complete/edit their profile details"""
    user = request.user
    
    # Check if profile is already complete (excluding names, as they are now required)
    if user.phone and user.address and user.dob and user.gender:
        messages.info(request, 'Your profile is already complete. You can update it below.')
    
    if request.method == 'POST':
        # Get form data
        first_name = request.POST.get('first_name', '').strip()
        last_name = request.POST.get('last_name', '').strip()
        phone = request.POST.get('phone', '').strip()
        whatsapp = request.POST.get('whatsapp', '').strip()
        address = request.POST.get('address', '').strip()
        dob = request.POST.get('dob')
        nationality = request.POST.get('nationality')
        gender = request.POST.get('gender')
        image = request.FILES.get('image')
        
        # Validate required fields
        if not first_name:
            messages.error(request, 'First name is required!')
            return render(request, 'admin1/profile/complete.html', {'user': user})
        if not last_name:
            messages.error(request, 'Last name is required!')
            return render(request, 'admin1/profile/complete.html', {'user': user})
        if not phone:
            messages.error(request, 'Phone number is required!')
            return render(request, 'admin1/profile/complete.html', {'user': user})
        
        # Update user profile
        user.first_name = first_name
        user.last_name = last_name
        user.phone = phone
        user.whatsapp = whatsapp if whatsapp else user.whatsapp
        user.address = address
        user.dob = dob if dob else None
        user.nationality = nationality
        user.gender = gender
        if image:
            user.image = image
        
        user.save()
        messages.success(request, 'Profile updated successfully! 🎉')
        return redirect('admin_dashboard')
    
    # GET request – display form with current user data
    return render(request, 'admin1/profile/complete.html', {'user': user})


