from django.http import HttpResponse
from django.utils import timezone
from datetime import timedelta
from django.contrib.auth.decorators import login_required
from django.shortcuts import get_object_or_404, render, redirect
from django.contrib import messages

# Paymob API endpoints
PAYMOB_API_URL = settings.PAYMOB_BASE_URL


def get_paymob_auth_token():
    """Get authentication token from Paymob"""
    try:
        response = requests.post(
            f"{PAYMOB_API_URL}/auth/tokens",
            json={"api_key": settings.PAYMOB_API_KEY},
            timeout=30
        )
        response.raise_for_status()
        return response.json().get("token")
    except Exception as e:
        print(f"Paymob auth error: {e}")
        return None


def create_paymob_order(auth_token, amount_cents, merchant_order_id):
    """Create order in Paymob"""
    try:
        response = requests.post(
            f"{PAYMOB_API_URL}/ecommerce/orders",
            json={
                "auth_token": auth_token,
                "delivery_needed": False,
                "amount_cents": amount_cents,
                "currency": "OMR",
                "merchant_order_id": merchant_order_id,
                "items": []
            },
            timeout=30
        )
        response.raise_for_status()
        return response.json()
    except Exception as e:
        print(f"Paymob order creation error: {e}")
        return None


def get_paymob_payment_key(auth_token, order_id, amount_cents, user_email, user_phone, integration_id, request):
    """Get payment key for redirect"""
    try:
        billing_data = {
            "apartment": "NA",
            "email": user_email,
            "floor": "NA",
            "first_name": request.user.username[:20] if request.user.username else "Customer",
            "street": "NA",
            "building": "NA",
            "phone_number": user_phone if user_phone else "00000000",
            "shipping_method": "NA",
            "postal_code": "NA",
            "city": "NA",
            "country": "NA",
            "last_name": "Customer",
            "state": "NA"
        }
        
        response = requests.post(
            f"{PAYMOB_API_URL}/acceptance/payment_keys",
            json={
                "auth_token": auth_token,
                "amount_cents": amount_cents,
                "expiration": 3600,
                "order_id": order_id,
                "billing_data": billing_data,
                "currency": "OMR",
                "integration_id": integration_id,
                "lock_order_when_paid": False
            },
            timeout=30
        )
        response.raise_for_status()
        return response.json().get("token")
    except Exception as e:
        print(f"Paymob payment key error: {e}")
        return None

@login_required
def buy_credits(request, package_id):
    """
    Purchase credit package via Paymob - Supports both Test and Live mode
    """
    from .models import CreditPackage, get_or_create_user_credits, add_credits_to_user, PaymentTransaction
    from django.urls import reverse
    
    package = get_object_or_404(CreditPackage, id=package_id, is_active=True)
    
    # Capture the 'next' URL from GET parameters (if any)
    next_url = request.GET.get('next') or request.POST.get('next')
    
    # ============================================================
    # TEST MODE - Direct credit addition (no real payment)
    # ============================================================
    if settings.PAYMENT_MODE == 'test':
        # Add credits to user
        credits = add_credits_to_user(request.user, package)
        
        # Create mock payment record
        PaymentTransaction.objects.create(
            user=request.user,
            package=package,
            amount_omr=package.price_omr,
            vat_amount=package.get_vat_amount(),
            total_amount=package.get_price_with_vat(),
            payment_id=f"TEST_{int(time.time())}_{request.user.id}",
            status='success',
            completed_at=timezone.now()
        )
        
        messages.success(
            request, 
            f"✅ [TEST MODE] {package.name} added to your account! "
            f"You now have {credits.available_listing_credits} listing credits "
            f"and {credits.boost_days_available} boost days."
        )
        
        # Redirect to next URL if provided, otherwise to my_credits
        if next_url:
            return redirect(next_url)
        return redirect('my_credits')
    
    # ============================================================
    # LIVE MODE - Real Paymob Payment
    # ============================================================
    else:
        # Calculate total with VAT
        total_amount = package.get_price_with_vat()
        amount_cents = int(total_amount * 100)  # 1 OMR = 1000 fills
        
        # Get Paymob token
        auth_token = get_paymob_auth_token()
        if not auth_token:
            messages.error(request, "Payment service temporarily unavailable. Please try again later.")
            return redirect('credit_packages')
        
        # Create unique order ID
        merchant_order_id = f"CREDIT_{request.user.id}_{package.id}_{int(time.time())}"
        
        # Create order in Paymob
        order_response = create_paymob_order(auth_token, amount_cents, merchant_order_id)
        if not order_response:
            messages.error(request, "Failed to create payment order. Please try again.")
            return redirect('credit_packages')
        
        order_id = order_response.get('id')
        
        # Get user phone
        user_phone = getattr(request.user, 'phone', '00000000')
        if user_phone:
            user_phone = user_phone.replace('+', '').replace('-', '').replace(' ', '')[-8:]
        
        # Get payment key
        payment_token = get_paymob_payment_key(
            auth_token, 
            order_id, 
            amount_cents,
            request.user.email,
            user_phone,
            settings.PAYMOB_INTEGRATION_ID,
            request
        )
        
        if not payment_token:
            messages.error(request, "Failed to initialize payment. Please try again.")
            return redirect('credit_packages')
        
        # Create payment transaction record
        payment = PaymentTransaction.objects.create(
            user=request.user,
            package=package,
            amount_omr=package.price_omr,
            vat_amount=package.get_vat_amount(),
            total_amount=total_amount,
            order_id=merchant_order_id,
            payment_token=payment_token,
            status='pending'
        )
        
        # Store in session for callback
        request.session['pending_payment_id'] = payment.id
        
        # Store the next URL in session for redirection after successful payment
        if next_url:
            request.session['payment_next_url'] = next_url
        
        # Redirect to Paymob iframe
        iframe_url = f"https://oman.paymob.com/api/acceptance/iframes/{settings.PAYMOB_IFRAME_ID}?payment_token={payment_token}"
        
        return redirect(iframe_url)


@login_required
def credit_packages(request):
    """
    Display available credit packages with mode indicator
    """
    from .models import CreditPackage, get_or_create_user_credits
    from django.conf import settings
    
    listing_packages = CreditPackage.objects.filter(
        is_active=True, 
        package_type='listing'
    ).order_by('display_order')
    
    boost_individual = CreditPackage.objects.filter(
        is_active=True, 
        package_type='boost_individual'
    ).order_by('display_order')
    
    boost_bulk_7 = CreditPackage.objects.filter(
        is_active=True, 
        package_type='boost_bulk',
        boost_days=7
    ).order_by('display_order')
    
    boost_bulk_14 = CreditPackage.objects.filter(
        is_active=True, 
        package_type='boost_bulk',
        boost_days=14
    ).order_by('display_order')
    
    business_package = CreditPackage.objects.filter(
        is_active=True, 
        package_type='business'
    ).first()
    
    # Get user's current credits
    credits = get_or_create_user_credits(request.user)
    
    context = {
        'listing_packages': listing_packages,
        'boost_individual': boost_individual,
        'boost_bulk_7': boost_bulk_7,
        'boost_bulk_14': boost_bulk_14,
        'business_package': business_package,
        'credits': credits,
        'free_credits_left': credits.available_free_listings,
        'purchased_credits_left': credits.purchased_listing_credits,
        'boost_days_left': credits.boost_days_available,
        'payment_mode': settings.PAYMENT_MODE,
    }
    
    return render(request, 'credits/packages.html', context)


@login_required
def my_credits(request):
    """
    Display user's credit balance and transaction history
    """
    from .models import get_or_create_user_credits, CreditTransaction
    from django.utils import timezone
    
    credits = get_or_create_user_credits(request.user)
    
    transactions = CreditTransaction.objects.filter(
        user=request.user
    ).select_related('package').order_by('-created_at')[:50]
    
    # Calculate days left for free tier
    free_tier_days_left = 0
    if credits.free_listings_expires_at:
        free_tier_days_left = max(0, (credits.free_listings_expires_at - timezone.now()).days)
    
    context = {
        'credits': credits,
        'transactions': transactions,
        'free_credits_left': credits.available_free_listings,
        'purchased_credits_left': credits.purchased_listing_credits,
        'boost_days_left': credits.boost_days_available,
        'free_tier_days_left': free_tier_days_left,
        'payment_mode': settings.PAYMENT_MODE,
    }
    
    return render(request, 'credits/my_credits.html', context)

@csrf_exempt
@require_http_methods(["POST"])
def paymob_webhook(request):
    """
    Handle Paymob payment callback/webhook (Live mode only)
    """
    from django.conf import settings
    from django.http import HttpResponse
    from .models import PaymentTransaction, add_credits_to_user, get_or_create_user_credits, ListingUsage
    from django.utils import timezone
    from datetime import timedelta
    import json
    import hmac
    import hashlib
    
    # Only process webhooks in live mode
    if settings.PAYMENT_MODE == 'test':
        return HttpResponse("Webhook disabled in test mode", status=200)
    
    try:
        body = request.body.decode('utf-8')
        data = json.loads(body)
        
        # Verify HMAC signature if secret is configured
        hmac_header = request.headers.get('HMAC')
        if hmac_header and settings.PAYMOB_HMAC_SECRET:
            expected_hmac = hmac.new(
                settings.PAYMOB_HMAC_SECRET.encode(),
                body.encode(),
                hashlib.sha512
            ).hexdigest()
            
            if hmac_header != expected_hmac:
                print(f"Invalid HMAC signature: {hmac_header}")
                return HttpResponse("Invalid signature", status=400)
        
        obj = data.get('obj', {})
        transaction_id = obj.get('id')
        order_id = obj.get('order', {}).get('merchant_order_id')
        success = obj.get('success', False)
        
        try:
            payment = PaymentTransaction.objects.get(order_id=order_id)
            payment.payment_id = transaction_id
            payment.webhook_response = data
            
            if success:
                payment.status = 'success'
                payment.completed_at = timezone.now()
                payment.save()
                
                # Add credits to user
                add_credits_to_user(payment.user, payment.package)
                
                # ========== PUBLISH EXCLUSIVE LISTING ==========
                # Extract listing_id from order_id (format: EXCLUSIVE_{user_id}_{listing_id}_{timestamp})
                parts = order_id.split('_')
                if len(parts) >= 3 and parts[0] == 'EXCLUSIVE':
                    listing_id = int(parts[2])
                    
                    # Find and update the listing
                    from .models import Land, Villa, Apartment, Commercial, Farm
                    property_models = [Land, Villa, Apartment, Commercial, Farm]
                    
                    for model in property_models:
                        try:
                            listing = model.objects.get(id=listing_id, user=payment.user)
                            if listing.status == 'pending_exclusive':
                                # Deduct 25 credits
                                credits = get_or_create_user_credits(payment.user)
                                if credits.purchased_listing_credits >= 25:
                                    credits.purchased_listing_credits -= 25
                                    credits.save()
                                    
                                    # Update listing status
                                    listing.status = 'exclusive'
                                    listing.save()
                                    
                                    # Track usage
                                    ListingUsage.objects.create(
                                        user=payment.user,
                                        listing_type=listing.__class__.__name__.lower(),
                                        listing_id=listing.id,
                                        credit_source='purchased',
                                        expires_at=timezone.now() + timedelta(days=45)
                                    )
                                    
                                    print(f"Exclusive listing {listing_id} published for user {payment.user.id}")
                            break
                        except model.DoesNotExist:
                            continue
                # ================================================
                
                print(f"Payment successful: {transaction_id} for user {payment.user.id}")
            else:
                payment.status = 'failed'
                payment.save()
                print(f"Payment failed: {transaction_id}")
                
        except PaymentTransaction.DoesNotExist:
            print(f"Payment transaction not found for order: {order_id}")
            return HttpResponse("Transaction not found", status=404)
        
        return HttpResponse("OK", status=200)
        
    except Exception as e:
        print(f"Webhook error: {e}")
        return HttpResponse("Error", status=500)


def paymob_success(request):
    payment_id = request.session.get('pending_payment_id')
    if payment_id:
        try:
            payment = PaymentTransaction.objects.get(id=payment_id, status='success')
            messages.success(request, f"✅ Payment successful! {payment.package.name} added to your account.")
        except PaymentTransaction.DoesNotExist:
            messages.success(request, "Payment successful! Your credits have been added.")
        if 'pending_payment_id' in request.session:
            del request.session['pending_payment_id']
    
    next_url = request.session.pop('payment_next_url', reverse('my_credits'))
    return redirect(next_url)


def paymob_cancel(request):
    """Redirect after cancelled payment"""
    from django.contrib import messages
    
    messages.warning(request, "Payment was cancelled. No charges were made.")
    return redirect('credit_packages')

@login_required
def boost_existing_listing(request, listing_type, listing_id, days=7):
    """
    Boost an existing listing with a chosen duration (7, 14, or 30 days).
    """
    from django.apps import apps
    from django.utils import timezone
    from datetime import timedelta
    from django.contrib import messages
    from django.shortcuts import redirect
    from .models import get_or_create_user_credits, BoostUsage, CreditTransaction

    # Validate days
    try:
        days = int(days)
    except (TypeError, ValueError):
        days = 7

    if days not in [7, 14, 30]:
        messages.error(request, "Invalid boost duration. Choose 7, 14, or 30 days.")
        return redirect(adss, user_id=request.user.id)

    # --- Dynamic model lookup (full mapping from your existing view) ---
    model_map = {
        # Motors
        'automobile': Automobile,
        'motorcycle': Motorcycle,
        'scooter': Scooter,
        'boat': Boat,
        'heavyvehicle': HeavyVehicle,
        'helmetclothes': HelmetClothes,
        'quadbikes': Quadbikes,
        'autoaccessorypart': AutoAccessoryPart,
        'tiresandcaps': TiresAndCaps,
        'junkcar': JunkCar,
        'numberplate': NumberPlate,
        'drivingtraining': DrivingTraining,
        'carrepairmaintenance': CarRepairMaintenance,
        # Real estate
        'land': Land,
        'villa': Villa,
        'apartment': Apartment,
        'commercial': Commercial,
        'farm': Farm,
        'office': Office,
        'shop': Shop,
        'cafe': Cafe,
        'warehouse': Warehouse,
        'townhouse': Townhouse,
        'wholebuilding': Wholebuilding,
        'factory': Factory,
        'complex': Complex,
        'clinic': Clinic,
        'hostel': Hostel,
        'staff': Staff,
        'showrooms': Showrooms,
        'fullfloors': Fullfloors,
        'supermarket': Supermarket,
        'foreign': Foreign,
        'shared': Shared,
        'suits': Suits,
        'chalet': Chalet,
        # Mobiles & electronics
        'mobile': Mobile,
        'tablet': Tablet,
        'smartwatch': SmartWatch,
        'headset': Headset,
        'cover': Cover,
        'accessory': Accessory,
        'mobilesim': MobileSIM,
        'computer': Computer,
        'sound': Sound,
        'computerlisting': ComputerListing,
        'electronicslisting': ElectronicsListing,
        # Services
        'autoservicelisting': AutoServiceListing,
        'consultancyservicelisting': ConsultancyServiceListing,
        'domesticservicelisting': DomesticServiceListing,
        'evententertainmentservicelisting': EventEntertainmentServiceListing,
        'healthwellbeingservicelisting': HealthWellbeingServiceListing,
        'homemaintenanceservicelisting': HomeMaintenanceServiceListing,
        'moversservicelisting': MoversServiceListing,
        'restorationservicelisting': RestorationServiceListing,
        'tutorsservicelisting': TutorsServiceListing,
        'webcomputerservicelisting': WebComputerServiceListing,
        'freelancersservicelisting': FreelancersServiceListing,
        'otherservicelisting': OtherServiceListing,
        # Other classifieds
        'fashion': Fashion,
        'toys': Toys,
        'food': Food,
        'fitness': Fitness,
        'pet': Pet,
        'book': Book,
        'appliance': Appliance,
        'business': Business,
        'education': Education,
        'service': Service,
        'petlisting': PetListing,
        'sportslisting': SportsListing,
        'musicallisting': MusicalListing,
        'gaminglisting': GamingListing,
        'ticketvoucherlisting': TicketVoucherListing,
        'collectiblelisting': CollectibleListing,
        'bookslisting': BooksListing,
        'musiclisting': MusicListing,
        'dvdsmovieslisting': DVDsMoviesListing,
        'furniturehomegardenlisting': FurnitureHomeGardenListing,
        'babyitemslisting': BabyItemsListing,
        'toyslisting': ToysListing,
        'lostfoundlisting': LostFoundListing,
        'cameralisting': CameraListing,
        'jewelrylisting': JewelryListing,
        'homeappliancelisting': HomeApplianceListing,
        'clothingaccessorieslisting': ClothingAccessoriesListing,
        'businessindustriallisting': BusinessIndustrialListing,
    }

    model = model_map.get(listing_type.lower())
    if not model:
        messages.error(request, f"Invalid listing type: {listing_type}")
        return redirect(adss, user_id=request.user.id)

    # --- Get the listing ---
    try:
        listing = model.objects.get(id=listing_id, user=request.user)
    except model.DoesNotExist:
        messages.error(request, "Listing not found or you don't have permission.")
        return redirect(adss, user_id=request.user.id)

    # --- Status check (only approved) ---
    if hasattr(listing, 'status') and listing.status != 'approved':
        messages.error(request, "Only approved listings can be boosted.")
        return redirect(adss, user_id=request.user.id)

    # --- 45-day creation cutoff ---
    cutoff_date = timezone.now() - timedelta(days=45)
    if listing.created_at < cutoff_date:
        messages.error(request, "This listing is older than 45 days and cannot be boosted.")
        return redirect(adss, user_id=request.user.id)

    # --- Check existing active boost ---
    existing_boost = BoostUsage.objects.filter(
        user=request.user,
        listing_type=listing_type.lower(),
        listing_id=listing_id,
        is_active=True
    ).first()

    if existing_boost and existing_boost.is_boost_active():
        days_remaining = existing_boost.days_remaining
        messages.warning(request, f"This ad is already boosted! Expires in {days_remaining} days. You can extend it by clicking Boost again.")
        return redirect(adss, user_id=request.user.id)

    # --- Check & deduct boost credits for the chosen days ---
    credits = get_or_create_user_credits(request.user)
    if credits.boost_days_available < days:
        messages.error(request, f"You don't have enough boost days. Need {days} days. Current balance: {credits.boost_days_available} days.")
        return redirect('credit_packages')

    success, msg = credits.use_boost_credit(days)
    if not success:
        messages.error(request, f"❌ {msg}")
        return redirect(adss, user_id=request.user.id)

    # --- Apply boost (new or extend) ---
    if existing_boost:
        # Extend existing boost
        existing_boost.expires_at = timezone.now() + timedelta(days=days)
        existing_boost.is_active = True
        existing_boost.boost_days = days
        existing_boost.save(update_fields=['expires_at', 'is_active', 'boost_days'])
        CreditTransaction.objects.create(
            user=request.user,
            transaction_type='usage',
            boost_days_change=-days,
            description=f"Extended boost for {listing_type} #{listing_id} by {days} days"
        )
        messages.success(request, f"✅ Boost extended by {days} days! Your ad will remain boosted for {days} more days.")
    else:
        # New boost
        if hasattr(listing, 'posting_method'):
            listing.posting_method = 'boosted'
            listing.save(update_fields=['posting_method'])
        BoostUsage.objects.create(
            user=request.user,
            listing_type=listing_type.lower(),
            listing_id=listing_id,
            boost_days=days,
            expires_at=timezone.now() + timedelta(days=days),
            is_active=True
        )
        CreditTransaction.objects.create(
            user=request.user,
            transaction_type='usage',
            boost_days_change=-days,
            description=f"Boosted {listing_type} #{listing_id} for {days} days"
        )
        messages.success(request, f"✅ Your ad is now BOOSTED for {days} days!")

    return redirect(adss, user_id=request.user.id)

@login_required
def initiate_paymob_payment(request, listing_id):
    """
    Initiates a Paymob payment for a specific listing.
    """
    from django.conf import settings
    from .models import PaymentTransaction, CreditPackage
    import requests
    import json
    from decimal import Decimal
    import time
    
    # --- Find the listing ---
    from .models import Land, Villa, Apartment, Commercial, Farm
    
    property_models = [Land, Villa, Apartment, Commercial, Farm]
    listing = None
    
    for model in property_models:
        try:
            listing = model.objects.get(id=listing_id, user=request.user)
            break
        except model.DoesNotExist:
            continue
    
    if not listing:
        messages.error(request, "Listing not found.")
        return redirect(adss, user_id=request.user.id)
    
    # Get or create a fixed package for 25 OMR
    package, created = CreditPackage.objects.get_or_create(
        name="25 OMR Exclusive Package",
        defaults={
            'package_type': 'listing',
            'listing_credits': 25,
            'price_omr': Decimal('25.000'),
            'vat_percentage': 5.00,
            'is_active': True
        }
    )
    
    total_amount_omr = Decimal('26.250')  # 25 + 5% VAT
    amount_cents = int(total_amount_omr * 100)  # 1 OMR = 1000 cents
    
    # 1. Get Auth Token
    try:
        auth_response = requests.post(
            f"{settings.PAYMOB_BASE_URL}/auth/tokens",
            json={"api_key": settings.PAYMOB_API_KEY},
            timeout=30
        )
        auth_response.raise_for_status()
        auth_token = auth_response.json()['token']
    except Exception as e:
        messages.error(request, f"Payment service error: {e}")
        return redirect(adss, user_id=request.user.id)
    
    # 2. Create Order
    merchant_order_id = f"EXCLUSIVE_{request.user.id}_{listing_id}_{int(time.time())}"
    
    try:
        order_response = requests.post(
            f"{settings.PAYMOB_BASE_URL}/ecommerce/orders",
            json={
                "auth_token": auth_token,
                "delivery_needed": False,
                "amount_cents": amount_cents,
                "currency": "OMR",
                "merchant_order_id": merchant_order_id,
                "items": []
            },
            timeout=30
        )
        order_response.raise_for_status()
        order_id = order_response.json()['id']
    except Exception as e:
        messages.error(request, f"Failed to create order: {e}")
        return redirect(adss, user_id=request.user.id)
    
    # 3. Get Payment Key
    billing_data = {
        "apartment": "NA",
        "email": request.user.email,
        "floor": "NA",
        "first_name": request.user.username[:20] if request.user.username else "Customer",
        "street": "NA",
        "building": "NA",
        "phone_number": getattr(request.user, 'phone', '00000000'),
        "shipping_method": "NA",
        "postal_code": "NA",
        "city": "NA",
        "country": "NA",
        "last_name": "Customer",
        "state": "NA"
    }
    
    try:
        payment_key_response = requests.post(
            f"{settings.PAYMOB_BASE_URL}/acceptance/payment_keys",
            json={
                "auth_token": auth_token,
                "amount_cents": amount_cents,
                "expiration": 3600,
                "order_id": order_id,
                "billing_data": billing_data,
                "currency": "OMR",
                "integration_id": settings.PAYMOB_INTEGRATION_ID,
                "lock_order_when_paid": False
            },
            timeout=30
        )
        payment_key_response.raise_for_status()
        payment_token = payment_key_response.json()['token']
    except Exception as e:
        messages.error(request, f"Failed to get payment token: {e}")
        return redirect(adss, user_id=request.user.id)
    
    # ========== CREATE PAYMENT TRANSACTION FOR WEBHOOK ==========
    payment_transaction = PaymentTransaction.objects.create(
        user=request.user,
        package=package,
        amount_omr=package.price_omr,
        vat_amount=package.get_vat_amount(),
        total_amount=total_amount_omr,
        order_id=merchant_order_id,  # This is what webhook uses to find payment
        payment_token=payment_token,
        status='pending'
    )
    # ============================================================
    
    # Store in session
    request.session['pending_payment_id'] = payment_transaction.id
    request.session['pending_listing_id'] = listing_id
    
    # Redirect to Paymob
    iframe_url = f"https://oman.paymob.com/api/acceptance/iframes/{settings.PAYMOB_IFRAME_ID}?payment_token={payment_token}"
    return redirect(iframe_url)

    
