# ============================================================
# REPOST UTILITY FUNCTION (FRESH START, AUTO-APPROVED)
# ============================================================
def repost_listing_instance(original, user):
    """
    Create a brand new listing from an expired one.
    - Does NOT copy any counter fields (views, inquiry_count, sold_at, etc.)
    - Does NOT copy unique fields (like VIN) to avoid IntegrityError.
    - Sets status='approved' (auto‑approved, live immediately)
    - Resets created_at to now (fresh 45‑day period)
    - posting_method = 'normal' (not boosted)
    """
    model = original.__class__
    model_field_names = {f.name for f in model._meta.get_fields() if f.concrete}
    
    # Fields that should never be copied (reset to default/zero)
    RESET_FIELDS = {
        'views', 'inquiry_count', 'sold_at', 'boost_days_used',
        'repost_count', 'featured_until', 'promoted_until'
    }
    
    kwargs = {}
    for field in model._meta.get_fields():
        if not field.concrete or field.primary_key:
            continue
        if field.unique:
            # Skip unique fields (e.g., vin_chassis_number)
            if field.null:
                kwargs[field.name] = None
            continue
        if field.name in RESET_FIELDS:
            # Do NOT copy – they will use the model’s default (0, None, etc.)
            continue
        kwargs[field.name] = getattr(original, field.name)
    
    # Override essential fields (force fresh values)
    kwargs['user'] = user
    if 'status' in model_field_names:
        kwargs['status'] = 'approved'          # ✅ live immediately
    if 'posting_method' in model_field_names:
        kwargs['posting_method'] = 'normal'    # ✅ not boosted
    if 'created_at' in model_field_names:
        kwargs['created_at'] = timezone.now()  # ✅ fresh 45-day timer
    
    # Remove any ID or expiry fields that might have been copied
    kwargs.pop('id', None)
    kwargs.pop('expires_at', None)
    
    new_listing = model(**kwargs)
    new_listing.save()
    
    # Copy images (re‑use the same files, create new Image records)
    if hasattr(original, 'images'):
        for img in original.images.all():
            new_listing.images.create(image=img.image)
    
    # Copy videos (re‑use the same files, create new Video records)
    if hasattr(original, 'videos'):
        for vid in original.videos.all():
            new_listing.videos.create(video=vid.video)
    
    return new_listing


# ============================================================
# REPOST VIEW (AUTO-APPROVED, DEDUCTS CREDIT, REDIRECT TO adss)
# ============================================================
@login_required
def repost_listing(request, product_type, product_id):
    """
    Repost an expired listing, auto‑approve it, and redirect to My Ads.
    """
    model = PRODUCT_MODEL_MAP.get(product_type.lower())
    if not model:
        messages.error(request, "Invalid listing type.")
        return redirect('home')
    
    # Get the original listing (must belong to the logged‑in user)
    try:
        original = model.objects.get(id=product_id, user=request.user)
    except model.DoesNotExist:
        messages.error(request, "Listing not found or you don't own it.")
        return redirect('home')
    
    # --- Check if the original listing is expired ---
    cutoff_date = timezone.now() - timedelta(days=45)
    status = getattr(original, 'status', None)
    is_expired = False
    if status == 'expired':
        is_expired = True
    elif status == 'approved' and original.created_at < cutoff_date:
        is_expired = True
    
    if not is_expired:
        messages.error(request, "Only expired listings can be reposted.")
        return redirect('product_detail', product_type=product_type, product_id=product_id)
    
    # --- Check and consume a listing credit ---
    credits = get_or_create_user_credits(request.user)
    if not credits.can_post_listing(posting_method='normal'):
        messages.error(request, "You don't have enough listing credits. Please buy a package.")
        return redirect('credit_packages')
    
    success, msg = credits.use_listing_credit(posting_method='normal')
    if not success:
        messages.error(request, msg)
        return redirect('my_credits')
    
    # --- Create the reposted listing (auto-approved, fresh) ---
    try:
        new_listing = repost_listing_instance(original, request.user)
    except Exception as e:
        logger.error(f"Repost failed for {product_type} #{product_id}: {e}", exc_info=True)
        messages.error(request, "Failed to repost listing. Please try again later.")
        return redirect('my_credits')
    
    # --- Log the transaction ---
    CreditTransaction.objects.create(
        user=request.user,
        transaction_type='usage',
        listing_credits_change=-1,
        description=f"Reposted {product_type} #{original.id} as #{new_listing.id} (auto-approved)"
    )
    
    messages.success(
        request,
        f"✅ Your listing has been reposted and is now LIVE (ID #{new_listing.id}). "
        f"It will be active for 45 days."
    )
    
    # Redirect to the user's own ads page (adss)
    return redirect(adss, user_id=request.user.id)


@login_required
def continue_normal_posting(request):
    """
    After purchasing listing credits, this view retrieves the saved normal ad data
    and posts it automatically.
    """
    user = request.user
    pending = request.session.get('pending_normal_ad')
    
    if not pending:
        messages.error(request, "No pending ad found. Please start over.")
        return redirect('listingcommunity')
    
    product_type = pending['product_type']
    form_data = pending['form_data']
    temp_files = pending['temp_files']
    
    credits = get_or_create_user_credits(user)
    
    # Re-check listing credits (should now be sufficient)
    if not credits.can_post_listing('normal'):
        messages.error(request, "You still don't have enough listing credits. Please purchase a package.")
        del request.session['pending_normal_ad']
        return redirect('credit_packages')
    
    # Process the saved ad (same helper as in listingcommunity)
    obj = process_community_registration(request, product_type, form_data, temp_files, 'normal', status='pending')
    if not obj:
        messages.error(request, "Failed to create listing. Please try again.")
        del request.session['pending_normal_ad']
        return redirect('listingcommunity')
    
    # Deduct listing credit
    success, msg = credits.use_listing_credit('normal')
    if success:
        ListingUsage.objects.create(
            user=user,
            listing_type=obj._meta.model_name,
            listing_id=obj.id,
            credit_source='free' if credits.available_free_listings + 1 > credits.free_listings_used else 'purchased',
            expires_at=timezone.now() + timedelta(days=45)
        )
        messages.success(request, f"✅ {msg}")
    else:
        messages.warning(request, f"⚠️ {msg}")
    
    # Clean up session
    del request.session['pending_normal_ad']
    
    return redirect(adss, user_id=user.id)

@login_required
def continue_boost_posting(request):
    """
    After purchasing listing credits or boost days, this view retrieves the saved boosted ad data
    and posts it automatically, deducting both listing and boost credits.
    """
    user = request.user
    pending = request.session.get('pending_boost_ad')
    
    if not pending:
        messages.error(request, "No pending ad found. Please start over.")
        return redirect('listingcommunity')
    
    product_type = pending['product_type']
    form_data = pending['form_data']
    temp_files = pending['temp_files']
    boost_duration = pending['boost_duration']
    
    credits = get_or_create_user_credits(user)
    
    # First, re-check listing credits
    if not credits.can_post_listing('normal'):
        messages.error(request, "You still don't have enough listing credits. Please purchase a package.")
        del request.session['pending_boost_ad']
        return redirect('credit_packages')
    
    # Then, re-check boost days
    if credits.boost_days_available < boost_duration:
        messages.error(request, f"You still don't have enough boost days. Need {boost_duration} days. Please purchase a boost package.")
        del request.session['pending_boost_ad']
        return redirect('credit_packages')
    
    # Process the saved ad
    obj = process_community_registration(request, product_type, form_data, temp_files, 'boosted', status='pending')
    if not obj:
        messages.error(request, "Failed to create listing. Please try again.")
        del request.session['pending_boost_ad']
        return redirect('listingcommunity')
    
    # Deduct listing credit
    success, msg = credits.use_listing_credit('normal')
    if success:
        ListingUsage.objects.create(
            user=user,
            listing_type=obj._meta.model_name,
            listing_id=obj.id,
            credit_source='free' if credits.available_free_listings + 1 > credits.free_listings_used else 'purchased',
            expires_at=timezone.now() + timedelta(days=45)
        )
        # Deduct boost credit
        boost_success, boost_msg = credits.use_boost_credit(boost_duration)
        if boost_success:
            BoostUsage.objects.create(
                user=user,
                listing_type=obj._meta.model_name,
                listing_id=obj.id,
                boost_days=boost_duration,
                expires_at=timezone.now() + timedelta(days=boost_duration),
                is_active=True
            )
            messages.success(request, f"✅ {msg} and {boost_msg}")
        else:
            messages.warning(request, f"✅ {msg} but {boost_msg}")
    else:
        messages.warning(request, f"⚠️ {msg}")
    
    # Clean up session
    del request.session['pending_boost_ad']
    
    return redirect(adss, user_id=user.id)

