@login_required
def continue_exclusive_property_posting(request):
    """
    Runs after the 25 OMR payment succeeds (webhook adds 25 credits).
    Deducts 25 credits and creates the exclusive listing as pending_exclusive.
    If the user never paid, this never runs -> nothing is created.
    """
    user = request.user
    pending = request.session.get('pending_exclusive_property_ad')

    if not pending:
        messages.error(request, "No pending exclusive ad found. Please start over.")
        return redirect('listingsub')

    EXCLUSIVE_COST = 25
    product_type = pending['product_type']
    form_data = pending['form_data']
    temp_files = pending['temp_files']

    credits = get_or_create_user_credits(user)

    # Webhook adds 25 credits on success. If not present yet, payment is still confirming.
    if credits.purchased_listing_credits < EXCLUSIVE_COST:
        messages.warning(
            request,
            "Your payment is still being confirmed. Your exclusive listing will be submitted "
            "once it clears — please refresh in a moment."
        )
        return redirect('my_credits')

    obj = process_property_registration(
        request, product_type, form_data, temp_files,
        'exclusive', status='pending_exclusive'
    )
    if not obj:
        messages.error(request, "Failed to create exclusive listing.")
        return redirect('listingsub')

    credits.purchased_listing_credits -= EXCLUSIVE_COST
    credits.save(update_fields=['purchased_listing_credits'])

    CreditTransaction.objects.create(
        user=user,
        transaction_type='usage',
        listing_credits_change=-EXCLUSIVE_COST,
        listing_id=obj.id,
        listing_type=obj._meta.model_name,
        description=f"Exclusive listing #{obj.id}: paid 25 OMR (awaiting admin approval)",
    )
    notify_admin_exclusive_request(obj, user, product_type)

    del request.session['pending_exclusive_property_ad']
    messages.success(request, "✅ Payment received! Your exclusive listing was sent to admin for approval.")
    return redirect(adss, user_id=user.id)


