from django.shortcuts import render, get_object_or_404, redirect
from django.contrib import messages
from django.contrib.auth.decorators import login_required
from django.apps import apps
from django.db import transaction
from decimal import Decimal, InvalidOperation
import logging

logger = logging.getLogger(__name__)

# Fields a normal user is NOT allowed to edit on their own listing.
EXCLUDED_EDIT_FIELDS = {
    'id', 'user', 'status', 'is_active', 'is_featured',
    'posting_method', 'created_at', 'updated_at', 'slug', 'views',
}

# Fields the map widget owns
MAP_FIELDS = {'latitude', 'longitude', 'city'}

# Statuses that allow editing
EDITABLE_STATUSES = ['pending', 'approved']


# =============================================================================
# USER PRODUCT EDIT VIEW
# =============================================================================
@login_required
@transaction.atomic
def user_product_edit(request, model_name, pk):
    """
    Edit user's product listing.
    
    ✅ Only 'pending' and 'approved' listings can be edited
    ✅ User can only edit their own listings
    ✅ Approved listings become 'pending' after changes
    """
    
    # 1. Resolve the model from the lowercase name
    try:
        model = apps.get_model('oman_app', model_name)
    except LookupError:
        messages.error(request, "Invalid product type.")
        return redirect(adss, user_id=request.user.id)  # ✅ adss is defined above

    if model is None:
        messages.error(request, "Invalid product type.")
        return redirect(adss, user_id=request.user.id)

    # 2. Ownership lock — user can ONLY load their own listing
    product = get_object_or_404(model, id=pk, user=request.user)

    # 2b. Check if status allows editing
    if hasattr(product, 'status'):
        if product.status not in EDITABLE_STATUSES:
            messages.error(request, f"This listing has status '{product.status}' and cannot be edited.")
            return redirect(adss, user_id=request.user.id)
    else:
        # If model doesn't have status field, block editing
        messages.error(request, "This product type doesn't support editing.")
        return redirect(adss, user_id=request.user.id)

    # 2c. Store original status for later comparison
    original_status = getattr(product, 'status', None)

    # 2d. Does this model support the location map?
    model_field_names = {f.name for f in product._meta.fields}
    has_map = MAP_FIELDS.issubset(model_field_names)

    # ------------------------------------------------------------------
    # 3. Build editable fields for the template
    # ------------------------------------------------------------------
    fields = []
    for field in product._meta.fields:
        if field.name in EXCLUDED_EDIT_FIELDS:
            continue

        # When the map is active it owns lat/lng
        if has_map and field.name in ('latitude', 'longitude'):
            continue

        field_info = {
            'name': field.name,
            'verbose_name': field.verbose_name or field.name.replace('_', ' ').title(),
            'type': field.get_internal_type(),
            'value': getattr(product, field.name),
            'choices': field.choices if field.choices else None,
            'is_relation': field.is_relation,
            'null': field.null,
            'blank': field.blank,
            'help_text': field.help_text,
            'required': not field.blank,
        }

        if field.is_relation and field.many_to_one:
            related_model = field.related_model
            if related_model.__name__ == 'User':
                continue
            field_info['related_choices'] = related_model.objects.all()

        fields.append(field_info)

    # ------------------------------------------------------------------
    # 4. ManyToMany fields
    # ------------------------------------------------------------------
    many_to_many_fields = []
    for field in product._meta.many_to_many:
        if field.name in EXCLUDED_EDIT_FIELDS or field.name in ['user', 'images', 'videos']:
            continue
        many_to_many_fields.append({
            'name': field.name,
            'verbose_name': field.verbose_name or field.name.replace('_', ' ').title(),
            'value': getattr(product, field.name).all(),
            'related_choices': field.related_model.objects.all(),
        })

    # ------------------------------------------------------------------
    # 5. Handle POST (save)
    # ------------------------------------------------------------------
    if request.method == 'POST':
        try:
            # ✅ Re-validate status on POST (defense in depth)
            if product.status not in EDITABLE_STATUSES:
                messages.error(request, "This listing cannot be edited due to status restrictions.")
                return redirect(adss, user_id=request.user.id)
            
            # Track if any changes were made to the product
            changes_made = False
            
            for field in product._meta.fields:
                field_name = field.name
                if field_name in EXCLUDED_EDIT_FIELDS:
                    continue

                internal_type = field.get_internal_type()

                # File/Image fields
                if internal_type in ['FileField', 'ImageField']:
                    if field_name in request.FILES:
                        setattr(product, field_name, request.FILES[field_name])
                        changes_made = True
                    continue

                post_value = request.POST.get(field_name)

                # Booleans
                if internal_type == 'BooleanField':
                    new_value = post_value in ('on', 'True', 'true', '1')
                    if getattr(product, field_name) != new_value:
                        setattr(product, field_name, new_value)
                        changes_made = True
                    continue

                if post_value is None:
                    continue

                if post_value == '' and field.null:
                    if getattr(product, field_name) is not None:
                        setattr(product, field_name, None)
                        changes_made = True
                    continue
                if post_value == '' and not field.null:
                    continue

                # Handle different field types
                if internal_type in ['IntegerField', 'PositiveIntegerField', 'SmallIntegerField', 'BigIntegerField']:
                    try:
                        new_value = int(post_value)
                        if getattr(product, field_name) != new_value:
                            setattr(product, field_name, new_value)
                            changes_made = True
                    except (ValueError, TypeError):
                        pass

                elif internal_type == 'DecimalField':
                    try:
                        new_value = Decimal(post_value)
                        if getattr(product, field_name) != new_value:
                            setattr(product, field_name, new_value)
                            changes_made = True
                    except (InvalidOperation, ValueError, TypeError):
                        pass

                elif field.is_relation:
                    related_model = field.related_model
                    if related_model.__name__ == 'User':
                        continue
                    try:
                        new_value = related_model.objects.get(id=post_value)
                        if getattr(product, field_name) != new_value:
                            setattr(product, field_name, new_value)
                            changes_made = True
                    except related_model.DoesNotExist:
                        pass

                else:
                    new_value = post_value
                    if getattr(product, field_name) != new_value:
                        setattr(product, field_name, new_value)
                        changes_made = True

            # ManyToMany fields
            for field in product._meta.many_to_many:
                field_name = field.name
                if field_name in EXCLUDED_EDIT_FIELDS or field_name in ['user', 'images', 'videos']:
                    continue
                new_values = request.POST.getlist(field_name)
                current_values = list(getattr(product, field_name).values_list('id', flat=True))
                if set(new_values) != set(current_values):
                    getattr(product, field_name).set(new_values)
                    changes_made = True

            # Images
            if hasattr(product, 'images'):
                delete_ids = request.POST.getlist('delete_images')
                if delete_ids:
                    product.images.filter(id__in=delete_ids).delete()
                    changes_made = True
                for f in request.FILES.getlist('new_images'):
                    image_model = product.images.model
                    img = image_model(image=f)
                    img.save()
                    product.images.add(img)
                    changes_made = True

            # Videos
            if hasattr(product, 'videos'):
                delete_ids = request.POST.getlist('delete_videos')
                if delete_ids:
                    product.videos.filter(id__in=delete_ids).delete()
                    changes_made = True
                for f in request.FILES.getlist('new_videos'):
                    video_model = product.videos.model
                    vid = video_model(video=f)
                    vid.save()
                    product.videos.add(vid)
                    changes_made = True

            # CRITICAL: If changes were made AND the product was approved,
            # set status back to pending for re-approval
            if changes_made and hasattr(product, 'status'):
                if product.status == 'approved':
                    product.status = 'pending'
                    messages.info(request, "This listing has been changed and is now pending re-approval.")
                elif product.status == 'pending':
                    messages.info(request, "Your pending listing has been updated.")

            # Only save if changes were made
            if changes_made:
                product.save()
                messages.success(request, "Your listing has been updated successfully.")
            else:
                messages.info(request, "No changes were made to your listing.")

            return redirect(adss, user_id=request.user.id)

        except Exception as e:
            logger.error(f"Error updating product {pk}: {str(e)}", exc_info=True)
            messages.error(request, f"Error updating listing: {str(e)}")

    # ------------------------------------------------------------------
    # 6. Render
    # ------------------------------------------------------------------
    existing_images = product.images.all() if hasattr(product, 'images') else []
    existing_videos = product.videos.all() if hasattr(product, 'videos') else []

    return render(request, 'Edit/user_product_edit.html', {
        'product': product,
        'product_type': model_name,
        'fields': fields,
        'many_to_many_fields': many_to_many_fields,
        'existing_images': existing_images,
        'existing_videos': existing_videos,
        'has_map': has_map,
        'is_editable': getattr(product, 'status', None) in EDITABLE_STATUSES,
    })
