from django.contrib.admin.views.decorators import staff_member_required
from django.core.paginator import Paginator, EmptyPage, PageNotAnInteger
from django.db.models import Count, Q
from django.shortcuts import render, get_object_or_404, redirect
from django.contrib import messages
from django.utils import timezone

@staff_member_required
def admin_all_comments(request):
    """
    View all comments across all listings in one place
    """
    # Get filter parameters
    search_query = request.GET.get('search', '')
    listing_type_filter = request.GET.get('listing_type', '')
    action_required_filter = request.GET.get('action_required', '')
    
    # Base queryset
    comments = ListingComment.objects.select_related('admin', 'user').order_by('-created_at')
    
    # Apply filters
    if search_query:
        comments = comments.filter(
            Q(comment__icontains=search_query) |
            Q(user__username__icontains=search_query) |
            Q(admin__username__icontains=search_query) |
            Q(listing_type__icontains=search_query)
        )
    
    if listing_type_filter:
        comments = comments.filter(listing_type=listing_type_filter)
    
    if action_required_filter == 'yes':
        comments = comments.filter(requires_action=True)
    elif action_required_filter == 'no':
        comments = comments.filter(requires_action=False)
    
    # Get unique listing types for filter dropdown
    listing_types = ListingComment.objects.values_list('listing_type', flat=True).distinct()
    
    # Pagination
    paginator = Paginator(comments, 20)
    page_number = request.GET.get('page')
    
    try:
        page_obj = paginator.get_page(page_number)
    except EmptyPage:
        page_obj = paginator.get_page(paginator.num_pages)
    
    # Get stats
    total_comments = ListingComment.objects.count()
    comments_with_action = ListingComment.objects.filter(requires_action=True).count()
    
    context = {
        'comments': page_obj,
        'total_comments': total_comments,
        'comments_with_action': comments_with_action,
        'listing_types': listing_types,
        'search_query': search_query,
        'listing_type_filter': listing_type_filter,
        'action_required_filter': action_required_filter,
    }
    
    return render(request, 'admin1/all_comments.html', context)


@staff_member_required
def admin_delete_comment(request, comment_id):
    """
    Delete a single comment
    """
    if request.method == 'POST':
        comment = get_object_or_404(ListingComment, id=comment_id)
        if comment.admin == request.user or request.user.is_superuser:
            comment.delete()
            messages.success(request, "Comment deleted.")
        else:
            messages.error(request, "You don't have permission to delete this comment.")
    
    return redirect('admin_all_comments')


@staff_member_required
def admin_toggle_action_required(request, comment_id):
    """
    Toggle the 'requires_action' flag on a comment
    """
    if request.method == 'POST':
        comment = get_object_or_404(ListingComment, id=comment_id)
        comment.requires_action = not comment.requires_action
        comment.save()
        messages.success(request, f"Action required status updated to: {comment.requires_action}")
    
    return redirect('admin_all_comments')


@staff_member_required
def admin_clear_all_comments(request):
    """
    Clear all comments (use with caution)
    """
    if request.method == 'POST':
        confirm = request.POST.get('confirm', '')
        if confirm == 'YES':
            count = ListingComment.objects.count()
            ListingComment.objects.all().delete()
            messages.success(request, f"All {count} comments have been deleted.")
        else:
            messages.error(request, "Confirmation failed. Please type 'YES' to confirm.")
    
    return redirect('admin_all_comments')

from django.http import JsonResponse
from django.contrib.auth.decorators import login_required
from django.apps import apps
from django.db.models import Q
import logging

logger = logging.getLogger(__name__)

@login_required
def get_user_comments(request, listing_type, listing_id):
    """
    Get comments for a specific listing (user view - view only, no reply)
    """
    try:
        # Try to get the model
        try:
            model = apps.get_model('oman_app', listing_type.title())
        except LookupError:
            return JsonResponse({
                'success': False,
                'error': f'Invalid listing type: {listing_type}'
            }, status=400)
        
        # Verify the user owns this listing
        try:
            listing = model.objects.get(id=listing_id, user=request.user)
        except model.DoesNotExist:
            return JsonResponse({
                'success': False,
                'error': 'Listing not found or you don\'t have permission'
            }, status=404)
        
        # Get comments for this listing
        comments = ListingComment.objects.filter(
            listing_type=listing_type.lower(),
            listing_id=listing_id
        ).select_related('admin', 'user').order_by('-created_at')
        
        # Mark comments as read
        comments.filter(is_read=False).update(is_read=True)
        
        # Get listing title
        title = getattr(listing, 'property_title', 
                  getattr(listing, 'title', 
                  getattr(listing, 'name', f"{listing_type} #{listing_id}")))
        
        comments_data = []
        for comment in comments:
            comments_data.append({
                'id': comment.id,
                'comment': comment.comment,
                'admin_name': comment.admin.username if comment.admin else 'Admin',
                'created_at': comment.created_at.strftime('%b %d, %Y %H:%M'),
                'requires_action': comment.requires_action,
            })
        
        return JsonResponse({
            'success': True,
            'comments': comments_data,
            'listing_title': title,
            'total': len(comments_data)
        })
        
    except Exception as e:
        logger.error(f"Error in get_user_comments: {str(e)}")
        return JsonResponse({
            'success': False,
            'error': str(e)
        }, status=500)